INSERT INTO `zzzzsys_email_template` (`zzzzsys_email_template_id`, `emt_form_id`, `emt_group`, `emt_category`, `emt_template`, `emt_language`, `emt_description`, `emt_code`, `emt_body`, `emt_subject`, `emt_to`, `emt_cc`, `emt_bcc`) VALUES
('68eafc1b8e60143', 'nuuser', 'nubuilder', '', '0', '', 'When \"Send welcome email\" is checked in the user form, a welcome email is sent to the new user.', 'nu_send_welcome_email', 'Dear #sus_name#\n\nWelcome to nuBuilder! Your temporary OTP is valid for a limited time for security reasons. \n\nFollow these steps to get started:\n\n1. Visit #NUBUILDER_URL# to access the login page.\n\n2. Enter your Username: #sus_login_name#\n\n3. Use the temporary OTP as your password: #check_password#\n\n4. Once logged in, create a more secure password that includes uppercase letters, lowercase letters, numbers, and special characters.\n\n5. Login with your new password.\n\nBest regards,\nAdministrator', 'Temporary OTP Password', '#sus_email#', '', ''),
('nu64f9586941b545d', 'nuuser', 'nubuilder', NULL, '1', NULL, 'When \"Send welcome email\" is checked in the user form, a welcome email is sent to the new user.', 'nu_send_welcome_email_template', 'Dear #sus_name#\n\nWelcome to nuBuilder! Your temporary OTP is valid for a limited time for security reasons. \n\nFollow these steps to get started:\n\n1. Visit #NUBUILDER_URL# to access the login page.\n\n2. Enter your Username: #sus_login_name#\n\n3. Use the temporary OTP as your password: #check_password#\n\n4. Once logged in, create a more secure password that includes uppercase letters, lowercase letters, numbers, and special characters.\n\n5. Login with your new password.\n\nBest regards,\nAdministrator', ' Welcome to nuBuilder - Temporary OTP Password', '#sus_email#', NULL, NULL);
INSERT INTO `zzzzsys_event` (`zzzzsys_event_id`, `sev_zzzzsys_object_id`, `sev_event`, `sev_javascript`, `sev_json`) VALUES
('68cb39fcca34f06', '68cb37f495bd3b9', 'onclick', 'nuOpenTab(1); // Opens the History tab', NULL),
('68cb4a5f886675b', '68cb4a5f87321a7', 'onclick', 'nuOpenTab(2); // Opens the Witness Statements tab', NULL),
('68cb4a930e80681', '68cb4a930d312f9', 'onclick', 'nuOpenTab(0); // Opens the Location & Contact tab', NULL),
('68cc56ad2a3d8cb', '68cb4ddee9ee5f7', 'onclick', 'window.open(nuGetValue(\'pk_loc_hist_docs_URL\'),\"_blank\");', NULL),
('68cc597a8ee52e6', '68cc597a8dac3c8', 'onclick', 'function nuVendorLogin(appId, table) {\n	const tableName = table || nuSERVERRESPONSE.table;\n	const params = new URLSearchParams({\n		sessid: window.nuSESSION,\n		appId: appId,\n		table: tableName,\n		timezone: nuSERVERRESPONSE.timezone\n	});\n	const url = `core/nuvendorlogin.php?${params.toString()}`;\n	return window.open(url, appId);\n}\n\n// open TFM vendor session\nvar win = nuVendorLogin(\'TFM\');\n\n// determine active tab\nvar tab_id = nuSelectedTabId();\nvar tablabel = \'\';\n\nif (tab_id === \'68ca2d0c176d4d4\') {\n	tablabel = \'Audio\';\n} else if (tab_id === \'68e16015b8742d6\') {\n	tablabel = \'Video\';\n} else if (tab_id === \'68e16037843edff\') {\n	tablabel = \'Photo\';\n} else if (tab_id === \'68ca2ad572dae00\') {\n	tablabel = \'History\';\n}\n\nvar recordNumber = nuRecordId();\n\n// resolve nuBuilder base path\nvar base = window.location.origin + window.location.pathname.split(\'/index.php\')[0];\n\n// build Tiny File Manager URL\n// build Tiny File Manager URL\nvar fileManagerUrl =\n    base +\n    \'/third_party/tinyfilemanager/tinyfilemanager.php?p=\' +\n    encodeURIComponent(\n        \'Investigation \' + recordNumber + \'/\' + tablabel\n    );\n\n// redirect vendor window\nif (win) {\n	setTimeout(function () {\n		win.location.href = fileManagerUrl;\n	}, 500);\n}\n', NULL),
('68cc5fff40cef99', '68cc5fff3f6c239', 'onclick', 'nuOpenTab(1); // Opens the History tab', NULL),
('68cc60287b685ec', '68cc60287a113ef', 'onclick', 'nuOpenTab(3); // Opens the Investigation Log tab', NULL),
('68ccce3923d62e6', '68ccce39229000e', 'onclick', 'nuOpenTab(4); // Opens the Personal Experiences tab', NULL),
('68cccebdb9f2ee9', '68cccebdb8bf22c', 'onclick', 'nuOpenTab(2); // Opens the Witness Statements tab', NULL),
('68ccd4f45e784e8', '68ccd4f45d383aa', 'onclick', 'nuOpenTab(4); // Opens the Personal Experiences tab', NULL),
('68ccd5914a58bcf', '68ccd591491a4e4', 'onclick', 'nuOpenTab(6); // Opens the Video tab', NULL),
('68ccd632c44539a', '68ccd632c3141d9', 'onclick', 'nuOpenTab(4); // Opens the fifth tab', NULL),
('68ccd6db50f9056', '68ccd6db4fbc234', 'onclick', 'nuOpenTab(6); // Opens the seventh tab', NULL),
('68ccd789707fcba', '68ccd7896f02941', 'onclick', 'nuOpenTab(7); // Opens the Photo tab', NULL),
('68d159521872ed8', '68d1595217e1ab3', 'onclick', 'nuOpenTab(5); // Opens the Audio tab', NULL),
('68d15a6a5fedced', '68d15a6a5f52f99', 'onclick', 'nuOpenTab(3); // Opens the Investigation Log tab', NULL),
('68d219512f6c883', '68d219512ef5603', 'onclick', 'function nuVendorLogin(appId, table) {\n	const tableName = table || nuSERVERRESPONSE.table;\n	const params = new URLSearchParams({\n		sessid: window.nuSESSION,\n		appId: appId,\n		table: tableName,\n		timezone: nuSERVERRESPONSE.timezone\n	});\n	const url = `core/nuvendorlogin.php?${params.toString()}`;\n	return window.open(url, appId);\n}\n\n// open TFM vendor session\nvar win = nuVendorLogin(\'TFM\');\n\n// determine active tab\nvar tab_id = nuSelectedTabId();\nvar tablabel = \'\';\nvar folderPath = \'\';\n\n// map tab to folder\nif (tab_id === \'68ca2d0c176d4d4\') {\n	tablabel = \'Audio\';\n	folderPath = \'Evidence/Audio\';\n} else if (tab_id === \'68e16015b8742d6\') {\n	tablabel = \'Video\';\n	folderPath = \'Evidence/Video\';\n} else if (tab_id === \'68e16037843edff\') {\n	tablabel = \'Photo\';\n	folderPath = \'Evidence/Photo\';\n} else if (tab_id === \'69cf47d2315252c\') {\n	tablabel = \'Sensors\';\n	folderPath = \'Evidence/Sensors\';\n} else if (tab_id === \'68ca2ad572dae00\') {\n	tablabel = \'History\';\n	folderPath = \'History\';\n} else {\n	alert(\'No upload folder is mapped for this tab.\');\n	throw new Error(\'No Tiny File Manager folder mapping for tab id: \' + tab_id);\n}\n\nvar recordNumber = nuRecordId();\n\n// resolve nuBuilder base path\nvar base = window.location.origin + window.location.pathname.split(\'/index.php\')[0];\n\n// build Tiny File Manager URL\nvar fileManagerUrl =\n	base +\n	\'/third_party/tinyfilemanager/tinyfilemanager.php?p=Investigation \' +\n	recordNumber +\n	\'/\' +\n	folderPath;\n\n// redirect vendor window\nif (win) {\n	setTimeout(function () {\n		win.location.href = fileManagerUrl;\n	}, 500);\n}', NULL),
('68d22f6210809e3', '68d22f6210130f7', 'onclick', 'var url = nuGetValue(\'pk_audio_url_1\');\nif (url && url.trim() !== \'\') {\n    window.open(url, \'_blank\');\n}', NULL),
