('68e598792d48b46', '68e598792cc0e47', 'onclick', '(function () {\n\n    var url = nuGetValue(\'pk_audio_files\');\n\n    // Empty field check\n    if (!url) {\n        nuMessage(\'No audio file has been specified.\');\n        return;\n    }\n\n    // Check file existence\n    fetch(url, { method: \'HEAD\' })\n        .then(function (response) {\n            if (response.ok) {\n                window.open(url, \'_blank\');\n            } else {\n                nuMessage(\'Audio file not found on the server.\');\n            }\n        })\n        .catch(function () {\n            nuMessage(\'Unable to verify audio file.\');\n        });\n\n})();\n\n\n//window.open(nuGetValue(\'pk_audio_files\'),\"_blank\");', NULL),
('68e5a23942eb40d', '68e5a239426836b', 'onclick', '(function () {\n\n    var url = nuGetValue(\'pk_video_files\');\n\n    // Empty field check\n    if (!url) {\n        nuMessage(\'No video file has been specified.\');\n        return;\n    }\n\n    // Check file existence\n    fetch(url, { method: \'HEAD\' })\n        .then(function (response) {\n            if (response.ok) {\n                window.open(url, \'_blank\');\n            } else {\n                nuMessage(\'Video file not found on the server.\');\n            }\n        })\n        .catch(function () {\n            nuMessage(\'Unable to verify video file.\');\n        });\n\n})();\n\n\n//window.open(nuGetValue(\'pk_video_files\'),\"_blank\");', NULL),
('68e5a7d4f106d19', '68e5a7d4f091ca2', 'onclick', '\n(function () {\n\n    var url = nuGetValue(\'pk_photo_files\');\n\n    // Empty field check\n    if (!url) {\n        nuMessage(\'No photo file has been specified.\');\n        return;\n    }\n\n    // Check file existence\n    fetch(url, { method: \'HEAD\' })\n        .then(function (response) {\n            if (response.ok) {\n                window.open(url, \'_blank\');\n            } else {\n                nuMessage(\'Photo file not found on the server.\');\n            }\n        })\n        .catch(function () {\n            nuMessage(\'Unable to verify photo file.\');\n        });\n\n})();\n\n//window.open(nuGetValue(\'pk_photo_files\'),\"_blank\");', NULL),
