('68e99ca21b04780', '68e99ca21a7df2c', 'onclick', 'function nuVendorLogin(appId, table) {\n	const tableName = table || nuSERVERRESPONSE.table;\n	const params = new URLSearchParams({\n		sessid: window.nuSESSION,\n		appId: appId,\n		table: tableName,\n		timezone: nuSERVERRESPONSE.timezone\n	});\n\n	const url = `core/nuvendorlogin.php?${params.toString()}`;\n	return window.open(url, appId);\n}\n\n// 1. Open TFM via nuVendorLogin()\nvar win = nuVendorLogin(\'TFM\');\n\n// 2. Determine nuBuilder base path dynamically\n// This strips everything after the nuBuilder root\nvar basePath = window.location.pathname\n	.replace(/\\/index\\.php.*$/, \'/\')\n	.replace(/\\/$/, \'\');\n\n// 3. Build Tiny File Manager path (NO hardcoding)\nvar recordNumber = nuRecordId();\nvar fileManagerUrl =\n	`${basePath}/third_party/tinyfilemanager/tinyfilemanager.php` +\n	`?p=Investigation ${recordNumber}/Evidence/Photo/`;\n\n// 4. Redirect vendor window once session is established\nif (win) {\n	setTimeout(() => {\n		win.location.href = fileManagerUrl;\n	}, 500);\n}\n\n\n/*\nfunction nuVendorLogin(appId, table) {\n	const tableName = table || nuSERVERRESPONSE.table;\n	const params = new URLSearchParams({\n		sessid: window.nuSESSION,\n		appId: appId,\n		table: tableName,\n		timezone: nuSERVERRESPONSE.timezone\n	});\n\n	const url = `core/nuvendorlogin.php?${params.toString()}`;\n	return window.open(url, appId); // use appId as window name for reuse\n}\n\n// 1. Open TFM via nuVendorLogin()\nvar win = nuVendorLogin(\'TFM\');\n\n// 2. Build the Tiny File Manager URL\n//var tab_id = nuSelectedTabId(); \n//var tablabel = \'\';\n\n//if (tab_id === \'68ca2c669f546c9\') {\n//	tablabel = \'Investigation\';\n//}\n\nvar recordNumber = nuRecordId();\n\n// Construct the file path dynamically\nvar path = \'/nubuilder2/third_party/tinyfilemanager/\';\n\n// Construct the full URL\nvar fileManagerUrl = `${path}tinyfilemanager.php?p=Case ${recordNumber}/Evidence/Photo/&upload`;\n\n// 3. Once the vendor login window is created, change its location\nif (win) {\n	setTimeout(() => {\n		win.location.href = fileManagerUrl;\n	}, 500); // wait 1/2 second before redirecting\n}\n*/', NULL),
