('69178c3f4bf032b', '691582134e5293d', 'onnuload', 'setTimeout(function() {\n    nuSetValue(\'htmlcontainer\', nuTinyMCEGetContent(\'MYREPORTS\'), \'html\');\n}, 2000);\n', NULL),
('691a1cfa9b21249', '691a1cfa9aa463c', 'onnuload', '/*\nsetTimeout(function() {\n    // Get the HTML content from the MYREPORTS element\n    var htmlContent = nuTinyMCEGetContent(\'MYREPORTS\');\n    \n    // Set the content in the current page\'s \'htmlcontainer\'\n    nuSetValue(\'htmlcontainer\', htmlContent, \'html\');\n    \n    // Open a new, blank tab\n    var newTab = window.open(\'about:blank\', \'_blank\');\n    \n    // Write the HTML content to the new tab\'s document\n    if (newTab) {\n        newTab.document.write(htmlContent);\n        newTab.document.close(); // Important to finish loading the page\n    } else {\n        // Handle cases where a pop-up blocker might prevent the new tab from opening\n        alert(\'Please allow pop-ups for this site to view the report in a new tab.\');\n    }\n}, 2000);\n*/', NULL),
