('6929d50a4e7d7ee', '6929d50a4e10828', 'onclick', '// Edit devices list\nvar base = window.location.origin + window.location.pathname.split(\'/index.php\')[0];\n\nvar win = window.open(\n    base + \'/index.php?f=nuobject&r=68eae61e952e201\',\n    \'_blank\',\n    \'width=1200,height=840,top=50,left=50,resizable=yes,scrollbars=yes\'\n);\n\nif (win) {\n\n    // loading overlay\n    var overlayInjected = false;\n\n    var overlayTimer = setInterval(function () {\n        try {\n            if (win.closed) { clearInterval(overlayTimer); return; }\n\n            if (!overlayInjected && win.document && win.document.body) {\n                var overlay = win.document.createElement(\'div\');\n                overlay.id = \'sf-wait-overlay\';\n                overlay.style.cssText =\n                    \'position:fixed;inset:0;background:rgba(0,0,0,0.35);display:flex;align-items:center;justify-content:center;z-index:999999;\';\n                overlay.innerHTML =\n                    \'<div style=\"background:#222;color:#fff;padding:24px 32px;border-radius:8px;font-size:18px;font-family:Arial,sans-serif;box-shadow:0 0 20px rgba(0,0,0,0.6);\">Opening Master Devices Listâ€¦<br>Please wait</div>\';\n                win.document.body.appendChild(overlay);\n                overlayInjected = true;\n                clearInterval(overlayTimer);\n            }\n        } catch (e) {}\n    }, 100);\n\n    // auto-select tab\n    var t = setInterval(function () {\n        try {\n            if (win.closed) { clearInterval(t); return; }\n            if (!win.document || win.document.readyState !== \'complete\') { return; }\n\n            var nodes = win.document.querySelectorAll(\'a,button,div,span,li\');\n            for (var i = 0; i < nodes.length; i++) {\n                var txt = nodes[i].textContent && nodes[i].textContent.trim();\n                if (txt === \'Select\') {\n                    nodes[i].click();\n                    var el = win.document.getElementById(\'sf-wait-overlay\');\n                    if (el) el.remove();\n                    clearInterval(t);\n                    break;\n                }\n            }\n        } catch (e) {}\n    }, 300);\n}\n\nreturn false;\n', NULL),
