('6929e14c9f5d37d', '6929e14c9ee76e4', 'onclick', '// Edit Computer Apps List\nvar base = window.location.origin + window.location.pathname.split(\'/index.php\')[0];\n\nvar win = window.open(\n    base + \'/index.php?f=nuobject&r=68eadeb74b8220f\',\n    \'_blank\',\n    \'width=1200,height=840,top=50,left=50,resizable=yes,scrollbars=yes\'\n);\n\nif (win) {\n\n    // loading overlay\n    var overlayInjected = false;\n\n    var overlayTimer = setInterval(function () {\n        try {\n            if (win.closed) { clearInterval(overlayTimer); return; }\n\n            if (!overlayInjected && win.document && win.document.body) {\n                var overlay = win.document.createElement(\'div\');\n                overlay.id = \'sf-wait-overlay\';\n                overlay.style.cssText =\n                    \'position:fixed;inset:0;background:rgba(0,0,0,0.35);display:flex;align-items:center;justify-content:center;z-index:999999;\';\n                overlay.innerHTML =\n                    \'<div style=\"background:#222;color:#fff;padding:24px 32px;border-radius:8px;font-size:18px;font-family:Arial,sans-serif;box-shadow:0 0 20px rgba(0,0,0,0.6);\">Opening Computer Apps Listâ€¦<br>Please wait</div>\';\n                win.document.body.appendChild(overlay);\n                overlayInjected = true;\n                clearInterval(overlayTimer);\n            }\n        } catch (e) {}\n    }, 100);\n\n    // auto-select tab\n    var t = setInterval(function () {\n        try {\n            if (win.closed) { clearInterval(t); return; }\n            if (!win.document || win.document.readyState !== \'complete\') { return; }\n\n            var nodes = win.document.querySelectorAll(\'a,button,div,span,li\');\n            for (var i = 0; i < nodes.length; i++) {\n                var txt = nodes[i].textContent && nodes[i].textContent.trim();\n                if (txt === \'Select\') {\n                    nodes[i].click();\n                    var el = win.document.getElementById(\'sf-wait-overlay\');\n                    if (el) el.remove();\n                    clearInterval(t);\n                    break;\n                }\n            }\n        } catch (e) {}\n    }, 300);\n}\n\nreturn false;\n', NULL),
('6929e4e7291a15b', '6929e4e728a841e', 'onclick', '// Edit Users (new tab with breadcrumbs)\nvar base = window.location.origin + window.location.pathname.split(\'/index.php\')[0];\n\nwindow.open(\n    base + \'/index.php?f=nuuser&r=\',\n    \'_blank\'\n);\n\n\n\n', NULL),
('692c8205384226d', '692c81d5ea57c66', 'onclick', '// Basic validation (optional)\nlet user  = nuGetValue(\'email_user\');\nlet subj  = nuGetValue(\'email_subject\');\nlet body  = nuGetValue(\'email_body\');\n\nif (!user || user.trim() === \'\') {\n    nuMessage(\'Please select a user.\');\n    return;\n}\n\nif (!subj || subj.trim() === \'\') {\n    nuMessage(\'Please enter a subject.\');\n    return;\n}\n\nif (!body || body.trim() === \'\') {\n    nuMessage(\'Please enter a message.\');\n    return;\n}\n\n// Mark that we want to send email on the next save\nnuSetValue(\'email_trigger\', \'SEND\');\n\n// Tell the user what to do next\nnuMessage(\'Now click the red Save button at the top to send the email.\');\n\n\n\n\n', NULL),
('692cc7c42caed48', '692cbc71b1ae673', 'onclick', 'var recips = nuGetValue(\'email_recipients\');\nif (!recips.trim()) {\n    alert(\"Please enter at least one email recipient.\");\n    return;\n}\n\nvar subj = nuGetValue(\'email_subject\');\nif (!subj.trim()) {\n    alert(\"Subject cannot be empty.\");\n    return;\n}\n\nvar msg = nuGetValue(\'email_body\');\nif (!msg.trim()) {\n    alert(\"Message cannot be empty.\");\n    return;\n}\n\nlocalStorage.setItem(\'_SEND_EMAIL\', \'1\');\nnuSaveAction();\n\n\n', NULL);
INSERT INTO `zzzzsys_event` (`zzzzsys_event_id`, `sev_zzzzsys_object_id`, `sev_event`, `sev_javascript`, `sev_json`) VALUES
('692f4dc6c2c4c19', '692f31ffa08be95', 'onclick', '// Store case info for subject\nlocalStorage.setItem(\'sf_caseNo\',   nuGetValue(\'pk_inv_case_no_A\'));\nlocalStorage.setItem(\'sf_caseName\', nuGetValue(\'pk_inv_case_name\'));\n\n// NEW: store Case ID for EmailComposer\nlocalStorage.setItem(\'sf_caseID\', nuGetValue(\'pk_inv_case_no_A\'));\n\n// Reset email (avoid old values being used)\nlocalStorage.removeItem(\'sf_email\');\n\n// Mark that EmailComposer should auto-fill\nlocalStorage.setItem(\'sfTriggered\', \"1\");\n\n// Get selected user ID from contact lookup\nvar userId = nuGetValue(\'pk_inv_contact\');\nif (!userId) {\n    alert(\'No contact selected.\');\n    return;\n}\n\n// Fetch the user\'s email from PHP\nfetch(\'custom/get_user_email.php?id=\' + encodeURIComponent(userId))\n    .then(function (r) { return r.text(); })\n    .then(function (email) {\n\n        email = (email || \'\').trim();\n\n        if (!email) {\n            alert(\'No email found for this contact.\');\n            return;\n        }\n\n        // Store email for EmailComposer\n        localStorage.setItem(\'sf_email\', email);\n\n        // --------------------------------------------------\n        // Open EmailComposer in POPUP (new record)\n        // --------------------------------------------------\n        let nuBase = window.location.origin +\n                     window.location.pathname.split(\'/index.php\')[0] +\n                     \'/\';\n\n        let width  = 970;\n        let height = 800;\n        let left   = 20;\n        let top    = screen.availHeight - height - 91;\n\n        window.open(\n            nuBase + \'index.php?f=692cb3cea1cf548&r=-1\',\n            \'EmailComposerPopup\',\n            `width=${width},\n             height=${height},\n             left=${left},\n             top=${top},\n             resizable=yes,\n             scrollbars=yes`\n        );\n\n\n\n    })\n    .catch(function (err) {\n        console.error(\'Error fetching email:\', err);\n        alert(\'Error getting email. Check console.\');\n    });\n\n\n\n', NULL),
('6930d90502dc944', '6930d83151c9f60', 'onnuload', 'setTimeout(function() {\n    var raw = nuGetValue(\'email_sent_datetime\');\n    if (!raw) return;\n    var dt = new Date(raw.replace(\" \", \"T\"));\n    var pretty = dt.toLocaleString(\'en-US\', {\n        year:\'numeric\',\n        month:\'long\',\n        day:\'numeric\',\n        hour:\'numeric\',\n        minute:\'2-digit\',\n        hour12:true\n    });\n    nuSetValue(\'email_sent_formatted\', pretty);\n}, 200);\n', NULL),
('6931e1f3e4e2d93', '691889aa83a0b04', 'onclick', '// Edit Notes / Report Templates\nvar base = window.location.origin + window.location.pathname.split(\'/index.php\')[0];\n\nwindow.open(\n    base + \'/index.php?f=nunotes&r=&sf_reports_only=1\',\n    \'_blank\'\n);\n\n/*\n// optional sized window\nwindow.open(\n    base + \'/index.php?f=nunotes&r=\',\n    \'\',\n    \'width=1260,height=800,top=50,left=50,resizable=yes,scrollbars=yes\'\n);\n*/\n', NULL),
('6932069bdf48827', '6932069bded6bd0', 'onclick', 'let noteID = nuGetValue(\'templateselector\');\n\nif (!noteID) {\n    nuMessage(\"Please select a template first.\");\n\n    setTimeout(function () {\n        $(\".nuMessage\").fadeOut(400, function () {\n            $(this).remove();\n        });\n    }, 7000);\n\n    return;\n}\n\n// ------------------------------------------------------\n// Resolve nuBuilder base path safely (LIVE + localhost)\n// ------------------------------------------------------\nlet nuBase = window.location.origin +\n             window.location.pathname.split(\'/index.php\')[0] +\n             \'/\';\n\n// ------------------------------------------------------\n// Fetch template HTML\n// ------------------------------------------------------\nfetch(nuBase + \'custom/get_note.php?id=\' + noteID)\n    .then(response => response.text())\n    .then(html => {\n\n        // --------------------------------------------------\n        // HARD GUARD: never copy a full HTML page\n        // --------------------------------------------------\n        if (html.includes(\'<html\') && html.includes(\'<head\')) {\n            nuMessage(\"ERROR: Wrong path returned a full page. Template NOT copied.\");\n            console.error(\'FETCH ERROR â€” received full HTML page:\', html);\n            return;\n        }\n\n        // --------------------------------------------------\n        // Clipboard copy (HTTPS + HTTP fallback)\n// --------------------------------------------------\n        if (navigator.clipboard && window.isSecureContext) {\n\n            navigator.clipboard.writeText(html).then(function () {\n\n                nuMessage(\"Template copied! Now paste it into the editor using \'Tools\' > \'Source Code\'.\");\n\n            }).catch(function (err) {\n\n                nuMessage(\"Clipboard error: \" + err);\n                console.error(err);\n\n            });\n\n        } else {\n\n            // HTTP fallback\n            let ta = document.createElement(\'textarea\');\n            ta.value = html;\n            ta.style.position = \'fixed\';\n            ta.style.left = \'-9999px\';\n\n            document.body.appendChild(ta);\n            ta.focus();\n            ta.select();\n\n            try {\n                document.execCommand(\'copy\');\n                nuMessage(\"Template copied! Now paste it into the editor using \'Tools\' > \'Source Code\'.\");\n            } catch (e) {\n                nuMessage(\"Clipboard copy not supported.\");\n                console.error(e);\n            }\n\n            document.body.removeChild(ta);\n        }\n\n        setTimeout(function () {\n            $(\".nuMessage\").fadeOut(400, function () {\n                $(this).remove();\n            });\n        }, 7000);\n\n    })\n    .catch(err => {\n\n        nuMessage(\"Error copying template: \" + err);\n        console.error(err);\n\n        setTimeout(function () {\n            $(\".nuMessage\").fadeOut(400, function () {\n                $(this).remove();\n            });\n        }, 7000);\n    });\n', NULL),
('6936e3b8a5b8f78', '6936e2d4ece49a3', 'onclick', '// --------------------------\n// BUILD RECIPIENT LIST\n// --------------------------\n\n// 1) Start with whatever is already in the email_recipients field\nvar to = nuGetValue(\'email_recipients\').trim();\n\n// 2) Add all selected items from the multi-select list\nvar selBox = document.getElementById(\'email_recipient_select\');\nvar all = [];\n\n// Any existing typed recipients (split on ; or ,)\nif (to !== \'\') {\n    var manualParts = to.split(/[,;]+/);\n    for (var j = 0; j < manualParts.length; j++) {\n        var m = manualParts[j].trim();\n        if (m) {\n            all.push(m);\n        }\n    }\n}\n\n// Add all selected items from the list (supports Ctrl-click / Shift-click)\nif (selBox) {\n    for (var i = 0; i < selBox.options.length; i++) {\n        var opt = selBox.options[i];\n        if (opt.selected) {\n            var addr = (opt.value || \'\').trim();\n            if (addr) {\n                all.push(addr);\n            }\n        }\n    }\n}\n\n// De-duplicate (case-insensitive)\nvar seen = {};\nvar finalList = [];\n\nfor (var k = 0; k < all.length; k++) {\n    var a = all[k].trim();\n    if (!a) continue;\n    var key = a.toLowerCase();\n    if (!seen[key]) {\n        seen[key] = true;\n        finalList.push(a);\n    }\n}\n\n// Write merged list back to email_recipients (semicolon-separated)\nif (finalList.length > 0) {\n    nuSetValue(\'email_recipients\', finalList.join(\';\'));\n    to = nuGetValue(\'email_recipients\').trim();\n} else {\n    to = \'\';\n}\n\n// --------------------------\n// VALIDATE REQUIRED FIELDS\n// --------------------------\n\nvar subj = nuGetValue(\'email_subject\').trim();\nvar body = nuGetValue(\'email_body\').trim();\n\nif (to === \'\') {\n    alert(\'Recipient cannot be empty.\');\n    return;\n}\n\nif (subj === \'\') {\n    alert(\'Subject cannot be empty.\');\n    return;\n}\n\nif (body === \'\') {\n    alert(\'Message cannot be empty.\');\n    return;\n}\n\n// --------------------------\n// SET SEND FLAG AND SAVE\n// --------------------------\n\nnuSetValue(\'_SEND_EMAIL\', \'1\');\nnuSaveAction();\n', NULL),
('6937a697563f34b', '693474537242d8c', 'onchange', '// Delay execution so nuBuilder finishes its internal auto-append\nsetTimeout(function () {\n\n    var sel = document.getElementById(\'email_recipient_select\');\n    var emails = [];\n\n    if (!sel) {\n        return;\n    }\n\n    // Extract existing emails from the recipients field (ignore all non-emails)\n    var existing = nuGetValue(\'email_recipients\') || \'\';\n    if (existing !== \'\') {\n        var matches = existing.match(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\\.[A-Z]{2,}/ig);\n        if (matches) {\n            for (var i = 0; i < matches.length; i++) {\n                if (emails.indexOf(matches[i]) === -1) {\n                    emails.push(matches[i]);\n                }\n            }\n        }\n    }\n\n    // Add selected option values (emails only)\n    for (var j = 0; j < sel.options.length; j++) {\n        var opt = sel.options[j];\n        if (opt.selected) {\n            var addr = (opt.value || \'\').trim();\n            if (addr && addr.indexOf(\'@\') !== -1 && emails.indexOf(addr) === -1) {\n                emails.push(addr);\n            }\n        }\n    }\n\n    // Write the merged, clean recipient list\n    nuSetValue(\'email_recipients\', emails.join(\'; \'));\n\n    // Notify nuBuilder the field changed so it saves correctly\n    var rec = document.getElementById(\'email_recipients\');\n    if (rec) {\n        rec.dispatchEvent(new Event(\'change\'));\n    }\n\n}, 0);\n\n\n\n\n/*\n// Build recipients from selected listbox options\nvar sel = document.getElementById(\'email_recipient_select\');\nvar emails = [];\nvar existing = nuGetValue(\'email_recipients\') || \'\';\n\n// Keep any emails already present\nif (existing.trim() !== \'\') {\n    var parts = existing.split(/[,;]+/);\n    for (var i = 0; i < parts.length; i++) {\n        var m = parts[i].trim();\n        if (m && m.indexOf(\'@\') !== -1 && emails.indexOf(m) === -1) {\n            emails.push(m);\n        }\n    }\n}\n\n// Add newly selected emails from the list (use option.value)\nfor (var j = 0; j < sel.options.length; j++) {\n    var opt = sel.options[j];\n    if (opt.selected) {\n        var addr = (opt.value || \'\').trim();\n        if (addr && addr.indexOf(\'@\') !== -1 && emails.indexOf(addr) === -1) {\n            emails.push(addr);\n        }\n    }\n}\n\n// Write back to the Recipients field\nnuSetValue(\'email_recipients\', emails.join(\'; \'));\n\n// â­â­â­ CRITICAL FIX â­â­â­\n// Tell nuBuilder the field has changed so it saves correctly\ndocument.getElementById(\'email_recipients\').dispatchEvent(new Event(\'change\'));\n*/', NULL),
('6939eaa62ae6b09', '6939ea5966cebcb', 'onclick', 'var lb = document.getElementById(\'delete_email_list\');\nvar ids = [];\n\n// Collect selected IDs\nfor (var i = 0; i < lb.options.length; i++) {\n    if (lb.options[i].selected) {\n        ids.push(\"\'\" + lb.options[i].value + \"\'\");\n    }\n}\n\nif (ids.length === 0) {\n    nuMessage(\"No emails selected.\");\n    return;\n}\n\n// Build SQL to delete the selected emails\nvar sql = `\n    DELETE FROM email_composer\n    WHERE email_composer_id IN (${ids.join(\",\")})\n`;\n\n// Execute SQL directly\nnuRunSQL(sql, function() {\n    nuMessage(\"Deleted \" + ids.length + \" emails.\");\n\n    // Refresh browse view\n    nuReloadBrowse();\n});\n', NULL),
('693c955a3c6a1d1', '693c4381f1e874b', 'onclick', '// ----------------------------------------------------\n// GUARD â€” require at least one selected email\n// ----------------------------------------------------\nvar listId = \'email_ids_to_delete\';   // <-- CONFIRMED OBJECT ID\nvar el = document.getElementById(listId);\n\nvar hasSelection = false;\n\nif (el) {\n\n    // Case 1: <select multiple>\n    if (el.tagName === \'SELECT\') {\n        for (var i = 0; i < el.options.length; i++) {\n            if (el.options[i].selected) {\n                hasSelection = true;\n                break;\n            }\n        }\n    }\n\n    // Case 2: textarea / list rendered as text\n    if (!hasSelection && typeof el.value === \'string\') {\n        if (el.value.trim() !== \'\') {\n            hasSelection = true;\n        }\n    }\n}\n\nif (!hasSelection) {\n    alert(\'Please select emails to delete first.\');\n    return;\n}\n\n// ----------------------------------------------------\n// ORIGINAL â€” confirmed working\n// ----------------------------------------------------\nif (confirm(\'Delete Selected Emails?\')) {\n    nuSaveAction();\n}\n\n\n\n/*\nif (confirm(\'Delete Selected Emails?\')) {\n    nuSaveAction();\n}\n*/', NULL),
('693e14d7eb274d6', '693e14967259f52', 'onchange', 'nuTabAdditionalSetMarker();', NULL),
('694ee5d99fdee9f', '694ee514a3be967', 'onchange', '// Reuse existing case: copy name + case_group_id into bound fields\nlet grp = nuGetValue(\'existing_case_group_id\');\n\nif (grp) {\n\n    // Get the selected text from the dropdown\n    let txt = $(\'#existing_case_group_id option:selected\').text();\n\n    // Set the existing bound Case Name field\n    nuSetValue(\'pk_inv_case_name\', txt);\n\n    // Reuse the existing case_group_id\n    nuSetValue(\'case_group_id\', grp);\n\n    // Prevent editing when reusing an existing case\n    $(\'#pk_inv_case_name\').prop(\'readonly\', true);\n}\n', NULL),
('694ee687e5bbad4', '68cb2c8194bec31', 'onchange', '// If user types a case name manually, they are creating a NEW case.\n// Clear the reuse selector so intent is unambiguous.\nif (nuGetValue(\'pk_inv_case_name\')) {\n    nuSetValue(\'existing_case_group_id\', \'\');\n$(\'#pk_inv_case_name\').prop(\'readonly\', false);\n}\n\n', NULL),
('6952baba55ef09b', '695011865eb63bb', 'onclick', '// --------------------------------------------------\n// Open Email List in NON-MODAL popup\n// --------------------------------------------------\n// EmailComposer_Admin form ID confirmed via CTRL+SHIFT+M\n\nlet nuBase = window.location.origin +\n             window.location.pathname.split(\'/index.php\')[0] +\n             \'/\';\n\nlet width  = 975;\nlet height = 800;\nlet left   = 20;\nlet top    = screen.availHeight - height - 91;\n\nwindow.open(\n    nuBase + \'index.php?f=69500164e61a85d&r=\',\n    \'EmailListPopup\',\n    `width=${width},\n     height=${height},\n     left=${left},\n     top=${top},\n     resizable=yes,\n     scrollbars=yes`\n);', NULL),
('6953ef7353172d2', '68fa51adbe65c0e', 'onclick', '// --------------------------------------------------\n// Open SpiritForms Reports in NON-MODAL popup\n// (Converted from Run object)\n// --------------------------------------------------\n\nlet nuBase = window.location.origin +\n             window.location.pathname.split(\'/index.php\')[0] +\n             \'/\';\n\n// Popup sizing & position\nlet width  = 700;\nlet height = 800;\nlet left   = 20;\nlet top    = screen.availHeight - height - 80;\n\nwindow.open(\n    nuBase + \'index.php?f=68f91df85e8e5ea&r=\',\n    \'SpiritFormsReportsPopup\',\n    `width=${width},\n     height=${height},\n     left=${left},\n     top=${top},\n     resizable=yes,\n     scrollbars=yes`\n);\n', NULL),
('6953f8afce87cc3', '693b11120666ee0', 'onchange', '// ------------------------------------------------------\n// Guard: Investigation dates required before completion\n// ------------------------------------------------------\n\nlet startDate = nuGetValue(\'pk_inv_start\');\nlet endDate   = nuGetValue(\'pk_inv_end\');\n\n// Only enforce when user tries to CHECK the box\nif (nuGetValue(\'report_is_complete\') == 1) {\n\n    if (!startDate || !endDate) {\n\n        nuMessage(\n            \'Investigation Start Date and End Date must be entered before marking the report as complete.\'\n        );\n\n        // Revert checkbox back to unchecked\n        nuSetValue(\'report_is_complete\', 0);\n\n        return;\n    }\n}\n', NULL),
('6953fdbec0de1b4', '693cb9fe37a36ac', 'onclick', '// --------------------------------------------------\n// Open SpiritForms Reports in NON-MODAL popup\n// (Converted from Run object)\n// --------------------------------------------------\n\nlet nuBase = window.location.origin +\n             window.location.pathname.split(\'/index.php\')[0] +\n             \'/\';\n\n// Popup sizing & position\nlet width  = 700;\nlet height = 800;\nlet left   = 20;\nlet top    = screen.availHeight - height - 80;\n\nwindow.open(\n    nuBase + \'index.php?f=68f91df85e8e5ea&r=\',\n    \'SpiritFormsReportsPopup\',\n    `width=${width},\n     height=${height},\n     left=${left},\n     top=${top},\n     resizable=yes,\n     scrollbars=yes`\n);\n', NULL),
('695aa16cca72384', '68d193a8abb141e', 'onclick', 'window.open(\'https://mooncalendar.astro-seek.com/\', \'_blank\', \'noopener\');', NULL),
('695aa7ef722573f', '695aa6479fb058a', 'onclick', 'let nuBase = window.location.origin +\n             window.location.pathname.split(\'/index.php\')[0] +\n             \'/\';\n\n// --------------------------------------------------\n// Popup window settings\n// --------------------------------------------------\nlet width  = 975;\nlet height = 800;\nlet left   = 20;\nlet top    = screen.height - height - 165;\n\nwindow.open(\n    nuBase + \'index.php?f=692cb3cea1cf548&r=\',\n    \'EmailBrowsePopup\',\n    `width=${width},\n     height=${height},\n     left=${left},\n     top=${top},\n     resizable=yes,\n     scrollbars=yes`\n);\n', NULL),
('696e81adc389b06', '696e7bce9e31d0e', 'onchange', '// Open selected investigation in a popup (side-by-side friendly)\nvar targetId = nuGetValue(\'jump_case_no\');\nif (!targetId) { return; }\n\n// Resolve nuBuilder base path (localhost + live safe)\nvar base =\n    window.location.origin +\n    window.location.pathname.split(\'/index.php\')[0] +\n    \'/\';\n\n// Current form id\nvar thisFormId = nuFORM.getProperty(\'form_id\');\n\n// Popup URL\nvar url = base + \'index.php?f=\' + thisFormId + \'&r=\' + targetId;\n\n// Popup size\nvar popupWidth = 1230;\nvar popupHeight = 800;\n\n// Popup position\nvar popupLeft = 650;   // move right\nvar popupTop  = 80;    // move down\n\n// Open popup\nwindow.open(\n    url,\n    \'InvestigationCompare\',\n    \'width=\' + popupWidth +\n    \',height=\' + popupHeight +\n    \',left=\' + popupLeft +\n    \',top=\' + popupTop +\n    \',resizable=yes,scrollbars=yes\'\n);\n\n// Optional: clear selection so user can pick again quickly\nnuSetValue(\'jump_case_no\', \'\');', NULL),
('69d12617916f71d', '69d1261790fbcfa', 'onclick', 'function nuVendorLogin(appId, table) {\n	const tableName = table || nuSERVERRESPONSE.table;\n	const params = new URLSearchParams({\n		sessid: window.nuSESSION,\n		appId: appId,\n		table: tableName,\n		timezone: nuSERVERRESPONSE.timezone\n	});\n	const url = `core/nuvendorlogin.php?${params.toString()}`;\n	return window.open(url, appId);\n}\n\n// open TFM vendor session\nvar win = nuVendorLogin(\'TFM\');\n\n// determine active tab\nvar tab_id = nuSelectedTabId();\nvar tablabel = \'\';\nvar folderPath = \'\';\n\n// map tab to folder\nif (tab_id === \'68ca2d0c176d4d4\') {\n	tablabel = \'Audio\';\n	folderPath = \'Evidence/Audio\';\n} else if (tab_id === \'68e16015b8742d6\') {\n	tablabel = \'Video\';\n	folderPath = \'Evidence/Video\';\n} else if (tab_id === \'68e16037843edff\') {\n	tablabel = \'Photo\';\n	folderPath = \'Evidence/Photo\';\n} else if (tab_id === \'69cf47d2315252c\') {\n	tablabel = \'Sensor Data\';\n	folderPath = \'Evidence/Sensors\';\n} else if (tab_id === \'68ca2ad572dae00\') {\n	tablabel = \'History\';\n	folderPath = \'History\';\n} else {\n	alert(\'No upload folder is mapped for this tab.\');\n	throw new Error(\'No Tiny File Manager folder mapping for tab id: \' + tab_id);\n}\n\nvar recordNumber = nuRecordId();\n\n// resolve nuBuilder base path\nvar base = window.location.origin + window.location.pathname.split(\'/index.php\')[0];\n\n// build Tiny File Manager URL\nvar fileManagerUrl =\n	base +\n	\'/third_party/tinyfilemanager/tinyfilemanager.php?p=Investigation \' +\n	recordNumber +\n	\'/\' +\n	folderPath;\n\n// redirect vendor window\nif (win) {\n	setTimeout(function () {\n		win.location.href = fileManagerUrl;\n	}, 500);\n}', NULL),
('69d13bfd2ef65e3', '69d13bfd2e83f3c', 'onclick', 'var url = nuGetValue(\'pk_sensor_1_file_1\');\nif (url && url.trim() !== \'\') {\n    window.open(url, \'_blank\');\n}', NULL),
