INSERT INTO `zzzzsys_form` (`zzzzsys_form_id`, `sfo_type`, `sfo_code`, `sfo_description`, `sfo_group`, `sfo_status`, `sfo_breadcrumb_title`, `sfo_table`, `sfo_primary_key`, `sfo_browse_redirect_form_id`, `sfo_browse_target`, `sfo_browse_row_height`, `sfo_browse_rows_per_page`, `sfo_browse_title_multiline`, `sfo_browse_autoresize_columns`, `sfo_browse_sql`, `sfo_javascript`, `sfo_browse_javascript`, `sfo_edit_javascript`, `sfo_style`, `sfo_mobile_view`, `sfo_json`) VALUES
('68c452e608cbadc', 'browseedit', 'SpiritForm', 'SpiritForms Investigations', NULL, '1', NULL, 'cases', 'pk_inv_case_no', '', '', 0, 0, '0', '0', 'SELECT \n    c.pk_inv_case_no,\n    c.pk_inv_contact_date,\n    u.sus_name AS contact_name,\n    c.pk_loc_name,\n    c.pk_inv_case_name,\n    c.pk_inv_street,\n    c.pk_inv_city,\n    c.pk_inv_state,\n    c.pk_inv_zip,\n    c.pk_inv_contact_phone,\n    \nFROM cases c\nLEFT JOIN zzzzsys_user u \n    ON c.pk_inv_contact = u.zzzzsys_user_id\nLEFT JOIN case_user_access cua\n    ON cua.fk_case_id = c.pk_inv_case_no\nWHERE (\n        \'#ACCESS_LEVEL_CODE#\' = \'Admin\'\n     OR \'#GLOBAL_ACCESS#\' = \'1\'\n     OR cua.fk_user_id = \'#USER_ID#\'\n)\nORDER BY c.pk_inv_case_no DESC;\n', '// ----------------------------------------------------\n// TinyMCE HR thickness override (nuBuilder-safe)\n// ----------------------------------------------------\nif (typeof tinymce !== \'undefined\') {\n\n    tinymce.on(\'AddEditor\', function (e) {\n\n        const editor = e.editor;\n\n        editor.on(\'init\', function () {\n\n            // Inject custom HR style into editor iframe\n            editor.dom.addStyle(\n    \'hr { border: 0 !important; border-top: 4px solid #000 !important; height: 0 !important; }\'\n);\n          \n\n        });\n\n    });\n\n}\n\n//Prevents F5 and instructs the user to use CTRL-SHIFT-R\n$(document).on(\'keydown\', function(e) {\n    if (e.which === 116) { // F5 key\n        e.preventDefault();\n        nuMessage(\'Please use the toolbar refresh button or use CTRL-SHIFT-R to refresh.\');\n    }\n});\n\n\n// =====================================================================\n// SpiritForm: TinyMCE safety patch (nuBuilder 4.9.2)\n// Prevents \"Cannot read properties of undefined (reading \'serialize\')\"\n// by making getContent() fall back to the underlying textarea value.\n// =====================================================================\n(function () {\n    if (window._sf_tinymce_getcontent_patch) return;\n    window._sf_tinymce_getcontent_patch = true;\n\n    function patchTinyMCE() {\n        if (!window.tinymce || !tinymce.Editor || !tinymce.Editor.prototype) return false;\n        if (tinymce.Editor.prototype._sf_patched_getContent) return true;\n\n        var origGetContent = tinymce.Editor.prototype.getContent;\n\n        tinymce.Editor.prototype.getContent = function () {\n            try {\n                return origGetContent.apply(this, arguments);\n            } catch (e) {\n                // Fallback: return the current textarea value (already populated by nuBuilder)\n                try {\n                    var el = document.getElementById(this.id);\n                    return el && typeof el.value === \'string\' ? el.value : \'\';\n                } catch (e2) {\n                    return \'\';\n                }\n            }\n        };\n\n        tinymce.Editor.prototype._sf_patched_getContent = true;\n        return true;\n    }\n\n    var t = setInterval(function () {\n        if (patchTinyMCE()) clearInterval(t);\n    }, 50);\n})();\n\n\n\n//Format phone number\n\nfunction formatPhoneUS(value) {\n    let digits = String(value || \'\').replace(/\\D/g, \'\').substring(0, 10);\n\n    if (digits.length > 6) {\n        return \'(\' + digits.substring(0, 3) + \') \' +\n               digits.substring(3, 6) + \'-\' +\n               digits.substring(6);\n    } else if (digits.length > 3) {\n        return \'(\' + digits.substring(0, 3) + \') \' +\n               digits.substring(3);\n    } else if (digits.length > 0) {\n        return \'(\' + digits;\n    }\n\n    return \'\';\n}\n\nfunction bindResidentOwnerPhoneFormatter() {\n    let $phone = $(\'#pk_inv_resident_own_phone\');\n\n    if ($phone.length === 0) {\n        console.log(\'Phone field not found\');\n        return;\n    }\n\n    $phone.off(\'.residentphone\');\n\n    $phone.on(\'input.residentphone blur.residentphone change.residentphone\', function () {\n        let start = this.selectionStart;\n        let oldLength = $(this).val().length;\n\n        $(this).val(formatPhoneUS($(this).val()));\n\n        let newLength = $(this).val().length;\n        let newPos = start + (newLength - oldLength);\n\n        this.setSelectionRange(newPos, newPos);\n    });\n\n    $phone.val(formatPhoneUS($phone.val()));\n}\n\nsetTimeout(function () {\n    bindResidentOwnerPhoneFormatter();\n}, 300);', '\n// =====================================================\n// nuBuilder hyperlink visibility controller (final stable version)\n// =====================================================\n(function () {\n    if (window._nu_hide_links_installed) return;\n    window._nu_hide_links_installed = true;\n\n    const headerMatchRegex = /(url|zip|\\?)/i;\n    const cssId = \'nu-hide-links-style\';\n\n    function injectCss() {\n        if (document.getElementById(cssId)) return;\n        const style = document.createElement(\'style\');\n        style.id = cssId;\n        style.textContent = `\n            /* hide anchors for non-admins */\n            #nuRECORD a[href], #nuRECORD a { display: none !important; pointer-events: none !important; }\n        `;\n        document.head.appendChild(style);\n    }\n\n    function removeCss() {\n        const el = document.getElementById(cssId);\n        if (el) el.remove();\n    }\n\n    function hideColumnsByHeader() {\n        const browse = document.getElementById(\'nuRECORD\');\n        if (!browse) return;\n        const headers = browse.querySelectorAll(\'.nuBrowseTitle\');\n        headers.forEach((header, i) => {\n            const txt = (header.textContent || \'\').trim();\n            if (headerMatchRegex.test(txt)) {\n                header.style.display = \'none\';\n                browse.querySelectorAll(`.nuCell[data-nu-column=\"${i}\"]`)\n                    .forEach(cell => (cell.style.display = \'none\'));\n                try { nuSetBrowseColumnSize(i, 0); } catch {}\n            }\n        });\n    }\n\n    function applyProtection(username) {\n        if (username === \'globeadmin\') {\n            console.log(\'nuHyperlinkController: detected globeadmin â†’ showing all links\');\n            removeCss();\n            return;\n        }\n        console.log(\'nuHyperlinkController: non-admin detected â†’ hiding links\');\n        injectCss();\n        hideColumnsByHeader();\n    }\n\n    // --- main wait-for-userName logic ---\n    function waitForUserName() {\n        if (typeof nuUserName !== \'function\') {\n            setTimeout(waitForUserName, 250);\n            return;\n        }\n\n        let username = \'\';\n        try {\n            username = nuUserName();\n        } catch {\n            setTimeout(waitForUserName, 250);\n            return;\n        }\n\n        if (!username) {\n            setTimeout(waitForUserName, 250);\n            return;\n        }\n\n        // once we have a username, proceed\n        console.log(\'nuHyperlinkController: user =\', username);\n        applyProtection(username);\n\n        if (username !== \'globeadmin\') {\n            // observe only for non-admins\n            const observer = new MutationObserver(() => {\n                applyProtection(username);\n            });\n            observer.observe(document.body, { childList: true, subtree: true });\n        }\n    }\n\n    waitForUserName();\n})();\n', '\n\n\n//---------------------------------------------\n// FULL SpiritForm Report Builder\n//---------------------------------------------\n\nfunction sfNuBase() {\n    return window.location.origin +\n           window.location.pathname.split(\'/index.php\')[0] +\n           \'/\';\n}\n\n//---------------------------------------------\n// FULL SpiritForms Report Builder\n//---------------------------------------------\nfunction spiritFormBuildReport() {\n\n    //-----------------------------------------\n    // helper: make safe filename text\n    //-----------------------------------------\n    function sfSafeFilePart(str) {\n        str = (str || \"\").toString().trim();\n        str = str.replace(/&/g, \"and\");\n        str = str.replace(/[^A-Za-z0-9]+/g, \"_\");\n        str = str.replace(/_+/g, \"_\");\n        str = str.replace(/^_+|_+$/g, \"\");\n        return str || \"Unknown\";\n    }\n\n    //-----------------------------------------\n    // 1. Investigation Number (from URL param r)\n    //-----------------------------------------\n    var caseNumber = \"Unknown\";\n    try {\n        var params = new URLSearchParams(window.location.search);\n        if (params.has(\"r\")) caseNumber = params.get(\"r\");\n    } catch (e) {\n        console.warn(\"Error reading investigation number:\", e);\n    }\n\n    //-----------------------------------------\n    // 2. Case Name\n    //-----------------------------------------\n    var caseName = \"Unknown\";\n    try {\n        caseName = nuGetValue(\"pk_inv_case_name\") || \"Unknown\";\n    } catch (e) {\n        console.warn(\"Error reading case name:\", e);\n    }\n\n    //-----------------------------------------\n    // 3. Case Investigation Number\n    //-----------------------------------------\n    var caseInvestigationNo = \"Unknown\";\n    try {\n        caseInvestigationNo = nuGetValue(\"case_investigation_no\") || \"Unknown\";\n    } catch (e) {\n        console.warn(\"Error reading case investigation number:\", e);\n    }\n\n    //-----------------------------------------\n    // 4. Investigation Date (Formatted)\n    //-----------------------------------------\n    var invDateReadable = \"Unknown\";\n    var invDateForFile = \"Unknown_Date\";\n    try {\n        var rawDate = nuGetValue(\"pk_inv_start\");\n        if (rawDate) {\n            var dt = new Date(rawDate);\n\n            invDateReadable = dt.toLocaleDateString(undefined, {\n                year: \"numeric\",\n                month: \"long\",\n                day: \"numeric\"\n            });\n\n            invDateForFile = dt.toLocaleDateString(undefined, {\n                year: \"numeric\",\n                month: \"long\",\n                day: \"numeric\"\n            });\n        }\n    } catch (e) {\n        console.warn(\"Error parsing investigation date:\", e);\n    }\n\n    //-----------------------------------------\n    // 5. Contact Name (HIDDEN Select dropdown)\n    //-----------------------------------------\n    var contactName = \"Unknown\";\n    try {\n        var cn = document.getElementById(\"pk_inv_contact\");\n        if (cn && cn.options && cn.selectedIndex >= 0) {\n            contactName = cn.options[cn.selectedIndex].text.trim();\n        }\n    } catch (e) {\n        console.warn(\"Error reading contact name:\", e);\n    }\n\n    //-----------------------------------------\n    // 6. Report body (MYREPORTS field)\n    //-----------------------------------------\n    var bodyHTML = \"\";\n    try {\n        bodyHTML = nuGetValue(\"MYREPORTS\") || \"\";\n    } catch (e) {\n        alert(\"Error reading MYREPORTS: \" + e);\n    }\n\n    //-----------------------------------------\n    // 7. ZIP base filename\n    // desired example:\n    // Northern_State_Hospital_Investigation_3_April_14_2026\n    //-----------------------------------------\n    var zipBaseName =\n        sfSafeFilePart(caseName) +\n        \"_Investigation_\" +\n        sfSafeFilePart(caseInvestigationNo) +\n        \"_\" +\n        sfSafeFilePart(invDateForFile);\n\n    //-----------------------------------------\n    // 8. Build Header HTML\n    //-----------------------------------------\n    var logoUrl = sfNuBase() + \"logo_small.png\";\n\n    var headerHTML =\n        \"<div style=\'background:#91a0b7;color:black;padding:14px;\" +\n        \"font-family:Arial;border-bottom:3px solid #6f7b8f;\'>\" +\n\n        \"<div style=\'display:flex;align-items:center;\'>\" +\n        \"<img src=\'\" + logoUrl + \"\' style=\'height:40px;margin-right:12px;\'>\" +\n        \"<div style=\'font-size:22px;font-weight:bold;\'>SpiritForms Report</div>\" +\n        \"</div>\" +\n\n        \"<div style=\'margin-top:8px;font-size:14px;\'>\" +\n        \"<strong>Investigation Number:</strong> \" + caseNumber + \"<br>\" +\n        \"<strong>Case Name:</strong> \" + caseName + \"<br>\" +\n        \"<strong>Case Investigation #:</strong> \" + caseInvestigationNo + \"<br>\" +\n        \"<strong>Contact Name:</strong> \" + contactName + \"<br>\" +\n        \"<strong>Investigation Date:</strong> \" + invDateReadable +\n        \"</div>\" +\n\n        \"</div><br>\";\n\n    //-----------------------------------------\n    // 9. Final HTML Document\n    //-----------------------------------------\n    var finalHTML =\n        \"<!DOCTYPE html><html><head><meta charset=\'UTF-8\'>\" +\n        \"<title>\" + zipBaseName + \"</title>\" +\n        \"<meta name=\'sf-zip-base-name\' content=\'\" + zipBaseName + \"\'>\" +\n        \"<meta name=\'sf-case-name\' content=\'\" + caseName + \"\'>\" +\n        \"<meta name=\'sf-case-investigation-no\' content=\'\" + caseInvestigationNo + \"\'>\" +\n        \"<meta name=\'sf-investigation-number\' content=\'\" + caseNumber + \"\'>\" +\n        \"<meta name=\'sf-investigation-date\' content=\'\" + invDateForFile + \"\'>\" +\n        \"</head><body style=\'background:#WHITE;\' \" +\n        \"data-sf-zip-base-name=\'\" + zipBaseName + \"\' \" +\n        \"data-sf-case-name=\'\" + caseName + \"\' \" +\n        \"data-sf-case-investigation-no=\'\" + caseInvestigationNo + \"\' \" +\n        \"data-sf-investigation-number=\'\" + caseNumber + \"\' \" +\n        \"data-sf-investigation-date=\'\" + invDateForFile + \"\'>\" +\n        headerHTML +\n        bodyHTML +\n        \"</body></html>\";\n\n    //-----------------------------------------\n    // 10. Open Report in New Tab\n    //-----------------------------------------\n    var w = window.open(\"about:blank\", \"_blank\");\n    if (!w) {\n        alert(\"Please allow pop-ups for this site.\");\n        return;\n    }\n\n    w.document.open();\n    w.document.write(finalHTML);\n    w.document.close();\n}\n\n\n\n\n\n\n\n// Filter for country dropdown\nif (nuIsNewRecord()) {\n    var countryDropdown = document.getElementById(\'country\');\n\n    if (countryDropdown) {\n        // Set default value\n        countryDropdown.value = \'United States\';\n\n        var typed = \'\'; // store what the user types\n        var typingTimer;\n        var typingDelay = 10000; // reset typed string after 10 seconds of inactivity\n\n        countryDropdown.addEventListener(\'keydown\', function (e) {\n            if (e.key.length === 1) { // only printable characters\n                typed += e.key.toLowerCase();\n\n                // find first matching option\n                for (var i = 0; i < countryDropdown.options.length; i++) {\n                    var option = countryDropdown.options[i];\n                    if (option.text.toLowerCase().includes(typed)) {\n                        countryDropdown.value = option.value;\n                        break;\n                    }\n                }\n\n                // reset typing after delay\n                clearTimeout(typingTimer);\n                typingTimer = setTimeout(function () {\n                    typed = \'\';\n                }, typingDelay);\n            }\n        });\n    }\n}\n\n\n\n\n\n\n\n//*\nnuOnLoad = function() {\n\n    // Example: static image URLs, or load from a field if stored in DB\n    const images = [\n        \'/uploads/example/95316841_175960953197161_r.jpeg\',\n        \'/uploads/example/95316841_1760313605788358_r.jpeg\',\n        \'/uploads/example/95316841_1760313820655379_r.png\',\n	\'/uploads/example/95316841_1760313972748865_r.jpeg\',\n    ];\n\n    let current = 0;\n    const imgElement = document.getElementById(\'slideImage\');\n\n    if (!imgElement) return;\n\n    // Set initial image\n    imgElement.src = images[current];\n\n    // Rotate every 9 seconds\n    setInterval(() => {\n    imgElement.style.opacity = 0;\n    setTimeout(() => {\n        current = (current + 1) % images.length;\n        imgElement.src = images[current];\n        imgElement.style.opacity = 1;\n    }, 11000);\n}, 11000);\n}\n*//\n\n\nnuSelectMultiWithoutCtrl(\'pk_spirit_itc_inv\');\nnuSelectMultiWithoutCtrl(\'pk_devices\');\nnuSelectMultiWithoutCtrl(\'pk_phoneapps\');\nnuSelectMultiWithoutCtrl(\'pk_computerapps\');\n\n\n//Displays the moon phase image on the Investigation tab of the Edit form\n// Replace \'yourImageField\' with the actual field name that holds the image URL\nvar imageUrl = nuGetValue(\'moonimageurl\');\n\n// Optional: if the field might be empty, handle that\nif (imageUrl && imageUrl.trim() !== \'\') {\n    var html = \'<img src=\"\' + imageUrl + \'\" style=\"max-width:100%; height:auto; border-radius:8px;\" />\';\n} else {\n    var html = \'<p style=\"color:gray; text-align:center;\">No image available</p>\';\n}\n// Replace \'HTML_ImageDisplay\' with your HTML object name\nnuSetValue(\'moonimagehtml\', html, \"html\");\n\n\n\nfunction styleObjectLabel(elementId, cssStyle) {\n  const labelId = `label_${elementId}`;\n  $(`#${labelId}`).css(cssStyle);\n}\n\n// Applies bold font to certain Labels\n// Apply black color and bold font to the label for the element with ID \"pk_pe_1\"\nstyleObjectLabel(\"pk_pe_1\", {\n  color: \"black\",\n  fontWeight: \"bold\"\n});\n\n// Apply black color and bold font to the label for the element with ID \"pk_pe_2\"\nstyleObjectLabel(\"pk_pe_2\", {\n  color: \"black\",\n  fontWeight: \"bold\"\n});\n\n// Apply black color and bold font to the label for the element with ID \"pk_pe_3\"\nstyleObjectLabel(\"pk_pe_3\", {\n  color: \"black\",\n  fontWeight: \"bold\"\n});\n\n\n// Apply black color and bold font to the label for the element with ID \"pk_desc_audio_1\"\nstyleObjectLabel(\"pk_desc_audio_1\", {\n  color: \"black\",\n  fontWeight: \"bold\"\n});\n\n// Apply black color and bold font to the label for the element with ID \"pk_desc_audio_2\