belOnTop([\'pk_desc_photo_12\'])\nnuLabelOnTop([\'pk_desc_photo_13\'])\nnuLabelOnTop([\'pk_desc_photo_14\'])\nnuLabelOnTop([\'pk_desc_photo_15\'])\nnuLabelOnTop([\'pk_desc_photo_16\'])\nnuLabelOnTop([\'pk_desc_photo_17\'])\nnuLabelOnTop([\'pk_desc_photo_18\'])\nnuLabelOnTop([\'pk_desc_photo_19\'])\nnuLabelOnTop([\'pk_desc_photo_20\'])\n\n\nnuLabelOnTop([\'pk_audio_url_1\'])\nnuLabelOnTop([\'pk_audio_url_2\'])\nnuLabelOnTop([\'pk_audio_url_3\'])\nnuLabelOnTop([\'pk_audio_url_4\'])\nnuLabelOnTop([\'pk_audio_url_5\'])\nnuLabelOnTop([\'pk_audio_url_6\'])\nnuLabelOnTop([\'pk_audio_url_7\'])\nnuLabelOnTop([\'pk_audio_url_8\'])\nnuLabelOnTop([\'pk_audio_url_9\'])\nnuLabelOnTop([\'pk_audio_url_10\'])\nnuLabelOnTop([\'pk_audio_url_11\'])\nnuLabelOnTop([\'pk_audio_url_12\'])\nnuLabelOnTop([\'pk_audio_url_13\'])\nnuLabelOnTop([\'pk_audio_url_14\'])\nnuLabelOnTop([\'pk_audio_url_15\'])\nnuLabelOnTop([\'pk_audio_url_16\'])\nnuLabelOnTop([\'pk_audio_url_17\'])\nnuLabelOnTop([\'pk_audio_url_18\'])\nnuLabelOnTop([\'pk_audio_url_19\'])\nnuLabelOnTop([\'pk_audio_url_20\'])\n\n\nnuLabelOnTop([\'pk_video_url_1\'])\nnuLabelOnTop([\'pk_video_url_2\'])\nnuLabelOnTop([\'pk_video_url_3\'])\nnuLabelOnTop([\'pk_video_url_4\'])\nnuLabelOnTop([\'pk_video_url_5\'])\nnuLabelOnTop([\'pk_video_url_6\'])\nnuLabelOnTop([\'pk_video_url_7\'])\nnuLabelOnTop([\'pk_video_url_8\'])\nnuLabelOnTop([\'pk_video_url_9\'])\nnuLabelOnTop([\'pk_video_url_10\'])\nnuLabelOnTop([\'pk_video_url_11\'])\nnuLabelOnTop([\'pk_video_url_12\'])\nnuLabelOnTop([\'pk_video_url_13\'])\nnuLabelOnTop([\'pk_video_url_14\'])\nnuLabelOnTop([\'pk_video_url_15\'])\nnuLabelOnTop([\'pk_video_url_16\'])\nnuLabelOnTop([\'pk_video_url_17\'])\nnuLabelOnTop([\'pk_video_url_18\'])\nnuLabelOnTop([\'pk_video_url_19\'])\nnuLabelOnTop([\'pk_video_url_20\'])\n\n\n\nnuLabelOnTop([\'pk_photo_url_1\'])\nnuLabelOnTop([\'pk_photo_url_2\'])\nnuLabelOnTop([\'pk_photo_url_3\'])\nnuLabelOnTop([\'pk_photo_url_4\'])\nnuLabelOnTop([\'pk_photo_url_5\'])\nnuLabelOnTop([\'pk_photo_url_6\'])\nnuLabelOnTop([\'pk_photo_url_7\'])\nnuLabelOnTop([\'pk_photo_url_8\'])\nnuLabelOnTop([\'pk_photo_url_9\'])\nnuLabelOnTop([\'pk_photo_url_10\'])\nnuLabelOnTop([\'pk_photo_url_11\'])\nnuLabelOnTop([\'pk_photo_url_12\'])\nnuLabelOnTop([\'pk_photo_url_13\'])\nnuLabelOnTop([\'pk_photo_url_14\'])\nnuLabelOnTop([\'pk_photo_url_15\'])\nnuLabelOnTop([\'pk_photo_url_16\'])\nnuLabelOnTop([\'pk_photo_url_17\'])\nnuLabelOnTop([\'pk_photo_url_18\'])\nnuLabelOnTop([\'pk_photo_url_19\'])\nnuLabelOnTop([\'pk_photo_url_20\'])\n\n\n\nnuLabelOnTop([\'pk_inv_directions\'])\nnuLabelOnTop([\'pk_inv_summary\'])\nnuLabelOnTop([\'investigators\'])\nnuLabelOnTop([\'new_case_flag\'])\nnuLabelOnTop([\'pk_inv_contact_date\'])\n\nnuLabelOnTop([\'sensor_device_1\'])\nnuLabelOnTop([\'sensor_device_2\'])\nnuLabelOnTop([\'sensor_device_3\'])\nnuLabelOnTop([\'pk_loc_hist_docs_inherited_url\'])\n\n\n\n\n', 'input[type=\"url\"],\ninput[type=\"text\"],\n  input[type=\"tel\"],\n input[type=\"nuDate\"],\n  input[type=\"email\"],\n  input[type=\"datetime-local\"],\ntextarea {\n  background: #8c8682;\n}\n\n.record-image {\n  display: block;\n  max-width: 100%;\n  height: auto;\n  border: 1px solid #ccc;\n  border-radius: 8px;\n  object-fit: contain;\n}\n\n\n\n\n//*\n#slideImage {\n  opacity: 0;\n  animation: fadeInOut 11s ease-in-out infinite;\n}\n\n@keyframes fadeInOut {\n  0%, 100% {\n    opacity: 0;\n  }\n  50% {\n    opacity: 1;\n  }\n}\n//*\n\n\n// Subforms background color CSS\n\n.nuSubformScrollDiv {\n    background-color: #91a0b7; \n}\n\n.nuSubformTitleHolder {\n    background-color: #91a0b7;\n}\n', NULL, NULL),
('68f65471d95e2d3', 'edit', 'enterfileurl', 'Allows input of a file url', NULL, '1', NULL, 'cases', 'pk_inv_case_no', NULL, NULL, NULL, NULL, '0', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('68f91df85e8e5ea', 'browseedit', 'html', 'SpiritForms Reports', '', '1', NULL, 'cases', 'pk_inv_case_no', NULL, NULL, NULL, NULL, '0', '0', 'SELECT\n    c.pk_inv_case_no,\n    c.pk_inv_contact_date,\n    c.pk_inv_case_name,\n    u.sus_name AS contact_name\nFROM cases c\nLEFT JOIN case_user_access cua\n    ON cua.fk_case_id = c.pk_inv_case_no\nLEFT JOIN zzzzsys_user u\n    ON u.zzzzsys_user_id = c.pk_inv_contact\nWHERE (\n        \'#ACCESS_LEVEL_CODE#\' = \'Admin\'\n     OR \'#GLOBAL_ACCESS#\' = \'1\'\n     OR (cua.fk_user_id = \'#USER_ID#\' AND c.report_is_complete = 1)\n);\n', '', NULL, 'function spiritFormBuildReport() {\n\n    // --------------------------------------------------\n    // helper: make safe filename text\n    // --------------------------------------------------\n    function sfSafeFilePart(str) {\n        str = (str || \"\").toString().trim();\n        str = str.replace(/&/g, \"and\");\n        str = str.replace(/[^A-Za-z0-9]+/g, \"_\");\n        str = str.replace(/_+/g, \"_\");\n        str = str.replace(/^_+|_+$/g, \"\");\n        return str || \"Unknown\";\n    }\n\n    // --------------------------------------------------\n    // 1. Investigation Number (URL â†’ fallback to localStorage)\n    // --------------------------------------------------\n    let caseNumber = \"Unknown\";\n\n    try {\n        const params = new URLSearchParams(window.location.search);\n\n        if (params.has(\"r\")) {\n            caseNumber = params.get(\"r\");\n        } else {\n            caseNumber = localStorage.getItem(\"sf_caseNumber\") || \"Unknown\";\n        }\n    } catch (e) {\n        console.warn(\"Could not determine case number:\", e);\n    }\n\n    // --------------------------------------------------\n    // 2. Case Name\n    // --------------------------------------------------\n    let caseName = nuGetValue(\"pk_inv_case_name\") || \"Unknown\";\n\n    // --------------------------------------------------\n    // 3. Case Investigation Number\n    // --------------------------------------------------\n    let caseInvestigationNo = \"Unknown\";\n    try {\n        caseInvestigationNo = nuGetValue(\"case_investigation_no\") || \"Unknown\";\n    } catch (e) {\n        console.warn(\"Could not determine case investigation number:\", e);\n    }\n\n    // --------------------------------------------------\n    // 4. Investigation Date (formatted)\n    // --------------------------------------------------\n    let invDateReadable = \"Unknown\";\n    let invDateForFile = \"Unknown_Date\";\n    try {\n        let raw = nuGetValue(\"pk_inv_start\");\n        if (raw) {\n            let d = new Date(raw);\n\n            invDateReadable = d.toLocaleDateString(undefined, {\n                year: \"numeric\",\n                month: \"long\",\n                day: \"numeric\"\n            });\n\n            invDateForFile = d.toLocaleDateString(undefined, {\n                year: \"numeric\",\n                month: \"long\",\n                day: \"numeric\"\n            });\n        }\n    } catch (e) {\n        console.warn(\"Invalid investigation date:\", e);\n    }\n\n    // --------------------------------------------------\n    // 5. Contact Name\n    // --------------------------------------------------\n    let contactName = \"Unknown\";\n    let cn = document.getElementById(\"pk_inv_contact\");\n    if (cn && cn.options && cn.selectedIndex >= 0) {\n        contactName = cn.options[cn.selectedIndex].text.trim();\n    }\n\n    // --------------------------------------------------\n    // 6. Report body HTML (from MYREPORTS field)\n    // --------------------------------------------------\n    let bodyHTML = nuGetValue(\"MYREPORTS\") || \"\";\n\n    // --------------------------------------------------\n    // 7. ZIP/report base filename\n    // --------------------------------------------------\n    let zipBaseName =\n        sfSafeFilePart(caseName) +\n        \"_Investigation_\" +\n        sfSafeFilePart(caseInvestigationNo) +\n        \"_\" +\n        sfSafeFilePart(invDateForFile);\n\n    // --------------------------------------------------\n    // 8. Build Header HTML  <<< NEW HEADER IS HERE\n    // --------------------------------------------------\n    let basePath = window.location.origin +\n        window.location.pathname\n            .replace(/\\/index\\.php.*$/, \'/\')\n            .replace(/\\/$/, \'\');\n\n    let logoUrl = basePath + \"/logo_small.png\";\n\n    let headerHTML =\n        \"<div style=\'background:#91a0b7;color:black;padding:14px;\" +\n        \"font-family:Arial;border-bottom:3px solid #6f7b8f;\'>\" +\n\n        \"  <div style=\'display:flex;align-items:center;\'>\" +\n        \"    <img src=\'\" + logoUrl + \"\' style=\'height:40px;margin-right:12px;\'>\" +\n        \"    <div style=\'font-size:22px;font-weight:bold;\'>SpiritForms Report</div>\" +\n        \"  </div>\" +\n\n        \"  <div style=\'margin-top:8px;font-size:14px;\'>\" +\n        \"    <strong>Investigation Number:</strong> \" + caseNumber + \"<br>\" +\n        \"    <strong>Case Name:</strong> \" + caseName + \"<br>\" +\n        \"    <strong>Case Investigation #:</strong> \" + caseInvestigationNo + \"<br>\" +\n        \"    <strong>Contact Name:</strong> \" + contactName + \"<br>\" +\n        \"    <strong>Investigation Date:</strong> \" + invDateReadable +\n        \"  </div>\" +\n\n        \"</div><br>\";\n\n    // --------------------------------------------------\n    // 9. Build complete HTML document\n    // --------------------------------------------------\n    let finalHTML =\n        \"<!DOCTYPE html><html><head><meta charset=\'UTF-8\'>\" +\n        \"<title>\" + zipBaseName + \"</title>\" +\n        \"<meta name=\'sf-zip-base-name\' content=\'\" + zipBaseName + \"\'>\" +\n        \"<meta name=\'sf-case-name\' content=\'\" + caseName + \"\'>\" +\n        \"<meta name=\'sf-case-investigation-no\' content=\'\" + caseInvestigationNo + \"\'>\" +\n        \"<meta name=\'sf-investigation-number\' content=\'\" + caseNumber + \"\'>\" +\n        \"<meta name=\'sf-investigation-date\' content=\'\" + invDateForFile + \"\'>\" +\n        \"</head><body style=\'background:white;\' \" +\n        \"data-sf-zip-base-name=\'\" + zipBaseName + \"\' \" +\n        \"data-sf-case-name=\'\" + caseName + \"\' \" +\n        \"data-sf-case-investigation-no=\'\" + caseInvestigationNo + \"\' \" +\n        \"data-sf-investigation-number=\'\" + caseNumber + \"\' \" +\n        \"data-sf-investigation-date=\'\" + invDateForFile + \"\'>\" +\n        headerHTML +\n        bodyHTML +\n        \"</body></html>\";\n\n    // --------------------------------------------------\n    // 10. Open Report in New Tab\n    // --------------------------------------------------\n    let w = window.open(\"about:blank\", \"_blank\");\n    if (!w) {\n        alert(\"Please allow popups for this site.\");\n        return;\n    }\n\n    w.document.open();\n    w.document.write(finalHTML);\n    w.document.close();\n}\n\n\n\n// ------------------------------------------------------\n// Force-enable the View Report button (unchanged)\n// ------------------------------------------------------\n(function () {\n    var tries = 0;\n    var t = setInterval(function () {\n        tries++;\n        if (typeof window.nuIsDisabled === \'function\') {\n            clearInterval(t);\n\n            if (!window._origNuIsDisabled) {\n                window._origNuIsDisabled = window.nuIsDisabled;\n\n                window.nuIsDisabled = function (id) {\n                    if (id === \'LaunchReportInNewTab\') return false;\n                    return window._origNuIsDisabled(id);\n                };\n            }\n        } else if (tries > 20) {\n            clearInterval(t);\n        }\n    }, 200);\n\n    setTimeout(function () {\n        var btn = document.getElementById(\'LaunchReportInNewTab\');\n        if (btn) {\n            btn.disabled = false;\n            btn.readOnly = false;\n            btn.classList.remove(\'nuReadonly\');\n        }\n    }, 500);\n})();', NULL, NULL, NULL);
INSERT INTO `zzzzsys_form` (`zzzzsys_form_id`, `sfo_type`, `sfo_code`, `sfo_description`, `sfo_group`, `sfo_status`, `sfo_breadcrumb_title`, `sfo_table`, `sfo_primary_key`, `sfo_browse_redirect_form_id`, `sfo_browse_target`, `sfo_browse_row_height`, `sfo_browse_rows_per_page`, `sfo_browse_title_multiline`, `sfo_browse_autoresize_columns`, `sfo_browse_sql`, `sfo_javascript`, `sfo_browse_javascript`, `sfo_edit_javascript`, `sfo_style`, `sfo_mobile_view`, `sfo_json`) VALUES
('692cb3cea1cf548', 'browseedit', 'EmailComposer', 'Email Composer', NULL, '1', NULL, 'email_composer', 'email_composer_id', NULL, NULL, NULL, NULL, '0', NULL, 'SELECT\n    email_composer_id,\n    email_sent_datetime,\n    email_recipients,\n    email_subject,\n    email_body\nFROM email_composer\nWHERE email_user = \'#USER_ID#\'\nORDER BY\n    (email_sent_datetime IS NULL) DESC,\n    email_sent_datetime DESC\n\n\n\n\n\n\n/*SELECT *\nFROM email_composer\nORDER BY\n    (email_sent_datetime IS NULL) DESC,\n    email_sent_datetime DESC;\n*/', 'console.log(\"EmailComposer JS Loaded\");\n\n/* ----------------------------------------------------------\n   1. ALWAYS PUT LABELS ON TOP\n---------------------------------------------------------- */\ntry {\n    nuLabelOnTop([\n        \'email_recipients\',\n        \'email_recipient_select\',\n        \'email_sent_formatted\',\n        \'emaillist\',\n        \'email_user\',\n        \'email_subject\',\n        \'email_body\',\n        \'send_email_button\'\n    ]);\n} catch (e) {\n    console.error(\"Label-on-top failed:\", e);\n}\n\n/* ----------------------------------------------------------\n   2. FILL FROM SPIRITFORM (localStorage)\n---------------------------------------------------------- */\nsetTimeout(function () {\n\n    var caseNo   = localStorage.getItem(\'sf_caseNo\')   || \'\';\n    var caseName = localStorage.getItem(\'sf_caseName\') || \'\';\n    var sfEmail  = localStorage.getItem(\'sf_email\')    || \'\';\n\n    console.log(\"DEBUG from SpiritForm:\", {\n        caseNo: caseNo,\n        caseName: caseName,\n        sfEmail: sfEmail\n    });\n\n// Subject like \"Investigation 24: Mystery Case\"\nif (caseNo && caseName) {\n    try {\n        nuSetValue(\'email_subject\', \'Investigation \' + caseNo + \': \' + caseName);\n    } catch (e1) {\n        console.error(\'Failed to set subject:\', e1);\n    }\n}\n\n\n    // Initial recipient from SpiritForm\n    if (sfEmail) {\n        try {\n            nuSetValue(\'email_recipients\', sfEmail);\n        } catch (e2) {\n            console.error(\'Failed to set recipients:\', e2);\n        }\n    }\n\n    // Put cursor in Message if opened from SpiritForm\n    if (sfEmail || (caseNo && caseName)) {\n        try {\n            document.getElementById(\'email_body\').focus();\n        } catch (e3) {}\n    }\n\n    /* ------------------------------------------------------\n       3. APPEND ADDITIONAL RECIPIENTS FROM SELECT LIST\n       (single-click OR ctrl-click)\n    ------------------------------------------------------ */\n\n    var selectObj = document.getElementById(\'email_recipient_select\');\n    var textArea  = document.getElementById(\'email_recipients\');\n\n    if (!selectObj || !textArea) {\n        console.log(\"DEBUG: select or textarea not found.\");\n        return;\n    }\n\n    selectObj.addEventListener(\'change\', function () {\n\n        var sel = selectObj.options[selectObj.selectedIndex];\n        if (!sel) { return; }\n\n        var selectedText = sel.text || \'\';\n\n        // Extract email between \':\' and \',\'\n        var email = \'\';\n        var match = selectedText.match(/:\\s*([^,]+)?,?/);\n        if (match && match[1]) {\n            email = match[1].trim();\n        }\n\n        if (!email) {\n            console.log(\"DEBUG: could not extract email from:\", selectedText);\n            return;\n        }\n\n        var existing = textArea.value.trim();\n\n        // Avoid duplicates\n        if (existing && existing.split(/[;,]\\s*/).indexOf(email) !== -1) {\n            return;\n        }\n\n        // Append using semicolons\n        if (existing === \'\') {\n            textArea.value = email;\n        } else {\n            textArea.value = existing + \';\' + email;\n        }\n\n        console.log(\"DEBUG recipients now:\", textArea.value);\n    });\n\n    /* ------------------------------------------------------\n       IMPORTANT: NOW CLEAR FLAGS SO SPIRITFORM DOES NOT\n       AFFECT FUTURE DIRECT OPENS\n    ------------------------------------------------------ */\n\n    localStorage.removeItem(\'sfTriggered\');\n    localStorage.removeItem(\'sf_caseNo\');\n    localStorage.removeItem(\'sf_caseName\');\n    localStorage.removeItem(\'sf_email\');\n\n}, 250);\n\n\n\n\n\n// EmailComposer Auto-Fill Injection\n// Runs on form load\n\n// Wait for nuBuilder to finish loading values\nsetTimeout(function () {\n\n    // Only auto-fill when triggered from SpiritForm\n    if (localStorage.getItem(\'sfTriggered\') === \'1\') {\n\n        // Populate case ID into hidden field\n        var caseID = localStorage.getItem(\'sf_caseID\');\n        if (caseID) {\n            nuSetValue(\'email_case_id\', caseID);\n        }\n\n        // Populate recipient email (if provided)\n        var autoEmail = localStorage.getItem(\'sf_email\');\n        if (autoEmail) {\n            nuSetValue(\'email_recipients\', autoEmail);\n        }\n\n        // Prevent re-filling on next load\n        localStorage.setItem(\'sfTriggered\', \'0\');\n    }\n\n}, 150);\n\n\n\n\n// Ensure _SEND_EMAIL localStorage flag is included in POST during save\n$(document).on(\'nuSaveBefore\', function () {\n    var f = document.forms[0];\n\n    // Create hidden input if it doesn\'t exist\n    var i = f.querySelector(\'input[name=\"_SEND_EMAIL\"]\');\n    if (!i) {\n        i = document.createElement(\'input\');\n        i.type = \'hidden\';\n        i.name = \'_SEND_EMAIL\';\n        f.appendChild(i);\n    }\n\n    // Pull from localStorage\n    var flag = localStorage.getItem(\'_SEND_EMAIL\') || \'0\';\n\n    // Set hidden field so PHP receives it\n    i.value = flag;\n});\n\n\n', NULL, '', NULL, NULL, NULL),
('6932235e44f1684', 'launch', 'ClientHome', 'Client Home', 'nubuilder', '1', '', '', '', '', '', 0, 0, '0', '', '', 'nuUserHomeCheckNoObjectsOnForm();\n\nfunction openNuObject() {\n\n    $(\'#nuMessageDiv\').remove();\n    nuPopup(\'nuobject\', \'-1\', window.nuFORM.getCurrent().form_id);\n\n}\n\nfunction nuUserHomeCheckNoObjectsOnForm() {\n    if (nuSERVERRESPONSE.objects.length === 0 && window.global_access) {\n        const message = `${nuTranslate(\'There are currently no objects on this form.\')}&nbsp;&nbsp;\n            <a href=\"javascript:openNuObject();\">${nuTranslate(\'Start adding some\')}</a>.`;\n        \n        $.nuInfoBar.info(message, {autoClose : false, closeOnClick : true});\n    }\n}\n', '', '', '', '', NULL),
('693c3ecfe33a1a0', 'edit', 'emaildeleteform', 'Delete Emails', NULL, '1', NULL, 'email_delete_form', 'email_delete_form_id', NULL, NULL, NULL, NULL, '0', NULL, NULL, NULL, NULL, 'nuLabelOnTop([\'email_ids_to_delete\'])\nnuLabelOnTop([\'email_composer_id\'])\n\n', NULL, NULL, NULL),
('693cafa2d26c280', 'launch', 'AdminHome', 'Admin Home', 'nubuilder', '1', '', '', '', '', '', 0, 0, '0', '', '', 'nuUserHomeCheckNoObjectsOnForm();\n\nfunction openNuObject() {\n\n    $(\'#nuMessageDiv\').remove();\n    nuPopup(\'nuobject\', \'-1\', window.nuFORM.getCurrent().form_id);\n\n}\n\nfunction nuUserHomeCheckNoObjectsOnForm() {\n    if (nuSERVERRESPONSE.objects.length === 0 && window.global_access) {\n        const message = `${nuTranslate(\'There are currently no objects on this form.\')}&nbsp;&nbsp;\n            <a href=\"javascript:openNuObject();\">${nuTranslate(\'Start adding some\')}</a>.`;\n        \n        $.nuInfoBar.info(message, {autoClose : false, closeOnClick : true});\n    }\n}', '', '', '', '', NULL),
('693dfdad8f237f9', 'browseedit', 'nureporttemplates', 'Report Templates', 'nubuilder', '0', '#not_title#|New', 'zzzzsys_note', 'zzzzsys_note_id', '', '', 0, 0, '0', '', 'SELECT\n    n.zzzzsys_note_id,\n    c.noc_name,\n    n.not_title,\n    n.not_updated_on,\n    n.not_text\nFROM zzzzsys_note n\nLEFT JOIN zzzzsys_note_category c\n  ON c.zzzzsys_note_category_id = n.not_zzzzsys_note_category_id\nWHERE c.noc_name = \'Reports\'\nORDER BY n.not_updated_on DESC\n\n\n\n/*\nSELECT\n    n.zzzzsys_note_id,\n    c.noc_name AS Category,\n    n.not_title AS Title,\n    n.not_updated_on AS UpdatedOn,\n    n.not_text AS Text\nFROM zzzzsys_note n\nLEFT JOIN zzzzsys_note_category c\n  ON c.zzzzsys_note_category_id = n.not_zzzzsys_note_category_id\nWHERE c.noc_name = \'Reports\'\nORDER BY n.not_updated_on DESC\n*/\n\n\n/*\nSELECT\n zzzzsys_note.*, noc_name\nFROM\n zzzzsys_note\nLEFT JOIN zzzzsys_note_category ON not_zzzzsys_note_category_id = zzzzsys_note_category.zzzzsys_note_category_id\nORDER BY\n not_title ASC\n*/', '', '', 'nuHide(\'label_not_title\');\nnuSetPlaceholder(\'not_title\', nuTranslate(\'Title\'));\n\nnuHide(\'label_not_zzzzsys_note_category_id\');\nnuSetPlaceholder(\'not_zzzzsys_note_category_idcode\', nuTranslate(\'Category\'));\n\nfunction nuNotesHandleEnterKey() {\n\n $(\'.ql-editor\').trigger(\"focus\");\n\n let tinyB = tinyMCE.get(\'not_content_container\').getBody();\n if (tinyB !== null) tinyB.focus();\n\n\n}\n\n$(\'#not_title\').nuOnEnterKey(nuNotesHandleEnterKey, true);\nnuTabAdditionalSetMarker();\n\n\nfunction nuTinyMCEOnInit(e, editor, id) {\n\n if (nuUseMobileView()) {\n $(function() {\n const maxWidth = $(\'#\' + id)?.attr(\'data-nu-mobile-max-width\')?.nuJustNumbers();\n const maxHeight = $(\'#\' + id)?.attr(\'data-nu-mobile-max-height\')?.nuJustNumbers();\n\n nuTinyMCESetBounds(\'not_content\', 5, 70, maxWidth, maxHeight);\n $(\'#not_updated_on\').css(\'top\', \'640px\');\n $(\'#label_not_updated_on\').css(\'top\', \'620px\');\n });\n }\n\n}\n\n\nfunction nuTabAdditionalSetMarker() {\n nuTabSetMarker(\'nu684e16abd1b5744\', \'not_text\');\n}\n\nfunction nuOnClone() {\n $(\'#not_updated_on\').removeClass(\'nuEdited\');\n}\n\n\n', '', '', NULL),
('69500164e61a85d', 'browseedit', 'EmailComposer_Admin', 'Email Composer (Admin)', '', '1', '', 'email_composer', 'email_composer_id', '692cb3cea1cf548', '3', NULL, NULL, '0', '', 'SELECT\n    t.email_composer_id,\n    t.email_sent_datetime,\n    t.email_recipients,\n    t.email_subject,\n    t.email_body,\n    t.email_user_display\nFROM (\n    SELECT\n        e.email_composer_id,\n        e.email_sent_datetime,\n        e.email_recipients,\n        e.email_subject,\n        e.email_body,\n        COALESCE(\n            CONCAT(u.sus_first_name, \' \', u.sus_last_name),\n            e.email_user\n        ) AS email_user_display\n    FROM email_composer e\n    LEFT JOIN zzzzsys_user u\n      ON u.zzzzsys_user_id COLLATE utf8mb4_general_ci = e.email_user\n) t\nORDER BY\n    (t.email_sent_datetime IS NULL) DESC,\n    t.email_sent_datetime DESC\n\n\n\n\n\n\n/*\nSELECT\n    email_composer_id,\n    email_sent_datetime,\n    email_recipients,\n    email_subject,\n    email_body\nFROM email_composer\nORDER BY\n    (email_sent_datetime IS NULL) DESC,\n    email_sent_datetime DESC\n*/\n\n/*SELECT *\nFROM email_composer\nORDER BY\n    (email_sent_datetime IS NULL) DESC,\n    email_sent_datetime DESC;\n*/', 'console.log(\"EmailComposer JS Loaded\");\n\n/* ----------------------------------------------------------\n   1. ALWAYS PUT LABELS ON TOP\n---------------------------------------------------------- */\ntry {\n    nuLabelOnTop([\n        \'email_recipients\',\n        \'email_recipient_select\',\n        \'email_sent_formatted\',\n        \'emaillist\',\n        \'email_user\',\n        \'email_subject\',\n        \'email_body\',\n        \'send_email_button\'\n    ]);\n} catch (e) {\n    console.error(\"Label-on-top failed:\", e);\n}\n\n/* ----------------------------------------------------------\n   2. FILL FROM SPIRITFORM (localStorage)\n---------------------------------------------------------- */\nsetTimeout(function () {\n\n    var caseNo   = localStorage.getItem(\'sf_caseNo\')   || \'\';\n    var caseName = localStorage.getItem(\'sf_caseName\') || \'\';\n    var sfEmail  = localStorage.getItem(\'sf_email\')    || \'\';\n\n    console.log(\"DEBUG from SpiritForm:\", {\n        caseNo: caseNo,\n        caseName: caseName,\n        sfEmail: sfEmail\n    });\n\n    // Subject like \"Case 24: Mystery Case\"\n    if (caseNo && caseName) {\n        try {\n            nuSetValue(\'email_subject\', \'Case \' + caseNo + \': \' + caseName);\n        } catch (e1) {\n            console.error(\'Failed to set subject:\', e1);\n        }\n    }\n\n    // Initial recipient from SpiritForm\n    if (sfEmail) {\n        try {\n            nuSetValue(\'email_recipients\', sfEmail);\n        } catch (e2) {\n            console.error(\'Failed to set recipients:\', e2);\n        }\n    }\n\n    // Put cursor in Message if opened from SpiritForm\n    if (sfEmail || (caseNo && caseName)) {\n        try {\n            document.getElementById(\'email_body\').focus();\n        } catch (e3) {}\n    }\n\n    /* ------------------------------------------------------\n       3. APPEND ADDITIONAL RECIPIENTS FROM SELECT LIST\n       (single-click OR ctrl-click)\n    ------------------------------------------------------ */\n\n    var selectObj = document.getElementById(\'email_recipient_select\');\n    var textArea  = document.getElementById(\'email_recipients\');\n\n    if (!selectObj || !textArea) {\n        console.log(\"DEBUG: select or textarea not found.\");\n        return;\n    }\n\n    selectObj.addEventListener(\'change\', function () {\n\n        var sel = selectObj.options[selectObj.selectedIndex];\n        if (!sel) { return; }\n\n        var selectedText = sel.text || \'\';\n\n        // Extract email between \':\' and \',\'\n        var email = \'\';\n        var match = selectedText.match(/:\\s*([^,]+)?,?/);\n        if (match && match[1]) {\n            email = match[1].trim();\n        }\n\n        if (!email) {\n            console.log(\"DEBUG: could not extract email from:\", selectedText);\n            return;\n        }\n\n        var existing = textArea.value.trim();\n\n        // Avoid duplicates\n        if (existing && existing.split(/[;,]\\s*/).indexOf(email) !== -1) {\n            return;\n        }\n\n        // Append using semicolons\n        if (existing === \'\') {\n            textArea.value = email;\n        } else {\n            textArea.value = existing + \';\' + email;\n        }\n\n        console.log(\"DEBUG recipients now:\", textArea.value);\n    });\n\n    /* ------------------------------------------------------\n       IMPORTANT: NOW CLEAR FLAGS SO SPIRITFORM DOES NOT\n       AFFECT FUTURE DIRECT OPENS\n    ------------------------------------------------------ */\n\n    localStorage.removeItem(\'sfTriggered\');\n    localStorage.removeItem(\'sf_caseNo\');\n    localStorage.removeItem(\'sf_caseName\');\n    localStorage.removeItem(\'sf_email\');\n\n}, 250);\n\n\n\n\n\n// EmailComposer Auto-Fill Injection\n// Runs on form load\n\n// Wait for nuBuilder to finish loading values\nsetTimeout(function () {\n\n    // Only auto-fill when triggered from SpiritForm\n    if (localStorage.getItem(\'sfTriggered\') === \'1\') {\n\n        // Populate case ID into hidden field\n        var caseID = localStorage.getItem(\'sf_caseID\');\n        if (caseID) {\n            nuSetValue(\'email_case_id\', caseID);\n        }\n\n        // Populate recipient email (if provided)\n        var autoEmail = localStorage.getItem(\'sf_email\');\n        if (autoEmail) {\n            nuSetValue(\'email_recipients\', autoEmail);\n        }\n\n        // Prevent re-filling on next load\n        localStorage.setItem(\'sfTriggered\', \'0\');\n    }\n\n}, 150);\n\n\n\n\n// Ensure _SEND_EMAIL localStorage flag is included in POST during save\n$(document).on(\'nuSaveBefore\', function () {\n    var f = document.forms[0];\n\n    // Create hidden input if it doesn\'t exist\n    var i = f.querySelector(\'input[name=\"_SEND_EMAIL\"]\');\n    if (!i) {\n        i = document.createElement(\'input\');\n        i.type = \'hidden\';\n        i.name = \'_SEND_EMAIL\';\n        f.appendChild(i);\n    }\n\n    // Pull from localStorage\n    var flag = localStorage.getItem(\'_SEND_EMAIL\') || \'0\';\n\n    // Set hidden field so PHP receives it\n    i.value = flag;\n});\n\n\n', '', '', '', '', NULL),
('69d2df8e79a71cc', 'browseedit', 'case_sensor_files', 'Case Sensor Files', NULL, NULL, NULL, 'case_sensor_files', 'case_sensor_file_id', NULL, NULL, NULL, NULL, '0', NULL, 'SELECT\n    case_sensor_file_id,\n    fk_inv_case_no,\n    sensor_device_master_id,\n    device_column_no,\n    file_no,\n    sensor_file_url,\n    file_desc,\n    file_path,\n    sensor_file_download_html\nFROM case_sensor_files\nORDER BY\n    device_column_no,\n    file_no,\n    case_sensor_file_id', NULL, NULL, NULL, '', '1', NULL),
