('nu5fdb9ffd45aaa', 'subform', 'nuobjectsubform', 'Forms Objects', 'nubuilder', '1', NULL, 'zzzzsys_object', 'zzzzsys_object_id', '', NULL, 0, 0, '0', NULL, 'SELECT * FROM zzzzsys_object \nORDER BY sob_all_zzzzsys_tab_id, sob_all_order', NULL, NULL, NULL, NULL, NULL, NULL),
('nu5fdb9ffd45efe', 'subform', 'nuaccesssubform', 'Accessible Forms', 'nubuilder', '1', NULL, 'zzzzsys_access_form', 'zzzzsys_access_form_id', '', NULL, 0, 0, '0', NULL, 'SELECT * FROM zzzzsys_access_form', NULL, NULL, NULL, NULL, NULL, NULL),
('nu5feb9ffd45efe', 'subform', 'nuaccesssubform_rep', 'Accessible Reports', 'nubuilder', '1', NULL, 'zzzzsys_access_report', 'zzzzsys_access_report_id', '', NULL, 0, 0, '0', NULL, 'SELECT * FROM zzzzsys_access_report', NULL, NULL, NULL, NULL, NULL, NULL),
