('nu61e9969a239c033', 'subform', 'nuobjectjsonsubform', 'Object JSON', 'nubuilder', '1', NULL, 'zzzzsys_object_json', 'zzzzsys_object_json_id', '', NULL, 0, 0, '0', NULL, 'SELECT * FROM zzzzsys_object_json', NULL, NULL, NULL, NULL, NULL, NULL),
('nu62aee4493239e3a', 'subform', 'nuconfigsettingssubform', 'config settings subform', 'nubuilder', '1', NULL, 'zzzzsys_config', 'zzzzsys_config_id', '', NULL, 0, 0, '0', NULL, 'SELECT * FROM zzzzsys_config \nORDER BY cfg_order', NULL, NULL, NULL, NULL, NULL, NULL),
('nu67f22e3ba027e23', 'browse', 'nufile_linked_objects', 'Linked Objects', 'nubuilder', '1', NULL, 'zzzzsys_object', 'zzzzsys_object_id', '', NULL, 0, 12, '0', NULL, 'SELECT\n    sob_all_id,\n    zzzzsys_form.sfo_code,\n    zzzzsys_form.sfo_description,\n    zzzzsys_object.sob_image_zzzzsys_file_id\nFROM\n    `zzzzsys_object`\nLEFT JOIN zzzzsys_form ON zzzzsys_form_id = zzzzsys_object.sob_all_zzzzsys_form_id\nWHERE\n    (sob_image_zzzzsys_file_id IS NOT NULL AND sfo_code <> \'nusample\')', NULL, 'nuHideHolders(0,1,2);\n\nfunction nuSelectBrowse(event, element) {    \n    const primaryKey = $(element).attr(\'data-nu-primary-key\');  \n    nuForm(\'nuObject\', primaryKey, \'\', \'\', \'2\');  \n}\n\n\nvar numRows = nuCurrentProperties().browse_filtered_rows;\nparent.nuSetValue(\'nuTab1\', nuTranslate(\'Linked Objects\') + \' (\' + numRows + \')\',\'html\')', NULL, NULL, NULL, NULL),
('nu682ce623ae184f0', 'launch', 'nuimportaccesslevel', 'Get Access Levels from a Form', 'nubuilder', '1', NULL, '', '', '', NULL, 0, 0, '0', NULL, '', 'nuAddActionButton(\'Run\', \'Run\', \'CopyACLRun()\');\n\nfunction CopyACLRun() {\n\n\n    if (nuGetValue(\'cpa_form_id\') === \'\' || nuGetValue(\'cpa_conflict\') === \'\') {\n        nuMessage(nuTranslate(\'Validation Error\'), \'Some required fields are missing.\');\n        return;\n    }\n\n    const sourceFormID = nuGetValue(\'cpa_form_id\');\n    const destinationFormID = parent.nuRecordId();\n\n    // const deleteAllExisting = nuGetValue(\'cpa_delete_all\'); // Boolean (true/false)\n    const skipIfExists = nuGetValue(\'cpa_delete_all\') == \'0\' // Boolean (true/false)\n    const overwriteIfExists = nuGetValue(\'overwrite_if_exists\') == \'1\' // Boolean (true/false)\n\n    nuHasNotBeenEdited();\n\n    // Send parameters to the PHP procedure\n    nuRunPHPHiddenWithParams(\'nu_get_access_levels_from_form\', \'params\', {\n        source_form_id: sourceFormID,\n        destination_form_id: destinationFormID,\n        // delete_all_existing: deleteAllExisting ? 1: 0,\n        skip_if_exists: skipIfExists ? 1: 0,\n        overwrite_if_exists: overwriteIfExists ? 1: 0\n    }, true);\n\n\n}\n\nfunction nuFormImportACLAfterRun() {\n  parent.nuFormImportACLAfterRun();\n}\n\n\nnuSetValue(\'cpa_conflict\',\'0\');', NULL, NULL, NULL, NULL, NULL),
('nu682ddc25aa0bb5f', 'browse', 'nunonsystemform_with_accesslevels', 'nuBuilder Forms with Access Levels', 'nubuilder', '1', NULL, 'zzzzsys_form', 'zzzzsys_form_id', '', NULL, 0, 0, '0', NULL, 'SELECT * FROM #TABLE_ID#', '$(\"[data-nu-column=\'0\']\").each(function() {\n    $(this).addClass(\'nu_\'+this.textContent);\n});\n\n$(\'#nuAddButton\').remove();\n$(\'#nuPrintButton\').remove();', NULL, NULL, NULL, NULL, NULL),
('nu68397bb77c048bb', 'browse', 'object_items', 'Items', 'nubuilder', '1', NULL, 'zzzzsys_item', 'zzzzsys_item_id', 'nuitem', NULL, 0, 13, '1', NULL, 'SELECT * FROM #TABLE_ID#\nWHERE (\n    itm_active = REPLACE(\'#nuBrowseTitle7_select#\', \'âœ”\', \'1\')\n    OR LEFT(\'#nuBrowseTitle7_select#\', 1) = \'\'\n    OR (LEFT(\'#nuBrowseTitle7_select#\', 1) = \'#\' AND itm_active = \'1\')\n)\nAND\n    (sob_all_zzzzsys_form_id = \'#PARENT_FORM_ID#\' OR \'#PARENT_FORM_ID#\' LIKE \'#%\')', 'var parentTabItems = parent.document.getElementById(\'nuTab2\');\nif (parentTabItems) {\n  parent.refreshIframeItems(parentTabItems);\n}', '$(function() {\n\n    const activeFilterId = \'nuBrowseTitle7_select\';\n    const hasVal = nuGetProperty(activeFilterId);\n    nuAddBrowseTitleSelect(7, [\"\", \"âœ”\"], 50, {\'text-align\': \'center\'\n    }); // Active\n    if (!hasVal) {\n        nuSetValue(activeFilterId, \'âœ”\', \'value\', false);\n    }\n\n    $(\'#\' + activeFilterId).parent().off(\"touchstart\");\n\n});', NULL, NULL, NULL, NULL),
('nuaccess', 'browseedit', 'nuaccess', 'Access Levels', 'nubuilder', '1', '#sal_code#|New', 'zzzzsys_access', 'zzzzsys_access_id', '', NULL, 0, 17, '0', '', 'SELECT zzzzsys_access.*, zzzzsys_form.sfo_code FROM zzzzsys_access\nLEFT JOIN zzzzsys_form \nON sal_zzzzsys_form_id = zzzzsys_form_id\nORDER BY sal_code\n', NULL, 'nuBrowseStyleBadge(2); // Group', '$(\'#sal_zzzzsys_form_id_open_button\').toggleClass(\'input_button nuButton nuLookupButton\');\nif (nuIsNewRecord()) nuHide(\'sal_zzzzsys_form_id_open_button\');\n\nnuAccessFormSetButtonIcons();\nnuAccessAddSfFilter();\n\nfunction nuAccessAddSfFilter() {\n\n    let sfFilter = {};\n    sfFilter.accform = {\n        \'slf_zzzzsys_form_id\': {\n            type: \'search\',\n            float: \'left\',\n            placeholder: nuTranslate(\'Search\')}\n    };\n\n    nuSubformAddFilter(sfFilter);\n\n}\n\nfunction nuTabsSetMarker() {\n   nuTabSetMarker(\'nu5bad6cb36af0c58\', \'accform000slf_zzzzsys_form_idcode\'); // Forms\n   nuTabSetMarker(\'nu5bad6cb36c16b42\', \'accphp000slp_zzzzsys_php_idcode\'); // Procedures\n   nuTabSetMarker(\'nu5bad6cb36c39fc8\', \'accreport000sre_zzzzsys_report_idcode\'); // Reports\n}\n\nnuTabsSetMarker();\n', '', '1', NULL),
