('nuaddattribute', 'launch', 'nuaddattribute', 'Add attribute', 'nubuilder', '1', NULL, '', '', '', NULL, 0, 0, '0', NULL, 'SELECT * FROM Launch Form 0', '/*\n    0|autocomplete|\n    1|accesskey|\n    2|data-|\n    3|maxlength|\n    4|placeholder|\n    5|spellcheck|\n    6|title|\n    7|value|\n    8|nu-label-position\n    9|nu-disable-calendar\n    10|nu-tooltip\n    11|nu-tooltip-icon\n\n*/\n\nnuHide(\'plh_value_select\');\nnuHide(\'plh_attribute_name\');\nnuHideTabs(0);\nnuSelectRemoveEmpty(\'plh_attribute\', \'-1\');\nnuAddActionButton(\'nuAddAttribute\', \'Add\', \'addAttribute();\');\n\nfunction nuOnMobileViewComplete() {\n  const currentTop = $(\'#plh_value_text\').css(\'top\');\n  const currentTopLabel = $(\'#label_plh_value_text\').css(\'top\');\n  $(\'#plh_value_select\').css(\'top\', currentTop);\n  $(\'#label_plh_value_select\').css(\'top\',  currentTopLabel);\n}\n\nif (typeObj().val() !== \'input\') {\n    nuSelectRemoveOption(\'plh_attribute\', \'7\').val(\'\');\n}\n\nfunction onAttributeChanged(value) {\n\n    nuShow(\'plh_value_select\', value === \'0\' || value === \'5\' || value === \'8\');\n    nuShow(\'plh_value_text\', !(value === \'0\' || value === \'5\' || value === \'8\' || value === \'9\'));\n    nuShow(\'plh_attribute_name\', value === \'2\');\n    \n    nuSetValue(\'plh_value_text\',\'\');\n\n    if (value === \'0\') {\n        $(\"#plh_value_select\").empty();\n        addSelectOption(\'0\', \'on\');\n        addSelectOption(\'1\', \'off\');\n    } else if (value === \'5\') {\n        $(\"#plh_value_select\").empty();\n        addSelectOption(\'0\', \'true\');\n        addSelectOption(\'1\', \'false\');\n    } else if (value === \'4\') {\n        nuSetPlaceholder(\'plh_value_text\', \'Placeholder text\');\n    } else if (value === \'6\' || value === \'10\' || value === \'11\') {\n        nuSetPlaceholder(\'plh_value_text\', \'Tooltip text\');\n    } else if (value === \'2\') {\n        nuSetPlaceholder(\'plh_value_text\', \'String value\');\n        $(\'#plh_attribute_name\').trigger(\"focus\");\n    } else if (value === \'1\') {\n        nuSetPlaceholder(\'plh_value_text\', \'Single character\');\n    } else if (value === \'3\') {\n        nuSetPlaceholder(\'plh_value_text\', \'Number value\');\n    }  else if (value === \'7\') {\n        nuSetPlaceholder(\'plh_value_text\', \'String\');\n    }  else if (value === \'8\') {\n        $(\"#plh_value_select\").empty();\n        addSelectOption(\'top\', \'top\');\n        addSelectOption(\'custom\', \'custom\');\n    } \n\n}\n\nfunction addSelectOption(value, text) {\n    $(\'#plh_value_select\').append(\'<option value=\"\' + value + \'\">\' + text + \'</option>\');\n}\n\nfunction attributesObj() {\n    return $(\"#sob_input_attribute\", window.parent.document);\n}\n\nfunction typeObj() {\n    return $(\"#sob_all_type\", window.parent.document);\n}\n\n\nfunction valueObjText() {\n    return $(\'#plh_value_text\').is(\":visible\") ? nuGetValue(\'plh_value_text\') : nuGetValue(\'plh_value_select\', \'text\');\n}\n\nfunction addAttribute() {\n    const attributeValue = valueObjText();\n    const attributeName = nuGetValue(\'plh_attribute_name\');\n    const attributeType = nuGetValue(\'plh_attribute\');\n    const attributeText = nuGetValue(\'plh_attribute\', \'text\');\n    \n    if (attributeValue === \'\' && attributeType != 9 && attributeType != 2) {\n        nuMessage(nuTranslate(\'Error\'), nuTranslate(\"Missing value\"));\n        return;\n    }\n    \n    if (attributeName === \'\' && nuIsVisible(\'plh_attribute_name\') ) {\n        nuMessage(nuTranslate(\'Error\'), nuTranslate(\"Missing name\"));\n        return;\n    }\n    \n    const attributeObj = attributesObj();\n    const attributeKey = attributeText + attributeName;\n    const attributeKeyWithEquals = attributeKey + \'=\"\';\n    \n    if (attributeObj.val().includes(attributeKeyWithEquals)) {\n        nuMessage(nuTranslate(\'Error\'), nuTranslate(\"The attribute already exists\"));\n        return;\n    }\n    \n    let kv = \'\';\n    if (attributeKeyWithEquals.includes(\'nu-disable-calendar\')) {\n        kv = \'nu-disable-calendar\';\n    } else {\n        kv = attributeKeyWithEquals + attributeValue + \'\"\';\n    }\n    \n    const currentVal = attributeObj.val();\n    if (currentVal === \'\') {\n        attributeObj.val(kv).change();\n    } else {\n        attributeObj.val(currentVal + \',\' + kv).change();\n    }\n}\n', NULL, NULL, NULL, '1', NULL),
('nuadddbcolumn', 'launch', 'nuadddbcolumn', 'Add Database Column', 'nubuilder', '1', NULL, '', '', '', NULL, 0, 0, '0', NULL, '', 'function nuAddDBColumnGetDataType(type, inputType, selectMultiple) {\n    \n    const BASE_TYPE_MAP = {\n        lookup: \'VARCHAR(25)\',\n        calc: \'DECIMAL(12,4)\',\n        textarea: \'TEXT\',\n    };\n\n    const SELECT_TYPE_MAP = {\n        single: \'VARCHAR(100)\',\n        multiple: \'VARCHAR(1000)\',\n    };\n\n    const INPUT_TYPE_MAP = {\n        date: \'DATE\',\n        nuDate: \'DATE\',\n        number: \'INT\',\n        nuAutoNumber: \'BIGINT UNSIGNED\',\n        nuNumber: \'DECIMAL(12,4)\',\n        file: \'LONGTEXT\',\n    };\n\n    if (type === \'select\') {\n        return SELECT_TYPE_MAP[selectMultiple ? \'multiple\' : \'single\'];\n    }\n\n    if (type === \'input\') {\n        return INPUT_TYPE_MAP[inputType] || \'VARCHAR(100)\';\n    }\n\n    return BASE_TYPE_MAP[type] || \'VARCHAR(100)\';\n    \n}\n\n\nfunction nuAddDBColumnSetDefault() {\n\n    const table = parent.$(\'#sob_all_table\').val();\n    const id = parent.$(\'#sob_all_id\').val();\n    const type = parent.$(\'#sob_all_type\').val();\n    const input = parent.$(\'#sob_input_type\').val();\n    /* const selectMultiple = parent.nuGetValue(\'sob_select_multiple\'); */ // Currently unused\n    const dataType = nuAddDBColumnGetDataType(type, input);\n\n    const query = `\\`${id}\\` ${dataType} NULL DEFAULT NULL`;\n    const alterStart = `ALTER TABLE \\`${table}\\` ADD`;\n\n    $(\'#sql_query_word\').html(alterStart);\n    $(\'#sql_query\').val(query);\n\n    nuSetProperty(\'sob_all_table\', table);\n    nuRefreshSelectObject(\'sql_after_column\');\n\n    return `${alterStart} ${query};`;\n\n}\n\nnuAddActionButton(\'Run\', \'Run\', \'nuHasNotBeenEdited(); nuRunPHPHidden(\"nu_run_add_db_column\")\');\nnuAddActionButton(\'Preview\', \'Preview\', \'nuAddDBColumnPreview()\');\nnuAddDBColumnSetDefault();\n\n\nfunction nuAddDBColumnPreview() {\n\n    const table = parent.$(\'#sob_all_table\').val();\n    const query = nuGetValue(\'sql_query\');\n    const after = nuGetValue(\'sql_after_column\');\n    let sql = \'ALTER TABLE `\' + table + \'`  ADD \' + query;\n\n    if (after != \'\') {\n        sql = sql + \" AFTER `\" + after + \'`\';\n    }\n\n    const escapeForHTMLAttribute = str => str.replace(/\\n/g, \'\\\\n\').replace(/\'/g, \"\\\\\'\");\n    const copyButtonHTML = (value, label) => `<button type=\"button\" class=\"nuActionButton nuAdminButton\" onclick=\"navigator.clipboard.writeText(nuTranslate(\'${escapeForHTMLAttribute(value)}\'))\">${nuTranslate(label)}</button>`;\n    const formIdCopyButton = copyButtonHTML(sql, \'Copy\');\n\n    nuMessage(\'Preview SQL\', sql + \';\' + \'<br></br>\' + formIdCopyButton);\n\n}\n\n$(\'#sql_query\').addClass(\'sql\');\n$(\'.sql\').on(\'dblclick\', function() {\n    nuOpenAce(\'SQL\', this.id);\n});', NULL, NULL, NULL, '1', NULL),
('nualterdbcolumn', 'launch', 'nualterdbcolumn', 'Alter Database Column', 'nubuilder', '1', NULL, '', '', '', NULL, 0, 0, '0', NULL, '', 'function nuAlterDBColumnSetDefault() {\n\n    const table = parent.$(\'#sob_all_table\').val();\n    const id = parent.$(\'#sob_all_id\').val();\n    const type = parent.$(\'#sob_all_id_datatype\').val();\n\n    let qry = `\\`${id}\\` ${type} NULL DEFAULT NULL`;\n    let start = `ALTER TABLE \\`${table}\\` CHANGE \\`${id}\\``;\n\n    $(\'#sql_query_word\').html(start);\n    $(\'#sql_query\').val(qry);\n\n    nuSetProperty(\'sob_all_table\', table);\n    nuSetProperty(\'sob_all_id\', id);\n\n}\n\nnuAddActionButton(\'Run\', \'Run\', \'nuHasNotBeenEdited(); nuRunPHPHidden(\"nu_run_alter_db_column\")\');\nnuAddActionButton(\'Preview\', \'Preview\', \'nuAlterDBColumnPreview()\');\nnuAlterDBColumnSetDefault();\n\n\nfunction nuAlterDBColumnPreview() {\n\n    const query = nuGetValue(\'sql_query\');\n    let sql = nuGetValue(\'sql_query_word\', \'html\') + \' \' + query;\n\n    const escapeForHTMLAttribute = str => str.replace(/\\n/g, \'\\\\n\').replace(/\'/g, \"\\\\\'\");\n    const copyButtonHTML = (value, label) => `<button type=\"button\" class=\"nuActionButton nuAdminButton\" onclick=\"navigator.clipboard.writeText(nuTranslate(\'${escapeForHTMLAttribute(value)}\'))\">${nuTranslate(label)}</button>`;\n    const formIdCopyButton = copyButtonHTML(sql, \'Copy\');\n\n    nuMessage(\'Preview SQL\', sql + \';\' + \'<br></br>\' + formIdCopyButton);\n\n}\n\n$(\'#sql_query\').addClass(\'sql\');\n$(\'.sql\').on(\'dblclick\', function() {\n    nuOpenAce(\'SQL\', this.id);\n});', NULL, NULL, NULL, '1', NULL),
('nuappcloner', 'browseedit', 'nuappcloner', 'Application Cloner', 'nubuilder', '1', '#cla_code#|New', 'zzzzsys_app_cloner', 'zzzzsys_app_cloner_id', '', NULL, 0, 0, '0', NULL, 'SELECT * FROM zzzzsys_app_cloner', NULL, NULL, 'var pwOrgValue = nuGetValue(\'cla_target_password\');\n\nfunction nuAppClonerNoAutoFill(targetInputId) {\n\n    let tries = 0;\n    const maxTries = 40;\n\n    const clearAutofill = setInterval(() => {\n        document.querySelectorAll(\'input\').forEach(input => {\n            if (input.matches(\':-webkit-autofill\')) {\n                if (nuIsNewRecord()) {\n                    input.value = \'\';\n                } else {\n                    if (pwOrgValue !== input.value) {\n                        input.value = pwOrgValue;\n                    }\n                }\n                nuHasNotBeenEdited();\n            }\n        });\n\n        const target = document.getElementById(targetInputId);\n        if (target) target.focus();\n\n        if (++tries >= maxTries) {\n            clearInterval(clearAutofill);\n        }\n    }, 10);\n\n}\n\nfunction nuLoadCloneForm() {\n    // Get current database configuration\n    nuSetProperty(\'clone_source_db\', nuSERVERRESPONSE.database);\n\n    //    nuAppClonerNoAutoFill(\'cla_code\');\n\n    if (nuIsNewRecord()) {\n\n        // Set default values\n        nuSetValue(\'cla_target_host\', nuSERVERRESPONSE.host);\n        nuSetValue(\'cla_target_charset\', \'utf8mb4\');\n        nuSetValue(\'cla_target_port\', \'3306\');\n        nuSetValue(\'cla_insert_type\', \'INSERT\');\n        nuSetValue(\'cla_database_collation\', \'utf8mb4_unicode_ci\');\n        //   nuSetValue(\'cla_excluded_files\', \'nuconfig.php\');\n        // nuSelectSelectAll(\'cla_opt_2_include\'); // include all user tables/views\n\n\n        // Check all clone options by default\n        for (let i = 1; i <= 9; i++) {\n            nuSetValue(\'cla_opt_\' + i, \'checked\', true);\n        }\n\n        // Check default config options\n        nuSetValue(\'cla_show_progress\', \'checked\', true);\n        nuSetValue(\'cla_target_db_mode\', \'fail\', true);\n        nuSetValue(\'cla_copy_files_mode\', \'fail\', true);\n        nuSetValue(\'cla_copy_files\', \'checked\', true);\n\n        // Set source and target paths\n        nuSetValue(\'cla_source_path\', \'..\');\n\n        const db = nuSERVERRESPONSE.database;\n        nuSetValue(\'cla_target_path\', \'../../\' + nuCurrentDate() + \'_clone_\' + db);\n        nuSetValue(\'cla_target_db\', nuCurrentDate() + \'_clone_\' + db);\n\n\n        nuHasBeenEdited();\n    } else {\n        nuAppClonerHostChanged();\n    }\n\n\n    // Helper tooltips\n    nuSetToolTip(\'cla_dry_run_label\', \'Test the clone without making any changes\', true);\n    //   nuSetToolTip(\'cla_create_database_label\', \'Create target database if it doesn\\\'t exist (requires CREATE privilege)\', true);\n    nuSetToolTip(\'cla_transaction_mode_label\', \'Use transactions (may not work with DDL statements)\', true);\n    nuSetToolTip(\'cla_show_progress_label\', \'Show progress messages during cloning\', true);\n    nuSetToolTip(\'cla_opt_1\', \'CREATE statements for all nuBuilder system tables. E.g. zzzzsys_user, zzzzsys_access,..\', true);\n    nuSetToolTip(\'cla_opt_2\', \'CREATE statements for all non-nuBuilder tables and views. Does not start with prefix zzzzsys_*\', true);\n    nuSetToolTip(\'cla_opt_3\', \'INSERT statements for all nuBuilder system records (nu*). Primary key starts with nu*.\', true);\n    nuSetToolTip(\'cla_opt_4\', \'INSERT statements for all records in the zzzzsys tables which define the user\\\'s own application. Primary key does not start with nu*.\', true);\n    nuSetToolTip(\'cla_opt_5\', \'INSERT statements for all non-nuBuilder tables\', true);\n\n}\n\nnuLoadCloneForm();\n\n// Add action button to run the clone\nnuAddActionButton(\'RunHidden\', \'Run\', \'nuRunCloneApplication()\');\nnuAddActionButton(\'RunHiddenDry\', \'Dry Run\', \'nuRunCloneApplication(true)\');\nnuAttachFontAwesome(\'nuRunHiddenDryButton\', \'fa-width-auto fa-regular fa-lg fa-circle-play\')\n\n\n\n\n// Function to run the clone application\nfunction nuRunCloneApplication(dryRun = false) {\n\n    if (!nuIsSaved()) {\n        alert(nuTranslate(\'Form must be saved first..\'));\n        return;\n    }\n\n\n    // Validate required fields\n    const required = [\'clone_target_host\', \'clone_target_db\', \'clone_target_username\', \'clone_target_charset\'];\n    for (let field of required) {\n        if ($(\'#\' + field).val() === \'\' || $(\'#\' + field).val() === \'enter_your_value\') {\n            nuMessage([\'Please fill in all required target database fields\']);\n            $(\'#\' + field).focus();\n            return;\n        }\n    }\n\n    const progressId = nuID();\n\n    // Collect all parameters\n    const params = {\n        targetHost: nuGetValue(\'cla_target_host\'),\n        targetDB: nuGetValue(\'cla_target_db\'),\n        targetUsername: nuGetValue(\'cla_target_username\'),\n        targetPassword: nuGetValue(\'cla_target_password\'),\n        targetCharset: nuGetValue(\'cla_target_charset\'),\n        targetPort: nuGetValue(\'cla_target_port\'),\n        sourcePath: nuGetValue(\'cla_source_path\'),\n        targetPath: nuGetValue(\'cla_target_path\'),\n        insertType: nuGetValue(\'cla_insert_type\'),\n        // Clone options\n        opts: [],\n\n        // Configuration\n        config: {\n            progressId: progressId,\n            copyFiles: nuGetValue(\'cla_copy_files\'),\n            showProgress: nuGetValue(\'cla_show_progress\'),\n            dryRun: dryRun, // nuGetValue(\'cla_dry_run\') ,\n            databaseMode: nuGetValue(\'cla_target_db_mode\'),\n            fileMode: nuGetValue(\'cla_copy_files_mode\'),\n            transactionMode: nuGetValue(\'cla_transaction_mode\'),\n            logFile: nuGetValue(\'cla_log_file\') || null,\n            databaseCollation: nuGetValue(\'cla_database_collation\'),\n            excludedFiles: $(\'#cla_excluded_files\').val().split(\',\').map(f => f.trim()).filter(f => f),\n            excludedDirs: $(\'#cla_excluded_dirs\').val().split(\',\').map(d => d.trim()).filter(d => d),\n            includeTablesAndViews: nuSelectToArray(\'cla_opt_2_include\'),\n            excludeTablesAndViews: nuSelectToArray(\'cla_opt_2_exclude\')\n            //  excludedFiles: nuGetValue(\'cla_excluded_files\').split(\',\').map(f => f.trim()).filter(f => f),\n            //   excludedDirs: nuGetValue(\'cla_excluded_dirs\').split(\',\').map(d => d.trim()).filter(d => d)\n        }\n    };\n\n    // Collect checked options\n    for (let i = 1; i <= 9; i++) {\n        if ($(\'#cla_opt_\' + i).is(\':checked\')) {\n            params.opts.push(i);\n        }\n    }\n\n    if (params.opts.length === 0) {\n        nuMessage([\'Please select at least one clone option\']);\n        return;\n    }\n\n\n    if (!dryRun) {\n        // Confirm action\n        const message = params.config.dryRun ?\n            \'Run clone in DRY RUN mode? (No changes will be made)\' :\n            \'Clone the application to \' + params.targetDB + \'?\\n\\nThis will copy all selected data and files.\';\n\n        if (!confirm(message)) {\n            return;\n        }\n    }\n\n    nuRunPHPHiddenWithParams(\'nu_app_cloner\', \'nu_app_cloner_params\', params);\n\n    const msgBody = nuAppClonerCreateProgressMessage();\n    nuAppClonerGetProgress(msgBody, nuFormId(), progressId);\n\n}\n\nfunction nuAppClonerGetProgress1(msgBody, progressId) {\n\n    function fetchProgress() {\n        fetch(\'core/nuapi.php?progressId=\' + encodeURIComponent(progressId))\n            .then(r => r.text())\n            .then(text => {\n                nuAppClonerOutputProgress(msgBody, text);\n            });\n    }\n\n    // Start polling every 3 seconds\n    const intervalId = setInterval(fetchProgress, 3000);\n\n    // Stop polling after 30 seconds // change in LIVE!\n    setTimeout(() => {\n        clearInterval(intervalId);\n    }, 30000);\n\n}\n\nfunction nuAppClonerGetProgress(msgBody, formId, progressId) {\n\n    function fetchProgress() {\n        if (window.stopPolling === true || formId !== formId || nuFormType() !== \'edit\') {\n            clearInterval(intervalId);\n            return;\n        }\n\n        fetch(\'core/nuapi.php?progressId=\' + encodeURIComponent(progressId))\n            .then(r => r.text())\n            .then(text => {\n                nuAppClonerOutputProgress(msgBody, text);\n            });\n    }\n\n    const intervalId = setInterval(fetchProgress, 2000);\n\n    setTimeout(() => {\n        clearInterval(intervalId);\n    }, 1200000); // 20 minutes\n}\n\n\nfunction nuAppClonerCreateProgressMessage() {\n    const msgDiv = nuMessage(\'Application Cloner\', \'<b>0</b> Starting Cloning Process\');\n    const msgElement = msgDiv[0];\n\n    msgElement.style.maxHeight = \'600px\';\n    msgElement.style.width = \'400px\';\n    msgElement.style.overflow = \'hidden\';\n\n    const msgBody = msgElement.querySelector(\'.nuMessageBody\');\n\n    if (msgBody) {\n        Object.assign(msgBody.style, {\n            maxHeight: \'600px\',\n            overflowY: \'auto\',\n            display: \'block\',\n            textAlign: \'left\',\n            paddingLeft: \'30px\'\n        });\n    }\n\n\n    msgDiv.addClass(\'nuAppClonerProgress\');\n\n    return msgBody;\n}\n\nfunction nuAppClonerOutputReverseLines(input) {\n    return input\n        .split(\'\\n\') // Split by line breaks\n        .filter(line => line) // Remove empty lines (optional)\n        .reverse() // Reverse the array of lines\n        .join(\'\\n\'); // Join back with line breaks\n}\n\n\nfunction nuAppClonerOutputProgress(msgBody, text) {\n    const childDiv = msgBody.querySelector(\'div\');\n    if (childDiv) {\n        childDiv.innerHTML = nuAppClonerOutputReverseLines(text).replace(/\\n/g, \'<br>\');\n        childDiv.scrollTop = childDiv.scrollHeight; // Scroll to bottom\n    }\n}\n\n\nfunction nuAppClonerHostChanged() {\n    $(\'[data-nu-copy-files]\').nuEnable(nuSERVERRESPONSE.host === cla_target_host.value);\n}\n', '', '0', NULL),
('nuauthentication', 'launch', 'nuauthentication', 'Authentication', 'nubuilder', '1', NULL, '', '', '', NULL, 0, 0, '0', NULL, '', 'function nuGet2FAProcedure() {\n    const d = nuDevMode();\n    const p = \'nu_authentication_2fa\';\n    return d ? p + \'_template\': p;\n}\n\nfunction nu2FAVerify() {\n    nuSetProperty(\'auth_code_verify\', $(\'#auth_code\').val());\n    nuSetProperty(\"nuauthcommand\", \"verify\");\n    const p = nuGet2FAProcedure();\n    nuRunPHPHidden(p);\n}\n\nfunction nu2FASendToken() {\n    nuSetProperty(\"nuauthcommand\", \"send\");\n    const p = nuGet2FAProcedure();\n    nuRunPHPHidden(p);\n}\n\nfunction handleEnterKey() {\n\n    $(\'#auth_code\').on(\'keydown\', function(evt) {\n        if (evt.key === \'Enter\') {\n            evt.preventDefault();\n            nu2FAVerify();\n        }\n    });\n\n}\n\nhandleEnterKey();\nnuHideHolders(0, 2);\n\n\n\n// Prevent [DOM] Password field is not contained in a form:\n$(\"#auth_code_verify\").wrap(\"<form id=\'nuFromVerif\' action=\'#\' method=\'post\' onsubmit=\'return false\'>\");', NULL, NULL, NULL, '1', NULL),
('nublank', 'launch', 'nublank', 'Blank', 'nubuilder', '1', NULL, '', '', '', NULL, 0, 0, '0', NULL, '', '\nnuSetTitle(nuFORM.getCurrent().run_description);\n', NULL, NULL, NULL, NULL, NULL),
('nubrowse', 'subform', 'nubrowse', 'Browse Columns', 'nubuilder', '1', NULL, 'zzzzsys_browse', 'zzzzsys_browse_id', '', NULL, 0, 5, '0', NULL, 'SELECT * FROM zzzzsys_browse\nORDER BY sbr_order\n', '$(\'#nuSearchButton\').remove();\n$(\'#nuSearchField\').remove();\n$(\'#nuPrintButton\').remove();\n\nnuSetTitle($(\'#sbr_title\').val());\n\nvar pid = parent.nuFORM.getCurrent().record_id;\n\nif(nuFORM.getCurrent().record_id == -1){\n    $(\'#sbr_zzzzsys_form_id\').val(pid).change();\n}\n', NULL, NULL, NULL, NULL, NULL),
('nubuildreport', 'browseedit', 'nubuildreport', 'Build Report', 'nubuilder', '1', '#sre_code#|New', 'zzzzsys_report', 'zzzzsys_report_id', '', NULL, 0, 0, '0', NULL, 'SELECT * FROM zzzzsys_report\nLEFT JOIN zzzzsys_form ON zzzzsys_form_id = sre_zzzzsys_form_id', 'if (nuFormType() == \'edit\') {\n\n    $(\'#sre_layout\').addClass(\'nuEdited\'); \n      nuAttachButtonImage(\'open_builder\',\'RD\');\n    \n    if (! nuIsNewRecord()) {\n  //    nuAddActionButton(\'Run\', \'Run\', \'nuRunReport(\"\'+ $(\'#sre_code\').val() +\'\")\');       \n    }\n    \n  }\n  \n  function nuBuildReportPickTableType(){\n      \n      var i   = $(\'#sre_zzzzsys_php_id\').val();\n      \n      var f   = \'\';\n      var r   = \'\';\n      \n      if(i.substr(0,10) == \'PROCEDURE:\'){\n          \n          f   = \'nuphp\';\n          r = i.substr(10);\n          \n      }\n      \n      if(i === \'\'){\n          \n          nuMessage([nuTranslate(\'No table selected\')]);\n          return;\n  \n      }\n      \n      if(i.substr(0,6) == \'TABLE:\'){\n          \n          nuVendorLogin(\'PMA\', sre_zzzzsys_php_iddescription.value)\n          return;\n  \n      }\n      \n      if(i.substr(0,4) == \'SQL:\'){\n          \n          f   = \'nuselect\';\n          r = i.substr(4);\n  \n      }\n      \n      nuPopup(f,r);\n      \n  }\n  \n  function nuBuildReportUpdateAclCount() {\n      var l = $(\"[data-nu-field=\'sre_zzzzsys_access_id\']\").length -2;\n      var t = l <= 0 ? \'\' : \' (\' + l + \')\';\n      $(\'#nuTab1\').html(nuTranslate(\'Access Level\') + t);\n  }', 'if (parent.nuCurrentProperties().form_id == \'nuaccess\') {\n    $(\'#nuBreadcrumb0\').html(nuTranslate(\'Reports\'));\n}\n\nnuBrowseStyleBadge(2); // Group', NULL, NULL, '1', NULL),
('nubuildtable', 'browse', 'nubuildtable', 'PHP or SELECT or TABLE', 'nubuilder', '1', NULL, 'zzzzsys_report_data', 'zzzzsys_report_data_id', 'nuselect', NULL, 0, 16, '0', NULL, 'SELECT * FROM zzzzsys_report_data', NULL, NULL, NULL, NULL, NULL, NULL),
('nucalcobjects', 'browse', 'nucalcobjects', 'Calc values On This Form And Its Subforms', 'nubuilder', '1', NULL, '#TABLE_ID#', 'thevalue', '', NULL, 0, 4, '0', NULL, 'SELECT * FROM #TABLE_ID#', '\nwindow.nuBrowseFunction = \'nuSelectCalcField\';\n\nfunction nuSelectCalcField(e){\n\n    var row = e.target.id.substr(0,8);\n    var fld = $(\'#\' + row + \'003\').html();\n    var frm = $(\'#sob_calc_formula\', parent.window.document).val();\n\n    $(\'#sob_calc_formula\', parent.window.document)\n    .val(frm + \'nuTotal(\"\' + fld + \'\")\')\n    .trigger(\'change\');\n\n}\n\n', NULL, NULL, NULL, NULL, NULL),
('nuclause', 'subform', 'nuclause', 'Select Clauses', 'nubuilder', '1', NULL, 'zzzzsys_select_clause', 'zzzzsys_select_clause_id', '', NULL, 0, 0, '0', NULL, 'SELECT * FROM zzzzsys_select_clause\nORDER BY ssc_type, ssc_order', NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `zzzzsys_form` (`zzzzsys_form_id`, `sfo_type`, `sfo_code`, `sfo_description`, `sfo_group`, `sfo_status`, `sfo_breadcrumb_title`, `sfo_table`, `sfo_primary_key`, `sfo_browse_redirect_form_id`, `sfo_browse_target`, `sfo_browse_row_height`, `sfo_browse_rows_per_page`, `sfo_browse_title_multiline`, `sfo_browse_autoresize_columns`, `sfo_browse_sql`, `sfo_javascript`, `sfo_browse_javascript`, `sfo_edit_javascript`, `sfo_style`, `sfo_mobile_view`, `sfo_json`) VALUES
('nucloner', 'browseedit', 'nucloner', 'Cloner', 'nubuilder', '1', '|New', 'zzzzsys_cloner', 'zzzzsys_cloner_id', '', NULL, 0, 0, '0', NULL, 'SELECT * FROM zzzzsys_cloner\nORDER BY clo_form_source', NULL, NULL, '// DEV\nif (!nuDevMode()) {\n    nuHideTabById(\'nu63ed1fef9b6331f\');\n}\n\nfunction nuSelectObjectRefreshed(o, f) {\n\n    nuSelectRemoveEmpty();\n    if (f == \'clo_tabs\') {\n        $(\'select#\' + f + \' > option\').prop(\'selected\', \'selected\');\n    }\n}\n\nfunction addRunButton() {\n    nuAddActionButton(\'nuRunCloner\', \'Run\', \'runCloner()\');\n    $(\'#nunuRunPHPHiddenButton\').css(\'background-color\', \'#117A65\');\n}\n\nfunction runCloner() {\n\n    if ($(\'#clo_form_source\').val() === \'\') {\n        nuMessage(nuTranslate(\'Validation Error\'), nuTranslate(\'Source Form cannot be left blank.\'));\n        return;\n    }\n\n    const tabsLength = $(\"#clo_tabs option\").length;\n    if ($(\'#clo_tabs :selected\').length === 0 && tabsLength > 0) {\n        nuMessage(nuTranslate(\'Validation Error\'), nuTranslate(\'Select at least 1 Tab.\'));\n        return;\n    }\n\n    nuSetProperty(\'cloner_refresh_selectId\', \'\');\n\n    const tabs = nuSelectToArray(\'clo_tabs\', \'index\');\n    nuSetProperty(\'cloner_tabs\', tabs.length === 0 ? \'\': JSON.stringify(tabs));\n\n    const subforms = $(\'#clo_subforms_include\').is(\':checked\');\n    const clo_subforms = nuSelectToArray(\'clo_subforms\');\n    nuSetProperty(\'cloner_subforms\', subforms === false || clo_subforms.length === 0 ? \'0\': JSON.stringify(clo_subforms));\n\n    const formsRunIFrame = nuSelectToArray(\'clo_iframe_forms\');\n    nuSetProperty(\'cloner_iframe_forms\', nuGetValue(\'clo_subforms_include\') == false || formsRunIFrame.length === 0 ? \'0\': JSON.stringify(formsRunIFrame));\n\n    const dump = $(\'#clo_dump\').is(\':checked\');\n    nuSetProperty(\'cloner_dump\', dump ? \'1\': \'0\');\n\n    const noObjects = $(\'#clo_objects\').is(\':checked\');\n    nuSetProperty(\'cloner_objects\', noObjects ? \'0\': \'1\');\n\n    const newPks = $(\'#clo_new_pks\').is(\':checked\');\n    nuSetProperty(\'cloner_new_pks\', newPks ? \'1\': \'0\');\n\n    const replaceInto = $(\'#clo_sql_replace_into\').is(\':checked\');\n    nuSetProperty(\'cloner_replace_into\', replaceInto ? \'1\': \'0\');\n\n    nuSetProperty(\'cloner_form_source\', $(\'#clo_form_source\').val());\n    nuSetProperty(\'cloner_form_dest\', $(\'#clo_form_dest\').val());\n    nuSetProperty(\'cloner_notes\', \'#clo_notes#\');\n\n    dump ? nuRunPHP(\'nu_cloner\', \'\', 1): nuRunPHPHidden(\'nu_cloner\');\n\n    const tables = nuSelectToArray(\'clo_tables_include\');\n    nuSetProperty(\'nubackup_tables_include\', tables.length === 0 ? \'\': JSON.stringify(tables));\n\n}\n\nfunction setTitle() {\n\n    if (!nuIsNewRecord()) {\n        nuSetTitle($(\'#clo_form_source\').val());\n    }\n\n}\n\nfunction setDefaultValues() {\n\n    if (nuIsNewRecord()) {\n        $(\'#clo_new_pks\').prop(\'checked\', true).trigger(\'change\');\n        $(\'#clo_dump\').prop(\'checked\', true).trigger(\'change\');\n    }\n\n}\n\nfunction setParentFormId() {\n\n    if (parent.$(\'#nuModal\').length > 0 && $(\'#clo_form_source\').val() === \'\') {\n        nuGetLookupId(window.parent.nuCurrentProperties().form_id, \'clo_form_source\', false, false);\n    }\n\n}\n\nfunction cloSubformsChecked() {\n\n    var c = $(\'#clo_subforms_include\').is(\':checked\');\n    c ? nuEnable(\'clo_subforms\'): nuDisable(\'clo_subforms\');\n    nuSelectSelectAll(\'clo_subforms\', c);\n\n}\n\nfunction cloIframeFormsChecked() {\n\n    var c = $(\'#clo_iframe_forms_include\').is(\':checked\');\n    c ? nuEnable(\'clo_iframe_forms\'): nuDisable(\'clo_iframe_forms\');\n    nuSelectSelectAll(\'clo_iframe_forms\', c);\n\n}\n\nfunction selectObjectPopuplated(formId, selectId, count) {\n\n    if (selectId == \'clo_tabs\') {\n        nuSelectSelectAll(\'clo_tabs\', true);\n    }\n\n    var chk;\n    if (selectId == \'clo_iframe_forms\') {\n        chk = $(\'#clo_iframe_forms_include\');\n        var c = chk.is(\':checked\');\n        if (c) {\n            nuSelectSelectAll(\'clo_iframe_forms\', true);\n        }\n        count === 0 ? nuDisable(\'clo_iframe_forms_include\'): nuEnable(\'clo_iframe_forms_include\');\n        if (count === 0) chk.prop(\'checked\', false).trigger(\'change\');\n    }\n\n\n    if (selectId == \'clo_subforms\') {\n\n        chk = $(\'#clo_subforms_include\');\n        var s = chk.is(\':checked\');\n        if (s) {\n            nuSelectSelectAll(\'clo_subforms\', true);\n        }\n        count === 0 ? nuDisable(\'clo_subforms_include\'): nuEnable(\'clo_subforms_include\');\n        if (count === 0) chk.prop(\'checked\', false).trigger(\'change\');\n    }\n\n}\n\n\n\nfunction nuClonerOpenBrowse() {\n\n    if (nuFormsUnsaved() !== 0) {\n        if (!confirm(nuTranslate(\'Leave this form without saving?\'))) {\n            return;\n        }\n\n    }\n    nuForm(nuFormId(), \'\', \'\', \'\', \'1\');\n\n}\n\n\nfunction unselectAllOptionsStartingWith(selectId, prefix) {\n    $(\"#\" + selectId + \" option\").each(function() {\n        if ($(this).text().startsWith(prefix)) {\n            $(this).prop(\"selected\", false);\n        }\n    });\n}\n\nfunction enableDisableCheckboxes() {\n    var v = nuGetValue(\'clo_dump\');\n    if (v == \'0\') {\n        nuSetValue(\'clo_sql_replace_into\', 0);\n        nuDisable(\'clo_sql_replace_into\');\n        nuSetValue(\'clo_new_pks\', 1);\n        nuDisable(\'clo_new_pks\');\n    } else {\n        nuEnable(\'clo_new_pks\');\n        nuEnable(\'clo_sql_replace_into\');\n    }\n}\n\n\nif (nuIsNewRecord()) {\n    $(\'#clo_tabs\').empty();\n    $(\'#clo_subforms\').empty();\n    $(\'#clo_iframe_forms\').empty();\n}\n\nenableDisableCheckboxes();\n\n// clo_dummy required to adjust correct popup width\nnuHide(\'clo_dummy\');\nnuSelectRemoveEmpty();\n\n$(\'#clo_subforms\').nuLabelOnTop(-18, 25)\n$(\'#clo_iframe_forms\').nuLabelOnTop(-18, 25)\nnuLabelOnTop([\'clo_tabs\', \'clo_tables_include\', \'clo_tables_exclude\']);\n\n$(\'#label_clo_subforms\').prop(\'for\', \'clo_subforms_include\');\n$(\'#label_clo_iframe_forms\').prop(\'for\', \'clo_iframe_forms_include\');\n\ncloSubformsChecked();\ncloIframeFormsChecked();\n\nsetParentFormId();\nsetDefaultValues();\n\naddRunButton();\nsetTitle();\n\n\nif (Array.isArray(nuFORM.breadcrumbs) && nuFORM.breadcrumbs.length === 1) {\n    nuAddActionButton(\"nuClonerOpenBrowse\", \"<i class=\'fa-fw fa-regular fa-rectangle-list\'></i>\", \'nuClonerOpenBrowse()\', nuTranslate(\'Open Browse Form\'));\n}\n\nnuHasNotBeenEdited();\n\n', NULL, '1', NULL),
('nucodesnippet', 'browseedit', 'nucodesnippet', 'Code Snippets', 'nubuilder', '1', '#cot_code#|New', 'zzzzsys_code_snippet', 'zzzzsys_code_snippet_id', '', NULL, 35, 10, '0', NULL, 'SELECT * FROM zzzzsys_code_snippet WHERE (\n\n		(IFNULL(cot_scope,\'\') LIKE \'%0%\' AND \'#IS_CUSTOM_CODE#\' = \'1\') OR\n		(IFNULL(cot_scope,\'\') LIKE \'%1%\' AND \'#IS_SETUP_HEADER#\' = \'1\') OR\n		(IFNULL(cot_scope,\'\') LIKE \'%2%\' AND \'#IS_SQL#\' = \'1\') OR\n		(IFNULL(cot_scope,\'\') LIKE \'%3%\' AND \'#IS_PHP#\' = \'1\') OR\n\n	(\n\n		LOCATE(\'#\', \'#IS_SETUP_HEADER#\') = 1 AND \n		LOCATE(\'#\', \'#IS_CUSTOM_CODE#\') = 1 AND\n		LOCATE(\'#\', \'#IS_PHP#\') = 1 AND \n		LOCATE(\'#\', \'#IS_SQL#\') = 1 \n\n	) \n)\n\nORDER BY cot_code ', NULL, 'nuBrowseStyleBadge(2); // Group', 'var sc = $(\'#cot_source_code\');\nsc.addClass(\'js\');\n\nsc.css(\'padding\', \'3px 3px 3px 3px\')\n\n// Add ACE event handlers\nsc.on(\'dblclick\', function() {\n    nuOpenAce(nuCodeSnippetGetSourceLangage(), this.id);\n});\n\n// Code Snippets form\nnuSetProperty(\'IS_SETUP_HEADER\', 0);\nnuSetProperty(\'IS_CUSTOM_CODE\', 1);\n\n// Disable nu-records\nif (String(nuRecordId()).startsWith(\'nu\') && !nuDevMode()) {\n    nuDisableAllObjects();\n    $(\'#nuSaveButton\').hide();\n}\n\nfunction nuCodeSnippetGetSourceLangage() {\n\n    let l = $(\'#cot_language\').val();\n    if (l === \'JavaScript\') l = \'JS\';\n    return l === \'\' ? \'JS\' : l;\n\n}\n\nif (nuCodeIsTemplate() && !nuDevMode()) {\n    nuDisableAllObjects();\n    nuMessage(\"Unable to save templates. Please clone them to create a new copy and save the cloned version instead.\", 2500);\n}\n\nfunction nuCodeIsTemplate() {\n    return nuGetValue(\'cot_template\');\n}\n\nfunction nuOnClone() {\n\n    let code = cot_code.value;\n\n    if (nuCodeIsTemplate()) {\n        code = code.substring(0, code.length - 9);\n        nuSetValue(\'cot_code\', code);\n        nuSetValue(\'cot_group\', \'\');\n        nuSetValue(\'cot_template\', false);\n        nuEnableAllObjects();\n        $(\'#nuSaveButton\').show();\n    }\n\n}', NULL, '1', NULL),
('nucsvtransfer', 'launch', 'nucsvtransfer', 'CSV Transfer', 'nubuilder', '1', NULL, '', '', '', NULL, 0, 0, '0', NULL, '', 'function nuCheckCSV() {\n\n    const csvTo = $(\'#csv_to\').val().trim();\n    const csvFrom = $(\'#csv_from\').val().trim();\n    const csvDelimiter = $(\'#csv_delimiter\').val().trim();\n    const csvTransfer = $(\'#csv_transfer\').val().trim();\n\n    if (!csvTransfer || !csvFrom || !csvTo || !csvDelimiter) {\n        return nuMessage(nuTranslate(\'Validation Error\'), nuTranslate(\'No fields can be left blank\') + \'...\');\n    }\n\n    if (csvTransfer === \'export\') {\n        if (nuFORM.getJustTables().includes(csvFrom)) {\n            return nuRunPHP(\'nu_csv_transfer\');\n        }\n        return nuMessage(nuTranslate(\'No such tablename\') + \'...\');\n    }\n\n    if (csvTransfer === \'import\') {\n        if (!nuCSVfiles.includes(csvFrom)) {\n            return nuMessage([\n                nuTranslate(\'File not found\'),\n                \'\',\n                nuTranslate(\'CSV File must be located in the temp directory of the nuBuilder directory\')\n            ]);\n        }\n\n        if (csvTo === \'zzzzsys_user\') {\n            return nuImportUsersFromCSV(csvFrom, csvDelimiter);\n        }\n\n        if (nuFORM.getJustTables().includes(csvTo)) {\n            return nuMessage([\n                nuTranslate(\'There is already a table named\'),\n                `<b>${csvTo}</b>`\n            ]);\n        }\n\n        return nuRunPHP(\'nu_csv_transfer\');\n    }\n\n}\n\n\n\nnuAddActionButton(\'transfer\', \"Transfer\", \'nuCheckCSV()\', \'\');\n\n$(\'#csv_transfer\').val(\'export\');\n$(\'#csv_delimiter\').val(\'44\');\n\nnuHide(\'csv_delete_after_import\');\n\nnuCSVTransfer(\'export\');\n\nfunction nuCSVTransfer(action) {\n\n    const isExport = action === \'export\';\n\n    $(\'#label_csv_from\').html(nuTranslate(isExport ? \'Export From (Table)\': \'Import From CSV File\'));\n    $(\'#label_csv_to\').html(nuTranslate(isExport ? \'Export To CSV File\': \'Import To (Table)\'));\n\n    const dataListValue = isExport ? nuFORM.getJustTables(): nuCSVfiles;\n\n    isExport ? nuHide(\'csv_delete_after_import\'): nuShow(\'csv_delete_after_import\');\n\n    nuAddDatalist(\'csv_from\', dataListValue, true);\n\n}', NULL, NULL, NULL, '1', NULL),
('nudebug', 'browseedit', 'nudebug', 'nuDebug Results', 'nubuilder', '1', NULL, 'zzzzsys_debug', 'zzzzsys_debug_id', '', NULL, 31, 13, '1', NULL, 'SELECT * FROM zzzzsys_debug\nLEFT JOIN zzzzsys_user on zzzzsys_user_id = deb_user_id\nWHERE (deb_flag = \'#nu65e9ea5e7414ca0_filter#\' OR LEFT(\'#nu65e9ea5e7414ca0_filter#\',1) IN (\'#\',\'\'))\nORDER BY zzzzsys_debug_id DESC', '$(\'#deb_message\')\n.css(\'font-size\', 10 + \'px\')\n// .css(\'background-color\', \'#FFEEA6\')\n.prop(\'readonly\', true)\n.on(\'dblclick\', function() {\n    nuOpenAce(\'Text\', this.id);\n});\n\n\n$(\'#delete_option\').val(0);\n$(\'#nuAddButton\').remove();\n$(\'#nuOptions\').remove();\n\nvar mess = String($(\'#deb_message\').val());\nvar i = mess.indexOf(\'<br>\');\nvar m = mess.substr(i + 6);\nvar t = mess.substr(0, i);\nvar isHTMLText = m.startsWith(\'<html>\');\n\nnuSetTitle(m.substr(0, i));\n\n$(\'#nuTab0\').remove();\n\n$(\'#nuBreadcrumb2\')\n.css(\'text-align\', \'center\')\n.css(\'width\', \'95%\')\n.css(\'color\', \'black\')\n.css(\'padding\', \'5px\')\n.html(t + \' :: \' + nuWhen(nuEscapeHTML($(\'#deb_added\').val())))\n.appendTo(\"#nuTabHolder\");\n\n$(\'#deb_message\').val(m);\n\n\n$(\"[data-nu-column=\'2\']\").each(function(index) {\n\n    if ($(this).html().trim() !== \'\') {\n\n        const nuhtm = nuWhen(Number($(this).html()));\n\n        $(this).html(nuhtm);\n\n    }\n\n});\n\nif (nuFORM.getCurrent().record_id !== \'\') {\n\n    $(\'.nuActionButton\').remove();\n    nuAddActionButton(\'Delete\');\n\n}\n\nnuAddActionButton(\'DeleteAll\', \'Delete All\', \'nuDeleteAllAction()\');\n\nif (isHTMLText) {\n    nuDebugConvertTextareaToDiv();\n}\n\nfunction nuDebugConvertTextareaToDiv() {\n\n    const textarea = document.getElementById(\'deb_message\');\n    const htmlCode = textarea.value;\n    const div = document.createElement(\'div\');\n    div.innerHTML = htmlCode;\n    div.style.cssText = textarea.style.cssText;\n    div.style.userSelect = \'text\';\n    textarea.parentNode.replaceChild(div, textarea);\n\n}', 'nuAddBrowseFilter(\'nu65e9ea5e7414ca0\').nuSearchablePopup({ items: getFlag() });\n\n\nnuAddActionCheckbox({\n  id: \'chkAutoRefresh\',\n  text: \'Auto Refresh\',\n  checked: false,\n  storage: \'local\',\n  onChecked(isChecked) { \n    nuDebugSetAutoRefresh(isChecked);\n  }\n});\n\nfunction nuDebugSetAutoRefresh(active) {\n   \n    const button = document.getElementById(\'nuSearchField\');\n    if (!button) return; \n\n    if (button._refreshTimer) {\n        clearInterval(button._refreshTimer);\n        delete button._refreshTimer;\n    }\n\n    if (!active) return;\n\n    button._refreshTimer = setInterval(() => {\n        if (!button.isConnected) {\n            clearInterval(button._refreshTimer);\n            delete button._refreshTimer;\n            return;\n        }\n        nuGetBreadcrumb();\n    }, 2000);\n    \n}\n\n\nnuDebugSetAutoRefresh(nuGetValue(\'chkAutoRefresh\'));', NULL, '', '', NULL),
('nuemaillog', 'browseedit', 'nuemaillog', 'E-Mail Log', 'nubuilder', '1', '#eml_subject#|New', 'zzzzsys_email_log', 'zzzzsys_email_log_id', '', NULL, 0, 0, '1', NULL, 'SELECT * FROM zzzzsys_email_log \nLEFT JOIN zzzzsys_user ON zzzzsys_user_id = eml_user_id\nLEFT JOIN zzzzsys_form ON zzzzsys_form_id = eml_form_id\nWHERE (eml_state = \'#nu65f28ff562c4cea_filter#\' OR LEFT(\'#nu65f28ff562c4cea_filter#\',1) IN (\'#\',\'\'))\nORDER BY eml_created_at DESC', NULL, 'nuAddBrowseFilter(\'nu65f28ff562c4cea\').nuSearchablePopup({ items: nuEmailLogFilterGetGroup()});', NULL, NULL, '1', NULL),
('nuemailtemplate', 'browseedit', 'nuemailtemplate', 'Email Templates', 'nubuilder', '1', '#emt_code#|New', 'zzzzsys_email_template', 'zzzzsys_email_template_id', '', NULL, 0, 0, '0', NULL, 'SELECT\n  zzzzsys_email_template.*,\n  sfo_description\nFROM\n  zzzzsys_email_template\n  LEFT JOIN zzzzsys_form ON zzzzsys_form_id = emt_form_id\nWHERE\n  (\n    (\n      ifnull(emt_group, \'\') = \'#nu635294e972c3b80_filter#\'\n      OR left(\'#nu635294e972c3b80_filter#\', 1) IN (\'#\', \'\')\n    )\n    AND (\n      ifnull(emt_category, \'\') = \'#nu68784fb4ac37836_filter#\'\n      OR left(\'#nu68784fb4ac37836_filter#\', 1) IN (\'#\', \'\')\n    )\n  )', NULL, 'nuBrowseStyleBadge(1); // Group\n\nnuAddBrowseFilter(\'nu635294e972c3b80\').nuSearchablePopup({ items: nuEmailTemplateFilterGetGroup() });\n\nnuAddBrowseFilter(\'nu68784fb4ac37836\').nuSearchablePopup({ items: nuEmailTemplateFilterGetCategory() });\n', 'nuLabelOnTop([\'emt_form_id\']);\nactiveObj = $(\'#emt_body\');\n\n$(\'#emt_avail_fields\').nuLabelOnTop();\nnuSelectRemoveMultiple(\'emt_avail_fields\');\n\nif (nuEmailTemplateIsTemplate() && !nuDevMode()) {\n    nuDisableAllObjects();\n    nuMessage(`${nuTranslate(\'Error\')}`, `${nuTranslate(\"Unable to save templates. Please clone them to create a new copy and save the cloned version instead.\")}`, 3500);\n}\n\nnuEmailTemplateSetPreviewText();\n\nfunction nuEmailTemplateAddSelectedField() {\n    const selObjectId = nuGetValue(\'emt_avail_fields\', \'text\');\n    const selObjectLabel = nuGetValue(\'emt_avail_fields\');\n    if (selObjectId !== \'\') {\n        const activeObjectId = nuEmailTemplateGetActiveObjectId();\n        const isBody = activeObjectId == \'emt_body\';\n        const label = isBody ? \'<b>\' + selObjectLabel + \': </b>\' : \'\';\n        nuInsertAtCaret(activeObjectId, label + \"#\" + selObjectId + \"#\" + (isBody ? \'\\n\' : \'\'));\n        $(\'#\' + activeObjectId).trigger(\'change\');\n    }\n}\n\n\nfunction nuEmailTemplateWrapText(elementID, openTag, closeTag) {\n    const textArea = $(\'#\' + elementID);\n    const len = textArea.val().length;\n    const start = textArea[0].selectionStart;\n    const end = textArea[0].selectionEnd;\n    if (start !== end) {\n        var selectedText = textArea.val().substring(start, end);\n        var replacement = openTag + selectedText + closeTag;\n        textArea.val(textArea.val().substring(0, start) + replacement + textArea.val().substring(end, len)).trigger(\'change\');\n    }\n}\n\nfunction nuEmailTemplateGetActiveObjectId() {\n    return activeObj.attr(\'id\');\n}\n\nfunction nuEmailTemplateFormatText(tag) {\n    nuEmailTemplateWrapText(nuEmailTemplateGetActiveObjectId(), \'<\' + tag + \'>\', \'</\' + tag + \'>\');\n}\n\nfunction nuEmailTemplateFormatText2(tag) {\n    nuEmailTemplateWrapText(nuEmailTemplateGetActiveObjectId(), tag, tag);\n}\n\nfunction nuEmailTemplateSetPreviewText() {\n    $(\'#textAreaPreviewDiv\').html($(\'#emt_body\').val().replace(/\\n/g, \'<br />\'));\n}\n\n\nfunction nuEmailTemplateIsTemplate() {\n    return nuGetValue(\'emt_template\');\n}\n\nfunction nuOnClone() {\n\n    const code = emt_code.value;\n\n    if (nuEmailTemplateIsTemplate()) {\n        nuSetValue(\'emt_code\', code.substring(0, code.length - 9));\n        nuSetValue(\'emt_group\', \'\');\n        nuSetValue(\'emt_template\', false);\n        nuEnableAllObjects();\n    }\n\n}', NULL, '1', NULL),
('nuemailtest', 'launch', 'nuemailtest', 'Send Test Email', 'nubuilder', '1', NULL, '', '', '', NULL, 0, 0, '0', NULL, '', 'nuAddActionButton(\'nuRuntestemail\', nuTranslate(\'Send\'), \'nuRunPHPHidden(\"nu_test_email\")\');\n\nif (parent.$(\'#nuModal\').length > 0) {\n\n    var p = window.parent;\n    $(\'#set_smtp_from_address\').val(p.set_smtp_from_address.value);\n    $(\'#ema_to\').val(p.set_smtp_from_address.value);\n    $(\'#set_smtp_from_name\').val(p.set_smtp_from_name.value);\n    $(\'#ema_body\').val(\'nuBuilder <b>Email<br> Test\');\n    $(\'#ema_subject\').val(\'nuBuilder Test - \' + new Date().toLocaleString());\n\n}\n\n\nnuSetToolTip(\'ema_load_data\', nuTranslate(\'Load from Local Storage\'));\nnuSetToolTip(\'ema_save_data\', nuTranslate(\'Save to Local Storage\'));\n\n\nfunction nuemailtestSaveDatatoLS() {\n\n    $(\'input[type=text], textarea\').each(function() {\n        localStorage.setItem(this.id, $(this).val());\n    });\n\n}\n\n\nfunction nuemailtestLoadDatafromLS() {\n\n    $(\'input[type=\"text\"], textarea\').each(function() {\n        var key = $(this).attr(\'id\');\n\n        var value = localStorage.getItem(key);\n        if (value || value === \'\') {\n            $(this).val(value);\n        } else {\n            nuMessage(`${nuTranslate(\'Information\')}`, `${nuTranslate(\"There\'s no Data to load in Local Storage\")}`);\n        }\n\n    });\n}', NULL, NULL, NULL, '1', NULL),
