('nufflaunch', 'launch', 'nufflaunch', 'Form Builder', 'nubuilder', '1', NULL, '', '', '', NULL, 0, 0, '0', NULL, '', 'var useMobileView = nuUseMobileView();\nnuInit();\n\nfunction nuFFSetPrimaryKey() {\n\n    let pk = \'\';\n\n    if (tableExists) {\n        const tableSchema = nuSERVERRESPONSE.tableSchema[fastform_table.value];\n        pk = tableSchema === undefined ? \'\': tableSchema.primary_key;\n    } else {\n        pk = nuGetValue(\'fastform_table\')+\'_id\';\n    }\n\n    nuSetValue(\'fastform_primary_key\', pk);\n    nuShow(\'fastform_primary_key\', (pk == \'\' || !tableExists) && fastform_type.value !== \'launch\')\n\n}\n\nfunction nuFFGetMessageTableEmpty() {\n   return nuTranslate(\'Either pick an existing table or enter a new table name.\');\n}\n\nfunction nuInit() {\n\n    $(\"[id$=\'ff_browse\']\").nuHide();\n    $(\'.nuActionButton\').nuHide();\n\n    nuHide([\'fastform_prefix\', \'nuFFAvailableColumnsWord\', \'check_nulog\', \'nuFFAvailableColumns\',\'fastform_primary_key\']);\n    nuDisable(\'nuFFAvailableColumns\');\n\n    nuSelectRemoveMultiple();\n    nuSelectRemoveEmpty(\'obj_sf000ff_type\', \'-1\');\n    nuSelectRemoveEmpty(\'fastform_type\', \'-1\');\n    nuMoveFieldPrefixToSubform();\n    nuSetValue(\'fastform_type\', \'browseedit\');\n\n    nuAddActionButton(\'BuildFastForm\');\n    nuSetToolTip(\'fastform_table\', nuFFGetMessageTableEmpty(), true);\n    nuSubformEnableMultiPaste(\"obj_sf\", \"#obj_sf000ff_label\", null, callbackPasted);\n    nuSetFFTypeOptionsColor(\'obj_sf000ff_type\');\n\n    nuSetFK();\n    nuDisableLastFFRow();\n\n    $(\"#fastform_type > option\").each(function() {\n        $(this).addClass(\'nu_\' + this.value);\n    });\n\n    $(\'#fastform_prefix\').on(\'click\', function(e) {\n        e.stopPropagation();\n    });\n\n    // Show all items again when clicking on the datalist arrow down button\n    $(\'#fastform_table\')\n    .on(\'click\', function(e) {\n        var t = $(this);\n        var inpLeft = t.offset().left;\n        var inpWidth = t.width();\n        var clickedLeft = e.clientX;\n        var clickedInpLeft = clickedLeft - inpLeft;\n        var arrowBtnWidth = 12;\n        if ((inpWidth - clickedInpLeft) < arrowBtnWidth) {\n            if (t.val() !== \"\") {\n                t.val(\'\');\n            }\n        }\n    })\n\n    .on(\'input\',\n        function() {\n\n            nuSetFFTable();\n            nuShowAvailableFields(false);\n\n            var selectedOption = $(\'option[value=\"\' + $(this).val() + \'\"]\');\n            if (selectedOption.length) {\n\n                nuSetProperty(\'available_columns\', $(\'#fastform_table\').val());\n                nuSetProperty(\'assigned_columns\', \'\');\n\n                $(\'#nuFFAvailableColumns\').empty();\n                nuAvailableColumnsSetLoading();\n                nuRefreshSelectObject(\'nuFFAvailableColumns\', \'\', true);\n\n            }\n        });\n\n    $(\'#fastform_table\').trigger(\"focus\");\n\n}\n\nfunction callbackPasted(modifiedObjects) {\n\n  modifiedObjects.forEach(function(obj) {\n     obj.attr(\'data-user-modified\', \'\');\n  });\n \n}\n\nfunction nuNoStoreObject(text) {\n    return [\'Word\', \'Subform\', \'Image\', \'HTML\', \'Button\'].indexOf(text) !== -1;\n}\n\nfunction nuNoBrowseObject(text) {\n    return [\'Display\', \'File\', \'Multiselect\'].indexOf(text) !== -1 || nuNoStoreObject(text)\n}\n\nfunction nuSetFFCheckboxes(type) {\n\n    let checkboxes = $(\"[id$=\'ff_browse\']:checkbox\");\n    if (type.startsWith(\'browse\')) {\n\n        const l = checkboxes.length;\n        checkboxes.each(function(index) {\n            if (index !== l - 1 && !$(this).is(\"[data-nu-no-browse]\")) {\n                $(this).show();\n            }\n        });\n\n    } else {\n        checkboxes.hide();\n    }\n\n}\n\nfunction nuOnFormTypeChanged() {\n\n    var type = nuGetValue(\'fastform_type\');\n\n    $(\'#fastform_type\').removeClass().addClass(\'nu_\' + type);\n    $(\'#fastform_table\').nuShow(type !== \'launch\');\n\n    nuSetFFCheckboxes(type);\n\n    $(\"[data-nu-field=\'ff_datatype\']\").nuShow(type !== \'launch\');\n    nuShow(\'title_obj_sfff_browse\', type.startsWith(\'browse\'));\n\n    nuSetFK();\n\n}\n\nvar tableExists = false;\n\nfunction nuSetFFTable() {\n\n    tableExists = nuFORM.getTables().indexOf(nuGetValue(\'fastform_table\')) !== -1;\n\n    $(\"[id$=\'ff_column_picker\']\")\n    .prop(\'disabled\', !tableExists)\n    .toggleClass(\'nuReadonly\', tableExists);\n\n    nuShow(\'fastform_prefix\', !tableExists);\n    nuShow(\'check_nulog\', !tableExists && nuGetValue(\'fastform_type\') !== \'launch\');\n\n    let c = $(\'#nuFFAvailableColumns\');\n\n    let l;\n    let rl;\n    let title = \'\';\n\n    if (tableExists) {\n        l = c.nuCSSNumber(\'left\') + c.nuCSSNumber(\'width\') + 30;\n        rl = \'1473px\';\n        title = $(\'#obj_sf000ff_field\').attr(\'title\');\n    } else {\n        l = c.nuCSSNumber(\'left\');\n    }\n\n    if (! useMobileView) {\n        $(\'#obj_sf\').css(\'left\', l);\n        $(\'#ffwrd\').css(\'left\', l);\n        $(\'#ff_resize\').css(\'left\', rl);\n    }\n    \n    $(\"[data-nu-field=\'ff_field\']\").attr(\'title\', title);\n\n    let bl = $(\"[id$=\'ff_browse\']\").length - 2;\n    $(\'#obj_sf\' + nuPad3(bl) + \'ff_browse\').hide();\n\n    nuEnableFFDataType();\n    nuSetFK();\n\n}\n\nfunction nuSetFK() {\n\n    nuHide(\'fastform_fk\');\n\n    let table = nuGetValue(\'fastform_table\');\n    if (table !== \'\' && nuFORM.getTables().indexOf(table) == -1 && nuGetValue(\'fastform_type\') == \'subform\') {\n        nuShow(\'fastform_fk\');\n    }\n\n}\n\nfunction nuShowFFO(e) {\n\n    let t = $(\'#\' + e.target.id).attr(\'data-nu-prefix\');\n    let i = nuGetValue(t + \'ff_id\');\n    let l = nuGetValue(t + \'ff_label\');\n    let f = nuGetValue(t + \'ff_field\');\n    let fff = \'fromfastform|\' + f + \'|\' + l;\n\n    nuPopup(\'nuobject\', i, fff);\n\n}\n\n\nfunction nuGetFFDataType(h) {\n\n    let t = \"VARCHAR(1000)\";\n\n    if (h == \'Checkbox\') t = \"VARCHAR(1)\";\n    if (h == \'Display\') t = \"VARCHAR(50)\";\n    if (h == \'Lookup\') t = \"VARCHAR(25)\";\n    if (h == \'Textarea\') t = \"TEXT\";\n    if (h == \'Calc\') t = \"DECIMAL\";\n    if (h == \'nuDate\') t = \"DATE\";\n    if (h == \'File\') t = \"LONGTEXT\";\n    if (h == \'nuAutoNumber\') t = \"VARCHAR(15)\";\n    if (h == \'Number\') t = \"INT\";\n    if (h == \'nuNumber\') t = \"DECIMAL(12,4)\";\n    if (h == \'Button\' || h == \'HTML\' || h == \'Image\' || h == \'Word\' || h == \'Subform\') t = null;\n\n    return t;\n\n}\n\nfunction nuEnableFFDataType() {\n\n    $(\"[data-nu-field=\'ff_datatype\']\").not(\".nuSubformTitleHolder\").each(function() {\n\n        var typeId = nuSubformRowObject(this.id, \'ff_type\').attr(\'id\');\n        var sel = $(\"#\" + typeId + \" option:selected\").text();\n        var noBrowse = nuNoBrowseObject(sel);\n\n        $(this).nuEnable(sel !== \'\' && !tableExists && !noBrowse && nuFFFormType() !== \'launch\');\n        if (nuFFFormType() == \'launch\') $(this).val(\'\');\n\n    });\n\n}\n\nfunction nuSetFFDataType(id, h) {\n\n    var dataType = nuGetFFDataType(h);\n    var noStoreObject = nuNoStoreObject(h);\n    var t;\n\n    if (tableExists && !noStoreObject) {\n        let index = nuSERVERRESPONSE.tableSchema[fastform_table.value].names.indexOf(\'cot_code\')\n        t = index !== -1 ? nuSERVERRESPONSE.tableSchema[fastform_table.value].types[index]: \'\';\n    } else\n        if (dataType !== null && !tableExists && !noStoreObject && nuFFFormType() !== \'launch\') {\n        t = dataType;\n    } else {\n        t = \'\';\n    }\n\n    nuEnableFFDataType();\n    $(id).val(t);\n\n}\n\nfunction nuFFFormType() {\n    return nuGetValue(\'fastform_type\');\n}\n\nfunction nuSelectFFObjects(e) {\n\n    if ($(\'#fastform_table\').val().trim() == \'\' && nuFFFormType() !== \'launch\') {\n        nuMessage(nuFFGetMessageTableEmpty());\n        $(\'#fastform_table\').trigger(\"focus\");\n        return;\n    }\n\n    const isObjectSelect = e.target.id === \'fastform_objects\' ;\n    \n    var id = isObjectSelect ? nuGetValue(\'fastform_objects\') : e.target.id;\n\n    var rowno = nuPad3($(\"[id^=\'obj_sf\'][id$=\'ff_label\']\", document).length - 1);\n    var rowsuf = nuPad2(rowno);\n    var sfrow = \'#obj_sf\' + rowno;\n\n    var h = isObjectSelect ? nuGetText(\'fastform_objects\') :  String(e.target.innerHTML).split(\':\');\n    var label = (isObjectSelect ? h : h[h.length - 1]) + rowsuf;\n\n    nuSetPlaceholder(sfrow.substring(1) + \'ff_label\', label);\n\n    $(sfrow + \'ff_label\').val(label).nuEnable().trigger(\'change\');\n    $(sfrow + \'ff_id\').val(id);\n    $(sfrow + \'ff_type\').val(id).nuEnable();\n    $(sfrow + \'ff_field\').nuEnable().attr(\'data-nu-picked\', true);\n    $(sfrow + \'nuDelete\').nuEnable();\n\n    var r = $(\'#\' + sfrow.substring(1) + \'ff_type\');\n    nuSetFFTypeColor(r[0]);\n\n    if (nuNoBrowseObject(e.target.innerHTML)) {\n        $(sfrow + \'ff_browse\').hide().attr(\'data-nu-no-browse\', \'\');\n    } else {\n        $(sfrow + \'ff_browse\').show().removeAttr(\'data-nu-no-browse\');\n    }\n\n    $(\'#fastform_type\').trigger(\'change\');\n\n    nuSetFFDataType(sfrow + \'ff_datatype\', h);\n\n    $(sfrow + \'ff_field\').trigger(\"focus\");\n\n}\n\nfunction nuOnChangeFFType(t, event) {\n\n    let target = event.target;\n    let i = target.id;\n\n    let id = nuSubformRowObject(i, \'ff_id\');\n    let browse = nuSubformRowObject(i, \'ff_browse\');\n    let label = nuSubformRowObject(i, \'ff_label\');\n    let field = nuSubformRowObject(i, \'ff_field\');\n    let dataType = nuSubformRowObject(i, \'ff_datatype\');\n    let objType = nuSubformRowObject(i, \'ff_type\');\n    let typeText = $(target).find(\"option:selected\").text();\n    let number = $(label).attr(\'placeholder\').nuJustNumbers();\n\n    nuSetPlaceholder(label.attr(\'id\'), typeText + number);\n\n    if (field.val() == \'\') {\n        label.val(typeText + number);\n    }\n\n    id.val(t.value);\n\n    let noStoreObj = nuNoStoreObject(typeText);\n    if (noStoreObj || nuFFFormType() === \'launch\') {\n        $(browse).hide().attr(\'data-nu-no-browse\', \'\').prop(\'checked\', 0);\n        nuSetValue(browse.id, true);\n    } else {\n        $(browse).show();\n    }\n\n    let objTypeText = nuGetValue($(objType).attr(\'id\'), \'text\');\n    nuSetFFDataType(\'#\' + $(dataType).attr(\'id\'), objTypeText);\n\n    nuEnableFFDataType();\n    nuSetFFTypeColor(t);\n\n}\n\nfunction nuOnChangeFFField(t, event) {\n\n    if (tableExists) {\n\n        let i = nuSERVERRESPONSE.tableSchema[fastform_table.value].names.indexOf(t.value);\n        let dataType = i === -1 ? \'\': nuSERVERRESPONSE.tableSchema[fastform_table.value].types[i].toUpperCase();\n        nuSubformRowObject(event.target.id, \'ff_datatype\').val(dataType);\n\n    }\n\n\n}\n\nvar selectedField = null;\n\nfunction onColumnPicker(event) {\n\n    let id = event.target.id;\n    if (id != \'\') {\n        selectedField = nuSubformRowObject(id, \'ff_field\');\n        if ($(selectedField).attr(\'data-nu-picked\')) {\n            $(\"[id$=\'ff_field\']\").removeClass(\'nuHighlight\');\n            $(selectedField).addClass(\'nuHighlight\');\n        }\n    }\n\n}\n\nfunction nuShowAvailableFields(v) {\n\n    let ac = [\'nuFFAvailableColumns\',\n        \'nuFFAvailableColumnsWord\'];\n    if (!tableExists) {\n        nuHide(ac);\n        return;\n    }\n\n    nuShow(ac);\n\n    if (v) {\n        let arr = nuSubformColumnArray(\'obj_sf\', \'ff_field\');\n        arr.push(\'\');\n        disableFromSelect(\'nuFFAvailableColumns\', arr);\n        $(\'#nuFFAvailableColumns\').prop(\'disabled\', false).removeClass(\'nuReadonly\');\n    } else {\n        if ($(\'#nuFFAvailableColumns option\').not(\"[value=\'\']\").length !== 0) {\n            $(\'#nuFFAvailableColumns\').prop(\'disabled\', true).addClass(\'nuReadonly\');\n        }\n    }\n}\n\nfunction disableFromSelect(id, arrOptionsVal) {\n\n    $(\"#nuFFAvailableColumns\").children(\'option\').attr(\"disabled\", false);\n    $(\'#\' + id).find(\'option\').filter(function() {\n        return arrOptionsVal.indexOf(this.value) != -1;\n    }).attr(\"disabled\", true);\n\n}\n\nfunction nuSelectObjectRefreshed(o, f, c) {\n    if (c == 0) nuShowAvailableFields(false);\n}\n\nfunction nuMoveFieldPrefixToSubform() {\n\n    let title = $(\'#title_obj_sfff_field\');\n    title.html(title.html() + \'<br>\');\n    let prefix = $(\'#fastform_prefix\');\n    title.append(prefix);\n    nuSetPlaceholder(\'fastform_prefix\', \'Prefix\', true);\n    prefix.css({\n        \'top\': \'1px\',\n        \'left\': \'0px\',\n        \'position\': \'relative\',\n        \'background-color\': \'#afe9ff\'\n    });\n\n}\n\nfunction nuSetLabel(field, label) {\n\n    let i = field.indexOf(\'_\');\n    if (i == 2 || i == 3) {\n        field = field.substring(i + 1);\n    }\n\n    label.val(field.replaceAll(\'_\', \' \').nuCapitalise().nuToTitleCase()).trigger(\'change\');\n\n}\n\nfunction nuAvailableFieldsOnClick(event, t) {\n\n    if (selectedField !== null) {\n\n        let v = t.value;\n        $(selectedField).val(v).trigger(\'change\');\n\n        let label = $(\'#\' + $(selectedField).attr(\'id\').replace(\'field\', \'label\'));\n        if (label.is(\'[data-user-modified]\')) {\n            let answer = window.confirm(nuTranslate(\'Overwrite the Label?\'));\n            if (!answer) return;\n        }\n\n        nuSetLabel(v, label);\n\n        nuSubformMoveFocus(selectedField, 1);\n\n    }\n\n    nuShowAvailableFields(true);\n}\n\nfunction nuGetStringAfterSubstring(parentString, substring) {\n    return parentString.substring(parentString.indexOf(substring) + substring.length)\n}\n\nfunction nuAvailableColumnsSetLoading() {\n    $(\'#nuFFAvailableColumns\').prepend(\'<option disabled=\"disabled\">\' + nuTranslate(\'Loading\') + \'...\' + \'</option>\');\n}\n\nfunction nuChangePrefix(prefix) {\n\n    prefix = prefix.trim() === \'\' ? \'\': prefix + \'_\';\n    let fieldArr = nuSubformColumnArray(\'obj_sf\', \'ff_field\');\n\n    for (var i = 0; i < fieldArr.length; i++) {\n        var n = fieldArr[i].indexOf(\"_\");\n        if (n == -1 || n == 2 || n == 3) {\n\n            var f = $(\'#obj_sf\' + nuPad3(i) + \'ff_field\');\n            if (f.val() !== \'\') {\n                f.val(prefix + nuGetStringAfterSubstring(f.val(), \'_\')).trigger(\'change\');\n            }\n\n        }\n    }\n\n}\n\nfunction nuDisableLastFFRow() {\n\n    let l = nuSubformObject(\'obj_sf\').rows.length;\n\n    let rowPrefix = \'#obj_sf\' + nuPad3(l == 1 ? 0: l - 1);\n    $(rowPrefix + \'ff_label\').nuDisable();\n    $(rowPrefix + \'ff_field\').nuDisable();\n    $(rowPrefix + \'ff_type\').nuDisable();\n    $(rowPrefix + \'ff_type\').nuDisable();\n    $(rowPrefix + \'ff_datatype\').nuDisable();\n\n}\n\nfunction nuButtonClass(id) {\n    return $(\'#\' + id).attr(\'class\').split(\' \')[1];\n}\n\nfunction nuSetFFTypeOptionsColor(id) {\n\n    $(\"#\" + id + \" > option\").each(function() {\n        if (this.value !== \'\') {\n            $(this).addClass($(\'#\' + this.value).attr(\'class\').split(\' \')[1]);\n        }\n    });\n\n}\n\nfunction nuSetFFTypeColor(t) {\n\n    let x = \'#\' + t.value;\n    if (t.value !== \'\') {\n        let id = $(x);\n        $(t).removeClass().addClass(id.attr(\'class\').split(\' \')[1]);\n    }\n\n}\n\nfunction nuSetDataUserModified(t, event) {\n\n    if ([37, 38, 39, 40, 9, 13].indexOf(event.keyCode) === -1) {\n        $(t).attr(\'data-user-modified\', \'\');\n    }\n\n}\n\nfunction nuOnBlurFFLabel(t, event) {\n\n    if (!tableExists) {\n\n        let ff_field = nuSubformRowObject(event.target.id, \'ff_field\');\n        if (!ff_field.is(\'[data-user-modified]\') && $(t).is(\'[data-user-modified]\')) {\n            let v = $(t).val();\n            if (v !== \'\') {\n                let prefix = $(\'#fastform_prefix\').val();\n                ff_field.val((prefix === \'\' ? \'\': prefix + \'_\') + v.toLowerCase().replaceAll(\' \', \'_\')).trigger(\'change\');\n            }\n        }\n    }\n\n}\n\nfunction nuOnBlurFFField(t, event) {\n\n    var v = $(t).val().trim();\n    if (v !== \'\') {\n\n        let prefix = $(\'#fastform_prefix\').val();\n        if (!v.startsWith(prefix)) {\n            v = prefix + \'_\' + v;\n            $(t).val(v);\n        }\n\n        let label = nuSubformRowObject(event.target.id, \'ff_label\');\n        if (!label.is(\'[data-user-modified]\')) {\n            nuSetLabel(v, label);\n        }\n    }\n\n}\n\nfunction nuClickDelete(event) {\n\n    let id = event.target.id;\n    let sf = $(\'#\' + id).attr(\'data-nu-checkbox\');\n    let row = id.substring(sf.length, sf.length + 3);\n    let checked = $(\'#\' + id).is(\":checked\");\n\n    $(\'[id^=\' + sf + nuPad3(row) + \']\')\n    .not(\':button, :checkbox\')\n    .toggleClass(\'nuSubformDeleteTicked\', checked)\n    .toggleClass(\'nuReadonly\', checked)\n    .nuEnable(!checked);\n\n}\n\nfunction nuFFInvalidColumns() {\n\n    let msg = \'\';\n    let table = nuGetValue(\'fastform_table\');\n\n    if (nuFORM.getTables().indexOf(table) == -1) return \'\';\n\n    let sf = nuSubformObject(\'obj_sf\');\n    for (let i = 0; i < sf.rows.length; i++) {\n\n        let field = sf.rows[i][2];\n        let type = nuGetValue(\'obj_sf\' + nuPad3(i) + \'ff_type\', \'text\');\n        let exists = nuFORM.tableSchema[table].names.indexOf(field);\n        if (sf.deleted[i] != 1 && exists == -1 && !nuNoStoreObject(type)) {\n            msg += nuTranslate(\'Invalid Field Name\') + \' <b>\' + field + \'</b><br>\'\n        }\n\n    }\n\n    return msg;\n\n}\n\nfunction nuBeforeSave() {\n\n    let table = nuGetValue(\'fastform_table\');\n    let type = nuGetValue(\'fastform_type\');\n    let pk = nuGetValue(\'fastform_primary_key\');\n    let fk = nuGetValue(\'fastform_fk\');\n\n    if (table === \'\' && type !== \'launch\') {\n        nuMessage(nuTranslate(\'Validation Error\'), [\'<b>\' + nuTranslate(\'Table Name\') + \'</b> \' + nuTranslate(\'cannot be left blank\')]);\n        return false;\n    }\n\n    if (type === \'\') {\n        nuMessage(nuTranslate(\'Validation Error\'), [\'<b>\' + nuTranslate(\'Form Type\') + \'</b> \' + nuTranslate(\'cannot be left blank\')]);\n        return false;\n    }\n\n    if (pk === \'\') {\n        nuMessage(nuTranslate(\'Validation Error\'), [\'<b>\' + nuTranslate(\'Primary Key\') + \'</b> \' + nuTranslate(\'cannot be left blank\')]);\n        return false;\n    }\n\n    if (type.startsWith(\'browse\') && $(\"[data-nu-field=\'ff_browse\']:checked\").length === 0) {\n\n        nuMessage(nuTranslate(\'Validation Error\'), [nuTranslate(\'At least 1 Browse needs to be checked\')]);\n        return false;\n\n    }\n\n    let fieldArr = nuSubformColumnArray(\'obj_sf\', \'ff_field\');\n    if (fieldArr.includes(\'\') || !nuArrayIsUnique(fieldArr)) {\n\n        nuMessage(nuTranslate(\'Validation Error\'), nuTranslate(\'The Field Names must be both unique and not blank\'));\n        return false;\n\n    }\n\n    //	let pk = table + \'_id\';\n    if (fieldArr.includes(pk)) {\n\n        nuMessage(nuTranslate(\'Validation Error\'),  nuTranslate(\'The Primary Key %s must not be entered.\').replace(\'%s\', \'<b>\' + pk + \'</b>\'));\n        return false;\n\n    }\n\n    if (type === \'subform\' && table !== \'\' && nuFORM.getTables().indexOf(table) === -1 && fk === \'\') {\n\n        nuMessage(nuTranslate(\'Validation Error\'), [\'<b>\' + nuTranslate(\'Foreign Key Field Name\') + \'</b> \' + nuTranslate(\'cannot be left blank\')]);\n        return false;\n\n    }\n\n    let a = [];\n    for (var i = 0; i < nuSubformObject(\'obj_sf\').rows.length; i++) {\n        a.push(nuSubformObject(\'obj_sf\').rows[i][2]);\n    }\n\n    if (fk !== \'\' && a.indexOf(fk) > -1 && type === \'subform\') {\n\n        nuMessage(nuTranslate(\'Validation Error\'), [\'<b>\' + nuTranslate(\'Foreign Key Field Name\') + \'</b> \' + nuTranslate(\'is already used\')]);\n        return false;\n\n    }\n\n    if (nuGetValue(\'obj_sf000ff_field\') == \'\') {\n\n        nuMessage(nuTranslate(\'Validation Error\'), nuTranslate(\' At least one Field must be specified\'));\n        return false;\n\n    }\n\n    let invalidColumns = nuFFInvalidColumns();\n    if (invalidColumns !== \'\') {\n\n        nuMessage(invalidColumns);\n        return false;\n\n    }\n\n    return true;\n\n}', NULL, NULL, NULL, '1', NULL),
('nufile', 'browseedit', 'nufile', 'Files', 'nubuilder', '1', '#sfi_code#|New', 'zzzzsys_file', 'zzzzsys_file_id', '', NULL, 150, 3, '0', NULL, 'SELECT * FROM #TABLE_ID# ', NULL, 'showBrowseImages();\nscaleImages();\n$(\'#nuBrowseTitle3\').css(\'text-align\', \'left\');\nnuSetNoSearchColumns([2, 3]);\n\nnuBrowseStyleBadge(4); // Group\n\n$(\'[data-nu-column=\"0\"]\').each(function(index) {\n    var code = \'#nucell_\' + index + \'_\';\n    window.nuImages[$(code + \'0\').text()] = $(code + \'2\').text();\n});\n\nfunction showBrowseImages() {\n\n    $(\'[data-nu-column=\"0\"]\').each(function(index) {\n\n        var p = $(this).attr(\'id\');\n        var r = String(p).split(\'_\')[1];\n        var i = \"nucell_\" + r + \"_2\";\n        var e = \"nucell_\" + r + \"_3\";\n        var h = $(\'#\' + i).html();\n\n        if (h !== \'\' && h !== undefined) {\n\n            nuEmbedObject(h, e, 140, 140);\n\n        }\n\n    });\n\n}\n\n\nfunction scaleImages() {\n\n    $(\"[data-nu-column=\'3\']\").each(function(index) {\n\n        var t = $(this);\n        if (t.html().trim() !== \'\') {\n\n            var embed = t.find(\'embed\');\n            if (t.length == 1) {\n\n                var p = new Image();\n                p.src = embed.attr(\'src\');\n\n                if (p.width < t.outerWidth() && p.height < t.outerHeight()) {\n                    embed.css({\n                        \'width\': p.width,\n                        \'height\': p.height\n                    });\n                    embed.css(\'height\', p.height);\n                }\n\n            }\n        }\n\n    });\n\n}', 'if (nuIsNewRecord()) {\n   // Hide Linked Objects Tab if new record \n   nuHideTabById(\'nu67f22d53d2c87ad\')\n}\n\nnuFilesDisplayFile($(\'#sfi_json\').val());\nnuSetToolTip(\'sfi_file_input\', nuTranslate(\'Max. 300Kb\'));\n\nfunction nuBeforeSave() {\n\n    const file = $(\'#sfi_file\').val();\n\n    if (file !== \'\') {\n\n        $(\'#sfi_json\')\n            .val(file)\n            .change();\n    }\n\n    return true;\n\n}\n\nfunction nuFilesDisplayFile(json) {\n    nuEmbedObject(json, \'view_image\', -1, -1);\n    nuShow(\'view_image\', json !== \'\');\n}\n\nfunction nuOnFileLoaded(e, id, json) {\n    nuFilesDisplayFile(json);\n}', NULL, '1', NULL);
INSERT INTO `zzzzsys_form` (`zzzzsys_form_id`, `sfo_type`, `sfo_code`, `sfo_description`, `sfo_group`, `sfo_status`, `sfo_breadcrumb_title`, `sfo_table`, `sfo_primary_key`, `sfo_browse_redirect_form_id`, `sfo_browse_target`, `sfo_browse_row_height`, `sfo_browse_rows_per_page`, `sfo_browse_title_multiline`, `sfo_browse_autoresize_columns`, `sfo_browse_sql`, `sfo_javascript`, `sfo_browse_javascript`, `sfo_edit_javascript`, `sfo_style`, `sfo_mobile_view`, `sfo_json`) VALUES
('nuform', 'browseedit', 'nuform', 'Forms', 'nubuilder', '1', '#sfo_code#|New', 'zzzzsys_form', 'zzzzsys_form_id', '', NULL, 0, 0, '1', NULL, 'SELECT\n  *\nFROM #TABLE_ID#\nWHERE\n  nu_filter_match (\'sfo_group\', \'nu648030319e8fa15\')\n  AND nu_filter_match (\'sfo_status\', \'nu682fe38322e7e70\')\n  AND nu_filter_match (\'sfo_type\', \'nu5bad6cb3764389f\')', NULL, '/*\n$(\"[data-nu-column=\'1\']\").each(function() {\n    $(this).addClass(\'nu_\' + this.textContent);\n});\n*/\n\n\nfunction nuFormBrowseStyleBadge(column) {\n\n    function createBadgeHtml(text, objClass) {\n        return `\n            <span class=\"text-badge ${objClass}\" style=\"\n                border: none;\n                border-color: transparent;\n                border-radius: 12px;\n                padding: 2px 10px;\n                box-shadow: none;\n                display: inline-block;\n                white-space: nowrap;\n                line-height: 1.2;\n                transition: all 0.2s ease;\n                margin-top: 1px;\n            \">${text}</span>\n        `;\n    }\n\n    nuBrowseLoop([column], function (cell) {\n        const $cell = $(cell);\n        const cellText = $cell.text().trim();\n	const objClass = \'nu_\' + cellText;\n        if (cellText && cellText.length > 0) {\n            $cell.html(createBadgeHtml(cellText, objClass));\n        }\n    });\n}\n\nnuFormBrowseStyleBadge(1);\nnuBrowseStyleStatusColumn(6);\nnuBrowseStyleBadge(5); // Group\n\n$(function() {\n    if (!nuMainForm()) {\n        // Hide Preview\n        nuSetBrowseColumnSize(0, 0);\n    } else {\n        addRowButtons(0);\n    }\n\n    $(\"[data-nu-column=\'1\']\").addClass(\'nuCellColored\');\n\n\n    nuAddBrowseFilter(\'nu648030319e8fa15\').nuSearchableMultiPopup({\n        items: nuFormFilterGetGroup()});\n\n    var dataStatus = [\n        [\"0\",\"Draft\"],\n        [\"1\",\"Active\"],\n        //    [\"2\",\"Disabled\"],\n        [\"3\",\"Archived\"]\n    ];\n\n    nuAddBrowseFilter(\'nu682fe38322e7e70\').nuSearchableMultiPopup({\n        items: dataStatus\n    });\n\n    var dataType = \n        [\'browseedit\',\'browse\',\'edit\',\'subform\'];\n\n    nuAddBrowseFilter(\'nu5bad6cb3764389f\').nuSearchableMultiPopup({\n        items: dataType\n    });\n    \n    nuPrintExcludeColumns([0]);\n\n\n});\n\n\nfunction createButton(target, pk, formType) {\n\n    let btn = $(\"<button id=\'nuPreviewButton\' type=\'button\' data-form-type=\'\" + formType + \"\' class=\'nuActionButton\'><i class=\'fa fa-search\'></i>&nbsp;</button>\");\n\n    $(target).html(btn).attr(\'title\',\n        nuTranslate(\'Preview Form\'));\n    btn.on(\'click\',\n        function(e) {\n            e.stopPropagation(); debugger;\n            const element = e.target.id === \'nuPreviewButton\' ? e.target : e.target.parentElement;\n            const ft = $(element).attr(\"data-form-type\");\n            const r = ft == \'launch\' || ft == \'edit\' || ft == \'subform\'  ? \'-1\': \'\';debugger;\n            nuForm(pk, r, \'\', \'\');\n        });\n}\n\nfunction addRowButtons(column) {\n\n    $(\"[data-nu-column=\'\" + column + \"\']\").each(function() {\n\n        var pk = $(this).attr(\'data-nu-primary-key\');\n        var r = $(this).attr(\'data-nu-row\');\n        var formType = $(\'#nucell_\' + r + \'_1\').text().trim();\n\n        if (typeof pk !== \"undefined\") {\n            createButton(this, pk, formType);\n        }\n    })\n\n}', 'if (!nuDevMode()) {\n  nuHideTabById(\'nu687b3c9ebc3e813\'); // Hide Custom Code 2\n}\n\n\nif ($(\'#zzzzsys_tab_sf000syt_access\').val() !== \'\') {\n    nuMessage(nuTranslate(\'Validation Error\'), nuTranslate(\'The first tab must not be set to hidden\'));\n}\n\nfunction nuDisplayObjectRefreshed(obj) {\n\n    let v = nuGetValue(obj);\n    if (v != \'\' && sfo_primary_key.value !== v) {\n        nuSetValue(\'sfo_primary_key\', v);\n    }\n}\n\nnuAccessFormSetButtonIcons();\n\nfunction nuFormColorObjectTypes() {\n\n    // Color Types\n    $(\'select[id$=sob_all_type]\').find(\'option\').each(function (index, element) {\n        $(element).addClass(\'nu_\' + element.value);\n    });\n\n    $(\'select[id$=sob_all_type]\').each(function (index, element) {\n\n        $(element).removeClass();\n        $(element).addClass(\'nu_\' + element.value);\n    });\n\n}\n\nfunction nuFormSetControlsVisibility() {\n\n    var pb = \'previewbrowse\';\n    var pe = \'previewedit\';\n    var js = \'sfo_javascript\';\n\n    var bb = \'bb_event\';\n    var be = \'be_event\';\n    var bs = \'bs_event\';\n    var as = \'as_event\';\n    var bd = \'bd_event\';\n    var ad = \'ad_event\';\n\n    nuEnable([pb, pe, bb, be, bs, as, bd, ad, js]);\n\n    var t = String($(\'#sfo_type\').val());\n\n    if (t == \'browseedit\') {\n        nuEnable([\'js_edit\', \'js_browse\', \'js_browse_edit\']);\n    } else\n        if (t == \'browse\') {\n            nuDisable([pe, be, bs, as, bd, ad, \'js_edit\']);\n            nuEnable([\'js_browse\', \'js_browse_edit\']);\n        } else\n            if (t == \'edit\') {\n                nuDisable([pb, pb, bb, \'js_browse\']);\n                nuEnable([\'js_edit\', \'js_browse_edit\']);\n            } else\n                if (t == \'launch\') {\n                    nuDisable([pb, bb, bs, as, bd, ad, \'js_browse\', \'js_edit\']);\n                    nuEnable(\'js_browse_edit\');\n                } else\n                    if (t == \'subform\') {\n                        nuDisable([pb, bb, be, bs, as, bd, ad, js, \'js_browse\', \'js_edit\', \'js_browse_edit\']);\n                        $(\'#js_browse_edit\').html(\'Launch\');\n                    }\n\n    for (let i = 1; i <= 3; i++) {\n        nuShow(\'nuTab\' + i, t !== \'subform\' || i == 1);\n    }\n\n}\n\nfunction nuFormAfterInsertRowObjects() {\n    nuFormColorObjectTypes();\n}\n\nfunction nuFormJSMod(i) {\n\n    var js = $(\'#\' + i);\n\n    if (js.val() !== \'\') {\n        $(\'#nuTab2\').css(\'font-weight\', \'bold\');\n    }\n\n    js.addClass(\'js\');\n\n}\n\nif (nuFormType() == \'edit\') {\n\n    $(\'#sfo_code_snippet_sql_lookupbutton\').on(\'click\', function () {\n        nuSetSnippetFormFilter(0, 0, 1, 0); // Custom Code\n    });\n\n    $(\'#sfo_code_snippet_lookupbutton\').on(\'click\', function () {\n        nuSetSnippetFormFilter(1, 0, 0, 0); // SQL\n    });\n\n    nuFormColorObjectTypes();\n\n    $(\'#title_objformbtnOpenDetails\').html(nuTranslate(\'Details\'));\n\n    nuHide(\'sfo_code_snippet_lookupcode\');\n    nuHide(\'sfo_code_snippet_sql_lookupcode\');\n    nuHide(\'label_sfo_browse_sql\');\n\n    nuSetPlaceholder(\'sfo_javascript\', \'JavaScript / Browse & Edit\');\n    nuSetPlaceholder(\'sfo_browse_javascript\', \'JavaScript / Browse\');\n    nuSetPlaceholder(\'sfo_edit_javascript\', \'JavaScript / Edit\');\n    nuSetPlaceholder(\'sfo_style\', \'CSS\');\n\n    $(\'#title_zzzzsys_tab_sfsyt_help\').attr(\'id\', \'help_title\');\n    $(\"[id$=\'syt_help\']\").addClass(\'js\');\n\n    nuAttachButtonImage(\'previewbrowse\', \'PB\', \'nuButtonImageSmall\');\n    nuAttachButtonImage(\'previewedit\', \'PE\', \'nuButtonImageSmall\');\n    nuAttachButtonImage(\'bb_event\', \'BB\', \'nuButtonImageSmall\');\n    nuAttachButtonImage(\'be_event\', \'BE\', \'nuButtonImageSmall\');\n    nuAttachButtonImage(\'bs_event\', \'BS\', \'nuButtonImageSmall\');\n    nuAttachButtonImage(\'as_event\', \'AS\', \'nuButtonImageSmall\');\n    nuAttachButtonImage(\'bd_event\', \'BD\', \'nuButtonImageSmall\');\n    nuAttachButtonImage(\'ad_event\', \'AD\', \'nuButtonImageSmall\');\n    nuAttachButtonImage(\'icon_js\', \'JS\');\n    nuAttachButtonImage(\'icon_sql\', \'SQL\');\n    nuAttachButtonImage(\'icon_php\', \'PHP\');\n    nuAttachButtonImage(\'icon_style\', \'CSS\');\n\n    nuFormJSMod(\'sfo_edit_javascript\');\n    nuFormJSMod(\'sfo_browse_javascript\');\n    nuFormJSMod(\'sfo_javascript\');\n\n    nuHide(\'sfo_edit_javascript\');\n    nuHide(\'sfo_browse_javascript\');\n    nuHide(\'sfo_style\');\n\n    $