('nufrlaunch', 'launch', 'nufrlaunch', 'Fast Report', 'nubuilder', '1', NULL, '', '', '', NULL, 0, 0, '0', NULL, '', '\n$(\'#wrdaddable\').css({\'font-size\' : \'14px\', \'font-weight\' : 700, \'padding\' : 5}).addClass(\'nuTabHolder\');\n$(\'#frwrd\').css({\'font-size\' : \'14px\', \'font-weight\' : 700, \'padding\' : 5}).addClass(\'nuTabHolder\');\n$(\'#nufr\').css({\'text-align\' : \'left\', \'height\' : 410, \'background-color\': \'#ebebeb\'});\n\n$(\'#list\').addClass(\'nuScroll\').removeClass(\'nuReadonly\');\n\n$(\'.nuActionButton\').hide();\nnuAddActionButton(\'BuildFastReport\');\n\n\nfunction nuAddReportField(t){\n\n    var f   = nuPad3($(\"[data-nu-label=\'Field Name\']\").length - 1);\n\n    $(\'#fast_report_sf\' + f + \'field\').val($(t).html()).change();\n    $(\'#fast_report_sf\' + f + \'width\').val(100).change();\n    $(\'#fast_report_sf\' + f + \'sum\').val(\'no\').change();\n    $(\'#fast_report_sf\' + f + \'title\').val($(t).html()).change().trigger( \"select\" );\n    \n}\n\n\nfunction nuBeforeSave(){\n    \n    if($(\'#table\').val() === \'\'){\n        \n        nuMessage(nuTranslate(\'Validation Error\'), [\'<b>Table Data</b>\', nuTranslate(\'Cannot be left blank...\')])\n        return false;\n        \n    }\n    \n    \n    if($(\'#orderby\').val() === \'\'){\n        \n        nuMessage(nuTranslate(\'Validation Error\'), [\'<b>Order By</b>\', nuTranslate(\'Cannot be left blank...\')])\n        return false;\n        \n    }\n    \n    nuBuildFastReport();\n    \n    return true;\n    \n}\n\n\nfunction nuFRSetData() {\n\n    if($(\'#fieldlist\').val() !== \'\'){\n       \n        var s   = String($(\'#fieldlist\').val());\n        var ds  = s.replaceAll(\'[\',\'\').replaceAll(\']\',\'\').replaceAll(\'\\\\\',\'\').replaceAll(\'\"\',\'\');\n        var fl  = ds.split(\',\');\n        var fu  = [];\n        \n        $(\'#orderby\').find(\'option\').remove();\n    \n        for(var i = 0 ; i < fl.length ; i++){\n            \n            if(fl[i] != \'KEEP EXACT HEIGHT\'){\n                \n                fu[i]   = \'<tr><td><div style=\"overflow:hidden;width:285px;text-align:left;padding:2px\" onclick=\"nuAddReportField(this);\" class=\"nuCalculatorButton nu_input\">\' + fl[i] + \'</div></td></tr>\';\n        \n                $(\'#orderby\').append(\'<option value=\"\' + fl[i] + \'\">\' + fl[i] + \'</option>\');\n            \n            }\n                \n        }\n    \n        $(\'#nufr\').html(\'<table>\' + fu.join(\'\') + \'</table>\');\n        $(\'#orderby\').val(fl[0]);\n    \n    }\n\n}', NULL, NULL, NULL, NULL, NULL),
('nuhome', 'launch', 'nuhome', 'Home', 'nubuilder', '1', NULL, '', '', '', NULL, 0, 0, '0', NULL, '', '//$(\'#user_home\').addClass(\'nuUserHomeButton\');\n$(\'.nuActionButton\').hide();\n\nnuGetStartingTab();\n\nfunction nuHomeOpenForm(formId, recordId, event) {\n    const target = event.ctrlKey ? \'2\' : \'0\';\n    nuForm(formId, recordId, \'\', \'\', target);\n}\n\n\nfunction nuHomeOpenCreateMenuConfig(menuType, event) {\n    const baseMenus = {\n        Procedure: [{\n                text: nuContextMenuItemText(\"Run\", \"fa-solid fa-play\"),\n                action: () => nuHomeOpenForm(\'nurunphp\', \'\', event)\n		},\n            {\n                text: nuContextMenuItemText(\"Add\", \"fa-solid fa-plus\"),\n                action: () => nuHomeOpenForm(\'nuprocedure\', \'-1\', event)\n		}\n		],\n        Notes: [{\n                text: nuContextMenuItemText(\"Add\", \"fa-solid fa-plus\"),\n                action: () => nuHomeOpenForm(\'nunotes\', \'-1\', event)\n		},\n            {\n                text: nuContextMenuItemText(\"Categories\", \"fa-solid fa-list\"),\n                action: () => nuHomeOpenForm(\'nunotescategroy\', \'\', event)\n		}\n		],\n        User: [{\n                text: nuContextMenuItemText(\"Add\", \"fa-solid fa-plus\"),\n                action: () => nuHomeOpenForm(\'nuuser\', \'-1\', event)\n		},\n            {\n                text: nuContextMenuItemText(\"Permission Items\", \"fa-solid fa-list\"),\n                action: () => nuHomeOpenForm(\'nupermissionitem\', \'\', event)\n		}\n		],\n        Email: [{\n                text: nuContextMenuItemText(\"Add Template\", \"fa-solid fa-plus\"),\n                action: () => nuHomeOpenForm(\'nuemailtemplate\', \'-1\', event)\n		},\n            {\n                text: nuContextMenuItemText(\"Email Templates\", \"fa-solid fa-list\"),\n                action: () => nuHomeOpenForm(\'nuemailtemplate\', \'\', event)\n		}\n		],\n        Report: [{\n                text: nuContextMenuItemText(\"Run\", \"fa-solid fa-play\"),\n                action: () => nuHomeOpenForm(\'nurunreport\', \'\', event)\n		},\n            {\n                text: nuContextMenuItemText(\"Add\", \"fa-solid fa-plus\"),\n                action: () => nuHomeOpenForm(\'nubuildreport\', \'-1\', event)\n		},\n            {\n                text: nuContextMenuItemText(\"Fast Report\", \"fa-solid fa-bolt\"),\n                action: () => nuHomeOpenForm(\'nufrlaunch\', \'\', event)\n		}\n		],\n        Form: [{\n                text: nuContextMenuItemText(\"Add\", \"fa-solid fa-plus\"),\n                action: () => nuHomeOpenForm(\'nuform\', \'-1\', event)\n		},\n            {\n                text: nuContextMenuItemText(\"Fast Form\", \"fa-solid fa-bolt\"),\n                action: () => nuHomeOpenForm(\'nufflaunch\', \'\', event)\n		}\n		],\n        Database: [{\n                text: nuContextMenuItemText(\"Sessions\", \"fa-solid fa-key\"),\n                action: () => nuHomeOpenForm(\'nusession\', \'\', event)\n		},\n            {\n                text: nuContextMenuItemText(\"Backup\", \"fa-regular fa-hard-drive\"),\n                action: () => nuRunBackup()\n		},\n            {\n                text: nuContextMenuItemText(nuTranslate(\"Cloner\") + \' (\' + nuTranslate(\"Forms\") + \')\', \"fa-regular fa-clone\"),\n                action: () => nuHomeOpenForm(\'nucloner\', \'\', event)\n		},\n            {\n                text: nuContextMenuItemText(nuTranslate(\"Cloner\") + \' (\' + nuTranslate(\"Application\") + \')\', \"fa-regular fa-clone\"),\n                action: () => nuHomeOpenForm(\'nuappcloner\', \'\', event)\n		},\n            {\n                text: nuContextMenuItemText(\"Update\", \"fa-solid fa-cloud-arrow-down\"),\n                action: () => nuHomeOpenForm(\'nuupdate\', \'\', event)\n		},\n            {\n                text: nuContextMenuItemText(\"CSV Transfer\", \"fa-solid fa-file-csv\"),\n                action: () => nuHomeOpenForm(\'nucsvtransfer\', \'-1\', event)\n		}\n		],\n        Setup: [{\n                text: nuContextMenuItemText(\"Format\", \"fa-solid fa-calendar\"),\n                action: () => nuHomeOpenForm(\'nuFormat\', \'\', event)\n		},\n            {\n                text: nuContextMenuItemText(\"Items\", \"fa-solid fa-list\"),\n                action: () => nuHomeOpenForm(\'nuitem\', \'\', event)\n		},\n            {\n                text: nuContextMenuItemText(\"Translation\", \"fa-solid fa-globe\"),\n                action: () => nuHomeOpenForm(\'nutranslate\', \'\', event)\n		}\n		]\n    };\n\n\n    if (menuType === \'Database\' && nuSERVERRESPONSE.is_demo) {\n        baseMenus.Database = baseMenus.Database.filter(item => item.text !== \"Sessions\");\n    }\n\n    if (menuType === \'Database\' && !nuDevMode()) {\n        baseMenus.Database = baseMenus.Database.filter(item =>\n            !item.text.includes(\"Application\")\n        );\n    }\n\n    const menu = [{\n        text: nuTranslate(menuType)\n	}, ...baseMenus[menuType]];\n    return menu;\n\n}\n\nfunction nuHomeMenuClick(element, event, menuType) {\n    const menu = nuHomeOpenCreateMenuConfig(menuType, event);\n    nuOpenContextMenu(event, menu, element);\n}', NULL, '', '', '1', NULL),
('nuitem', 'browseedit', 'nuitems', 'Items', 'nubuilder', '1', '#itm_value#|New', 'zzzzsys_item', 'zzzzsys_item_id', '', NULL, 0, 0, '1', NULL, 'SELECT\n  *\nFROM #TABLE_ID#\nWHERE\n  (\n    itm_active =\n    REPLACE\n      (\n        REPLACE\n          (\'#nu6836b7e927aed72_filter#\', \'âœ”\', \'1\'),\n          \'âœ–\',\n          \'0\'\n      )\n      OR left(\'#nu6836b7e927aed72_filter#\', 1) = \'\'\n      OR (\n        left(\'#nu6836b7e927aed72_filter#\', 1) = \'#\'\n        AND itm_active = \'1\'\n      )\n      AND nu_filter_match (\'itm_group\', \'nu683c1ed713aefaa\')\n  )', NULL, '$(function() {\n    nuAddBrowseFilter(\'nu6836b7e927aed72\').nuSearchablePopup({ items: [\"âœ”\",\"âœ–\"] });\n    nuAddBrowseFilter(\'nu683c1ed713aefaa\').nuSearchableMultiPopup({ items: nuItemsFilterGetGroup() });\n});\n\nnuBrowseStyleBadge(4); // Group', 'nuSetValue(\'itm_active\',true,null,false);\n\nif (Array.isArray(nuFORM.breadcrumbs) && nuFORM.breadcrumbs.length >= 2) {\n    var previousCrumb = nuFORM.breadcrumbs[nuFORM.breadcrumbs.length - 2];\n    var filter = previousCrumb?.filter;\n\n    if (nuIsNewRecord() && filter) {\n        nuGetLookupId(filter, \'itm_object_id\', false, false);\n    }\n}\n\n\n\n$(function() {\n\n    const ADDITIONAL_FIELDS = [\n      \'itm_css\',\n      \'itm_icon\',\n      \'itm_language\',\n      \'itm_access_level\'\n    ];\n\n    function nuTabsAdditionalSetMarker() {\n        const mark = ADDITIONAL_FIELDS.some(fieldId => {\n            const raw = nuGetValue(fieldId);\n            return typeof raw === \'string\' && raw.trim() !== \'\';\n        });\n\n        nuTabSetMarker(\'nu6836ba2403b7939\', mark);\n    }\n\n    function nuTabsAdditionalSetup() {\n        ADDITIONAL_FIELDS.forEach(fieldId => {\n            const el = document.getElementById(fieldId);\n            if (el) {\n                el.addEventListener(\'change\', nuTabsAdditionalSetMarker);\n            }\n        });\n\n        nuTabsAdditionalSetMarker();\n    }\n\n\n    nuTabsAdditionalSetup();\n\n});\n', NULL, NULL, NULL),
('nulaunchable', 'browse', 'nulaunchable', 'Launchable Forms', 'nubuilder', '1', NULL, 'zzzzsys_form', 'zzzzsys_form_id', '', NULL, 0, 16, '0', NULL, 'SELECT * FROM zzzzsys_form\nWHERE sfo_type IN (\'edit\', \'browseedit\', \'launch\')\nAND (\n    SUBSTRING(zzzzsys_form_id, 1, 2) != \'nu\'\n    OR zzzzsys_form_id = \'nublank\'\n    OR zzzzsys_form_id = \'nuuserhome\'\n    )\nORDER BY sfo_code\n', '$(\'#sfo_breadcrumb_title\').addClass(\'sql\');\n$(\'#sfo_browse_sql\').addClass(\'sql\');\n$(\'#sfo_javascript\').addClass(\'js\');\n\nnuSetTitle($(\'#sfo_table\').val());\n\nnuACEInitDblClickHandlers();\n\nif(window.filter == \'justjs\'){\n    \n    $(\'#nuDeleteButton\').remove();\n    $(\'#nuCloneButton\').remove();\n    $(\'#nuTab0\').remove();\n    $(\'#nuTab1\').remove();\n    $(\'#nuTab2\').trigger( \"click\" );\n    $(\'#nuTab2\').remove();\n    \n    nuSetTitle($(\'#sfo_description\').val());\n    \n}\n\nfunction nuFormColor(){\n\n    var t   = String($(\'#sfo_type\').val());\n\n    var pb  = \'previewbrowse\';\n    var pe  = \'previewedit\';\n\n    var bb  = \'bb_event\';\n    var be  = \'be_event\';\n    var bs  = \'bs_event\';\n    var as  = \'as_event\';\n    var bd  = \'bd_event\';\n    var ad  = \'ad_event\';\n    \n    if(t == \'browse\'){\n        nuDisable([pe, be, bs, as, bd, ad]);\n    }\n    \n    if(t == \'edit\'){\n        nuDisable([pb, bb]);\n    }\n\n    if(t == \'launch\'){\n        nuDisable([pb, bb, as, as, bd, ad]);\n    }\n    \n    if(t == \'subform\'){\n        nuDisable([pb, bb, be, bs, as, bd, ad, \'sfo_javascript\']);\n    }\n\n    var h           = $(\'#sfo_type\').addClass(\'nuEdited\');\n    \n    var o           = [];\n    o.browse		= [0,1,2];\n    o.edit 		    = [0,2];\n    o.browseedit    = [0,1,2];\n    o.launch 	    = [0,2];\n    o.subform       = [0,1];\n    \n    $(\'#sfo_type\').removeClass();\n    $(\'#sfo_type\').addClass(\'nu_\'+$(\'#sfo_type\').val());\n    \n    if(h){\n        $(\'#sfo_type\').addClass(\'nuEdited\');\n    }\n    \n    $(\"#sfo_type > option\").each(function() {\n        $(this).addClass(\'nu_\'+this.value);\n    });\n\n    for(let i = 0 ; i < 7 ; i++){\n        $(\'#nuTab\' + i).removeClass(\'nuRelatedTab\');\n    }\n    \n    const oType   = o[$(\'#sfo_type\').val()];\n\n    if(oType !== undefined){\n        \n    	for(let i = 0 ; i < t.length ; i++){\n    		$(\'#nuTab\' + oType[i]).addClass(\'nuRelatedTab\');		\n    	}\n    	\n    }\n    \n}\n\nnuFormColor();\n\n$(\"[data-nu-column=\'nucolumn000\']\").each(function() {\n    $(this).addClass(\'nu_\'+this.textContent);\n});\n\nfunction nuEventList(){\n	\n	if($(\'sob_all_type\').val() == \'subform\'){\n		return [\'onchange\',\'onadd\'];\n	}else{\n		return [\'onblur\',\'onchange\',\'onfocus\',\'onkeydown\'];\n	}\n	\n}\n\n\n', NULL, NULL, NULL, NULL, NULL),
