('nulaunchform', 'browse', 'nulaunchform', 'nuBuilder non-System Forms', 'nubuilder', '1', NULL, 'zzzzsys_form', 'zzzzsys_form_id', '', NULL, 0, 0, '0', NULL, 'SELECT * FROM zzzzsys_form\nWHERE sfo_type != \'subform\' AND zzzzsys_form_id != \'nuhome\'\nORDER BY sfo_code\n', '$(\"[data-nu-column=\'0\']\").each(function() {\n    $(this).addClass(\'nu_\'+this.textContent);\n});\n\n$(\'#nuAddButton\').remove();\n$(\'#nuPrintButton\').remove();\n\n', NULL, NULL, NULL, NULL, NULL),
('nunonsystemform', 'browse', 'nunonsystemform', 'nuBuilder non-System Forms', 'nubuilder', '1', NULL, 'zzzzsys_form', 'zzzzsys_form_id', '', NULL, 0, 0, '0', NULL, 'SELECT * FROM zzzzsys_form\nWHERE ((zzzzsys_form_id NOT LIKE \'nu%\' AND sfo_type != \'subform\')\nOR zzzzsys_form_id IN (\'nuaccess\', \'nuuser\', \'nulaunchdates\', \'nutranslate\', \'nupassword\', \'nufile\', \'nuuserhome\', \'nublank\', \'nurunreport\'))\nORDER BY sfo_code', '$(\"[data-nu-column=\'0\']\").each(function() {\n    $(this).addClass(\'nu_\'+this.textContent);\n});\n\n$(\'#nuAddButton\').remove();\n$(\'#nuPrintButton\').remove();\n\n', NULL, NULL, NULL, NULL, NULL),
('nunotes', 'browseedit', 'nunotes', 'Notes', 'nubuilder', '1', '#not_title#|New', 'zzzzsys_note', 'zzzzsys_note_id', '', NULL, 0, 0, '0', NULL, 'SELECT\r\n zzzzsys_note.*, noc_name\r\nFROM\r\n zzzzsys_note\r\nLEFT JOIN zzzzsys_note_category ON not_zzzzsys_note_category_id = zzzzsys_note_category.zzzzsys_note_category_id\r\nORDER BY\r\n not_title ASC', NULL, NULL, 'nuHide(\'label_not_title\');\r\nnuSetPlaceholder(\'not_title\', nuTranslate(\'Title\'));\r\n\r\nnuHide(\'label_not_zzzzsys_note_category_id\');\r\nnuSetPlaceholder(\'not_zzzzsys_note_category_idcode\', nuTranslate(\'Category\'));\r\n\r\nfunction nuNotesHandleEnterKey() {\r\n\r\n $(\'.ql-editor\').trigger(\"focus\");\r\n\r\n let tinyB = tinyMCE.get(\'not_content_container\').getBody();\r\n if (tinyB !== null) tinyB.focus();\r\n\r\n\r\n}\r\n\r\n$(\'#not_title\').nuOnEnterKey(nuNotesHandleEnterKey, true);\r\nnuTabAdditionalSetMarker();\r\n\r\n\r\nfunction nuTinyMCEOnInit(e, editor, id) {\r\n\r\n if (nuUseMobileView()) {\r\n $(function() {\r\n const maxWidth = $(\'#\' + id)?.attr(\'data-nu-mobile-max-width\')?.nuJustNumbers();\r\n const maxHeight = $(\'#\' + id)?.attr(\'data-nu-mobile-max-height\')?.nuJustNumbers();\r\n\r\n nuTinyMCESetBounds(\'not_content\', 5, 70, maxWidth, maxHeight);\r\n $(\'#not_updated_on\').css(\'top\', \'640px\');\r\n $(\'#label_not_updated_on\').css(\'top\', \'620px\');\r\n });\r\n }\r\n\r\n}\r\n\r\n\r\nfunction nuTabAdditionalSetMarker() {\r\n nuTabSetMarker(\'nu684e16abd1b5744\', \'not_text\');\r\n}\r\n\r\nfunction nuOnClone() {\r\n $(\'#not_updated_on\').removeClass(\'nuEdited\');\r\n}\r\n\r\n\r\n', '', '1', NULL),
('nunotescategroy', 'browseedit', 'nunotescategory', 'Categories', 'nubuilder', '1', '#noc_name#|New', 'zzzzsys_note_category', 'zzzzsys_note_category_id', '', NULL, 0, 15, '0', NULL, 'SELECT * FROM zzzzsys_note_category\nORDER BY noc_name', 'nuHide(\'nuPrintButton\');', 'if (nuIsIframe()) {\n    var btn = nuAddActionButton(\'runCategories\', \'\', \'nuForm(\"\' + nuFormId() + \'\", \"\", \"\", \"\", 2);\');\n    btn.attr(\'title\', nuTranslate(\'Edit Categories\'));\n    nuAttachFontAwesome(btn.attr(\'id\'), \'fa-solid fa-list\');\n}', NULL, NULL, '1', NULL),
('nunuobjectevent', 'browseedit', 'nuobjectevent', 'Object Events', 'nubuilder', '1', '', 'zzzzsys_event', 'zzzzsys_event_id', '', NULL, 65, 5, '0', NULL, 'SELECT\n    *\nFROM\n    zzzzsys_event\nLEFT JOIN zzzzsys_object ON zzzzsys_object_id = sev_zzzzsys_object_id\nLEFT JOIN zzzzsys_tab ON zzzzsys_tab_id = sob_all_zzzzsys_tab_id\nWHERE\n    sob_all_zzzzsys_form_id = \'#PARENT_FORM_ID#\'\nORDER BY\n    syt_title,\n    sob_all_id', '$(\'#nuAddButton\').remove();\n$(\'#nuBreadcrumb1\').remove();\n\nfunction nuOnAddAction() {\n    return false;\n}\n\n\n// JavaScript column: Replace \\n with html br\n$(\"[data-nu-column=3]\").each(function() {\n    $(this).html($(this).html().replaceAll(\' \', \'&nbsp\').replace(/\\n/g, \"<br />\"));\n});', 'var parentTabEvents = parent.document.getElementById(\'nuTab1\');\nif (parentTabEvents) {\n  parent.refreshIframeEvents(parentTabEvents);\n}', '$(\"#sev_javascript\").addClass(\'js\');\n\n\n$(\'.js\').on(\'dblclick\', function() {\n    nuOpenAce(\'JS\', this.id);\n});\n', NULL, NULL, NULL);
INSERT INTO `zzzzsys_form` (`zzzzsys_form_id`, `sfo_type`, `sfo_code`, `sfo_description`, `sfo_group`, `sfo_status`, `sfo_breadcrumb_title`, `sfo_table`, `sfo_primary_key`, `sfo_browse_redirect_form_id`, `sfo_browse_target`, `sfo_browse_row_height`, `sfo_browse_rows_per_page`, `sfo_browse_title_multiline`, `sfo_browse_autoresize_columns`, `sfo_browse_sql`, `sfo_javascript`, `sfo_browse_javascript`, `sfo_edit_javascript`, `sfo_style`, `sfo_mobile_view`, `sfo_json`) VALUES
('nuobject', 'browseedit', 'nuobject', 'Objects', 'nubuilder', '1', '#sob_all_id#|New', 'zzzzsys_object', 'zzzzsys_object_id', '', '', 0, 0, '1', '0', 'SELECT\n  *\nFROM\n  zzzzsys_object\n  JOIN #TABLE_ID# ON zzzzsys_object_id = theid JOIN zzzzsys_tab ON zzzzsys_tab_id = sob_all_zzzzsys_tab_id\n  JOIN zzzzsys_form ON zzzzsys_form_id = syt_zzzzsys_form_id\nWHERE\n  (\n    (\n      sob_all_type = \'#nu5bad6cb375afa75_filter#\'\n      OR left(\'#nu5bad6cb375afa75_filter#\', 1) IN (\'#\', \'\')\n    )\n    AND (\n      sob_input_type = \'#nu5bad6cb377a01b0_filter#\'\n      OR left(\'#nu5bad6cb377a01b0_filter#\', 1) IN (\'#\', \'\')\n    )\n    \n    AND (\n      sob_all_label = \'#nu5bad6cb375bd72e_filter#\'\n      OR left(\'#nu5bad6cb375bd72e_filter#\', 1) IN (\'#\', \'\')\n      OR LOCATE(sob_all_label, \'#nu5bad6cb375bd72e_filter#\') > 0\n    )\n\n  )\nORDER BY\n  sfo_description,\n  sob_input_type,\n  sob_all_id\n  \n  ', NULL, 'function nuObjectBrowseStyleBadge(column) {\n\n    function createBadgeHtml(text, objClass) {\n        return `\n            <span class=\"text-badge ${objClass}\" style=\"\n                border: none;\n                border-color: transparent;\n                border-radius: 12px;\n                padding: 2px 10px;\n                box-shadow: none;\n                display: inline-block;\n                white-space: nowrap;\n                line-height: 1.2;\n                transition: all 0.2s ease;\n                margin-top: 1px;\n            \">${text}</span>\n        `;\n    }\n\n    nuBrowseLoop([column], function (cell) {\n        const $cell = $(cell);\n        const cellText = $cell.text().trim();\n		const objClass = \'nu_\' + cellText;\n        if (cellText && cellText.length > 0) {\n            $cell.html(createBadgeHtml(cellText, objClass));\n        }\n    });\n}\n\nnuObjectBrowseStyleBadge(0);\n\n\n\n$(\"[data-nu-column=\'4\']\").each(function() {\n  $(this).html(stripHTMLTags($(this).html()).replace(/&nbsp;/g, \' \').trim());\n});\n\nfunction stripHTMLTags(s) {\n  return s == \'\' ? \'\' : s.replace(/<\\/?[^>]+(>|$)/g, \"\");\n}\n$(function() {\n  const types = [\n    [\"calc\", \"Calc\"],\n    [\"display\", \"Display\"],\n    [\"contentbox\", \"ContentBox\"],\n    [\"editor\", \"WYSIWYG Editor\"],\n    [\"chart\", \"Chart\"],\n    [\"html\", \"HTML\"],\n    [\"image\", \"Image\"],\n    [\"input\", \"Input\"],\n    [\"lookup\", \"Lookup\"],\n    [\"run\", \"Run\"],\n    [\"select\", \"Select\"],\n    [\"subform\", \"Subform\"],\n    [\"textarea\", \"Textarea\"],\n    [\"word\", \"Word\"]\n  ];\n  nuAddBrowseFilter(\'nu5bad6cb375afa75\').nuSearchablePopup({\n    items: types\n  });\n  const inputTypes = [\n    [\"nuDate\", \"nuDate\"],\n    [\"nuNumber\", \"nuNumber\"],\n    [\"nuScroll\", \"nuScroll\"],\n    [\"nuAutoNumber\", \"nuAutoNumber\"],\n    [\"button\", \"Button\"],\n    [\"checkbox\", \"Checkbox\"],\n    [\"color\", \"Color\"],\n    [\"datetime-local\", \"Datetime-Local\"],\n    [\"email\", \"Email\"],\n    [\"file\", \"File\"],\n    [\"image\", \"Image\"],\n    [\"month\", \"Month\"],\n    [\"number\", \"Number\"],\n    [\"password\", \"Password\"],\n    [\"radio\", \"Radio\"],\n    [\"range\", \"Range\"],\n    [\"reset\", \"Reset\"],\n    [\"search\", \"Search\"],\n    [\"tel\", \"Telephone\"],\n    [\"text\", \"Text\"],\n    [\"time\", \"Time\"],\n    [\"url\", \"URL\"],\n    [\"week\", \"Week\"]\n  ];\n  nuAddBrowseFilter(\'nu5bad6cb377a01b0\').nuSearchablePopup({\n    items: inputTypes\n  });\n});', 'if (! nuDevMode()) {\n    nuHideTabById(\'nu61e9964c9bf5e13\'); // JSON\n}\n\nnuShow(\'se_items_run\', !nuIsNewRecord());\nnuShow(\'sob_items_run\', !nuIsNewRecord());\n\n// Code Snippets form\nnuSetSnippetFormFilter(0, 0, 1, 0); // SQL\n\nnuHide(\'sob_code_snippet_display_lookupcode\');\nnuHide(\'sob_code_snippet_select_lookupcode\');\nnuHide(\'label_zzzzsys_event_sf\');\nnuHide(\'label_sob_html_code\');\nnuShow(\'sob_run_zzzzsys_form_open_button\', sob_run_zzzzsys