' type=\'button\' data-form-type=\'\"+ formType +\"\' class=\'nuActionButton\'><i class=\'fa fa-search\'></i>&nbsp;</button>\");\n\n	$(target).html(btn).attr(\'title\',nuTranslate(\'Preview Form\'));\n	btn.on(\'click\',function(){\n	    var formType = $(this).attr(\"data-form-type\");\n	    var r = formType == \'launch\' || formType == \'edit\' || formType == \'subform\'  ? \'-1\' : \'\';\n	    nuForm(pk,r,\'\',\'\');\n	});\n}\n\nfunction addRowButtons(column) {\n  \n  $(\"[data-nu-column=\'\" + column + \"\']\").each(function(index) {\n      \n      var pk = $(this).attr(\'data-nu-primary-key\');\n      var r = $(this).attr(\'data-nu-row\');\n      var formType = $(\'#nucell_\'+ r + \'_1\').html();\n      \n      if (typeof pk !== \"undefined\") {\n          createButton(this, pk, formType);\n      }\n  })\n\n}\n\n', NULL, 'function nuOnSelectTab(tab) {\n    if (tab.id == \'nuTab1\') {\n     //   refreshIframe(tab);\n    }\n}\n\nfunction refreshIframeEvents(tab) {\n\n    const attrLoaded = \'nu-iframe-events-loaded\';\n    $tab = $(\'#\' + tab.id);\n    if (! $tab.attr(attrLoaded)) {\n        $tab.attr(attrLoaded, \'1\');\n        let fx = $(\"#iframe_objectevent\")[0].contentWindow;\n        fx.nuSetProperty(\'PARENT_FORM_ID\', nuRecordId());\n        fx.nuGetBreadcrumb();\n    }\n    \n}\n\nfunction refreshIframeItems(tab) {\n\n    const attrLoaded = \'nu-iframe-events-loaded\';\n    $tab = $(\'#\' + tab.id);\n    if (! $tab.attr(attrLoaded)) {\n        $tab.attr(attrLoaded, \'1\');\n        let fx = $(\"#iframe_items\")[0].contentWindow;\n        fx.nuSetProperty(\'PARENT_FORM_ID\', nuRecordId());\n        fx.nuGetBreadcrumb();\n    }\n    \n}', NULL, NULL, NULL),
('nupassword', 'launch', 'nupassword', 'Change Password', 'nubuilder', '1', NULL, '', '', '', NULL, 0, 0, '0', NULL, '', '$(\'#nuTab0\').hide();\n\n\nnuAddActionButton(\'nuRunPHPHidden\', nuTranslate(\'Save\'), \'nuRunPHPHidden(\"nu_change_password\")\');\n\n\nvar changePW = nuGetValue(\'display_change_required\');\n\nif (changePW) {\n    nuSetValue(\'display_change_required\', nuTranslate(changePW));\n} else {\n    nuHide(\'display_change_required\');\n}', NULL, NULL, NULL, '1', NULL),
('nupasswordgenerator', 'launch', 'nupasswordgenerator', 'Password Generator', 'nubuilder', '1', NULL, '', '', '', NULL, 0, 0, '0', NULL, '', 'nuHideHolders(2);\n\nnuAddActionButton(\'use_password\', nuTranslate(\'Use Password\'), \'nuPWGenUsePassword();\');\n\nfunction nuPWGenUsePassword() {\n   nuHasNotBeenEdited();\n   parent.nuSetValue(\'new_password\', pwg_input.value);\n   parent.nuSetValue(\'check_password\', pwg_input.value);\n   parent.nuClosePopup();\n}\n\n// Function to refresh the generated password\nfunction nuPWGenRefreshPassword() {\n\n    const length = parseInt(nuGetValue(\'pwg_length\')) || 15;\n    const upperBox = document.getElementById(\"pwg_uppercase\").checked;\n    const lowerBox = document.getElementById(\"pwg_lowercase\").checked;\n    const numberBox = document.getElementById(\"pwg_numbers\").checked;\n    const symbolBox = document.getElementById(\"pwg_symbols\").checked;\n\n    const arr = nuCharacterArray(symbolBox, numberBox, lowerBox, upperBox);\n    if (arr.length === 0) {\n        nuSetValue(\"pwg_input\", \"\");\n        return;\n    }\n\n    const password = nuRandomPassword(arr, length);\n    nuSetValue(\"pwg_input\", password);\n\n}\n\n// Initial password generation\n$(document).ready(function() {\n    $(\"#pwg_range\").attr(\"max\", \"50\");\n    nuSetValue(\'pwg_range\', 15);\n    nuPWGenRefreshPassword();\n});\n\n\n// generate new password on slider change\ndocument.querySelector(\"#pwg_range\").oninput = () => {\n    document.querySelector(\"#pwg_length\").textContent = document.querySelector(\n        \"#pwg_length\"\n    ).value = document.querySelector(\"#pwg_range\").value;\n    nuPWGenRefreshPassword();\n};\n\n', NULL, NULL, 'input[type=range]::-webkit-slider-runnable-track {\n  width: 100%;\n  height: 10.4px;\n  cursor: pointer;\n  box-shadow: 1px 1px 1px #000000, 0px 0px 1px #0d0d0d;\n  background: #3071a9;\n  border-radius: 1.3px;\n  border: 0.2px solid #010101;\n}\n\ninput[type=range]:focus::-webkit-slider-runnable-track {\n  background: #367ebd;\n}\n\ninput[type=\"range\"]::-webkit-slider-thumb {\n  -webkit-appearance: none;\n  appearance: none;\n  width: 25px;\n  height: 25px;\n  border-radius: 50%;\n  background: #009fda;\n  cursor: pointer;\n  margin: -2px; /* alignment fix for Chrome */\n}', '1', NULL),
('nupermissionitem', 'browseedit', 'nupermissionitem', 'Permission Items', 'nubuilder', '1', '#pme_ident#|New', 'zzzzsys_permission_item', 'zzzzsys_permission_item_id', '', NULL, 0, 0, '0', NULL, 'SELECT * FROM zzzzsys_permission_item', NULL, NULL, NULL, NULL, '1', NULL),
('nuphp', 'browseedit', 'nuphp', 'PHP', 'nubuilder', '1', '#sph_code#|New', 'zzzzsys_php', 'zzzzsys_php_id', '', NULL, 0, 0, '0', NULL, 'SELECT * FROM zzzzsys_php\nLEFT JOIN zzzzsys_form ON zzzzsys_form_id = sph_zzzzsys_form_id\nWHERE sph_description = \'SYSTEM PHP\' AND (LEFT(sph_code, 2) <> \'nu\' OR \'#DEV_MODE#\' = \'1\')\nORDER BY sph_code', NULL, 'if (parent.nuCurrentProperties().form_id == \'nuaccess\') {\n    $(\'#nuBreadcrumb0\').html(nuTranslate(\'Procedures\'));\n}\n\n\nnuDevMode();', 'nuHide(\'sph_code_snippet_select_lookupcode\');\n\n// Code Snippets form\nnuSetSnippetFormFilter(0, 0, 0, 1); // PHP Code\n\nvar recordId = nuRecordId();\nvar recordIdSuffix = recordId.slice(-2);\n\nwindow.nuImages = parent.nuImages;\nwindow.nuHelp = \'Functions\';\n\n$(\'#nuCloneButton\').remove();\n\nvar title = nuEventName() + \' - \' + recordId;\nif (nuIsIframe()) {\n    $(\'#nuBreadcrumb0\').html(title);\n} else {\n   nuSetTitle(title);\n}\n\nnuAttachButtonImage(\'icon\', recordIdSuffix);\nnuSetValue(\'sph_code\', recordId);\nnuHide(\'sph_code\');\nsetStyles();\n\n$(\'.nuSaveButtonEdited\').removeClass(\'nuSaveButtonEdited\');\n\n$(\'#sph_php\')\n.addClass(\'php\')\n.on(\'dblclick\', function() {\n    nuOpenAce(\'PHP\', this.id);\n});\n\n$(function() {\n    $(\'#sph_php\').scrollTop(window.scrollTop);\n});\n\nnuHasNotBeenEdited();\n\nfunction setStyles() {\n\n    $(\'#sph_php\')\n    .css(\'padding\', \'3px 3px 3px 3px\')\n    .trigger(\"focus\");\n\n}\n\nfunction nuPHPStartsWithPHPTag(str) {\n    return str.toLowerCase().startsWith(\"<?php\");\n}\n\nfunction nuBeforeSave() {\n\n    $php = $(\'#sph_php\');\n\n    if (nuPHPStartsWithPHPTag($php.val())) {\n       nuMessage(nuTranslate(\'The script must not start with a PHP tag\'));\n       return false;\n    }\n\n    if (nuFormType() == \'edit\') {\n        window.scrollTop = $php.scrollTop();\n    }\n\n    return true;\n\n}', NULL, '1', NULL),
('nuprocedure', 'browseedit', 'nuprocedure', 'Procedures', 'nubuilder', '1', '#sph_code#|New', 'zzzzsys_php', 'zzzzsys_php_id', '', NULL, 0, 19, '1', NULL, 'SELECT\n  *\nFROM\n  zzzzsys_php\n  LEFT JOIN zzzzsys_form ON zzzzsys_form_id = sph_zzzzsys_form_id\nWHERE\n  (\n    (\n      sph_system != \'1\'\n      OR sph_system IS NULL\n    )\n    OR (\n      \'#DEV_MODE#\' = \'1\'\n      AND LEFT(RIGHT(sph_code, 3), 1) <> \'_\'\n    )\n  )\n  AND nu_filter_match(\'sph_group\',\'nu5bad6cb376bd159\')\n  AND nu_filter_match(\'sph_category\',\'nu6878434013629b5\')\n  AND (\n    IFNULL(sph_status, \'1\') = \'#nu6862f0becfb7938_filter#\'\n    OR (\n      LEFT(\'#nu6862f0becfb7938_filter#\', 1) IN (\'#\', \'\') AND IFNULL(sph_status, \'\') <> \'3\'\n    )\n  )\nORDER BY\n  sph_code;\n', NULL, 'if (parent.nuCurrentProperties().form_id == \'nuaccess\') {\n    $(\'#nuBreadcrumb0\').html(nuTranslate(\'Procedures\'));\n}\n\nnuAddBrowseFilter(\'nu5bad6cb376bd159\').nuSearchableMultiPopup({ items: nuProcedureFilterGetGroup() });\n\nnuAddBrowseFilter(\'nu6878434013629b5\').nuSearchableMultiPopup({ items: nuProcedureFilterGetCategory() });\n\n\nvar dataStatus = [\n        [\"0\", \"Draft\"],\n        [\"1\", \"Active\"],\n        //    [\"2\",\"Disabled\"],\n        [\"3\", \"Archived\"]\n    ];\n\nnuAddBrowseFilter(\'nu6862f0becfb7938\').nuSearchablePopup({ // Status\n    items: dataStatus\n});\n\n\nnuBrowseStyleStatusColumn(4);\nnuBrowseStyleBadge(2); // Group', 'nuHide(\'sph_code_snippet_select_lookupcode\');\n\n// Code Snippets form\nnuSetSnippetFormFilter(0, 0, 0, 1); // PHP Code\n\nnuSetToolTip(\'title_accphpslp_zzzzsys_access_id\', \'Access levels that can use this procedure\');\nnuAttachButtonImage(\'icon_include_js\', \'JS\');\n\nvar recordId = nuRecordId();\nvar recordIdSuffix = recordId.slice(-2);\n\nwindow.nuImages = parent.nuImages;\n\nif (nuProcIsTemplate() && !nuDevMode()) {\n    nuDisableAllObjects();\n    nuMessage(\"Unable to save templates. Please clone them to create a new copy and save the cloned version instead.\", 2500);\n}\n\nwindow.nuHelp = \'Procedures\';\n\nif (!recordId.startsWith(\'nu\')) {\n    nuSetValue(\'sph_system\', \'0\');\n    nuSetValue(\'sph_hide\', \'\');\n}\n\nif (!nuIsNewRecord()) {\n    nuProcUpdateAclCount();\n    nuAddActionButton(\'RunHidden\');\n} else {\n    nuSetValue(\'sph_demo\', true);\n}\n\n\nif (nuGetValue(\'sph_javascript\') === \'\') {\n\nnuSetPlaceholder(\'sph_javascript\', \'// Enter * to use the example.\\n\\n\' + `function nuOnProcedureRun() {\n    // JavaScript code placed here will execute only if the procedure is run from this location.\n    \n    // Set Hash Cookie to pass to the PHP procedure\n    // nuSetProperty(\'myproperty\', \'myvalue\');\n    \n    // Override the default execution behavior (e.g., when running code asynchronously):\n    // nuRunThisProcedure();\n    // return false;\n}`);\n\n}\n\n\n$(\'#sph_php\')\n    .addClass(\'php\')\n    .on(\'dblclick\', function() {\n        nuOpenAce(\'PHP\', this.id);\n    });\n\n$(\'#sph_javascript\')\n    .addClass(\'js\')\n    .on(\'dblclick\', function() {\n        nuOpenAce(\'JS\', this.id);\n    });\n\n$(function() {\n    $(\'#sph_php\').scrollTop(window.scrollTop);\n});\n\nif (nuGetValue(\'sph_status\') === \'\') {\n    nuSetValue(\'sph_status\', \'1\', \'value\', false);\n}\n\nnuHasNotBeenEdited();\n\nfunction nuProcSetStyles() {\n    $(\'#sph_php\')\n        .css(\'padding\', \'3px 3px 3px 3px\')\n        .trigger(\"focus\");\n\n}\n\nfunction nuRunHiddenAction() {\n\n    let result = true;\n    if (nuGetValue(\'sph_javascript_active\') === true) {\n        eval(nuGetValue(\'sph_javascript\') + \' result = nuOnProcedureRun();\');\n    }\n\n    if (result !== false) {\n        nuRunThisProcedure();\n    }\n\n}\n\nfunction nuRunThisProcedure() {\n    if (sph_run.value == \'window\') {\n        nuRunPHP(sph_code.value, \'\', 0);\n    } else {\n        nuRunPHPHidden(sph_code.value);\n    }\n}\n\nfunction nuProcUpdateAclCount() {\n\n    const l = $(\"[data-nu-field=\'slp_zzzzsys_access_id\']\").length - 2;\n    const t = l <= 0 ? \'\' : \' (\' + l + \')\';\n    $(\'div[data-nu-tab-id=\' + \'nu5fdf7df2d873dd1\' + \']\').html(nuTranslate(\'Access Levels\') + t);\n\n}\n\nfunction nuProcIsTemplate() {\n    return nuGetValue(\'sph_template\');\n}\n\n\nfunction nuOnClone() {\n\n    let code = sph_code.value;\n\n    if (nuProcIsTemplate()) {\n        code = code == \'nu_send_welcome_email_template\' ? \'nu_send_welcome_email\' : code.substring(0, code.length - 9);\n        nuSetValue(\'sph_code\', code);\n        nuSetValue(\'sph_group\', \'\');\n        nuSetValue(\'sph_template\', false);\n        nuEnableAllObjects();\n    }\n\n    nuHide(\'nuRunHiddenButton\');\n\n}\n\nfunction nuOnSetSaved(v) {\n    nuEnable(\'nuRunHiddenButton\', v);\n}\n\nfunction nuBeforeSave() {\n\n    window.scrollTop = $(\'#sph_php\').scrollTop();\n    return true;\n\n}\n\nfunction nuProcedureSetMarker() {\n    const markerACL = nuGetValue(\'accphp000slp_zzzzsys_access_id\') !== \'\' || nuGetValue(\'sph_global\') === true;\n    nuTabSetMarker(\'nu5fdf7df2d873dd1\', markerACL);\n\n    const markerCode = nuGetValue(\'sph_javascript\').includes(\'nuOnProcedureRun\');\n    if (markerCode) {\n        const isActive = nuGetValue(\'sph_javascript_active\');\n        const markerClass = \'nuTabMarker\' + (isActive ? \'\' : \' nuTabGrey\');\n        nuTabSetMarker(\'nu68874e7a14a63ee\', true, markerClass);\n    } else {\n        nuTabSetMarker(\'nu68874e7a14a63ee\', false, \'nuTabMarker nuTabGrey\');\n    }\n\n}    \n\nnuProcedureSetMarker();\n\n\nfunction nuOnTabSelected(tab) {\n    nuProcedureSetMarker();\n}', '.nuTabMarker.nuTabGrey:after {\n    color: #8e8e8e !important;\n}', '1', NULL);
INSERT INTO `zzzzsys_form` (`zzzzsys_form_id`, `sfo_type`, `sfo_code`, `sfo_description`, `sfo_group`, `sfo_status`, `sfo_breadcrumb_title`, `sfo_table`, `sfo_primary_key`, `sfo_browse_redirect_form_id`, `sfo_browse_target`, `sfo_browse_row_height`, `sfo_browse_rows_per_page`, `sfo_browse_title_multiline`, `sfo_browse_autoresize_columns`, `sfo_browse_sql`, `sfo_javascript`, `sfo_browse_javascript`, `sfo_edit_javascript`, `sfo_style`, `sfo_mobile_view`, `sfo_json`) VALUES
('nupromptgenerator', 'browseedit', 'nupromptgenerator', 'Prompt Generator', 'nubuilder', '1', '#pge_code#|New', 'zzzzsys_prompt_generator', 'zzzzsys_prompt_generator_id', '', NULL, 0, 0, '0', NULL, 'SELECT * FROM zzzzsys_prompt_generator \nORDER BY IFNULL(pge_template,\'\') DESC, pge_code', NULL, 'function nuSelectBrowse(event, element) {\n    const primaryKey = $(element).attr(\'data-nu-primary-key\');\n    nuForm(nuFormId(), primaryKey, \'\', \'\',  nuIsPopup() ? \'1\': \'0\');\n}', 'if (nuIsNewRecord()) {\n    \n    if (nuIsPopup()) {\n      nuGeneratorGetParentInfo();\n    }\n\n    nuSetValue(\'pge_instruction\', \n      `Generate code snippets and explanations following nuBuilder conventions. ` +\n      `Use the information below when relevant to the prompt. ` +\n      `This context is provided to help understand requirements for generating code snippets and answering questions.\\n`\n    );\n    \n    nuHasNotBeenEdited();\n} else {\n   nuGeneratorRun(false);\n}\n\nnuGeneratorOnLoad();\n\nfunction nuGeneratorOnLoad() {\n  \n    if (Array.isArray(nuFORM.breadcrumbs) && nuFORM.breadcrumbs.length === 1) {\n        nuAddActionButton(\"PromptGeneratorBrowse\", \"<i class=\'fa-fw fa-regular fa-rectangle-list\'></i>\", \'nuGeneratorOpenBrowse()\', nuTranslate(\'Open Browse Form\'));\n    }\n    \n    nuAddActionButton(\'RunAIPromptGenerator\', nuTranslate(\'Copy\'), \'nuGeneratorRun()\', nuTranslate(\'Copy to Clipboard\'),\'fa fa-copy\');\n    nuAddActionButton(\'RunAIPromptGeneratorResponse\', nuTranslate(\'Ask AI\')+ \'&thinsp;&thinsp;&thinsp;\', \'nuAIPromptGetResponse(this)\', nuTranslate(\'Send prompt to AI and output response\'),\'fa  fa-wand-magic-sparkles\');\n    \n    nuSelectRemoveEmpty(\'pge_language\');\n    nuSelectRemoveEmpty(\'pge_scope\');\n    nuSelectRemoveEmpty(\'pge_tag\');\n    nuSelectRemoveEmpty(\'pge_table\');\n\n    $(\'#pge_prompt\').css(\'z-index\', 100);\n\n}\n\nfunction nuGeneratorCheckMandatory() {\n\n    const prompt = nuGetValue(\'pge_prompt\').trim();\n\n    if (prompt.length < 10) {\n        nuMessage(nuTranslate(\'The prompt must be at least 10 characters long. Please enter a more detailed prompt to continue.\'));\n        return false;\n    }\n\n    return true;\n\n}\n\n\nfunction nuGeneratorExec(button, procedureName, paramName, params, requireMandatory = true) {\n    \n    if (requireMandatory && !nuGeneratorCheckMandatory()) {\n        return;\n    }\n    \n    if (button) {\n        nuButtonLoading(button.id, true, 15);\n        params.buttonId = button.id; \n    }\n\n    nuRunPHPHiddenWithParams(procedureName, paramName, params);\n\n}\n\nfunction nuGeneratorRunGetTags(button) {\n\n    if (!nuGeneratorCheckMandatory()) return;\n\n    nuGeneratorExec(button,\n        \'nu_ai_prompt_generator_call_api\',\n        \'nuaipromptgenerator_params\', {\n            prompt: nuGetValue(\'pge_prompt\'),\n            tags: JSON.stringify(nuSelectToArray(\'pge_tag\',\'text\', false)),\n            procedure_type: \'tag\'\n        }, true\n    );\n}\n\nfunction nuGeneratorRun(copy = true) {\n \n    if (copy && !nuGeneratorCheckMandatory()) return;\n    \n    nuGeneratorExec(null,\n        \'nu_ai_prompt_generator_prompt\',\n        \'nuaipromptgenerator_prompt_params\', {\n            tables: JSON.stringify(nuSelectToArray(\'pge_table\')),\n            languages: JSON.stringify(nuSelectToArray(\'pge_language\')),\n            scopes: JSON.stringify(nuSelectToArray(\'pge_scope\')),\n            tags: JSON.stringify(nuSelectToArray(\'pge_tag\')),\n            copy: copy\n        }, false\n    );\n}\n\nfunction nuAIGeneratorGetFullPrompt() {\n	return nuGetValue(\'pge_instruction\') + \"\\n\\n\" + \"## User Input/Question:\\n\\n\"+ nuGetValue(\'pge_prompt\') + \"\\n\\n\" + nuGetValue(\'pge_prompt_extra\')\n}\n\nfunction nuAIPromptGetResponse(button) {\n\n    if (!nuGeneratorCheckMandatory()) return;\n\n    nuGeneratorExec(button,\n        \'nu_ai_prompt_generator_call_api\',\n        \'nuaipromptgenerator_params\', {\n            prompt: nuAIGeneratorGetFullPrompt(),\n            procedure_type: \'response\'\n        }\n    );\n}\n\nfunction nuGeneratorOpenBrowse() {\n\n    if (nuFormsUnsaved() !== 0) {\n        if (!confirm(nuTranslate(\'Leave this form without saving?\'))) {\n            return;\n        }\n\n    }\n\n    nuForm(nuFormId(), \'\', \'\', \'\', \'1\');\n\n}\n\nfunction nuGeneratorNormaliseNewlines(str) {\n    return str.replace(/\\\\r?\\\\n/g, String.fromCharCode(10));\n}\n\nfunction nuGeneratorExecuted(text, copy) {\n\n    const normalized = nuGeneratorNormaliseNewlines(text);\n    nuSetValue(\'pge_prompt_extra\', normalized);\n\n    if (copy) {\n        nuCopyToClipboard(nuAIGeneratorGetFullPrompt());\n    }\n\n}\n\nfunction nuGeneratorExecutedTags(id, arr, result) {\n\n    nuButtonLoading(id, false);\n        \n    if (!result) {\n        nuMessage(arr);\n        return;\n    }    \n        \n    function hasCommonElement(a, b) {\n      return a.some(item => b.includes(item));\n    }\n\n    function getOptionValuesByText(selectId, textsToMatch) {\n        const selectElement = document.getElementById(selectId);\n        if (!selectElement || !selectElement.options || !Array.isArray(textsToMatch)) {\n            return [];\n        }\n    \n        const normalizedTexts = textsToMatch.map(t => t.trim().toLowerCase());\n        const matchingValues = [];\n    \n        for (let option of selectElement.options) {\n            const optionText = option.text.trim().toLowerCase();\n            if (normalizedTexts.includes(optionText)) {\n                matchingValues.push(option.value);\n            }\n        }\n    \n        return matchingValues;\n    }\n\n    \n    const allTags = nuSelectToArray(\'pge_tag\',\'text\', false);\n    const selectedTags = nuSelectToArray(\'pge_tag\',\'text\', true);\n\n    if (!hasCommonElement(arr, allTags)) {\n        nuMessage(arr);       \n        return;\n    }\n\n    const textsToMatch = selectedTags.concat(arr);\n    nuSetValue(\'pge_tag\', getOptionValuesByText(\'pge_tag\', textsToMatch));\n\n}\n\nfunction nuGeneratorResponseExecuted(id, text, result) {\n\n    nuButtonLoading(id, false);\n        \n    if (!result) {\n        nuMessage(text);\n        return;\n    }    \n\n    nuSetValue(\'pge_output\', text);\n    nuSelectTabById(\'nu6835cb1661ba10b\'); // Select \"API Response\" Tab\n}\n\nfunction nuGeneratorGetParentInfo() {\n\n    const formId = parent.nuFormId();\n    if (!nuSERVERRESPONSE) return;\n\n    nuSetFocus(pge_prompt);\n\n    // 1) Table\n    const table = parent.nuSERVERRESPONSE.table;\n    if (table && table !== \'\' && table !== \'zzzzsys_php\' && table !== \'nupromptgenerator\') {\n        nuSetValue(\'pge_table\', table);\n    }\n\n    // 2) Suffix-based PHP scopes\n    const recordId = parent.nuRecordId();\n    const suffix = recordId.slice(-2).toLowerCase();\n    const phpSuffixes = [\'bb\', \'be\', \'as\', \'bs\', \'bd\'];\n    if (phpSuffixes.includes(suffix)) {\n        nuSetValue(\'pge_language\', \'nuphp\');\n        nuSetValue(\'pge_scope\', `nuphp_${suffix}`);\n        return; // done\n    }\n\n    // 3) Perâ€form (and perâ€tab) config\n    const config = {\n\n        nupromptgenerator:  {\n            tag: \"nuaiprompt_generator\"\n        },\n        \n        nuitem: {\n            tag: \"nuitems\"\n        },      \n        \n        nuuser: {\n            tag: \"nuusers\"\n        },\n        \n        nuaccess: {\n            tag: \"nuuser_access\"\n        },\n        \n        nufflaunch: {\n            language: \'numysql\',\n            scope: \'nufast_form_builder\'\n        },\n        \n        nuprocedure: {\n            language: \'nuphp\',\n            scope: \'nuphp_procedure\'\n        },\n        \n        nufile: {\n            tag: \"nufiles\"\n        },        \n\n        nutranslate: {\n            tag: \"nutranslations\"\n        },        \n\n        nucloner: {\n            tag: \"nucloner\"\n        },    \n        \n        nucsvtransfer: {\n            tag: \"nucsv_transfer\"\n        },    \n        \n        nuFormat: {\n            tag: \"nuformat_builder\"\n        },    \n        \n        nuobject: {\n            tabMap: {\n                \'nu5bad6cb36974818\': { // Display\n                    language: \'numysql\'\n                }, \n                \'nu5bad6cb369a6ee3\': {  // Select\n                    language: \'numysql\'\n                }\n            },\n            tag: \'nuobjects\'\n        },\n\n        nuform: {\n            tabMap: {\n                \'nu5bad6cb37026348\': {\n                    language: [\'javascript\', \'jquery\'],\n                    scope: \'nuform_custom_code\'\n                },\n                \'nu5bad6cb36757b92\': {\n                    language: \'numysql\'\n                }\n            },\n            tag: \'nuforms\'\n        },\n\n        nusetup: {\n            tabMap: {\n                \'nu61ce913f08336db\': {\n                    language: \'nucss\'\n                },\n                \'nu5bad6cb36e9143a\': {\n                    language: [\'nujavascript\', \'nujquery\'],\n                    scope: \'nusetup_header\'\n                }\n            },\n            tag: \'nusetup\'\n        }\n    };\n\n    const formCfg = config[formId];\n    if (!formCfg) return;\n\n    // If it\'s a simple formâ€level setting...\n    if (formCfg.language) {\n        nuSetValue(\'pge_language\', formCfg.language);\n    }\n    if (formCfg.scope) {\n        nuSetValue(\'pge_scope\', formCfg.scope);\n    }\n    if (formCfg.tag) {\n        nuSetValue(\'pge_tag\', formCfg.tag);\n    }\n\n    // If itâ€™s a tab-based setting, look up the tab\n    if (formCfg.tabMap) {\n        const tabId = parent.nuSelectedTabId();\n        const tabCfg = formCfg.tabMap[tabId];\n        if (tabCfg) {\n            nuSetValue(\'pge_language\', tabCfg.language);\n            if (tabCfg.scope) {\n                nuSetValue(\'pge_scope\', tabCfg.scope);\n            }\n        }\n    }\n\n}\n\n\nfunction nuGeneratorPasteCodeFromTextArea(insert = true) {\n\n  let parentTextAreaId = parent.nuGetProperty(\'js\');\n\n  if (parentTextAreaId) {\n\n    let text = parent.nuGetSelectedText(parentTextAreaId);\n\n    if (text === \'\') {\n      text = parent.nuGetValue(parentTextAreaId);\n    }\n\n    if (text !== \'\') { \n      if (insert) nuInsertTextAtCaret(\'pge_prompt\', text);\n      return true;\n    }\n  }\n\n return false;\n\n}\n\nnuShow(\'btn_insert_parent_code\', nuGeneratorPasteCodeFromTextArea(false));', NULL, NULL, NULL),
('nurunjavascript', 'launch', 'nurunjavascript', 'Run JavaScript', 'nubuilder', '1', NULL, '', '', '', NULL, 0, 0, '0', NULL, '', 'nuAddActionButton(\'runOutputEval\', \'Run\', \'nuOutputEval()\');\n\nfunction scrollToBottom(id) {\n    let textarea = document.getElementById(id);\n    textarea.scrollTop = textarea.scrollHeight;\n}\n\nfunction nuOutputEval() {\n\n    try {\n        jsc_output.value += eval(jsc_Input.value) + \"\\n\";\n        scrollToBottom(\'jsc_output\');\n    } catch (e) {\n\n        jsc_output.value += e.message;\n    }\n\n}', NULL, NULL, NULL, NULL, NULL),
