('nurunphp', 'browse', 'nurunphp', 'Run Procedure', 'nubuilder', '1', NULL, 'zzzzsys_php', 'zzzzsys_php_id', '', NULL, 0, 0, '0', NULL, 'SELECT * FROM zzzzsys_php\nJOIN zzzzsys_form ON zzzzsys_form_id = sph_zzzzsys_form_id\nWHERE (sph_system != \'1\' OR sph_system IS NULL)\nORDER BY sph_code', '$(\'#nuAddButton\').remove();\n$(\'#nuPrintButton\').remove();\n\nfunction nuSelectBrowse(event) {\n\n    const $element = $(\'#\' + event.target.id);\n    const primaryKey = $element.attr(\'data-nu-primary-key\');\n\n    const row = $element.attr(\'data-nu-row\');\n    const phpFunction = $(\'#nucell_\' + row + \'_3\').html();\n\n    nuGetPHP(phpFunction, primaryKey);\n\n}\n', NULL, NULL, NULL, NULL, NULL),
