('6931f28d68fcc07', '68c452e608cbadc', 'cases', 'select', 'templateselector', 'Select A Template', '691567b2500f4c3', 3790, 3, 332, 150, 22, '1', 'left', '0', '0', NULL, '0', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '0', '0', 'SELECT\n    n.zzzzsys_note_id,\n    n.not_title\nFROM zzzzsys_note n\nJOIN zzzzsys_note_category c\n  ON c.zzzzsys_note_category_id = n.not_zzzzsys_note_category_id\nWHERE c.noc_name = \'Reports\'\nORDER BY n.not_title;\n\n\n\n/*\nSELECT zzzzsys_note_id, not_title \nFROM zzzzsys_note\nORDER BY not_title\n*/', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'nu-tooltip-position=\"bottom\", nu-tooltip-icon=\"Select a template for your Report. Then click the \'Copy HTML Template\' button.\"', '0', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
