('693474537242d8c', '692cb3cea1cf548', 'email_composer', 'select', 'email_recipient_select', 'Select Recipients', '692cb3cea236464', 40, 24, 308, 400, 73, '1', 'left', '0', '0', NULL, '1', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '0', '0', 'SELECT\n    sus_email AS value,\n    CONCAT(\n        sus_name,\n        \' : \',\n        IFNULL(sus_position, \'\'),\n        CASE WHEN IFNULL(sus_position,\'\') <> \'\' THEN \', \' ELSE \'\' END,\n        sus_email\n    ) AS display\nFROM zzzzsys_user\nWHERE sus_email IS NOT NULL\n  AND TRIM(sus_email) <> \'\'\n  AND LOWER(TRIM(sus_email)) <> \'null\'\nORDER BY sus_name;\n\n\n/*\nSELECT sus_email AS value, \nCONCAT( \nsus_name,\n \' : \',\n sus_position,\n \', \',\n sus_email\n ) AS display\nFROM zzzzsys_user\nWHERE sus_email <> \'\'\nORDER BY sus_name;\n*/\n\n\n/*\nSELECT\n    sus_email AS value,\n    CONCAT(\n        sus_name,\n        \' : \',\n        sus_email,\n        \', \',\n        sus_position\n    ) AS display\nFROM zzzzsys_user\nWHERE sus_email <> \'\'\nORDER BY sus_name\n*/\n\n\n\n\n\n\n', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'multiple, size=\"8\"', '0', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
