('693c41ad57d9c84', '693c3ecfe33a1a0', 'email_delete_form', 'select', 'email_ids_to_delete', 'Sent Date/Time   |   Subject   |   Recipient Email Address', '693c3ecfe3a5e80', 20, 139, 55, 760, 380, '1', 'left', '0', '0', NULL, '0', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '1', '0', 'SELECT\n    email_composer_id AS value,\n    CONCAT(\n        CASE\n            WHEN email_sent_datetime IS NULL\n                THEN \'draft\'\n            ELSE CONCAT(\n                \'Sent | \',\n                DATE_FORMAT(email_sent_datetime, \'%Y-%m-%d %H:%i\')\n            )\n        END,\n        \' | \',\n        COALESCE(email_subject, \'(no subject)\'),\n        \' | \',\n        COALESCE(email_recipients, \'(no recipients)\')\n    ) AS display\nFROM email_composer\nORDER BY email_sent_datetime DESC\n\n\n\n/*\nSELECT\n    email_composer_id AS value,\n    CONCAT(\n        COALESCE(\n            DATE_FORMAT(email_sent_datetime, \'%Y-%m-%d %H:%i\'),\n            \'draft\'\n        ),\n        \' | \',\n        COALESCE(email_subject, \'(no subject)\'),\n        \' | \',\n        COALESCE(email_recipients, \'(no recipients)\')\n    ) AS display\nFROM email_composer\nORDER BY email_sent_datetime DESC\n*/\n', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', '0', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
