('694ee514a3be967', '68c452e608cbadc', 'cases', 'select', 'existing_case_group_id', 'Select An Existing Case:', '68c452e6098ca3d', 70, 9, 151, 200, 22, '1', 'left', '0', '0', NULL, '1', 'CSS', 'background-color: #8c8682;', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '0', '0', 'SELECT\n    case_group_id AS value,\n    pk_inv_case_name AS display\nFROM cases\nWHERE pk_inv_case_name IS NOT NULL\nGROUP BY case_group_id, pk_inv_case_name\nORDER BY pk_inv_case_name\n', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'nu-tooltip-position=\"bottom\", nu-tooltip-icon=\"A \'Case\' may have many investigations. Think of Cases as locations or story names like \'The Enfield Poltergiest\'. When creating a new investigation record, you must either select an existing Case Name or enter a new one. If the Case Name does not already exist in the dropdown, type it into the Case Name field.\"', '0', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
