('695aa6479fb058a', '68c452e608cbadc', 'cases', 'input', 'emaillist2', 'My Email List', '68c452e6098ca3d', 130, 233, 468, 92, 22, '1', 'left', '0', '0', '', '1', 'CSS', 'background: none; border: none; padding: 0; margin: 0;  color: #0077cc; font-size: 14px; font-weight: bold; text-decoration: none;  cursor: pointer; :hover {     text-decoration: underline; }', '', '', '', '', '', '', '', '', '', '', '0', '0', '', '', '', '', '', NULL, '', '', NULL, '', '', '', '', '', '', '', '', '', 'button', '', '', '', 'nu-tooltip-icon=\"Opens a list of emails created by you. Draft emails are on top, then sorted by newest sent emails.\"', '0', '<style>\n.tooltip-wrap {\n    position: relative;\n    display: inline-block;\n}\n\n.tooltip-wrap .tooltip-text {\n    visibility: hidden;\n    opacity: 0;\n    transition: opacity 0.2s ease;\n\n    position: absolute;\n    bottom: -160%;\n    left: 286%;\n    transform: translateX(-50%);\n\n    background-color: white;\n    color: black;\n    padding: 6px 10px;\n    border-radius: 4px;\n    white-space: nowrap;\n\n    font-size: 14px;\n    z-index: 9999;\n}\n\n.tooltip-wrap:hover .tooltip-text {\n    visibility: visible;\n    opacity: 1;\n}\n</style>\n\n<div class=\"tooltip-wrap\">\n    <a href=\"#\" id=\"openEmailList\"\n       style=\"font-size:14px; color:#0077cc; text-decoration:none; font-weight:bold;\">\n        My Email Listâ†—\n    </a>\n    <span class=\"tooltip-text\">\n        Opens a list of emails created by you. Draft emails are on top, then sorted by newest sent emails.\n    </span>\n</div>\n\n<script>\ndocument.getElementById(\'openEmailList\').addEventListener(\'click\', function (e) {\n    e.preventDefault();\n\n    let nuBase = window.location.origin +\n                 window.location.pathname.split(\'/index.php\')[0] +\n                 \'/\';\n\n   // --------------------------------------------------\n    // Popup window settings\n    // --------------------------------------------------\n    let width  = 1060;\n    let height = 800;\n   let left = 20;                       // left margin\nlet top  = screen.height - height - 165; // bottom margin\n\nwindow.open(\n    nuBase + \'index.php?f=692cb3cea1cf548&r=\',\n    \'EmailBrowsePopup\',\n    `width=${width},\n     height=${height},\n     left=${left},\n     top=${top},\n     resizable=yes,\n     scrollbars=yes`\n);\n});\n\n\n\n</script>\n\n\n\n', '', '', '', '', '', '', '', NULL),
('696e6f73155272e', '68c452e608cbadc', 'cases', 'input', 'case_investigation_no', 'Case Investigation #', '68c452e6098ca3d', 30, 69, 150, 43, 22, '1', 'left', '0', '1', NULL, '0', 'CSS', 'background-color: #8c8682;', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '0', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'number', NULL, NULL, NULL, 'nu-tooltip-icon=\"This is the investigation number in the series of investigations for this case.\"', '0', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('696e7bce9e31d0e', '68c452e608cbadc', 'cases', 'select', 'jump_case_no', 'Compare', '68c452e6098ca3d', 20, 69, 299, 100, 22, '1', 'left', '0', '0', NULL, '1', 'CSS', 'background-color: #8c8682;', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '0', '0', 'SELECT \n    pk_inv_case_no AS value,\n    CONCAT(\n        IFNULL(DATE_FORMAT(pk_inv_contact_date, \'%Y-%m-%d\'), \'No contact date\'),\n        \' â€” \',\n        case_investigation_no,\n        \' â€” \',\n        pk_inv_case_name\n    ) AS display\nFROM cases\nWHERE case_group_id = (\n    SELECT case_group_id\n    FROM cases\n    WHERE pk_inv_case_no = \'#RECORD_ID#\'\n)\nAND pk_inv_case_no <> \'#RECORD_ID#\'\nORDER BY pk_inv_contact_date DESC, case_investigation_no DESC\n\n\n\n/*\nSELECT \n    pk_inv_case_no AS value,\n    CONCAT(pk_inv_case_no, \' â€” \', pk_inv_case_name) AS display\nFROM cases\nWHERE case_group_id = (\n    SELECT case_group_id\n    FROM cases\n    WHERE pk_inv_case_no = \'#RECORD_ID#\'\n)\nAND pk_inv_case_no <> \'#RECORD_ID#\'\nORDER BY pk_inv_case_no DESC\n*/', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'nu-tooltip-icon=\"Compare details of this investigation with another investigation from this case.\"', '0', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
