('nu5bad6cb35772a8c', 'nufile', 'zzzzsys_file', 'input', 'sfi_file', 'Upload File', 'nu5bad6cb3719774c', 30, 46, 153, 322, 50, '1', 'left', '0', '0', NULL, '0', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '0', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'file', NULL, NULL, NULL, NULL, '0', '\n        <div id=\"#uppy_div#\"></div>\n\n        <script>\n\n        nuInitUppy();\n\n        function nuInitUppy() {\n\n        const $objId= $(\'#\' + \'#this_object_id#\');\n        const target = \'#\' + \'#uppy_div#\';\n\n        let uppy = nuUppyCreate();\n\n        uppy.use(Uppy.Dashboard, {\n        inline: true\n        , bundle: true\n        , height: $objId.nuCSSNumber(\'height\')\n        , width: $objId.nuCSSNumber(\'width\')\n        , target: target\n        , showProgressDetails: true\n        , replaceTargetContent: true\n        , method: \'post\'\n        })\n        .use(Uppy.XHRUpload, {\n        endpoint: \'core/nuapi.php\'\n        })\n\n        uppy.on(\'upload\', (file) => {\n        uppy.setMeta({\n        procedure: \'NUUPLOADFILE_TEMPLATE\',\n        session_id: window.nuSESSION\n        })\n        });\n\n        uppy.on(\'complete\', (result) => {\n\n        if (window.nuOnFileUploadComplete) {\n        nuOnFileUploadComplete(\'FS\', $objId.attr(\'id\'), result);\n        }\n\n        })\n\n        }\n\n        </script>\n        ', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
