('nu6878429d04f44ed', 'nuprocedure', 'zzzzsys_php', 'input', 'sph_category', 'Category', 'nu5bad6cb36b27343', 50, 121, 142, 283, 22, '1', 'left', '0', '0', NULL, '0', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '0', '0', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'text', NULL, NULL, 'SELECT DISTINCT\n    `sph_group`\nFROM\n    `zzzzsys_php`\nWHERE\n    TRIM(IFNULL(`sph_group`, \'\')) <> \'\'\n    AND `sph_group` <> \'nubuilder\'\nORDER BY\n    `sph_group`', NULL, '0', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('nu687b3cd707cfbfd', 'nuform', 'zzzzsys_form', 'html', 'custom_code_2', 'Â°', 'nu687b3c9ebc3e813', 540, 3, 10, 1194, 488, '1', 'left', '0', '0', NULL, '0', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '0', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '0', '<style>\n        .nu-code-container {\n            display: flex;\n            height: 520px;\n        }\n        \n        .nu-sidebar {\n            width: 250px;\n            background: #f8f9fa;\n            color: #495057;\n            overflow-y: auto;\n            box-sizing: border-box;\n            border-right: 1px solid #dee2e6;\n        }\n\n        .nu-sidebar h3 {\n            padding: 0px 20px 3px;\n            font-size: 14px;\n            color: #6c757d;\n            text-transform: uppercase;\n            letter-spacing: 0.5px;\n            border-bottom: 1px solid #dee2e6;\n            margin-bottom: 15px;\n        }\n\n        .nu-nav-section {\n            margin-bottom: 2px;\n        }\n\n        .nu-nav-button {\n            display: block;\n            width: 100%;\n            padding: 8px 20px;\n            background: none;\n            border: none;\n            color: #495057;\n            text-align: left;\n            cursor: pointer;\n            transition: background-color 0.2s ease, padding-left 0.2s ease;\n            font-size: 14px;\n            position: relative;\n            box-sizing: border-box;\n        }\n\n        .nu-nav-button:nth-child(even) {\n            background: #f1f3f4;\n        }\n\n        .nu-nav-button:hover {\n            background: #e9ecef;\n            padding-left: 25px;\n        }\n\n        .nu-nav-button.active {\n            background: #2d84d1;\n            color: white;\n            border-left: 4px solid #1352a4;\n        }\n\n        .nu-nav-button.active:hover {\n            background: #1352a4;\n            color: white;\n        }\n\n        .nu-nav-button .badge {\n            background: #dc3545;\n            color: white;\n            padding: 2px 6px;\n            border-radius: 10px;\n            font-size: 10px;\n            float: right;\n            margin-top: 2px;\n        }\n\n        .nu-nav-button.active .badge {\n            background: #ffffff;\n            color: #2d84d1;\n        }\n\n        .nu-main-content {\n            flex: 1;\n            display: flex;\n            flex-direction: column;\n            background: white;\n        }\n\n        .nu-content-header {\n            background: white;\n            padding: 0px 20px;\n            border-bottom: 1px solid #ddd;\n        }\n\n        .nu-content-header h2 {\n            color: #2c3e50;\n            font-size: 18px;\n            margin-bottom: 5px;\n        }\n\n        .nu-content-header p {\n            color: #7f8c8d;\n            font-size: 14px;\n        }\n\n        .nu-code-area {\n            flex: 1;\n            padding: 30px;\n            display: none;\n        }\n\n        .nu-code-area.active {\n            display: block;\n        }\n\n        .nu-code-textarea {\n            width: 100%;\n            height: 100%;\n            border: 1px solid #ddd;\n            border-radius: 6px;\n            padding: 7px;\n            font-family: var(--nu-font-code), \'Monaco\', \'Menlo\', \'Ubuntu Mono\', monospace;\n            line-height: 1.5;\n            resize: none;\n            outline: none;\n            transition: border-color 0.2s ease;\n            box-sizing: border-box;\n        }\n\n        .nu-code-textarea:focus {\n            border-color: #3498db;\n        }\n\n        /* Custom scrollbar for sidebar */\n        .nu-sidebar::-webkit-scrollbar {\n            width: 6px;\n        }\n\n        .nu-sidebar::-webkit-scrollbar-track {\n            background: #f8f9fa;\n        }\n\n        .nu-sidebar::-webkit-scrollbar-thumb {\n            background: #dee2e6;\n            border-radius: 3px;\n        }\n\n        .nu-sidebar::-webkit-scrollbar-thumb:hover {\n            background: #adb5bd;\n        }\n    </style>\n\n    <div class=\"nu-code-container\">\n        <div class=\"nu-sidebar\">\n            <div class=\"nu-nav-section\">\n                <h3>JS Events</h3>\n                <button class=\"nu-nav-button active\" data-target=\"browse-edit\">Browse & Edit</button>\n                <button class=\"nu-nav-button\" data-target=\"browse\">Browse</button>\n                <button class=\"nu-nav-button\" data-target=\"edit\">Edit</button>\n            </div>\n\n            <div class=\"nu-nav-section\">\n                <h3>PHP Events</h3>\n                <button class=\"nu-nav-button\" data-target=\"before-browse\">\n                    Before Browse\n                    <span class=\"badge\">BB</span>\n                </button>\n                <button class=\"nu-nav-button\" data-target=\"before-edit\">\n                    Before Edit\n                    <span class=\"badge\">BE</span>\n                </button>\n                <button class=\"nu-nav-button\" data-target=\"before-save\">\n                    Before Save\n                    <span class=\"badge\">BS</span>\n                </button>\n                <button class=\"nu-nav-button\" data-target=\"after-save\">\n                    After Save\n                    <span class=\"badge\">AS</span>\n                </button>\n                <button class=\"nu-nav-button\" data-target=\"before-delete\">\n                    Before Delete\n                    <span class=\"badge\">BD</span>\n                </button>\n                <button class=\"nu-nav-button\" data-target=\"after-delete\">\n                    After Delete\n                    <span class=\"badge\">AD</span>\n                </button>\n            </div>\n\n            <div class=\"nu-nav-section\">\n                <h3>Styling</h3>\n                <button class=\"nu-nav-button\" data-target=\"css-style\">CSS Style</button>\n            </div>\n        </div>\n\n        <div class=\"nu-main-content\">\n            <div class=\"nu-content-header\">\n                <p id=\"current-description\">Code that runs when users can both browse and edit records</p>\n            </div>\n\n            <!-- Code areas for each section -->\n            <div class=\"nu-code-area active\" id=\"browse-edit-area\">\n                <textarea id=\"nu-code-textarea-browse-edit\" class=\"js nu-code-textarea\" title=\"Browse & Edit\" placeholder=\"Enter your Browse & Edit code here...\"></textarea>\n            </div>\n\n            <div class=\"nu-code-area\" id=\"browse-area\">\n                <textarea id=\"nu-code-textarea-browse\" class=\"js nu-code-textarea\"  title=\"Browse\" placeholder=\"Enter your Browse code here...\"></textarea>\n            </div>\n\n            <div class=\"nu-code-area\" id=\"edit-area\">\n                <textarea id=\"nu-code-textarea-edit\" class=\"js nu-code-textarea\"  title=\"Edit\" placeholder=\"Enter your Edit code here...\"></textarea>\n            </div>\n\n            <div class=\"nu-code-area\" id=\"before-browse-area\">\n                <textarea id=\"nu-code-textarea-php-bb\" class=\"php nu-code-textarea\" title=\"Before Browse (BB)\" placeholder=\"Enter your Before Browse PHP code here...\"></textarea>\n            </div>\n\n            <div class=\"nu-code-area\" id=\"before-edit-area\">\n                <textarea id=\"nu-code-textarea-php-be\" class=\"php nu-code-textarea\" title=\"Before Edit (BE)\" placeholder=\"Enter your Before Edit PHP code here...\"></textarea>\n            </div>\n\n            <div class=\"nu-code-area\" id=\"before-save-area\">\n                <textarea id=\"nu-code-textarea-php-bs\" class=\"php nu-code-textarea\" title=\"Before Save (BS)\" placeholder=\"Enter your Before Save PHP code here...\"></textarea>\n            </div>\n\n            <div class=\"nu-code-area\" id=\"after-save-area\">\n                <textarea id=\"nu-code-textarea-php-as\" class=\"php nu-code-textarea\" title=\"After Save (AS)\" placeholder=\"Enter your After Save PHP code here...\"></textarea>\n            </div>\n\n            <div class=\"nu-code-area\" id=\"before-delete-area\">\n                <textarea id=\"nu-code-textarea-php-bd\" class=\"php nu-code-textarea\" title=\"Before Delete (BD)\" placeholder=\"Enter your Before Delete PHP code here...\"></textarea>\n            </div>\n\n            <div class=\"nu-code-area\" id=\"after-delete-area\">\n                <textarea id=\"nu-code-textarea-php-ad\" class=\"php nu-code-textarea\" title=\"After Delete (AD)\" placeholder=\"Enter your After Delete PHP code here...\"></textarea>\n            </div>\n\n            <div class=\"nu-code-area\" id=\"css-style-area\">\n                <textarea id=\"nu-code-textarea-css\" class=\"nu-code-textarea css\" title=\"CSS Style\" placeholder=\"Enter your CSS styles here...\"></textarea>\n            </div>\n        </div>\n    </div>\n\n    <script>\n        var navButtons = document.querySelectorAll(\'.nu-nav-button\');\n        var codeAreas = document.querySelectorAll(\'.nu-code-area\');\n        var currentDescription = document.getElementById(\'current-description\');\n\n        var sectionInfo = {\n            \'browse-edit\': {\n                title: \'Browse & Edit\',\n                description: \'Code that runs when users can both browse and edit records\'\n            },\n            \'browse\': {\n                title: \'Browse\',\n                description: \'Code that runs when users are browsing records\'\n            },\n            \'edit\': {\n                title: \'Edit\',\n                description: \'Code that runs when users are editing records\'\n            },\n            \'before-browse\': {\n                title: \'Before Browse\',\n                description: \'PHP code executed before browsing records\'\n            },\n            \'before-edit\': {\n                title: \'Before Edit\',\n                description: \'PHP code executed before editing a record\'\n            },\n            \'before-save\': {\n                title: \'Before Save\',\n                description: \'PHP code executed before saving a record\'\n            },\n            \'after-save\': {\n                title: \'After Save\',\n                description: \'PHP code executed after saving a record\'\n            },\n            \'before-delete\': {\n                title: \'Before Delete\',\n                description: \'PHP code executed before deleting a record\'\n            },\n            \'after-delete\': {\n                title: \'After Delete\',\n                description: \'PHP code executed after deleting a record\'\n            },\n            \'css-style\': {\n                title: \'CSS Style\',\n                description: \'Custom CSS styles for this form\'\n            }\n        };\n\n        navButtons.forEach(button => {\n            button.addEventListener(\'click\', () => {\n                const targetId = button.dataset.target;\n                \n                // Remove active class from all buttons\n                navButtons.forEach(btn => btn.classList.remove(\'active\'));\n                // Add active class to clicked button\n                button.classList.add(\'active\');\n                \n                // Hide all code areas\n                codeAreas.forEach(area => area.classList.remove(\'active\'));\n                \n                // Show target code area\n                const targetArea = document.getElementById(targetId + \'-area\');\n                if (targetArea) {\n                    targetArea.classList.add(\'active\');\n                }\n                \n                // Update header\n                const info = sectionInfo[targetId];\n                if (info) {\n                    currentDescription.textContent = info.description;\n                }\n            });\n        });\n\n        // Function to programmatically select a navigation button\n        function nuSelectNavButton(targetId) {\n            const button = document.querySelector(`[data-target=\"${targetId}\"]`);\n            if (button) {\n                // Remove active class from all buttons\n                navButtons.forEach(btn => btn.classList.remove(\'active\'));\n                // Add active class to target button\n                button.classList.add(\'active\');\n                \n                // Hide all code areas\n                codeAreas.forEach(area => area.classList.remove(\'active\'));\n                \n                // Show target code area\n                const targetArea = document.getElementById(targetId + \'-area\');\n                if (targetArea) {\n                    targetArea.classList.add(\'active\');\n                }\n                \n                // Update header\n                const info = sectionInfo[targetId];\n                if (info) {\n                    currentDescription.textContent = info.description;\n                }\n                \n                return true; // Success\n            }\n            return false; // Button not found\n        }\n\n        // Function to get the currently active navigation button\n        function nuGetActiveNavButton() {\n            const activeButton = document.querySelector(\'.nu-nav-button.active\');\n            return activeButton ? activeButton.getAttribute(\'data-target\') : null;\n        }\n\n        // Handle textarea changes\n        document.querySelectorAll(\'.nu-code-textarea\').forEach(textarea => {\n            // Add nuEdited class on change\n            textarea.addEventListener(\'change\', function() {\n                this.classList.add(\'nuEdited\');\n                \n                // Map textarea ID to corresponding button data-target\n                const textareaToTarget = {\n                    \'nu-code-textarea-browse-edit\': \'browse-edit\',\n                    \'nu-code-textarea-browse\': \'browse\',\n                    \'nu-code-textarea-edit\': \'edit\',\n                    \'nu-code-textarea-php-bb\': \'before-browse\',\n                    \'nu-code-textarea-php-be\': \'before-edit\',\n                    \'nu-code-textarea-php-bs\': \'before-save\',\n                    \'nu-code-textarea-php-as\': \'after-save\',\n                    \'nu-code-textarea-php-bd\': \'before-delete\',\n                    \'nu-code-textarea-php-ad\': \'after-delete\',\n                    \'nu-code-textarea-css\': \'css-style\'\n                };\n                \n                const targetButton = textareaToTarget[this.id];\n                if (targetButton) {\n                    const button = document.querySelector(`[data-target=\"${targetButton}\"]`);\n                    if (button) {\n                        // Add/remove nuTabMarker based on content\n                        if (this.value.trim() !== \'\') {\n                            button.classList.add(\'nuTabMarker\');\n                        } else {\n                            button.classList.remove(\'nuTabMarker\');\n                        }\n                    }\n                }\n            });\n        });\n    </script>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
