INSERT INTO `zzzzsys_php` (`zzzzsys_php_id`, `sph_code`, `sph_description`, `sph_group`, `sph_category`, `sph_status`, `sph_php`, `sph_javascript`, `sph_javascript_active`, `sph_run`, `sph_zzzzsys_form_id`, `sph_system`, `sph_global`, `sph_demo`, `sph_template`, `sph_hide`, `sph_json`) VALUES
('-1_AB', '-1_AB', 'System PHP', 'nubuilder', NULL, NULL, '$contactID = nuFormData()[\'pk_inv_contact\'];\n\nif($contactID == \'\') {\n    return;\n}\n\n$sql = \"\n    SELECT sus_email \n    FROM zzzzsys_user\n    WHERE zzzzsys_user_id = ?\n\";\n\n$rows = nuRunQuery($sql, [$contactID]);\n\nif (count($rows) > 0) {\n    $email = $rows[0][\'sus_email\'];\n\n    $GLOBALS[\'nuLookupThis\'][\'display\'] = $email;\n    $GLOBALS[\'nuLookupThis\'][\'id\']      = $email;\n}\n', NULL, NULL, NULL, NULL, '1', '0', '1', '0', NULL, NULL),
('68c452e608cbadc_AD', '68c452e608cbadc_AD', 'System PHP', 'nubuilder', NULL, NULL, '// --- Automatically delete case access rows when a case is deleted ---\n\n// Get the deleted Case ID\n$case_id = \'#RECORD_ID#\';\nnuDebug(\"Deleting access rows for Case ID: $case_id\");\n\n// Safety checks\nif ($case_id === \'\' || $case_id === null) {\n    nuDebug(\"No Case ID provided â€” aborting cleanup.\");\n    return;\n}\n\n// Delete associated access rows\n$sql = \"\n    DELETE FROM case_user_access\n    WHERE case_id = :case_id\n\";\n\nnuRunQuery($sql, [\'case_id\' => $case_id]);\n\nnuDebug(\"Access rows deleted for Case $case_id\");\n', NULL, NULL, NULL, NULL, '1', '0', '1', '0', NULL, NULL),
('68c452e608cbadc_AS', '68c452e608cbadc_AS', 'System PHP', 'nubuilder', NULL, NULL, '// -----------------------------------------------------\n// Assign case_group_id for NEW investigations (authoritative)\n// Do NOT stop the rest of After Save if case_group_id already exists\n// -----------------------------------------------------\n\n$cid = \'#RECORD_ID#\';\n\nif (empty($_POST[\'case_group_id\'])) {\n\n    $sql_check = \"\n        SELECT case_group_id\n        FROM cases\n        WHERE pk_inv_case_no = ?\n    \";\n    $rs  = nuRunQuery($sql_check, [$cid]);\n    $row = db_fetch_object($rs);\n\n    if ($row && trim((string)$row->case_group_id) === \'\') {\n\n        $uuid = sprintf(\n            \'%04x%04x-%04x-4%03x-%04x-%04x%04x%04x\',\n            random_int(0, 0xffff),\n            random_int(0, 0xffff),\n            random_int(0, 0xffff),\n            random_int(0, 0x0fff),\n            random_int(0, 0x3fff) | 0x8000,\n            random_int(0, 0xffff),\n            random_int(0, 0xffff),\n            random_int(0, 0xffff)\n        );\n\n        $sql_upd = \"\n            UPDATE cases\n            SET case_group_id = ?\n            WHERE pk_inv_case_no = ?\n        \";\n        nuRunQuery($sql_upd, [$uuid, $cid]);\n\n        nuDebug(\"case_group_id assigned AFTER SAVE: $uuid\");\n    }\n}\n\n\n// -----------------------------------------------------\n// 1. AUTOMATICALLY CREATE UPLOAD FOLDERS\n// -----------------------------------------------------\n\n$record_id = \'#RECORD_ID#\';\nnuDebug($record_id);\n\n$base_path = isset($nuUploadsRoot) && $nuUploadsRoot != \'\'\n    ? $nuUploadsRoot\n    : rtrim($_SERVER[\'DOCUMENT_ROOT\'], \'/\\\\\') . \'/uploads\';\n\nnuDebug(\"DOCUMENT_ROOT: \" . $_SERVER[\'DOCUMENT_ROOT\']);\nnuDebug(\"Uploads base path: \" . $base_path);\n\nif (!is_dir($base_path)) {\n    nuDebug(\"Error: Uploads base path does not exist â€” $base_path\");\n    return;\n}\n\nif (!is_writable($base_path)) {\n    nuDebug(\"Error: Uploads base path is not writable â€” $base_path\");\n    return;\n}\n\n$case_folder = $base_path . \'/Investigation \' . $record_id;\n\n$folders_to_create = [\n    $case_folder . \'/Evidence/Audio\',\n    $case_folder . \'/Evidence/Photo\',\n    $case_folder . \'/Evidence/Video\',\n    $case_folder . \'/Evidence/Sensors\',\n    $case_folder . \'/History\'\n];\n\nforeach ($folders_to_create as $folder_path) {\n\n    if (!file_exists($folder_path)) {\n\n        if (mkdir($folder_path, 0755, true)) {\n            nuDebug(\"Folder created: $folder_path\");\n        } else {\n            nuDebug(\"Error: Failed to create folder â€” $folder_path\");\n        }\n\n    } else {\n\n        if (is_dir($folder_path)) {\n            nuDebug(\"Folder already exists: $folder_path\");\n        } else {\n            nuDebug(\"Error: Path exists but is not a directory â€” $folder_path\");\n        }\n    }\n}\n\n\n// -----------------------------------------------------\n// 1A. CLONE CLEANUP\n// KEEP: Location and Contact, History\n// CLEAR: all investigation-specific data on the cases table\n// DO NOT touch sensor child rows\n// -----------------------------------------------------\n\n$is_clone = false;\n\n$sql_clone_check = \"\n    SELECT case_group_id, case_investigation_no\n    FROM cases\n    WHERE pk_inv_case_no = ?\n\";\n$rs_clone_check  = nuRunQuery($sql_clone_check, [$record_id]);\n$row_clone_check = db_fetch_object($rs_clone_check);\n\nif ($row_clone_check) {\n\n    $clone_case_group_id = trim((string)$row_clone_check->case_group_id);\n    $clone_case_inv_no   = trim((string)$row_clone_check->case_investigation_no);\n\n    if ($clone_case_group_id !== \'\' && $clone_case_inv_no !== \'\') {\n\n        $sql_dup = \"\n            SELECT COUNT(*) AS cnt\n            FROM cases\n            WHERE case_group_id = ?\n              AND case_investigation_no = ?\n              AND pk_inv_case_no <> ?\n        \";\n        $rs_dup  = nuRunQuery($sql_dup, [$clone_case_group_id, $clone_case_inv_no, $record_id]);\n        $row_dup = db_fetch_object($rs_dup);\n\n        if ($row_dup && (int)$row_dup->cnt > 0) {\n            $is_clone = true;\n            nuDebug(\"CLONE CLEANUP: cloned record detected\");\n        }\n    }\n}\n\nif ($is_clone) {\n\n    $set_parts = [];\n\n    // Investigation / session fields\n    $set_parts[] = \"pk_inv_start = NULL\";\n    $set_parts[] = \"pk_inv_end = NULL\";\n    $set_parts[] = \"pk_devices = \'\'\";\n    $set_parts[] = \"pk_phoneapps = \'\'\";\n    $set_parts[] = \"pk_computerapps = \'\'\";\n    $set_parts[] = \"pk_spirit_itc_inv = \'\'\";\n    $set_parts[] = \"pk_anom_readings = \'\'\";\n    $set_parts[] = \"pk_anomalous_dt = NULL\";\n    $set_parts[] = \"pk_weather = \'\'\";\n    $set_parts[] = \"pk_moon = \'\'\";\n    $set_parts[] = \"moonimageurl = \'\'\";\n    $set_parts[] = \"pk_inv_notes = \'\'\";\n\n    // Personal experiences\n    $set_parts[] = \"pk_spirit_itc_inv_pe_1 = \'\'\";\n    $set_parts[] = \"pk_spirit_itc_inv_pe_2 = \'\'\";\n    $set_parts[] = \"pk_spirit_itc_inv_pe_3 = \'\'\";\n\n    // Summary / report\n    $set_parts[] = \"pk_inv_summary = \'\'\";\n    $set_parts[] = \"pk_inv_summary_2 = \'\'\";\n    $set_parts[] = \"MYREPORTS = \'\'\";\n    $set_parts[] = \"report_is_complete = 0\";\n\n    // File-list style fields on cases\n    $set_parts[] = \"pk_audio_files = \'\'\";\n    $set_parts[] = \"pk_video_files = \'\'\";\n    $set_parts[] = \"pk_photo_files = \'\'\";\n    $set_parts[] = \"sensor_files_zip = \'\'\";\n\n    // History archive fields\n    $set_parts[] = \"pk_loc_hist_docs_inherited_url = pk_loc_hist_docs_URL\";\n    $set_parts[] = \"pk_loc_hist_docs_URL = \'\'\";\n\n    // Repeating Audio fields\n    for ($i = 1; $i <= 20; $i++) {\n        $set_parts[] = \"pk_desc_audio_$i = \'\'\";\n        $set_parts[] = \"pk_audio_url_$i = \'\'\";\n        $set_parts[] = \"audio_{$i}_time = NULL\";\n    }\n\n    // Repeating Video fields\n    for ($i = 1; $i <= 20; $i++) {\n        $set_parts[] = \"pk_desc_video_$i = \'\'\";\n        $set_parts[] = \"pk_video_url_$i = \'\'\";\n        $set_parts[] = \"video_{$i}_time = NULL\";\n    }\n\n    // Repeating Photo fields\n    for ($i = 1; $i <= 20; $i++) {\n        $set_parts[] = \"pk_desc_photo_$i = \'\'\";\n        $set_parts[] = \"pk_photo_url_$i = \'\'\";\n        $set_parts[] = \"photo_{$i}_time = NULL\";\n    }\n\n    // Any witness fields and pk_pe_ fields\n    $columns_rs = nuRunQuery(\"SHOW COLUMNS FROM cases\");\n\n    while ($col = $columns_rs->fetch(PDO::FETCH_ASSOC)) {\n\n        $field = $col[\'Field\'];\n\n        if (\n            strpos($field, \'pk_wit_\') === 0\n            || strpos($field, \'pk_pe_\') === 0\n        ) {\n\n            $type = strtolower($col[\'Type\']);\n\n            if (\n                strpos($type, \'date\') !== false\n                || strpos($type, \'time\') !== false\n                || strpos($type, \'int\') !== false\n                || strpos($type, \'decimal\') !== false\n                || strpos($type, \'float\') !== false\n                || strpos($type, \'double\') !== false\n            ) {\n                $set_parts[] = \"$field = NULL\";\n            } else {\n                $set_parts[] = \"$field = \'\'\";\n            }\n\n            nuDebug(\"CLONE CLEANUP will clear dynamic field: $field\");\n        }\n    }\n\n    $sql_clear_cases = \"\n        UPDATE cases\n        SET \" . implode(\",\\n            \", $set_parts) . \"\n        WHERE pk_inv_case_no = ?\n    \";\n\n    nuRunQuery($sql_clear_cases, [$record_id]);\n    nuDebug(\"CLONE CLEANUP: cleared investigation-specific fields in cases\");\n}\n\n\n// -----------------------------------------------------\n// 2. NORMALIZE ALL UPLOAD URL FIELDS â€” AFTER SAVE\n// -----------------------------------------------------\n\n$case_id = \'#RECORD_ID#\';\n\n// Build list of fields to normalize\n$upload_fields = [];\n\n// Audio URLs\nfor ($i = 1; $i <= 20; $i++) {\n    $upload_fields[] = \"pk_audio_url_$i\";\n}\n\n// Video URLs\nfor ($i = 1; $i <= 20; $i++) {\n    $upload_fields[] = \"pk_video_url_$i\";\n}\n\n// Photo URLs\nfor ($i = 1; $i <= 20; $i++) {\n    $upload_fields[] = \"pk_photo_url_$i\";\n}\n\n// History documents URLs\n$upload_fields[] = \"pk_loc_hist_docs_URL\";\n$upload_fields[] = \"pk_loc_hist_docs_inherited_url\";\n\n// Moon image URL\n$upload_fields[] = \"moonimageurl\";\n\n// File-list style fields\n$upload_fields[] = \"pk_audio_files\";\n$upload_fields[] = \"pk_video_files\";\n$upload_fields[] = \"pk_photo_files\";\n$upload_fields[] = \"sensor_files_zip\";\n\n// Fetch all current values\n$field_list = implode(\', \', $upload_fields);\n\n$sql_get = \"\n    SELECT $field_list\n    FROM cases\n    WHERE pk_inv_case_no = ?\n\";\n$rs  = nuRunQuery($sql_get, [$case_id]);\n$row = db_fetch_object($rs);\n\nif ($row) {\n\n    foreach ($upload_fields as $field) {\n\n        $raw = trim((string)$row->$field);\n\n        if ($raw === \'\') {\n            continue;\n        }\n\n        $normalized = $raw;\n\n        // Strip protocol + host\n        if (preg_match(\'/^https?:\\/\\//i\', $normalized)) {\n            $parts = parse_url($normalized);\n            $path  = isset($parts[\'path\']) ? $parts[\'path\'] : \'\';\n            $query = isset($parts[\'query\']) ? (\'?\' . $parts[\'query\']) : \'\';\n            $normalized = $path . $query;\n        }\n\n        // Convert legacy app path\n        $normalized = preg_replace(\'#^/nubuilder2/uploads#i\', \'/uploads\', $normalized);\n\n        // Ensure leading slash\n        if ($normalized !== \'\' && substr($normalized, 0, 1) !== \'/\') {\n            $normalized = \'/\' . $normalized;\n        }\n\n        // Only normalize uploads paths\n        if (\n            preg_match(\'#^/uploads/#i\', $normalized)\n            && $normalized !== $raw\n        ) {\n\n            $sql_upd = \"\n                UPDATE cases\n                SET $field = ?\n                WHERE pk_inv_case_no = ?\n            \";\n            nuRunQuery($sql_upd, [$normalized, $case_id]);\n\n            nuDebug(\"Normalized $field\");\n            nuDebug(\"FROM: $raw\");\n            nuDebug(\"TO:   $normalized\");\n        }\n    }\n}\n\n\n//--------------------------------\n// Normalize Sensor File Upload URLs\n//--------------------------------\n\n$caseNo = \'#RECORD_ID#\';\n\n$sql = \"\n    SELECT case_sensor_file_id, sensor_file_url\n    FROM case_sensor_files\n    WHERE fk_inv_case_no = ?\n\";\n$stmt = nuRunQuery($sql, [$caseNo]);\n\nwhile ($row = $stmt->fetch(PDO::FETCH_ASSOC)) {\n\n    $id  = $row[\'case_sensor_file_id\'];\n    $url = trim((string)$row[\'sensor_file_url\']);\n\n    if ($url === \'\') {\n        continue;\n    }\n\n    $newUrl = $url;\n\n    // If a full URL was pasted, extract just the path part\n    $parts = @parse_url($url);\n    if (is_array($parts) && isset($parts[\'path\']) && $parts[\'path\'] !== \'\') {\n        $newUrl = $parts[\'path\'];\n    }\n\n    // If it starts with uploads/ but no leading slash, add one\n    if (stripos($newUrl, \'uploads/\') === 0) {\n        $newUrl = \'/\' . $newUrl;\n    }\n\n    // Only keep values that resolve to /uploads/...\n    if (stripos($newUrl, \'/uploads/\') !== 0) {\n        continue;\n    }\n\n    // Save only if changed\n    if ($newUrl !== $url) {\n        nuRunQuery(\n            \"UPDATE case_sensor_files\n             SET sensor_file_url = ?\n             WHERE case_sensor_file_id = ?\",\n            [$newUrl, $id]\n        );\n    }\n}\n\n\n//------------------------------------------------\n// Create hyperlinks for Sensor Data File downloads\n//------------------------------------------------\n\n$caseNo = \'#RECORD_ID#\';\n\n$sql = \"\n    SELECT case_sensor_file_id, sensor_file_url\n    FROM case_sensor_files\n    WHERE fk_inv_case_no = ?\n\";\n$stmt = nuRunQuery($sql, [$caseNo]);\n\nwhile ($row = $stmt->fetch(PDO::FETCH_ASSOC)) {\n\n    $id  = $row[\'case_sensor_file_id\'];\n    $url = trim((string)$row[\'sensor_file_url\']);\n\n    if ($url === \'\') {\n        $html = \'\';\n    } else {\n        $safeUrl = htmlspecialchars($url, ENT_QUOTES, \'UTF-8\');\n        $html = \'<a href=\"\' . $safeUrl . \'\" target=\"_blank\" download \'\n              . \'style=\"display:inline-block;padding:4px 10px;border-radius:4px;\'\n              . \'background:#2f80ed;color:#fff;text-decoration:none;font-size:12px;\">\'\n              . \'Download File</a>\';\n    }\n\n    nuRunQuery(\n        \"UPDATE case_sensor_files\n         SET sensor_file_download_html = ?\n         WHERE case_sensor_file_id = ?\",\n        [$html, $id]\n    );\n}\n\n\n// -----------------------------------------------------\n// 3. case_user_access â€” INITIAL ASSIGNMENT (LEGACY)\n// -----------------------------------------------------\n\n$uid = isset($_POST[\'pk_inv_contact\']) ? $_POST[\'pk_inv_contact\'] : \'\';\n$cid = isset($_POST[\'pk_inv_case_no\']) ? $_POST[\'pk_inv_case_no\'] : \'\';\n\nif ($uid !== \'\' && $cid !== \'\') {\n\n    $deleteSQL = \"\n        DELETE FROM case_user_access\n        WHERE fk_case_id = $cid\n    \";\n    nuRunQuery($deleteSQL);\n\n    $uuid = str_replace(\'-\', \'\', nuID());\n\n    $insertSQL = \"\n        INSERT INTO case_user_access\n            (case_user_access_id, fk_case_id, fk_user_id)\n        VALUES\n            (\'$uuid\', $cid, \'$uid\')\n    \";\n    nuRunQuery($insertSQL);\n}\n\n\n// -----------------------------------------------------\n// 4. KEEP case_user_access IN SYNC (AFTER SAVE)\n// -----------------------------------------------------\n\n$sql_contact = \"\n    SELECT pk_inv_contact\n    FROM cases\n    WHERE pk_inv_case_no = ?\n\";\n$rs  = nuRunQuery($sql_contact, [$record_id]);\n$row = db_fetch_object($rs);\n\nif ($row) {\n\n    $contact_user_id = trim((string)$row->pk_inv_contact);\n\n    if ($contact_user_id !== \'\') {\n\n        $sql_delete = \"\n            DELETE FROM case_user_access\n            WHERE fk_case_id = ?\n        \";\n        nuRunQuery($sql_delete, [$record_id]);\n\n        $uuid = str_replace(\'-\', \'\', nuID());\n\n        $sql_insert = \"\n            INSERT INTO case_user_access\n                (case_user_access_id, fk_case_id, fk_user_id)\n            VALUES\n                (?, ?, ?)\n        \";\n        nuRunQuery($sql_insert, [$uuid, $record_id, $contact_user_id]);\n    }\n}\n\n\n// -----------------------------------------------------\n// 5. ASSIGN / REASSIGN Case Investigation Number\n// Handles NEW records and CLONED records\n// -----------------------------------------------------\n\n$sql_case_group = \"\n    SELECT case_group_id, case_investigation_no\n    FROM cases\n    WHERE pk_inv_case_no = ?\n\";\n$rs_case_group  = nuRunQuery($sql_case_group, [$record_id]);\n$row_case_group = db_fetch_object($rs_case_group);\n\nif ($row_case_group) {\n\n    $case_group_id         = trim((string)$row_case_group->case_group_id);\n    $existing_case_inv_no  = trim((string)$row_case_group->case_investigation_no);\n    $needs_case_inv_number = false;\n\n    if ($case_group_id !== \'\') {\n\n        // Brand new blank value\n        if ($existing_case_inv_no === \'\') {\n            $needs_case_inv_number = true;\n        } else {\n\n            // Detect cloned record carrying a duplicate investigation number\n            $sql_dup = \"\n                SELECT COUNT(*) AS cnt\n                FROM cases\n                WHERE case_group_id = ?\n                  AND case_investigation_no = ?\n                  AND pk_inv_case_no <> ?\n            \";\n            $rs_dup  = nuRunQuery($sql_dup, [$case_group_id, $existing_case_inv_no, $record_id]);\n            $row_dup = db_fetch_object($rs_dup);\n\n            if ($row_dup && (int)$row_dup->cnt > 0) {\n                $needs_case_inv_number = true;\n                nuDebug(\"Duplicate case_investigation_no detected on clone: $existing_case_inv_no\");\n            }\n        }\n\n        if ($needs_case_inv_number) {\n\n            $sql_next = \"\n                SELECT COALESCE(MAX(case_investigation_no), 0) + 1 AS next_no\n                FROM cases\n                WHERE case_group_id = ?\n                  AND pk_inv_case_no <> ?\n            \";\n            $rs_next  = nuRunQuery($sql_next, [$case_group_id, $record_id]);\n            $row_next = db_fetch_object($rs_next);\n\n            $case_inv_no = $row_next ? (int)$row_next->next_no : 1;\n\n            $sql_update_case_inv_no = \"\n                UPDATE cases\n                SET case_investigation_no = ?\n                WHERE pk_inv_case_no = ?\n            \";\n            nuRunQuery($sql_update_case_inv_no, [$case_inv_no, $record_id]);\n\n            nuDebug(\"Assigned case_investigation_no: $case_inv_no for case_group_id: $case_group_id\");\n        }\n    }\n}\n\n\n// -----------------------------------------------------\n// Renumber Sensor Device File No\n// -----------------------------------------------------\n$inv_no = \'#RECORD_ID#\';\n\nif ($inv_no == \'\' || $inv_no == \'-1\') {\n    return;\n}\n\n$sql = \"\n    SELECT\n        case_sensor_file_id,\n        sensor_device_name\n    FROM case_sensor_files\n    WHERE fk_inv_case_no = :inv_no\n    ORDER BY\n        sensor_device_name,\n        case_sensor_file_id\n\";\n\n$t = nuRunQuery($sql, [\'inv_no\' => $inv_no]);\n\n$counts = [];\n\nwhile ($r = db_fetch_object($t)) {\n\n    $device = trim($r->sensor_device_name);\n\n    if ($device == \'\') {\n        continue;\n    }\n\n    if (!isset($counts[$device])) {\n        $counts[$device] = 1;\n    } else {\n        $counts[$device]++;\n    }\n\n    $new_no = $counts[$device];\n\n    nuRunQuery(\n        \"UPDATE case_sensor_files\n         SET file_no = :file_no\n         WHERE case_sensor_file_id = :id\",\n        [\n            \'file_no\' => $new_no,\n            \'id\'      => $r->case_sensor_file_id\n        ]\n    );\n}', NULL, NULL, NULL, NULL, '1', '0', '1', '0', NULL, NULL),
('68c452e608cbadc_BB', '68c452e608cbadc_BB', 'System PHP', 'nubuilder', NULL, NULL, 'function getUserEmail($p) {\n    $id = $p[\'id\'];\n\n    $sql = \"SELECT sus_email FROM zzzzsys_user WHERE zzzzsys_user_id = ?\";\n    $result = nuRunQuery($sql, [$id]);\n\n    if (count($result) > 0) {\n        return [\'email\' => $result[0][\'sus_email\']];\n    }\n\n    return [\'email\' => \'\'];\n}\n\n\n\n\n\n\nnuAddJavaScript(\"\nsetTimeout(function () {\n\n    function sfFormatPhone(v) {\n        if (!v) return v;\n        var d = v.toString().replace(/\\\\D/g, \'\');\n        if (d.length === 10) {\n            return \'(\' + d.substr(0, 3) + \') \' + d.substr(3, 3) + \'-\' + d.substr(6, 4);\n        }\n        return v;\n    }\n\n    var titles = document.querySelectorAll(\'.nuBrowseTitle\');\n    var phoneColIndex = -1;\n\n    for (var i = 0; i < titles.length; i++) {\n        if (titles[i].innerText.trim() === \'Contact Phone\') {  // header text\n            phoneColIndex = i;\n            break;\n        }\n    }\n\n    if (phoneColIndex === -1) return;\n\n    var cells = document.querySelectorAll(\'.nuCell\');\n    for (var j = 0; j < cells.length; j++) {\n        var col = parseInt(cells[j].getAttribute(\'data-nu-column\'), 10);\n        if (col === phoneColIndex) {\n            cells[j].innerText = sfFormatPhone(cells[j].innerText);\n        }\n    }\n\n}, 400);\n\");\n', NULL, NULL, NULL, NULL, '1', '0', '1', '0', NULL, NULL),
('68c452e608cbadc_BD', '68c452e608cbadc_BD', 'System PHP', 'nubuilder', NULL, NULL, '$record_id = \'#RECORD_ID#\';\nnuDebug(\"Deleting folders for record: $record_id\");\n\n// Base path\n$base_path = $_SERVER[\'DOCUMENT_ROOT\'] . \'/uploads\';\n\n// -----------------------------------------------------\n// Recursive delete function\n// -----------------------------------------------------\nfunction deleteFolderRecursively($dir) {\n\n    if (!file_exists($dir)) {\n        return true;\n    }\n\n    if (!is_dir($dir)) {\n        return unlink($dir);\n    }\n\n    $items = scandir($dir);\n\n    foreach ($items as $item) {\n\n        if ($item === \'.\' || $item === \'..\') {\n            continue;\n        }\n\n        $path = $dir . \'/\' . $item;\n\n        if (is_dir($path)) {\n            deleteFolderRecursively($path);\n        } else {\n            unlink($path);\n        }\n    }\n\n    return rmdir($dir);\n}\n\n// -----------------------------------------------------\n// Delete BOTH legacy and current folder names\n// -----------------------------------------------------\n$folders_to_delete = [\n    $base_path . \'/Investigation \' . $record_id, // current\n    $base_path . \'/Case \' . $record_id           // legacy\n];\n\nforeach ($folders_to_delete as $folder) {\n\n    if (file_exists($folder)) {\n\n        if (deleteFolderRecursively($folder)) {\n            nuDebug(\"Successfully deleted folder: $folder\");\n        } else {\n            nuDebug(\"Error deleting folder: $folder\");\n        }\n\n    } else {\n\n        nuDebug(\"Folder does not exist: $folder\");\n    }\n}\n\n\n\n/*\n$record_id = \'#RECORD_ID#\';\nnuDebug(\"Deleting folders for record: $record_id\");\n\n// Base path\n$base_path = $_SERVER[\'DOCUMENT_ROOT\'] . \'/uploads\';\n\n// Case folder\n$case_folder = $base_path . \'/Investigation \' . $record_id;\n\n// Recursive delete function\nfunction deleteFolderRecursively($dir) {\n    if (!file_exists($dir)) {\n        return true;\n    }\n\n    if (!is_dir($dir)) {\n        return unlink($dir);\n    }\n\n    $items = scandir($dir);\n    foreach ($items as $item) {\n        if ($item == \'.\' || $item == \'..\') {\n            continue;\n        }\n\n        $path = $dir . \'/\' . $item;\n\n        if (is_dir($path)) {\n            deleteFolderRecursively($path);\n        } else {\n            unlink($path);\n        }\n    }\n\n    return rmdir($dir);\n}\n\n// Check & delete\nif (file_exists($case_folder)) {\n    if (deleteFolderRecursively($case_folder)) {\n        nuDebug(\"Successfully deleted folder: $case_folder\");\n    } else {\n        nuDebug(\"Error deleting folder: $case_folder\");\n    }\n} else {\n    nuDebug(\"Folder does not exist: $case_folder\");\n}\n*/', NULL, NULL, NULL, NULL, '1', '0', '1', '0', NULL, NULL),
('68c452e608cbadc_BE', '68c452e608cbadc_BE', 'System PHP', 'nubuilder', NULL, NULL, '\n\nnuAddJavaScript(\"\nsetTimeout(function(){\n\n    function sfFormatPhone(v){\n        v = v.replace(/\\\\D/g,\'\');\n        if(v.length === 10){\n            return \'(\' + v.substr(0,3) + \') \' + v.substr(3,3) + \'-\' + v.substr(6,4);\n        }\n        return v;\n    }\n\n    var f = document.getElementById(\'pk_inv_contact_phone\');\n    if(!f){ return; }\n\n    // Format on load\n    f.value = sfFormatPhone(f.value);\n\n    // Format on blur\n    f.addEventListener(\'blur\', function(){\n        this.value = sfFormatPhone(this.value);\n    });\n\n}, 300);\n\");\n', NULL, NULL, NULL, NULL, '1', '0', '1', '0', NULL, NULL),
('68c452e608cbadc_BS', '68c452e608cbadc_BS', 'System PHP', 'nubuilder', NULL, NULL, '//', NULL, NULL, NULL, NULL, '1', '0', '1', '0', NULL, NULL),
('68f91df85e8e5ea_BB', '68f91df85e8e5ea_BB', 'System PHP', 'nubuilder', NULL, NULL, '\n', NULL, NULL, NULL, NULL, '1', '0', '1', '0', NULL, NULL),
('691586dfac881b7', 'getmyreporthtml', 'Gets html from MYREPORTS', NULL, NULL, NULL, '//', NULL, NULL, NULL, NULL, '0', '0', '1', '0', '', NULL),
('691dfbcacd9a5a1', 'getCaseReportData', 'This safely fetches the HTML and identifiers for any given case number.', 'nuBuilder', NULL, NULL, 'function getCaseReportData($args) {\n    $caseNo = $args[\'caseNo\'];\n\n    // Use the correct table + columns, and ALIAS them to the names we want\n    $sql = \"\n        SELECT \n            MYREPORTS,\n            pk_inv_case_name AS CASE_NAME,\n            pk_inv_start      AS INVESTIGATION_DATE\n        FROM cases\n        WHERE pk_inv_case_no = \'$caseNo\'\n        LIMIT 1\n    \";\n\n    $rs = nuRunQuery($sql);\n    if (!$rs) {\n        return array(\n            \"MYREPORTS\"         => \"\",\n            \"CASE_NAME\"         => \"\",\n            \"INVESTIGATION_DATE\"=> \"\"\n        );\n    }\n\n    $row = db_fetch_object($rs);\n    if (!$row) {\n        return array(\n            \"MYREPORTS\"         => \"\",\n            \"CASE_NAME\"         => \"\",\n            \"INVESTIGATION_DATE\"=> \"\"\n        );\n    }\n\n    return array(\n        \"MYREPORTS\"          => $row->MYREPORTS,\n        \"CASE_NAME\"          => $row->CASE_NAME,\n        \"INVESTIGATION_DATE\" => $row->INVESTIGATION_DATE\n    );\n}', NULL, NULL, 'hide', '', '0', '1', '1', '0', '', NULL),
('691e2d4f18c9450', 'testPing', 'Test procedure', NULL, NULL, NULL, 'function testPing($args) {\n    return array(\n        \"ok\"      => true,\n        \"message\" => \"Hello from PHP\",\n        \"args\"    => $args\n    );\n}', NULL, NULL, 'hide', NULL, '0', '1', '1', '0', '', NULL),
('692cb3cea1cf548_AS', '692cb3cea1cf548_AS', 'System PHP', 'nubuilder', NULL, NULL, '// STEP 2: assign email owner AFTER insert (authoritative)\n$rid = \'#RECORD_ID#\';\n\nnuRunQuery(\n    \"UPDATE email_composer\n     SET email_user = ?\n     WHERE email_composer_id = ?\n       AND (email_user IS NULL OR email_user = \'\')\",\n    [nuUserID(), $rid]\n);\n\n\n\n\n\n// ======================================================================\n// AFTER SAVE â€” EmailComposer (Correct array-mode nuSendEmail version)\n// ======================================================================\n\n// Helper to extract a field safely from nuFORMdata\nfunction sfGetField($name, $form) {\n    $fields = $form[\'fields\'];\n    $rows   = $form[\'rows\'][0];\n    $idx    = array_search($name, $fields);\n\n    if ($idx === false) {\n        return \'\';\n    }\n    return isset($rows[$idx]) ? $rows[$idx] : \'\';\n}\n\n// Ensure nuFORMdata exists\nif (!isset($_POST[\'nuSTATE\'][\'nuFORMdata\'][0])) {\n    nuDebug(\'AFTER SAVE: nuFORMdata missing â€” aborting.\');\n    return;\n}\n\n$form = $_POST[\'nuSTATE\'][\'nuFORMdata\'][0];\n\n// Read fields\n$flag    = sfGetField(\'_SEND_EMAIL\',      $form);\n$to      = sfGetField(\'email_recipients\', $form);\n$subject = sfGetField(\'email_subject\',    $form);\n$body    = sfGetField(\'email_body\',       $form);\n\nnuDebug(\'AFTER SAVE STARTED\');\nnuDebug(\'SEND FLAG: \' . $flag);\nnuDebug(\'RAW TO: \' . $to);\nnuDebug(\'SUBJECT: \' . $subject);\n\n// ----------------------------------------------------------------------\n// ONLY SEND EMAIL IF USER CLICKED \"SEND EMAIL\"\n// ----------------------------------------------------------------------\nif ($flag != \'1\') {\n    nuDebug(\'SEND FLAG != 1 â€” skipping email send.\');\n    return;\n}\n\n// ----------------------------------------------------------------------\n// UPDATE TIMESTAMP\n// ----------------------------------------------------------------------\n$id  = \'#RECORD_ID#\';\n$now = date(\'Y-m-d H:i:s\');\n\n$sql = \"\n    UPDATE email_composer\n       SET email_sent_datetime = ?\n     WHERE email_composer_id = ?\n\";\n\nnuRunQuery($sql, [$now, $id]);\n\nnuDebug(\'TIMESTAMP UPDATED FOR: \' . $id);\n\n// ----------------------------------------------------------------------\n// NORMALIZE RECIPIENT LIST\n// ----------------------------------------------------------------------\n$to = str_replace(\';\', \',\', $to);                 // semicolons â†’ commas\n$to = preg_replace(\'/,+/\', \',\', $to);             // collapse duplicate commas\n$toArray = array_filter(array_map(\'trim\', explode(\',\', $to))); // trim + drop empties\n$to = implode(\',\', $toArray);\n\nnuDebug(\'NORMALIZED RECIPIENTS: \' . $to);\n\n// ----------------------------------------------------------------------\n// SEND EMAIL â€” ARRAY MODE (CORRECT FOR YOUR VERSION)\n// ----------------------------------------------------------------------\n$sent = nuSendEmail([\n    \'to\'         => $to,\n    \'from_email\' => \'noreply@example.com\',   // MUST match SMTP user\n    \'from_name\'  => \'SpiritForms\',                // Friendly display name\n    \'subject\'    => $subject,                    // Correct subject\n    \'body\'       => $body,                       // Message body\n    \'html\'       => false                        // Set to true if needed\n]);\n\nnuDebug(\'nuSendEmail returned: \' . var_export($sent, true));\n\nnuDebug(\'AFTER SAVE COMPLETE\');\n// ======================================================================\n', NULL, NULL, NULL, NULL, '1', '0', '1', '0', NULL, NULL),
('692cb3cea1cf548_BE', '692cb3cea1cf548_BE', 'System PHP', 'nubuilder', NULL, NULL, 'nuAddJavaScript(\"\n    // Auto-fill SUBJECT when SpiritForm triggers EmailComposer\n    if (localStorage.getItem(\'sfTriggered\') === \'1\') {\n\n        let caseNo   = localStorage.getItem(\'sf_caseNo\')   || \'\';\n        let caseName = localStorage.getItem(\'sf_caseName\') || \'\';\n\n        let subject = \'Case \' + caseNo + \': \' + caseName;\n\n        // Fill subject field\n        nuSetValue(\'email_subject\', subject);\n\n        // Fill recipient if provided\n        let em = localStorage.getItem(\'sf_email\') || \'\';\n        if (em) nuSetValue(\'email_recipients\', em);\n\n        // Use once\n        localStorage.removeItem(\'sfTriggered\');\n    }\n\");\n', NULL, NULL, NULL, NULL, '1', '0', '1', '0', NULL, NULL),
('692cb3cea1cf548_BS', '692cb3cea1cf548_BS', 'System PHP', 'nubuilder', NULL, NULL, '\n\n\n\n// Sanitize recipients so ONLY valid email addresses remain\n$raw = isset($_POST[\'email_recipients\']) ? trim($_POST[\'email_recipients\']) : \'\';\n\n// Extract valid email addresses only\npreg_match_all(\n    \'/[A-Z0-9._%+-]+@[A-Z0-9.-]+\\.[A-Z]{2,}/i\',\n    $raw,\n    $matches\n);\n\n// De-duplicate and rebuild clean recipient list\n$emails = array_unique($matches[0]);\n$cleanRecipients = implode(\'; \', $emails);\n\n// Always overwrite POST so database stays clean\n$_POST[\'email_recipients\'] = $cleanRecipients;\n\n// Read send-email flag\n$flag = $_POST[\'_SEND_EMAIL\'] ?? \'0\';\n\nif ($flag === \'1\') {\n\n    // Abort send if no valid recipients exist\n    if ($cleanRecipients === \'\') {\n        nuDebug(\'Email NOT sent: no valid recipients\');\n        $_POST[\'_SEND_EMAIL\'] = \'0\';\n        return;\n    }\n\n    // Stamp sent datetime\n    $_POST[\'email_sent_datetime\'] = date(\'Y-m-d H:i:s\');\n\n    // Reset flag to prevent duplicate sending\n    $_POST[\'_SEND_EMAIL\'] = \'0\';\n}\n\n\n\n/*\n// ----------------------------\n// 1. PRESERVE RECIPIENTS (EXISTING)\n// ----------------------------\nif (isset($_POST[\'email_recipients\'])) {\n    $_POST[\'email_recipients\'] = $_POST[\'email_recipients\'];\n}\n\n\n\n// ----------------------------\n// 2. HANDLE SEND EMAIL FLAG (EXISTING)\n// ----------------------------\n$flag = $_POST[\'_SEND_EMAIL\'] ?? \'0\';\n\nif ($flag === \'1\') {\n\n    // Timestamp when sending\n    $_POST[\'email_sent_datetime\'] = date(\'Y-m-d H:i:s\');\n\n    // Reset flag to avoid duplicate sending\n    $_POST[\'_SEND_EMAIL\'] = \'0\';\n}\n*/', NULL, NULL, NULL, NULL, '1', '0', '1', '0', NULL, NULL),
('692cb607c13ee07_AB', '692cb607c13ee07_AB', 'System PHP', 'nubuilder', NULL, NULL, '//', NULL, NULL, NULL, NULL, '1', '0', '1', '0', NULL, NULL),
('692cbdaf9be18c6', 'proc_send_email', 'send email', NULL, NULL, NULL, '$pk = $_POST[\'nuSTATE\'][\'nuFORMdata\'][0][\'rows\'][0][2];\n\n// Load fields\n$sql = \"\n    SELECT email_user, email_subject, email_body\n    FROM email_composer\n    WHERE email_composer_id = :id\n\";\n$r = nuRunQuery($sql, [\'id\' => $pk]);\n$row = db_fetch_object($r);\n\nif (!$row) {\n    nuJavascriptCallback(\"nuMessage(\'Email record not found\')\");\n    return;\n}\n\n// Lookup recipient address\n$sql2 = \"\n    SELECT sus_email\n    FROM zzzzsys_user\n    WHERE zzzzsys_user_id = :id\n\";\n$r2 = nuRunQuery($sql2, [\'id\' => $row->email_user]);\n$u = db_fetch_object($r2);\n\nif (!$u || $u->sus_email == \'\') {\n    nuJavascriptCallback(\"nuMessage(\'User has no email address\')\");\n    return;\n}\n\n$toAddress = $u->sus_email;\n\n// SEND EMAIL (your version format)\n$sendResult = nuEmail(\n    [$toAddress],                    // to_list (array!)\n    \'noreply@example.com\',       // from_address\n    \'SpiritForms Administrator\',                    // from_name\n    $row->email_body,                // content\n    $row->email_subject,             // subject\n    [],                              // file_list\n    false,                           // html\n    [],                              // cc_list\n    [],                              // bcc_list\n    [],                              // reply_to_list\n    0,                               // debug\n    \'SMTP\',                          // method\n    \'\',                              // priority\n    []                               // smtp_options\n);\n\n// sendResult is ARRAY: [success, msg, errorinfo, debug]\nif ($sendResult[0] === true) {\n    nuJavascriptCallback(\"nuMessage(\'Email sent to $toAddress\')\");\n} else {\n    $err = addslashes($sendResult[2]);\n    nuJavascriptCallback(\"nuMessage(\'FAILED: $err\')\");\n}', NULL, NULL, NULL, NULL, '0', '0', '1', '0', '', NULL),
('693c3ecfe33a1a0_AS', '693c3ecfe33a1a0_AS', 'System PHP', 'nubuilder', NULL, NULL, 'if (\n    !isset($_POST[\'nuSTATE\'][\'email_ids_to_delete\']) ||\n    trim($_POST[\'nuSTATE\'][\'email_ids_to_delete\']) === \'\'\n) {\n    return;\n}\n\n$json = $_POST[\'nuSTATE\'][\'email_ids_to_delete\'];\n$ids  = json_decode($json, true);\n\nif (!is_array($ids) || count($ids) === 0) {\n    return;\n}\n\n// Clear previous queue\nnuRunQuery(\"DELETE FROM email_delete_queue\");\n\n// Insert selected IDs\nforeach ($ids as $id) {\n    $id = addslashes($id);\n    nuRunQuery(\n        \"INSERT INTO email_delete_queue (email_composer_id)\n         VALUES (\'$id\')\"\n    );\n}\n\n// Delete emails\nnuRunQuery(\n    \"DELETE ec\n     FROM email_composer ec\n     JOIN email_delete_queue q\n       ON q.email_composer_id = ec.email_composer_id\"\n);\n\n// Clear queue\nnuRunQuery(\"DELETE FROM email_delete_queue\");\n', NULL, NULL, NULL, NULL, '1', '0', '1', '0', NULL, NULL),
