('693c57284501b64', 'delete_emails_proc', 'Delete selected emails from email_composer', NULL, NULL, NULL, '$ids = nuGetValue(\'email_ids_to_delete\');\n\nif (!is_array($ids) || count($ids) === 0) {\n    return;\n}\n\n$list = \"\'\" . implode(\"\',\'\", $ids) . \"\'\";\n\nnuRunQuery(\n    \"DELETE FROM email_composer WHERE email_composer_id IN ($list)\"\n);', '', NULL, NULL, NULL, '0', '0', '1', '0', '', NULL),
