INSERT INTO `zzzzsys_php` (`zzzzsys_php_id`, `sph_code`, `sph_description`, `sph_group`, `sph_category`, `sph_status`, `sph_php`, `sph_javascript`, `sph_javascript_active`, `sph_run`, `sph_zzzzsys_form_id`, `sph_system`, `sph_global`, `sph_demo`, `sph_template`, `sph_hide`, `sph_json`) VALUES
('nu5fee06b1acbe4bb', 'nu_backup', 'Create a Database Backup using mysqldump', 'nubuilder', 'Backup', '1', '// Use the correct namespace\nuse Ifsnop\\Mysqldump\\Mysqldump;\n\n// Get the JSON settings passed from JS via the \'params\' property\n$params = nuGetProperty(\'NUBACKUP_params\');\n$settings = $params ? nuDecode($params)[\'settings\'] : [];\n\n// Call backup process using the decoded settings\nnuBackupRun($settings);\n\nfunction nuBackupRun($settings) {\n\n	nuBackupLoadMysqldumpLibrary(\'../third_party/mysqldump/Mysqldump.php\');\n\n	// Extract values with defaults using null coalescing operator\n	$directory = $settings[\'directory\'] ?? \'\';\n	$fileName = $settings[\'fileName\'] ?? \'\';\n	$includeTables = $settings[\'include-tables\'] ?? [];\n	$excludeTables = $settings[\'exclude-tables\'] ?? [];\n	$includeViews = $settings[\'include-views\'] ?? [];\n	$nuRecordsFilter = $settings[\'nuRecordsFilter\'] ?? \'\'; // nu, user, empty = all (default)\n	unset($settings[\'nuRecordsFilter\']);\n	\n	$nuTableFilter = $settings[\'nuTableFilter\'] ?? \'\'; // nu, user, empty = all (default)\n	unset($settings[\'nuTableFilter\']);\n\n	// Merge default dump settings with any settings passed from JS\n	$dumpSettings = nuBackupBuildDumpSettings($settings);\n\n	// Prepare the backup directory and filename\n	$backupDirectory = nuBackupDirectory($directory);\n	$backupFileName = nuBackupFileName($fileName, $dumpSettings);\n\n	// Set which tables to include/exclude\n	nuBackupSetTables($dumpSettings, $includeTables, $excludeTables, $includeViews, $nuTableFilter);\n\n	$dumper = nuBackupCreateDumper($dumpSettings);\n\n	$tableWheres = nuBackupBuildTableWheres($nuRecordsFilter);\n	$dumper->setTableWheres($tableWheres);\n\n    $backupDirectory = str_replace([\'/\', \'\\\\\'], DIRECTORY_SEPARATOR, $backupDirectory);\n	$dumpFile = $backupDirectory . nuSanitizeFilename($backupFileName);\n	nuBackupCreateDirectoryIfNotExists($backupDirectory);\n\n	nuBackupStartDump($dumper, $dumpFile);\n\n	nuBackupCompleteNotification($backupDirectory, $backupFileName);\n}\n\nfunction nuBackupFileExtension($dumpSettings) {\n	if (!array_key_exists(\'compress\', $dumpSettings) || $dumpSettings[\'compress\'] === \'None\' || $dumpSettings[\'compress\'] === \'\') {\n		return \'\';\n	}\n	return \'.\' . strtolower($dumpSettings[\'compress\']);\n}\n\nfunction nuBackupDirectory($directory) {\n    // Use provided directory or default\n    $backupDir = !empty($directory) ? $directory : \'../backup/\';\n\n    // Ensure the directory exists\n    if (!is_dir($backupDir)) {\n        mkdir($backupDir, 0755, true);\n    }\n\n    // Define the path to index.htm\n    $indexFile = rtrim($backupDir, \'/\\\\\') . \'/index.htm\';\n\n    // If index.htm doesn\'t exist, create it with a hidden comment\n    if (!file_exists($indexFile)) {\n        $comment = \"<!-- for security reasons, do not delete this file. -->\";\n        file_put_contents($indexFile, $comment);\n    }\n\n    return $backupDir;\n}\n\nfunction nuBackupFileName($fileName, $dumpSettings) {\n	// If fileName is provided, use it; otherwise generate a default filename\n	$extension = nuBackupFileExtension($dumpSettings);\n\n	return !empty($fileName)\n		? $fileName . $extension\n		: date(\'Y-m-d_H:i:s\') . \'_\' . uniqid() . \'_nuBuilder_backup.sql\' . $extension;\n\n}\n\nfunction nuBackupBuildDumpSettings($settings = []) {\n\n	$defaults = [\n		\'single-transaction\' => false,\n		\'no-create-info\' => false,\n		\'lock-tables\' => false,\n		\'add-locks\' => false,\n		\'extended-insert\' => false,\n		\'skip-definer\' => true,\n		\'routines\' => true,\n        \'events\' => true,\n		\'compress\' => $settings[\'compress\'] ?? \'None\' // Mysqldump::NONE\n	];\n\n	return array_merge($defaults, $settings);\n\n}\n\nfunction nuBackupLoadMysqldumpLibrary($path) {\n	try {\n		require_once($path);\n	} catch (Exception $e) {\n		nuDisplayError(\'require_once failed! Error: \' . $e->getMessage());\n	}\n}\n\nfunction nuBackupCreateDumper($dumpSettings) {\n	global $nuConfigDBHost,\n	$nuConfigDBName,\n	$nuConfigDBUser,\n	$nuConfigDBPassword,\n	$nuConfigDBPort;\n	$nuConfigDBPort = $nuConfigDBPort ?? \'3306\';\n\n	$dsn = \"mysql:host={$nuConfigDBHost};dbname={$nuConfigDBName};port={$nuConfigDBPort}\";\n	return new Ifsnop\\Mysqldump\\Mysqldump($dsn, $nuConfigDBUser, $nuConfigDBPassword, $dumpSettings);\n}\n\nfunction nuBackupBuildTableWheres($nuRecordsFilter = \'\') {\n	$tableWheres = [\n		\"zzzzsys_session\" => \"zzzzsys_session_id not like \'s%\'\"\n	];\n\n	if (in_array($nuRecordsFilter, [\'user\', \'nu\'])) {\n		$sysTables = nuGetSysTables();\n		$conditionFunction = ($nuRecordsFilter === \'user\') ? \'nuBackupTableIdNotLikeNu\' : \'nuBackupTableIdLikeNu\';\n		foreach ($sysTables as $tableName) {\n		    if ($tableName !== \'zzzzsys_session\') {\n			    $tableWheres[$tableName] = $conditionFunction($tableName);\n		    }\n		}\n	}\n\n	return $tableWheres;\n}\n\nfunction nuBackupTableIdNotLikeNu($tableName) {\n	return \"{$tableName}_id not like \'nu%\'\";\n}\n\nfunction nuBackupTableIdLikeNu($tableName) {\n	return \"{$tableName}_id like \'nu%\'\";\n}\n\nfunction nuBackupCreateDirectoryIfNotExists($directory) {\n	if (!is_dir($directory)) {\n		mkdir($directory, 0755, true);\n	}\n}\n\nfunction nuBackupStartDump($dumper, $dumpFile) {\n	try {\n		$dumper->start($dumpFile);\n	} catch (Exception $e) {\n		nuDisplayError(\'Export Error: \' . $e->getMessage());\n	}\n}\n\nfunction nuBackupCompleteNotification($backupDirectory, $backupFileName) {\n	$encodedPath = base64_encode($backupDirectory . $backupFileName);\n	$js = \"nuMessage([\'<h2>Export completed!</h2><br>SQL Dump saved in \' + atob(\'$encodedPath\')]);\";\n	nuJavaScriptCallback($js);\n}\n\nfunction nuBackupSetTables(&$dumpSettings, $includeTables, $excludeTables, $includeViews, $nuTableFilter) {\n\n	$dumpSettings[\"include-tables\"] = is_array($includeTables) ? $includeTables : [];\n	$dumpSettings[\"exclude-tables\"] = is_array($excludeTables) ? $excludeTables : [];\n	$dumpSettings[\"include-views\"] = is_array($includeViews) ? $includeViews : [];\n\n    if ($nuTableFilter === \'nu\') {\n        $dumpSettings[\"include-tables\"] = array_merge($dumpSettings[\"include-tables\"], nuGetSysTables());\n        $dumpSettings[\"exclude-tables\"] = array_merge($dumpSettings[\"exclude-tables\"], nuGetUserTables());\n    } else if ($nuTableFilter === \'user\') {\n        $dumpSettings[\"exclude-tables\"] = array_merge($dumpSettings[\"exclude-tables\"], nuGetSysTables());\n        $dumpSettings[\"include-tables\"] = array_merge($dumpSettings[\"exclude-tables\"], nuGetUserTables());\n    }\n\n}', NULL, NULL, 'hide', '', '1', '0', '0', '0', '', NULL),
('nu5ff7efb1ed369a6', 'nu_refresh_select_object', 'Refresh a select object', 'nubuilder', 'Object', '1', 'function nuGetSelectValues($formId, $selectId) {\n\n    $sql = \"\n        SELECT\n            sob_select_sql\n        FROM\n            `zzzzsys_object`\n        WHERE\n            sob_all_zzzzsys_form_id = ? AND sob_all_id = ?\n    \";\n\n    $t = nuRunQuery($sql, [$formId, $selectId]);\n\n    $a = [];\n    if (db_num_rows($t) == 1) {\n\n        $r = db_fetch_row($t);\n        if ($r != false) {\n            \n            $disS = nuReplaceHashVariables($r[0]);\n\n            $t = nuRunQuery($disS);\n\n            while ($row = db_fetch_row($t)) {\n                $a[] = $row;\n            }\n\n            return json_encode($a);\n        }\n\n    }\n\n    return false;\n\n}\n\nfunction nuPopulateSelectObject($formId, $selectId, $removeBlank, $prefix) {\n\n    $j = nuGetSelectValues($formId, $selectId);\n\n    $selectId = $prefix.$selectId;\n\n    $cb = \"if (window.nuSelectObjectRefreshed) {\n    	    nuSelectObjectRefreshed(\'$formId\', \'$selectId\', nuSelectObjectRefreshedCount);\n         }\";\n\n    if ($j == false) {\n        \n        return \"var count = -1; \".$cb;\n        \n    } else {\n    	\n    return \"\n    	function nuPopulateSelectObject() {\n    	\n    		var p = $j;\n    \n    		$(\'#$selectId\').empty();\n    		\n    		if (\'$removeBlank\' == \'0\' ) {\n    		    $(\'#$selectId\').append(\'<option value=\\\"\\\"></option>\');\n    		}\n            \n            var count = 0;\n    \n    		if (p != \'\') {\n    		    var s = nuIsSaved();\n    			\n    			for (var i = 0; i < p.length; i++) {\n    				$(\'#$selectId\').append(\'<option value=\\\"\' + p[i][0] + \'\\\">\' + p[i][1] + \'</option>\');\n    				count ++;\n    			}\n    			\n    			if (s) { nuHasNotBeenEdited(); }\n    			\n    		}\n    		\n    		return count;\n    	}\n    	\n    	var nuSelectObjectRefreshedCount = nuPopulateSelectObject();\n\n    \".$cb;\n    }\n\n}\n\nfunction nu_refresh_select_object($selectId, $formIdHk, $removeBlank, $prefixHK) {\n\n    if (!nuHasProperty($formIdHk, $formId, false)) {\n        $formId = \'#form_id#\';\n    }\n\n    if (!nuHasProperty($prefixHK, $prefix, false)) {\n        $prefix = \'\';\n    }\n\n    $js = nuPopulateSelectObject($formId, $selectId, $removeBlank, $prefix);\n    nuJavaScriptCallback($js);\n\n}\n\nnu_refresh_select_object(\'#nu_refresh_select_object_selectid#\', \'nu_refresh_select_object_formid\', \'#nu_refresh_select_object_removeblank#\',\'nu_refresh_select_object_prefix\');', NULL, NULL, 'hide', '', '1', '1', '1', '0', '', NULL),
('nu5ff8249659aef00', 'nu_refresh_display_object', 'Refresh a display object', 'nubuilder', 'Object', '1', 'function nuGetDisplayValue($formId, $id) {\n\n    $sql = \"SELECT sob_display_sql, sob_display_procedure FROM `zzzzsys_object` WHERE sob_all_zzzzsys_form_id = ? AND sob_all_id = ?\";\n    $selectObject = nuRunQuery($sql, [$formId, $id]);\n\n    if (db_num_rows($selectObject) == 1) {\n        $obj = db_fetch_object($selectObject);\n\n        if ($obj != false) {\n\n            $displayProcedure = $obj->sob_display_procedure;\n\n            if (empty($displayProcedure)) {\n\n                $disS = nuReplaceHashVariables($obj->sob_display_sql);\n                $disT = nuRunQuery($disS);\n\n                if (db_num_rows($disT) >= 1) {\n                    $disR = db_fetch_row($disT);\n                    return $disR[0];\n                } else {\n                    return \"\";\n                }\n\n            } else {\n\n                $procedureCode = nuProcedure($displayProcedure);\n                if ($procedureCode !== \'\') {\n                    return nuEval($displayProcedure, $procedureCode);\n                } else {\n                    return false;\n                }\n            }\n        }\n    }\n\n    return false;\n}\n\n\nfunction nuRefreshDisplayObject() {\n\n    $HKPREFIX = \"nu_refresh_display_object_\";\n\n    if (!nuHasProperty(\"{$HKPREFIX}displayid\", $displayId, false)) {\n        return;\n    }\n\n    if (!nuHasProperty(\"{$HKPREFIX}formid\", $formId, false)) {\n        $formId = \'#form_id#\';\n    }\n\n    if (!nuHasProperty(\"{$HKPREFIX}prefix\", $prefix, false)) {\n        $prefix = \'\';\n    }\n\n\n    $value = nuGetDisplayValue($formId, $displayId);\n    $displayId = $prefix.$displayId;\n\n    if ($value === false && $value !== \'\') {\n        $js = \"nuMessage(nuTranslate(\'Error\'), nuTranslate(\'Failed to refresh the Display Object:\') + \' $displayId\'); \";\n    } else {\n\n        $value = base64_encode(json_encode($value));\n\n        $js = \"\n		    function nuRefreshDisplayObjectSetNewValue(displayId, value) {\n    			let obj = $(\'#\' + displayId);\n    			const format = obj.attr(\'data-nu-format\');\n    			const formattedValue = nuFORM.addFormatting(value, format);\n    			nuSetValue(displayId, formattedValue);\n		    }\n		    nuRefreshDisplayObjectSetNewValue(\'$displayId\', JSON.parse(atob(\'$value\')));\n			if (window.nuDisplayObjectRefreshed) {\n				nuDisplayObjectRefreshed(\'$displayId\', \'$formId\');\n			}\n		\";\n    }\n\n    nuJavaScriptCallback($js);\n\n}\n\nnuRefreshDisplayObject();', NULL, NULL, 'hide', '', '1', '1', '1', '0', '', NULL),
('nu6068bee1b6c63be', 'nu_run_add_db_column', 'Add a new database column', 'nubuilder', 'Database', '1', 'if (nuHash()[\'GLOBAL_ACCESS\'] == \'0\') return;\n\n$sql = \'ALTER TABLE `#sob_all_table#` ADD \' . \'#sql_query#\';\n$after = \'#sql_after_column#\';\nif ($after != \'\') {\n    $sql .= \" AFTER \" . $after;\n}\n\nif (preg_match(\'/DELETE |DROP |INSERT |;/\', strtoupper($sql))) {\n    $r = -2;\n} else {\n    $r = nuRunQuery($sql, [], true);\n}\n\nif ($r == 0) {\n    $js = \"$.nuInfoBar.success(nuTranslate(\'The column has been created successfully\')); \n           nuRefreshSelectObject(\'sql_after_column\'); \n           parent.nuUpdateMessage(\'refresh_required\');\";\n} else if ($r == -1) {\n    $js = \"$.nuInfoBar.error(nuTranslate(\'An error occurred while creating the column\') + \'. \' + nuTranslate(\'Check nuDebug Results for details\'));\";\n} else if ($r == -2) {\n    $js = \"$.nuInfoBar.error(nuTranslate(\'An error occurred while creating the column\') + \'. \' + nuTranslate(\'The query contains invalid keywords\'));\";\n}\n\nnuJavaScriptCallback($js);', NULL, NULL, 'hide', '', '1', '0', '0', '0', '', NULL),
('nu60f3f621d215470', 'nu_set_refresh_cache', 'Set marker to Refresh Form, Table schema', 'nubuilder', 'Session', '1', 'require(\'../nuconfig.php\');\n\nnuSetJSONDataAll(\'REFRESH_CACHE\',\'1\');\n\n$js = \"\n\nnuGetBreadcrumb();\n\nfunction nuMsgCacheRefreshed() {\n   nuMessage(nuTranslate(\'Information\'), nuTranslate(\'Cache Refreshed\'));\n}\nsetTimeout(nuMsgCacheRefreshed, 1000); \n\n\";\n\nnuJavaScriptCallback($js);\n\n', NULL, NULL, 'hide', '', '1', '0', '1', '0', '', NULL),
('nu60f8e2ea4d13aff', 'nu_import_users', 'Import users from a CSV file', 'nubuilder', 'User', '1', 'require_once(\'nusecurity.php\');\n\n$file = nuGetProperty(\'nu_import_users_file\');\n$delimiter = nuGetProperty(\'nu_import_users_delimiter\');\n\nnuImportUsersFromCSV(\"../temp/\".$file, $delimiter, \"\\n\");', NULL, NULL, 'window', NULL, '1', '0', '1', '0', '', NULL),
('nu610fd4ba4e73ede', 'nu_update_object', 'Update an Object\'s Properties', 'nubuilder', 'Object', '1', '$id = nuGetProperty(\'nu_update_object_id\');\n$value = nuGetProperty(\'nu_update_object_value\');\n$formId = nuGetProperty(\'nu_update_object_form_id\');\n$type = nuGetProperty(\'nu_update_object_type\');\n$column = nuGetProperty(\'nu_update_object_column\');\n$action = nuGetProperty(\'nu_update_object_action\');\n\nif ($action == \'move\') {\n\n        $query = \"\n            UPDATE\n                `zzzzsys_object`\n            SET\n                `sob_all_zzzzsys_tab_id` = ?\n            WHERE\n                `sob_all_zzzzsys_form_id` = ? AND `sob_all_id` = ?\n        \";\n\n        nuRunQuery($query, [$column, $formId, $id]);\n\n        $js = \"if (nuIsSaved()) {\n    	      nuGetBreadcrumb();\n    	   } else {\n    		  nuUpdateMessage(\'refresh_required\');\n    	}\";\n    	\n    	nuJavaScriptCallback($js);\n    	    \n        return;\n    \n}\n\nif ($action == \'delete\') {\n\n    $backupSQL = nuBuildInsertSQL(\n        \'zzzzsys_object\',\n        \'`sob_all_zzzzsys_form_id` = ? AND `sob_all_id` = ?\',\n        [$formId, $id]\n    );\n\n    nuDebug(\"Object $id Deleted in form $formId\", \"SQL to restore it:\", $backupSQL);\n\n    if ($type == \'tab\') {\n        // not in use yet\n\n        $query = \"\n            DELETE FROM `zzzzsys_tab`\n            WHERE `zzzzsys_tab_id` = ?\n        \";\n\n        nuRunQuery($query, [$id]);\n\n    } else if ($type == \'edit\') {\n\n        $query = \"\n            DELETE FROM `zzzzsys_object`\n            WHERE `sob_all_zzzzsys_form_id` = ? AND `sob_all_id` = ?\n        \";\n\n        nuRunQuery($query, [$formId, $id]);\n\n    } else {\n        // not in use yet\n\n        $query = \"\n            DELETE FROM `zzzzsys_browse`\n            WHERE `sbr_zzzzsys_form_id` = ? AND `sbr_order` = ?\n        \";\n\n        nuRunQuery($query, [$formId, $id]);\n\n    }\n\n\n    $js = \"nuHide(\'$id\')\";\n    nuJavaScriptCallback($js);\n\n    return;\n\n}\n\nif ($type == \'tab\') {\n\n    $query = \"\n            UPDATE `zzzzsys_tab`\n            SET $column = ?\n            WHERE `zzzzsys_tab_id` = ?\n    \";\n\n    nuRunQuery($query, [$value, $id]);\n\n} else if ($type == \'edit\') {\n\n    $query = \"\n        UPDATE `zzzzsys_object`\n        SET $column = ?\n        WHERE `sob_all_zzzzsys_form_id` = ? AND `sob_all_id` = ?\n    \";\n\n    nuRunQuery($query, [$value, $formId, $id]);\n\n} else {\n\n    $query = \"\n            UPDATE `zzzzsys_browse`\n            SET `$column` = ?\n            WHERE `sbr_zzzzsys_form_id` = ? AND `sbr_order` = ?\n    \";\n\n    nuRunQuery($query, [$value, $formId, $id]);\n\n}\n\nfunction nuBuildInsertSQL($table, $whereClause, $params) {\n    \n    $query = \"SELECT * FROM `$table` WHERE $whereClause\";\n    $result = nuRunQuery($query, $params);\n\n    if (db_num_rows($result) === 0) {\n        return null;\n    }\n\n    $row = db_fetch_array($result);\n\n    $columns = array_keys($row);\n\n    $values = array_map(function ($v) {\n        if (is_null($v)) {\n            return \'NULL\';\n        }\n        return \"\'\" . addslashes($v) . \"\'\";\n    },\n        array_values($row));\n\n    $colList = \'`\' . implode(\'`, `\',\n        $columns) . \'`\';\n    $valList = implode(\', \',\n        $values);\n\n    $insertSQL = \"INSERT INTO `$table` ($colList) VALUES ($valList);\";\n    return $insertSQL;\n    \n}', NULL, NULL, 'hide', NULL, '1', '0', '0', '0', '', NULL),
('nu61d8283e98e8b2e', 'nu_check_password_policy_template', 'Rules for enforcing Password policies', 'nubuilder', 'User', '1', 'function nuFATick($nok) {\n\n    $icon = $nok == false ? \"far fa-check-circle\" : \"far fa-times-circle\";\n    $color = $nok == false ? \"green\" : \"red\";\n    return \"&nbsp;&nbsp;<i class=\'$icon\' style=\'color:$color\'></i>&nbsp;&nbsp;\";\n\n}\n\nfunction nuCheckPasswordPolicy() {\n\n    $oldpw = \'#old_password#\';\n    $newpw = \'#new_password#\';\n\n    $atLeast = nuTranslate(\"Your New Password must contain at least\").\":\";\n    $msg = \'\';\n    $c = 0;\n\n    $check = strlen($newpw) < 8;\n    if ($check == true) $c++;\n    $msg .= nuFATick($check) . nuTranslate(\"8 Characters\") . \"<br>\";\n\n    $check = !preg_match(\"#[0-9]+#\", $newpw);\n    if ($check == true) $c++;\n    $msg .= nuFATick($check) . nuTranslate(\"1 Number\") . \"<br>\";\n\n    $check = !preg_match(\"#[A-Z]+#\", $newpw);\n    if ($check == true) $c++;\n    $msg .= nuFATick($check) . nuTranslate(\"1 Capital Letter\") . \"<br>\";\n\n    $check = !preg_match(\"#[a-z]+#\", $newpw);\n    if ($check == true) $c++;\n    $msg .= nuFATick($check) . nuTranslate(\"1 Lowercase Letter\") . \"<br>\";\n\n    $check = !preg_match(\'/[\\\'\\/~`\\!@#\\$%\\^&\\*\\(\\)_\\-\\+=\\{\\}\\[\\]\\|;:\"\\<\\>,\\.\\?\\\\\\]/\', $newpw);\n    if ($check == true) $c++;\n    $msg .= nuFATick($check) . nuTranslate(\"1 Special Character\") . \"<br>\";\n\n    if ($msg != $atLeast) $msg = $atLeast . \"<br><br>\" . $msg;\n\n    if ($newpw === $oldpw) {\n        $msg .= \"<br>\" . nuFATick(true) . nuTranslate(\"The provided New Password cannot be the same as the Current Password\") . \"<br>\";\n        $c++;\n    }\n\n    if ($c > 0) {\n        nuDisplayError($msg);\n        return false;\n    } else {\n        return true;\n    }\n\n}\n\n$check = nuCheckPasswordPolicy();', NULL, NULL, 'hide', '', '0', '1', '1', '1', '', NULL),
('nu61eceada0768c21', 'nu_change_password', 'Change user password', 'nubuilder', 'User', '1', '$oldPassword = \'#old_password#\';\n$newPasswordCheck = \'#new_password_check#\';\n$newPassword = \'#new_password#\';\n$session = \'#SESSION_ID#\';\n$userId = \"#USER_ID#\";\n\n\n\n//--\n\n$s = \"\n    SELECT sss_access\n    FROM zzzzsys_session\n    WHERE zzzzsys_session_id = ?\n\";\n\n$t = nuRunQuery($s, [$session]);\n$r = db_fetch_object($t);\n$j = json_decode($r->sss_access);\n\n//--\n\n$s = \"\n SELECT\n    sus_login_password,\n    sus_change_password\n FROM zzzzsys_user\n WHERE zzzzsys_user_id = ?\n\";\n\n$t = nuRunQuery($s, [$userId]);\n$r = db_fetch_object($t);\n$current = $r->sus_login_password;\n$changePassword = $r->sus_change_password;\n\n$useMd5 = $_SESSION[\'nubuilder_session_data\'][\'USE_MD5_PASSWORD_HASH\'] == true;\n\nif ($useMd5) {\n    $check = md5($oldPassword) == $current;\n} else {\n    $check = password_verify($oldPassword, $current);\n}\n\nif ($check == false) {\n    nuDisplayError(\'<h2>\' . nuTranslate(\'Error\') . \'</h2>\' . nuTranslate(\'Incorrect Password\'));\n    return;\n}\n\nif ($oldPassword == $newPassword) {\n\n    nuDisplayError(\'<h2>\' . nuTranslate(\'Error\') . \'</h2>\' . nuTranslate(\'Your new password cannot be the same as your old password\'));\n    return;\n}\n\nif ($oldPassword === \'\' || $newPassword === \'\') {\n    nuDisplayError(\'<h2>\' . nuTranslate(\'Error\') . \'</h2>\' . nuTranslate(\'The password cannot be left blank\'));\n    return;\n}\n\n\n//--\n\n$p = nuProcedure(\'nu_check_password_policy\');\n\nif ($p != \'\') {\n\n    eval($p);\n\n    if ($check == false) {\n        return;\n    }\n\n}\n\n//--\n\nif ($newPassword == $newPasswordCheck) {\n\n    $s = \"\n\n         UPDATE zzzzsys_user\n         SET\n            sus_login_password = ?,\n            sus_change_password = ?\n         WHERE zzzzsys_user_id = ?\n    \";\n\n    $pwHash = $useMd5 == true ? md5($newPassword) : nuPasswordHash($newPassword);\n\n    nuRunQuery($s, [$pwHash, \'0\', $userId]);\n\n    nuSetUserJSONData(\'PASSWORD_CHANGED_TIME\', time(), $userId);\n    nuSetUserJSONData(\'PASSWORD_CHANGED_SOURCE\', \'user\', $userId);\n\n\n\n    if (nuObjKey($_SESSION[\'nubuilder_session_data\'], \'SESSION_CHANGE_PW_STATUS\') == \'PENDING\') {\n        $_SESSION[\'nubuilder_session_data\'][\'SESSION_CHANGE_PW_STATUS\'] = \'CHANGED\';\n    }\n\n    $js = \"\n        function nuMsgAfterPasswordChange() {\n            if (\'$changePassword\' == \'1\') {\n                nuLogout();\n            }\n        }\n        nuMessage(nuTranslate(\'Information\'), nuTranslate(\'Your password has been successfully changed\'), 1500, nuMsgAfterPasswordChange);\n    \";\n\n\n} else {\n    $msg = nuTranslate(\'\"New Password\" must be the same as \"Confirm New Password\"\');\n    $js = \"nuMessage(nuTranslate(\'Error\'), \'$msg\');\";\n}\n\n\nnuJavaScriptCallback($js);', NULL, NULL, 'hide', '', '1', '1', '1', '0', '', NULL),
('nu62afe0e1933ee3b_BE', 'nu62afe0e1933ee3b_BE', 'System PHP', 'nubuilder', NULL, '1', 'require_once(\'nusetuplibs.php\');\n\n$config = nuConfigScript();\n$configCode = $config[\'code\'];\n$configJS = $config[\'js\'];\n\n$configJS = $configJS == null ? \"\" : $configJS. \" \" . \"nuHide(\'nuconfigsettingsfromdb_hint\'); \";\n\n\nif ($configCode != null) {\n    eval($config[\'code\']);\n}\n\nnuAddJavaScript($configJS);\n\n\nif (isset($_SESSION[\'nubuilder_session_data\'][\'USER_ADDITIONAL1_LABEL\']) && isset($nuConfigUserAdditional1Label)) {\n    $_SESSION[\'nubuilder_session_data\'][\'USER_ADDITIONAL1_LABEL\'] = $nuConfigUserAdditional1Label;\n}    \n\nif (isset($_SESSION[\'nubuilder_session_data\'][\'USER_ADDITIONAL2_LABEL\']) && isset($nuConfigUserAdditional2Label)) {\n    $_SESSION[\'nubuilder_session_data\'][\'USER_ADDITIONAL2_LABEL\'] = $nuConfigUserAdditional2Label;\n}\n\nif (isset($_SESSION[\'nubuilder_session_data\'][\'USER_CODE_LABEL\']) && isset($nuConfigUserCodeLabel)) {\n    $_SESSION[\'nubuilder_session_data\'][\'USER_CODE_LABEL\'] = $nuConfigUserCodeLabel;\n}\n\nnuAddJavaScript (\" \n   nuSERVERRESPONSE.buttons.Clone = \'0\';\n   nuSERVERRESPONSE.buttons.Delete = \'0\';\n\", true);', NULL, NULL, NULL, NULL, '1', '0', '1', '0', NULL, NULL),
('nu62bdc77f2dc0351', 'nu_generate_uid_list', 'Generate nuID List', 'nubuilder', 'Dev', '1', '// Call: nuRunPHP(\'nu_generate_uid_list\',\'\',0)\n\nfor ($x = 0; $x <= 1000; $x++) {\n  echo nuID().\"<br>\";\n}', NULL, NULL, 'window', '', '1', '1', '1', '0', '', NULL),
('nu62c488df22285ea', 'nu_dump_form_codes', 'Dump form js and php codes  to files', 'nubuilder', 'Dev', '1', 'if (!nuGlobalAccess()) {\n    return;\n}\n\n// PHP\n$s = \"SELECT sph_code, sph_php FROM `zzzzsys_php`\";\n$t = nuRunQuery($s);\n\nwhile ($r = db_fetch_object($t)) {\n    nuSetupDumpCodeFile(\'php_codes\', $r->sph_code, $r->sph_php, \'\', \"php\");\n}\n\n// Object events\n$s = \"\n    SELECT\n        CONCAT(sfo_code, \'_\', sob_all_id, \'_\', zzzzsys_event_id) as id,\n        sev_javascript\n    FROM\n        zzzzsys_object\n    JOIN zzzzsys_event ON zzzzsys_event.sev_zzzzsys_object_id = zzzzsys_object.zzzzsys_object_id\n    JOIN zzzzsys_tab ON zzzzsys_tab_id = sob_all_zzzzsys_tab_id\n    JOIN zzzzsys_form ON zzzzsys_form_id = syt_zzzzsys_form_id\n    WHERE\n        IFNULL(sev_javascript, \'\') <> \'\'\n\";\n\n$t = nuRunQuery($s);\nwhile ($r = db_fetch_object($t)) {\n    nuSetupDumpCodeFile(\'object_events\', $r->id, $r->sev_javascript, \'\', \"js\");\n}\n\n\n// Form JS\n$s = \"SELECT sfo_code, sfo_javascript, sfo_browse_javascript, sfo_edit_javascript FROM `zzzzsys_form`\";\n$t = nuRunQuery($s);\n\nwhile ($r = db_fetch_object($t)) {\n\n    nuSetupDumpCodeFile(\'js_codes\', $r->sfo_code, $r->sfo_javascript, \'sfo_javascript\', \"js\");\n    nuSetupDumpCodeFile(\'js_codes\', $r->sfo_code, $r->sfo_edit_javascript, \'sfo_edit_javascript\', \"js\");\n    nuSetupDumpCodeFile(\'js_codes\', $r->sfo_code, $r->sfo_browse_javascript, \'sfo_browse_javascript\', \"js\");\n\n}\n\n\nfunction nuSetupDumpCodeFile($folder, $sfoCode, $code, $postfix, $extension) {\n    $postfix = $postfix == \'\' ? \'\' : \"_\" . $postfix;\n    $file = $sfoCode . $postfix . \".\" . $extension;\n    $code = $code == NULL ? \'\' : $code;\n\n    if (strlen($code) > 0) {\n        $dir = dirname(__DIR__, 1) . DIRECTORY_SEPARATOR . \"form_codes\" . DIRECTORY_SEPARATOR . $folder . DIRECTORY_SEPARATOR;\n\n        if (!file_exists($dir)) {\n            mkdir($dir, 0777, true);\n        }\n\n        $file_path = $dir . $file;\n        file_put_contents($file_path, $code);\n    }\n}', NULL, NULL, 'hide', '', '1', '0', '1', '0', '', NULL),
('nu62da72900a02b9a', 'nu_upload_file_template', 'Upload Files Template', 'nubuilder', 'File Upload', '1', '$allowedTypes = [\n    // Documents\n    \'application/pdf\',\n    \'application/msword\',\n    \'application/vnd.openxmlformats-officedocument.wordprocessingml.document\',\n    \'application/rtf\',\n\n    // Spreadsheets\n    \'application/vnd.ms-excel\',\n    \'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet\',\n\n    // Presentations\n    \'application/vnd.ms-powerpoint\',\n    \'application/vnd.openxmlformats-officedocument.presentationml.presentation\',\n\n    // Text / Code\n    \'text/plain\',\n    \'text/csv\',\n    \'application/json\',\n    \'application/xml\',\n    \'text/xml\',\n    \'application/javascript\',\n    \'text/html\',\n    \'text/css\',\n\n    // Archives\n    \'application/zip\',\n    \'application/x-rar-compressed\',\n    \'application/x-7z-compressed\',\n\n    // Images\n    \'image/png\',\n    \'image/jpeg\',\n    \'image/svg+xml\',\n    \n    // Media\n    \'audio/mpeg\',\n    \'video/mp4\'\n];\n\n// Maximum file size\n$maxFileSize = 5 * 1024 * 1024; // (5 MB)\n\n// Target directory\n$targetDirectory = $_SERVER[\'DOCUMENT_ROOT\'] . \'/\';\n// $targetDirectory = \'../uploads/\';\n\n// Ensure the directory exists\nif (!is_dir($targetDirectory)) {\n    mkdir($targetDirectory, 0755, true);\n}\n\ntry {\n\n    // Sanitize file name\n    $fileName = nuSanitizeFilename(basename($_FILES[\'file\'][\'name\']));\n\n    // Check file size\n    if ($_FILES[\'file\'][\'size\'] > $maxFileSize) {\n        throw new Exception(\'Exceeded file size limit\');\n    }\n\n    // Check file type\n    $finfo = new finfo(FILEINFO_MIME_TYPE);\n    if (!in_array($finfo->file($_FILES[\'file\'][\'tmp_name\']), $allowedTypes)) {\n        throw new Exception(\'Invalid file type\');\n    }\n\n    // Build target file path\n    $targetFile = $targetDirectory . $fileName;\n\n    if (move_uploaded_file($_FILES[\'file\'][\'tmp_name\'], $targetFile)) {\n        $data = [\'url\' => $targetFile,\n            \'file\' => $fileName,\n            \'message\' => \'The file \' . $fileName . \' has been uploaded.\'];\n        http_response_code(201);\n        $result = json_encode($data);\n    } else {\n        throw new Exception(nuTranslate(\'Unable to move the uploaded file to its final location:\') . $targetFile);\n    }\n\n} catch(\\Throwable $th) {\n\n    $result = nuSetUploadError(\'Sorry, there was an error uploading your file.\');\n\n}', NULL, NULL, 'hide', '', '0', '1', '1', '1', '', NULL),
('nu6401bbc46484fe0', 'nu_debug_result_added_template', 'nuDebug Result Added Template', 'nubuilder', 'Debugging', '1', '$body = \"Debug ID: $nuDebugId <br><br>Debug Message: \" . nl2br($nuDebugMsg) . \"<br><br>User ID: $nuDebugUserId <br><br>Flag: $nuDebugFlag\";\n\n$to = \'your_email_address_here\';\n\n$subject = \'[nuBuilder] nuDebug Information Added\';\n\nnuSendEmail([\n    \'to\' => $to,\n    \'body\' => $body,\n    \'subject\' => $subject\n]);\n', NULL, NULL, 'hide', '', '0', '1', '1', '1', '', NULL),
('nu6454bcdad05d10e', 'nu_version_info', 'Display Version information', 'nubuilder', 'Information', '1', '$databaseSql = \"SELECT CONCAT(@@version_comment, \' \', @@version)\";\n$nuDbSql = \"SELECT inf_details FROM zzzzsys_info WHERE inf_code = ?\";\n$nuDbVersion = db_fetch_row(nuRunQuery($nuDbSql, [\'nuDBVersion\']))[0];\n$nuFilesVersion = db_fetch_row(nuRunQuery($nuDbSql, [\'nuFilesVersion\']))[0];\n\n$versionInfo =\n\'<h2>Version Info</h2><br>\' .\n\'Database: \' . db_fetch_row(nuRunQuery($databaseSql))[0] . \'<br>\' .\n\'PHP: \' . phpversion() . \'<br>\' .\n\'nuBuilder DB: \' . $nuDbVersion . \'<br>\' .\n\'nuBuilder Files: \' . $nuFilesVersion;\n\n$js = \"nuMessage(\'$versionInfo\').css(\'max-width\',\'400px\')\";\nnuJavaScriptCallback($js);', NULL, NULL, 'hide', '', '1', '0', '1', '0', '', NULL),
('nu64f9c4ec5f59275', 'nu_send_welcome_email_template', 'Procedure is called when \"Send welcome email\" is checked in the user form', 'nubuilder', 'Email', '1', '/*\n$userSavedInfo = nuUserSavedInfo();\n\n$changePassword = $userSavedInfo[\"change_password\"];\n$newUser = $userSavedInfo[\"new_user\"];\n*/\n\n\n// Retrieve the template data (Template code, language, group)\n$template = nuGetEmailTemplateData(\"nuWelcomeEmailTemplate\", \'\', \'nubuilder\');\nif ($template == false) {\n    nuDisplayError(\'Unknown email template!\');\n    return;\n}\n\n$sendResult = sendEmailFromTemplate($template);\nif ($sendResult[0] != true) {\n    nuDisplayError($sendResult[1].\'<br>\'.$sendResult[2]);\n}\n\n// Sends an email message using an email template.\nfunction sendEmailFromTemplate($template) {\n\n    $body = str_replace(\'#\'.\'NUBUILDER_URL\'.\'#\', nuGetHttpOrigin() , $template[\'body\']);\n\n    $params = array(\n        \'to\' => $template[\'to\'],\n        \'cc\' => $template[\'cc\'],\n        \'bcc\' => $template[\'bcc\'],\n        \'body\' => nl2br($body),\n        \'subject\' => $template[\'subject\']\n    );\n\n    // Replace all Hash Cookies\n    foreach ($params as $key => $value) {\n        $params[$key] = nuReplaceHashVariables($value);\n    }\n\n    return nuSendEmail($params);\n\n}', NULL, NULL, 'hide', '', '0', '1', '1', '1', '', NULL),
('nu65046f695d2ff3d', 'nu_create_test_user', 'Create a test user', 'nubuilder', 'Dev', '1', '$password = \'$2y$10$WqzRBCCDuPvyyq3Us53kFewUa02vhlT9NhZz5IOITVz3N8ZOSWgIu\'; // test\n\n$qry = \"\n    REPLACE\n    INTO `zzzzsys_user`(\n        `zzzzsys_user_id`,\n        `sus_zzzzsys_access_id`,\n        `sus_language`,\n        `sus_name`,\n        `sus_code`,\n        `sus_position`,\n        `sus_department`,\n        `sus_team`,\n        `sus_email`,\n        `sus_additional1`,\n        `sus_additional2`,\n        `sus_login_name`,\n        `sus_login_password`,\n        `sus_expires_on`,\n        `sus_change_password`,\n        `sus_accessibility_features`,\n        `sus_json`\n    )\n    VALUES(\n        \'test65046e167e07b56\',\n        \'test6505159c7272cf6\',\n        NULL,\n        \'test\',\n        \'test\',\n        \'pos1\',\n        \'dep1\',\n        \'test\',\n        NULL,\n        \'add1\',\n        \'add2\',\n        \'test\',\n        \'$password\',\n        NULL,\n        \'0\',\n        NULL,\n        NULL\n    );\n    \n    REPLACE INTO `zzzzsys_access` (`zzzzsys_access_id`, `sal_code`, `sal_description`, `sal_group`, `sal_zzzzsys_form_id`, `sal_use_2fa`, `sal_json`)\n    VALUES (\'test6505159c7272cf6\', \'test\', \'test\', \'test\', \'nuuserhome\', NULL, NULL);\n    \n    REPLACE INTO `zzzzsys_access_form` (`zzzzsys_access_form_id`, `slf_zzzzsys_access_id`, `slf_zzzzsys_form_id`, `slf_add_button`, `slf_save_button`, `slf_delete_button`, `slf_clone_button`, `slf_new_button`, `slf_print_button`, `slf_data_mode`, `slf_form_type`, `slf_json`)\n    VALUES\n    (\'test6505159c730ed6e\', \'test6505159c7272cf6\', \'nufile\', \'1\', \'1\', \'0\', \'1\', NULL, \'1\', NULL, NULL, NULL),\n    (\'test6505159c72cb67d\', \'test6505159c7272cf6\', \'nutranslate\', \'1\', \'1\', \'0\', \'1\', NULL, \'1\', NULL, NULL, NULL)\n\n\n\";\n\nnuRunQuery($qry);', NULL, NULL, 'hide', NULL, '1', '0', '1', '0', '', NULL),
('nu65d7dabf1036576_AB', 'nu65d7dabf1036576_AB', 'System PHP', 'nubuilder', NULL, '1', 'nuSetFormValue(\'upe_active\', \'1\');', NULL, NULL, NULL, NULL, '1', '0', '1', '0', NULL, NULL),
('nu65f27499be765b1_AB', 'nu5fe94c6815842ec_AB', 'System PHP', 'nubuilder', NULL, '1', 'nuSetFormValue(\'sph_code_snippet_paste\', nuLookupRecord()->cot_source_code);', NULL, NULL, NULL, NULL, '1', '0', '1', '0', NULL, NULL),
('nu67a6f7ac7964d96', 'nu_session_terminate', 'Terminate nuBuilder Sessions', 'nubuilder', 'Session', '1', '$option = nuGetProperty(\'nu_session_terminate_option\');\nif (!$option) {\n    nuRunQuery(\'DELETE FROM `zzzzsys_session`\');\n} else {\n    $sessionID = nuHash()[\"session_id\"];\n    nuRunQuery(\'DELETE FROM `zzzzsys_session` WHERE zzzzsys_session_id <> ?\', [$sessionID]);\n}', NULL, NULL, 'hide', '', '1', '0', '0', '0', '', NULL),
('nu67aa95468188689', 'nu_browse_delete_row', 'Delete a Browse row', 'nubuilder', 'Browse', '1', 'function nuDeleteRowGetFormTableInfo($formId) {\n\n    $sql = \"SELECT sfo_table, sfo_primary_key FROM `zzzzsys_form` WHERE `zzzzsys_form_id` = ?\";\n\n    $t = nuRunQuery($sql, [$formId]);\n    $r = db_fetch_object($t);\n\n    return [$r->sfo_table,\n        $r->sfo_primary_key];\n\n}\n\n\nfunction nuDeleteRowHasDeletePermission($formId) {\n\n    if (nuGlobalAccess()) {\n        return true;\n    }\n\n    $sql = \"SELECT * FROM zzzzsys_access_form WHERE slf_zzzzsys_access_id = ? AND slf_zzzzsys_form_id = ?\";\n\n    $t = nuRunQuery($sql, [$groupId, $formId]);\n    $r = db_fetch_object($t);\n\n    return $r->slf_delete_button == 1;\n}\n\nfunction nuDeleteRowDeleteRecord($formId, $recordId) {\n\n    if (nuDeleteRowHasDeletePermission($formId)) {\n\n        $tableInfo = nuDeleteRowGetFormTableInfo($formId);\n        $tableName = $tableInfo[0];\n        $tablePk = $tableInfo[1];\n\n        $qry = \"DELETE FROM `$tableName` WHERE `$tablePk` = ? \";\n\n        nuRunQuery($qry, [$recordId]);\n\n        // The function afterDeleteRow() must be declared in the form\'s Custom Code\n        $j = \"nuAfterDeleteRow();\";\n        nuJavascriptCallback($j);\n\n    } else {\n        nuDisplayError(nuTranslate(\"Delete is disabled for this Access Level\"));\n    }\n\n}\n\nnuDeleteRowDeleteRecord(\"#nu_browse_delete_row_form_id#\", \"#nu_browse_delete_row_record_id#\");', NULL, NULL, 'hide', '', '1', '0', '0', '0', '', NULL),
('nu67b5eba0a682823', 'nu_format_get_default', 'Get Default Input Format', 'nubuilder', 'Format', '1', '$inputType = nuGetProperty(\'nu_format_get_default_input_type\');\n$formats = nuGetDefaultFormats();\n$default = $formats[$inputType];\n\n$js = \"nuSetDefaultFormat(\'$default\'); \";\n\nnuJavaScriptCallback($js);', NULL, NULL, 'hide', '', '1', '0', '1', '0', '', NULL),
('nu682ce26ca553942', 'nu_get_access_levels_from_form', 'Copies Access Levels from one form to another', 'nubuilder', 'Access Level', '1', '$decodedParams = nuGetProperty(\'params\');\nif ($decodedParams) {\n	$parsedData = nuDecode($decodedParams);\n\n	// Retrieve form IDs\n	$sourceFormID = $parsedData[\'source_form_id\'] ?? \'\';\n	$destinationFormID = $parsedData[\'destination_form_id\'] ?? \'\';\n\n	// Retrieve boolean options (expected as 0 or 1)\n	$deleteAllExisting = isset($parsedData[\'delete_all_existing\']) ? (bool) $parsedData[\'delete_all_existing\'] : false;\n	$skipIfExists = isset($parsedData[\'skip_if_exists\']) ? (bool) $parsedData[\'skip_if_exists\'] : true;\n	$overwriteIfExists = isset($parsedData[\'overwrite_if_exists\']) ? (bool) $parsedData[\'overwrite_if_exists\'] : true;\n\n} \n\n// nuDebug($sourceFormID, $destinationFormID, $deleteAllExisting, $skipIfExists, $overwriteIfExists);\n\n// Validate mutually exclusive options\nif ($skipIfExists && $overwriteIfExists) {\n	$js = \" nuMessage(\\\"Error: \'skipIfExists\' and \'overwriteIfExists\' cannot both be set to true.\\\");\";\n\n	nuJavaScriptCallback($js);  \n	return;\n}\n\n// If deletion is enabled, remove existing rows with the new form ID\nif ($deleteAllExisting) { nuDebug(\'delete existing\');\n	$deleteSQL = \"DELETE FROM zzzzsys_access_form WHERE slf_zzzzsys_form_id = ?\";\n	$deleteResult = nuRunQuery($deleteSQL, [$destinationFormID], true);\n\n	// Check if the DELETE was successful\n	if ($deleteResult === -1) {\n		// Handle the error (optional)\n		$error = nuGetLastError();\n		nuDebug(\'Delete failed:\', $error);\n	}\n}\n\n// Prepare the SELECT query to fetch rows with the old form ID\n$selectSQL = \"\n    SELECT\n        slf_zzzzsys_access_id,\n        slf_add_button,\n        slf_save_button,\n        slf_delete_button,\n        slf_clone_button,\n        slf_new_button,\n        slf_print_button,\n        slf_data_mode,\n        slf_form_type,\n        slf_json\n    FROM\n        zzzzsys_access_form\n    WHERE\n        slf_zzzzsys_form_id = ?\n\";\n\n// Execute the SELECT query\n$stmt = nuRunQuery($selectSQL, [$sourceFormID]);\n\n// Loop through each fetched row\nwhile ($row = db_fetch_object($stmt)) {\n	// Check if a matching row exists in the new form\n	$checkSQL = \"\n        SELECT zzzzsys_access_form_id FROM zzzzsys_access_form\n        WHERE slf_zzzzsys_form_id = ? AND slf_zzzzsys_access_id = ?\n        LIMIT 1\n    \";\n	$checkStmt = nuRunQuery($checkSQL, [$destinationFormID, $row->slf_zzzzsys_access_id]);\n	$existingRow = db_fetch_object($checkStmt);\n\n	if ($existingRow) {\n		if ($skipIfExists) {\n			// Matching row exists, skip insertion\n			continue;\n		} elseif ($overwriteIfExists) {\n			// Delete the existing matching row\n			$deleteMatchSQL = \"\n                DELETE FROM zzzzsys_access_form\n                WHERE zzzzsys_access_form_id = ?\n            \";\n			$deleteMatchResult = nuRunQuery($deleteMatchSQL, [$existingRow->zzzzsys_access_form_id], true);\n\n			// Check if the DELETE was successful\n			if ($deleteMatchResult === -1) {\n				// Handle the error (optional)\n				$error = nuGetLastError();\n				nuDebug(\'Delete matching row failed:\', $error);\n				continue; // Skip insertion if deletion fails\n			}\n		} else {\n			// Matching row exists and neither skip nor overwrite is enabled, skip insertion\n			continue;\n		}\n	}\n\n	// Generate a new unique ID for the primary key\n	$newID = nuID();\n\n	// Prepare the INSERT query to duplicate the row with the new form ID and new primary key\n	$insertSQL = \"\n        INSERT INTO zzzzsys_access_form (\n            zzzzsys_access_form_id,\n            slf_zzzzsys_access_id,\n            slf_zzzzsys_form_id,\n            slf_add_button,\n            slf_save_button,\n            slf_delete_button,\n            slf_clone_button,\n            slf_new_button,\n            slf_print_button,\n            slf_data_mode,\n            slf_form_type,\n            slf_json\n        ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)\n    \";\n\n	// Execute the INSERT query with the new values\n	$params = [\n		$newID,\n		$row->slf_zzzzsys_access_id,\n		$destinationFormID,\n		$row->slf_add_button,\n		$row->slf_save_button,\n		$row->slf_delete_button,\n		$row->slf_clone_button,\n		$row->slf_new_button,\n		$row->slf_print_button,\n		$row->slf_data_mode,\n		$row->slf_form_type,\n		$row->slf_json\n	];\n\n	$result = nuRunQuery($insertSQL, $params, true);\n\n	// Check if the INSERT was successful\n	if ($result === -1) {\n		// Handle the error (optional)\n		$error = nuGetLastError();\n		nuDebug(\'Insert failed:\', $error);\n	}\n}\n\n\n$js = \" nuFormImportACLAfterRun();\";\nnuJavaScriptCallback($js); ', NULL, NULL, 'hide', '', '1', '0', '0', '0', '', NULL),
('nu682ddc25aa0bb5f_BB', 'nu682ddc25aa0bb5f_BB', 'System PHP', 'nubuilder', NULL, '1', '$query = \"\n\nSELECT\n    f.*,\n    COUNT(af.slf_zzzzsys_form_id) AS access_levels_count,\n    GROUP_CONCAT(a.sal_code ORDER BY a.sal_code SEPARATOR \', \') AS access_levels\nFROM\n    zzzzsys_form f\nLEFT JOIN zzzzsys_access_form af\n    ON af.slf_zzzzsys_form_id = f.zzzzsys_form_id\nLEFT JOIN zzzzsys_access a\n    ON a.zzzzsys_access_id = af.slf_zzzzsys_access_id\nWHERE\n    f.zzzzsys_form_id NOT LIKE \'nu%\'\n    AND f.sfo_type != \'subform\'\nGROUP BY\n    f.zzzzsys_form_id\nHAVING\n    access_levels_count > 0\nORDER BY\n    f.sfo_code \";\n\n\nnuCreateTableFromSelect(\'#TABLE_ID#\', $query);\n', NULL, NULL, NULL, NULL, '1', '0', '1', '0', NULL, NULL),
('nu683830320e3343b', 'nu_ai_prompt_generator_test_credentials', 'Testing AI Credentials', 'nubuilder', 'Generator', '1', 'include_once \'nuai.php\';\n\n\n$result = nuAITestCredentials();\n\nif ($result[\'success\']) {\n    // Credentials are good\n    echo $result[\'message\'];            // e.g. â€œCredentials are valid!â€\n} else {\n    // Something went wrong\n    // You can log full details if you like:\n   // error_log(\"OpenAI test failed ({$result[\'http_code\']}) Raw response: {$result[\'raw\']}\");\n    \n    // And display a userâ€friendly message:\n    echo \"Error testing credentials: \" . $result[\'message\'];\n}', NULL, NULL, 'window', NULL, '1', '0', '1', '0', '', NULL),
('nu68394ef10bf2cc9', 'nu_ai_prompt_generator_call_api', 'AI Prompt Generator ', 'nubuilder', 'Generator', '1', 'include_once \'nuai.php\';\n\n// 1. Fetch the raw JSON params\n$paramsJson = nuGetProperty(\'nuaipromptgenerator_params\');\nif (empty($paramsJson)) {\n    return; // nothing to do\n}\n\n// 2. Decode\n$params       = nuDecode($paramsJson);\n$procedure    = $params[\'procedure_type\'] ?? null;\n$buttonId     = $params[\'buttonId\']       ?? null;\n\n// 3. Dispatch based on procedure_type\nswitch ($procedure) {\n    case \'response\':\n        $response     = nuAIPromptGetResponse($params);\n        $callbackName = \'nuGeneratorResponseExecuted\';\n        break;\n\n    case \'tag\':\n        $response     = nuAIPromptGetTagsFromPrompt($params);\n        $callbackName = \'nuGeneratorExecutedTags\';\n        break;\n\n    // --- add new cases here ---\n    // case \'something_else\':\n    //     $response     = nuAIPromptDoSomethingElse($params);\n    //     $callbackName = \'nuGeneratorSomethingElseExecuted\';\n    //     break;\n\n    default:\n        // unknown procedure â€” return or fire a generic error callback\n        $errorMsg = json_encode(\"Unknown procedure: {$procedure}\");\n        nuJavaScriptCallback(\"(function(){ console.error({$errorMsg}); })();\");\n        return;\n}\n\n// 4. Determine error vs. success\n$isError = ! empty($response[\'error\']);\n$payload = $isError\n    ? $response[\'message\']\n    : $response[\'result\'];\n\n// 5. JSON-encode for JS\n$buttonJs = json_encode($buttonId, JSON_UNESCAPED_SLASHES | JSON_UNESCAPED_UNICODE);\n$dataJs   = json_encode($payload,  JSON_UNESCAPED_SLASHES | JSON_UNESCAPED_UNICODE);\n\n// 6. Build & fire the callback\n$js = sprintf(\n    \"(function(){%s(%s, %s, %s);})();\",\n    $callbackName,\n    $buttonJs,\n    $dataJs,\n    $isError ? \'false\' : \'true\'\n);\n\nnuJavaScriptCallback($js);\n', NULL, NULL, 'hide', '', '1', '0', '1', '0', '', NULL),
('nu68397bb77c048bb_BB', 'nu68397bb77c048bb_BB', 'System PHP', 'nubuilder', NULL, '1', '$denied = $GLOBALS[\'nuSetup\']->set_denied == 1;\n\n$condition = $denied\n    ? \"(zzzzsys_item_id NOT LIKE \'nu%\')\"\n    : \"1=1\";\n\n$sql = \"\n    SELECT\n        zzzzsys_item_id,\n        itm_value,\n        itm_description,\n        itm_category,\n        itm_object_id,\n        itm_tag,\n        itm_language,\n        sob_all_id,\n        sfo_code,\n        itm_active,\n        itm_created_on,\n        itm_updated_on,\n        itm_sort_order,\n        sob_all_zzzzsys_form_id\n    FROM\n        zzzzsys_item\n    LEFT JOIN zzzzsys_object ON zzzzsys_object_id = itm_object_id\n    LEFT JOIN zzzzsys_form ON zzzzsys_form_id = zzzzsys_object.sob_all_zzzzsys_form_id\n    WHERE\n        $condition\n    ORDER BY\n        sfo_code ASC,\n        sob_all_id ASC,\n        itm_value ASC\n\";\n\n\nnuCreateTableFromSelect(\'#TABLE_ID#\', $sql);', NULL, NULL, NULL, NULL, '1', '0', '1', '0', NULL, NULL);
INSERT INTO `zzzzsys_php` (`zzzzsys_php_id`, `sph_code`, `sph_description`, `sph_group`, `sph_category`, `sph_status`, `sph_php`, `sph_javascript`, `sph_javascript_active`, `sph_run`, `sph_zzzzsys_form_id`, `sph_system`, `sph_global`, `sph_demo`, `sph_template`, `sph_hide`, `sph_json`) VALUES
('nu683f01deaab6666', 'nu_inspect_record', 'Inspect a Record\'s Columns and Values', 'nubuilder', 'Debugging', '1', '$table = nuGetProperty(\'nu_inspect_record_table\');\n$record_id = nuGetProperty(\'nu_inspect_record_record_id\');\n\n$style = \"<style>\n.responsive-table {\n  overflow-x: auto;\n}\n\n.styled-table {\n  width: 100%;\n  border-collapse: collapse;\n  font-family: Arial, sans-serif;\n  margin-top: 1em;\n}\n\n.styled-table thead {\n  background-color: #f2f2f2;\n  cursor: pointer;\n}\n\n.styled-table th, .styled-table td {\n  border: 1px solid #ddd;\n  padding: 8px 12px;\n  user-select: text;\n}\n\n.styled-table tbody tr:nth-child(odd) {\n  background-color: #fafafa;\n}\n\n.styled-table tbody tr:nth-child(even) {\n  background-color: #f5f5f5;\n}\n\n.styled-table thead th {\n  position: sticky;\n  top: 0;\n  background-color: #f2f2f2;\n  z-index: 2;\n  user-select: all;\n}\n\ncode {\n  font-family: monospace;\n  padding: 2px 4px;\n  border-radius: 3px;\n}\n\n.filter-controls label {\n  user-select: none;\n}\n\n.filter-controls select {\n  user-select: none;\n  -webkit-user-select: none;\n  -moz-user-select: none;\n}\n\n.filter-controls select {\n  padding: 4px 8px;\n  font-size: 14px;\n}\n\n.sort-icon {\n  margin-left: 5px;\n  opacity: 0.6;\n}\n\n.copy-icon {\n  margin-left: 8px;\n  cursor: pointer;\n  color: #5a5a5a;\n}\n</style>\";\n\n$link = \'<link rel=\"stylesheet\" href=\"../third_party/fontawesome/css/all.min.css\">\';\n\n$script = <<<JS\n<script>\nfunction filterRows() {\n	const select = document.getElementById(\'columnFilter\');\n	const rows = document.querySelectorAll(\'.styled-table tbody tr\');\n	const mode = select.value;\n\n	rows.forEach(row => {\n		const valueCell = row.querySelector(\'td:nth-child(3)\');\n		const text = valueCell.textContent.trim();\n		const isEmpty = text === \'\' || text === \'NULL\';\n		const isNonEmpty = !isEmpty;\n\n		if (mode === \'all\') {\n			row.style.display = \'\';\n		} else if (mode === \'nonempty\' && isNonEmpty) {\n			row.style.display = \'\';\n		} else if (mode === \'empty\' && isEmpty) {\n			row.style.display = \'\';\n		} else {\n			row.style.display = \'none\';\n		}\n	});\n}\n\nlet currentSort = { column: -1, direction: \'\' };\nfunction sortTable(columnIndex) {\n	const table = document.querySelector(\'.styled-table tbody\');\n	const rows = Array.from(table.rows);\n	const headers = document.querySelectorAll(\'.styled-table thead th\');\n\n	headers.forEach((th, i) => {\n		const icon = th.querySelector(\'.sort-icon\');\n		if (icon) icon.className = \'fa-solid sort-icon\';\n	});\n\n	let direction = \'asc\';\n	if (currentSort.column === columnIndex && currentSort.direction === \'asc\') direction = \'desc\';\n\n	rows.sort((a, b) => {\n		let aText = a.cells[columnIndex].innerText.trim().toLowerCase();\n		let bText = b.cells[columnIndex].innerText.trim().toLowerCase();\n		return (direction === \'asc\') ? aText.localeCompare(bText) : bText.localeCompare(aText);\n	});\n\n	rows.forEach(row => table.appendChild(row));\n\n	const icon = headers[columnIndex].querySelector(\'.sort-icon\');\n	if (icon) icon.classList.add(direction === \'asc\' ? \'fa-caret-up\' : \'fa-caret-down\');\n\n	currentSort = { column: columnIndex, direction };\n}\n\nfunction copyToClipboard(icon) {\n	const value = icon.getAttribute(\'data-value\');\n	navigator.clipboard.writeText(value);\n\n	icon.classList.remove(\"fa-copy\");\n	icon.classList.add(\"fa-solid\",\"fa-check\");\n\n	setTimeout(() => {\n		icon.classList.remove(\"fa-solid\",\"fa-check\");\n		icon.classList.add(\"fa-copy\");\n	}, 550);\n}\n\n</script>\nJS;\n\n$columns_query = \"\n	SELECT COLUMN_NAME, COLUMN_TYPE, COLUMN_KEY, COLUMN_COMMENT\n	FROM INFORMATION_SCHEMA.COLUMNS\n	WHERE TABLE_SCHEMA = DATABASE()\n	  AND TABLE_NAME = \'$table\'\n	ORDER BY ORDINAL_POSITION\n\";\n\n$columns_result = nuRunQuery($columns_query);\n\n$fieldInfo = db_field_info($table);\n$primaryKeys = $fieldInfo[2] ?? [];\n$firstPrimaryKey = $primaryKeys[0] ?? null;\n\n$data_query = \"SELECT * FROM `$table` WHERE `$firstPrimaryKey` = \'$record_id\' LIMIT 1\";\n$data_result = nuRunQuery($data_query);\n$data_row = db_fetch_array($data_result);\n\necho \'<div class=\"responsive-table\">\';\necho $style . $link . $script;\n\necho \'<div class=\"filter-controls\">\';\necho \'<label for=\"columnFilter\"><strong>Show:</strong> </label>\';\necho \'<select id=\"columnFilter\" onchange=\"filterRows()\">\';\necho \'<option value=\"all\">All Columns</option>\';\necho \'<option value=\"nonempty\">Only Columns With a Value</option>\';\necho \'<option value=\"empty\">Only Empty/Null Columns</option>\';\necho \'</select>\';\necho \'</div>\';\n\necho \'<table class=\"styled-table\">\';\necho \'<thead><tr>\';\necho \'<th onclick=\"sortTable(0)\">Field <i class=\"fa-solid sort-icon\"></i></th>\';\necho \'<th onclick=\"sortTable(1)\">Type <i class=\"fa-solid sort-icon\"></i></th>\';\necho \'<th onclick=\"sortTable(2)\">Value <i class=\"fa-solid sort-icon\"></i></th>\';\necho \'</tr></thead>\';\necho \'<tbody>\';\n\nwhile ($col = db_fetch_array($columns_result)) {\n	$name = $col[\'COLUMN_NAME\'];\n	$type = $col[\'COLUMN_TYPE\'];\n	$key = $col[\'COLUMN_KEY\'];\n	$comment = $col[\'COLUMN_COMMENT\'];\n\n	$raw_value = $data_row[$name] ?? null;\n	$value = is_null($raw_value) ? \'<em>NULL</em>\' : htmlspecialchars($raw_value);\n\n	$icon = \'\';\n	$bg = \'\';\n	if ($key == \'PRI\') {\n		$icon = \' <i class=\"fa-solid fa-key\" style=\"color:goldenrod;\" title=\"Primary Key\"></i>\';\n		$bg = \' style=\"background-color:#fff8dc;\"\';\n	} elseif ($key == \'MUL\') {\n		$icon = \' <i class=\"fa-solid fa-key\" style=\"color:grey;\" title=\"Foreign Key\"></i>\';\n		$bg = \' style=\"background-color:#f5f5f5;\"\';\n	}\n\n	$raw_length = mb_strlen($raw_value ?? \'\');\n\n	if ($raw_value === null || $raw_length <= 200) {\n		$display_value = $value;\n		$tooltip = \'\';\n	} else {\n		$display_value = htmlspecialchars(mb_substr($raw_value, 0, 200)) . \'â€¦\';\n\n		$tooltip_content = mb_substr($raw_value, 0, 2000);\n		if ($raw_length > 2000) {\n			$tooltip_content .= \'â€¦\';\n		}\n\n		$tooltip = \' title=\"\' . htmlspecialchars($tooltip_content) . \'\"\';\n	}\n\n	$escaped_value = htmlspecialchars($raw_value ?? \'\', ENT_QUOTES);\n\n	if (is_null($raw_value) || $raw_value === \'\') {\n		$copy_icon = \'\';\n	} else {\n		$copy_icon = \"<i class=\'fa-regular fa-copy copy-icon\' title=\'Copy\' data-value=\'$escaped_value\' onclick=\'copyToClipboard(this)\'></i>\";\n	}\n\n	$field_title = $comment ? \' title=\"\' . htmlspecialchars($comment) . \'\"\' : \'\';\n\n	echo \"<tr>\";\n	echo \"<td$bg><strong$field_title>$name</strong>$icon</td>\";\n	echo \"<td$bg><code>$type</code></td>\";\n	echo \"<td$bg><code$tooltip>$display_value</code>$copy_icon</td>\";\n	echo \"</tr>\";\n}\n\necho \'</tbody></table></div>\';', NULL, NULL, 'window', NULL, '1', '0', '1', '0', '', NULL),
('nu683fd76e8963821', 'nu_run_alter_db_column', 'Alter a database column', 'nubuilder', 'Database', '1', 'if (nuHash()[\'GLOBAL_ACCESS\'] == \'0\') return;\n\n$sql = \'ALTER TABLE `#sob_all_table#` CHANGE `#sob_all_id#` \' . \'#sql_query#\';\n\nif (preg_match(\'/DELETE |DROP |INSERT |;/\', strtoupper($sql))) {\n    $r = -2;\n} else {\n    $r = nuRunQuery($sql, [], true);\n}\n\nif ($r == 0) {\n    nuSetJSONDataAll(\'REFRESH_CACHE\', \'1\');\n    $js = \"$.nuInfoBar.success(nuTranslate(\'The column has been altered successfully\'));\n           parent.nuUpdateMessage(\'refresh_required\');\";\n} else if ($r == -1) {\n    $js = \"$.nuInfoBar.error(nuTranslate(\'An error occurred while altering the column\') + \'. \' + nuTranslate(\'Check nuDebug Results for details\'));\";\n} else if ($r == -2) {\n    $js = \"$.nuInfoBar.error(nuTranslate(\'An error occurred while altering the column\') + \'. \' + nuTranslate(\'The query contains invalid keywords\'));\";\n}\n\nnuJavaScriptCallback($js);', NULL, NULL, 'hide', '', '1', '0', '0', '0', '', NULL),
('nu684d2e20baf5b67', 'nu_browse_add_tab', 'Add Browse Tab', 'nubuilder', 'Browse', '1', '$decodedParams = nuGetProperty(\'nu_browse_add_tab_params\');\n\nif ($decodedParams) {\n    $parsedData = nuDecode($decodedParams);\n\n    $formId = $parsedData[\'form_id\'] ?? \'\';\n    $title = $parsedData[\'title\']  ?? \'New Tab\';\n    $order = $parsedData[\'order\']  ?? 0;\n\n    nuBrowseAddNewTab($formId, $title, $order);\n    nuReorderBrowse($formId);\n\n    $js = \"if (nuIsSaved()) { nuGetBreadcrumb()} else { parent.nuUpdateMessage(\'refresh_required\')} \";\n    nuJavaScriptCallback($js);\n}\n\nfunction nuBrowseAddNewTab($formId, $title, $order) {\n\n    $tabId = nuID();\n\n    $sql = \"\n        INSERT INTO zzzzsys_tab (\n            zzzzsys_tab_id,\n            syt_zzzzsys_form_id,\n            syt_title,\n            syt_order\n        ) VALUES (\n            :tabId,\n            :formId,\n            :title,\n            :tabOrder\n        )\n    \";\n\n    nuRunQuery($sql, [\n        \':tabId\' => $tabId,\n        \':formId\' => $formId,\n        \':title\' => $title,\n        \':tabOrder\' => $order\n    ]);\n\n    return $tabId;\n}', NULL, NULL, 'hide', NULL, '1', '0', '0', '0', '', NULL),
('nu6866e2a9c6afd1c', 'nu_upload_file_load_uppy_code', 'Get Uppy html code', 'nubuilder', 'File Upload', NULL, 'function getNuRunFileUppyHtmlSourceCombined() {\n\n    $codes = [\'nu_upload_file_uppy_code_template\',\n        \'nu_upload_file_uppy_code\'];\n    foreach ($codes as $code) {\n        $source = db_fetch_value(\n            \'zzzzsys_code_snippet\',\n            \'cot_code\',\n            $code,\n            \'cot_source_code\'\n        );\n        if ($source) {\n            return $source;\n        }\n    }\n\n    return false;\n\n}\n\n$source = getNuRunFileUppyHtmlSourceCombined();\nif ($source !== false) {\n    $source = base64_encode(json_encode($source));\n    $js = \"let htmlCode = $(\'#sob_html_code\');\n        nuSetValue(\'sob_html_code\', htmlCode.val() + JSON.parse(atob(\'$source\'))); \";\n\n    nuJavaScriptCallback($js);\n}', NULL, NULL, 'window', NULL, '1', '0', '1', '0', '', NULL),
('nu6881aa082e6e173', 'nu_form_get_php', 'nubuilder', 'nubuilder', 'Dev', NULL, 'function nuFormGetPHP($record_id) {\n    return db_fetch_value(\'zzzzsys_php\', \'zzzzsys_php_id\', $record_id, \'sph_php\');\n}\n\n$val = nuEncode(nuFormGetPHP(\'nuuser_BB\'));\n$js = \"nuSetValue(\'nu-code-textarea-php-bb\', nuDecode(\'$val\'));\";\n\nnuJavaScriptCallback($js);\n\n\nnuDebug(nuEncode(\'1\'));', NULL, NULL, NULL, NULL, '1', '0', '1', '0', '', NULL),
('nuaipromptgenerator', 'nu_ai_prompt_generator_prompt', 'AI prompt Generator', 'nubuilder', 'Generator', '1', 'include_once \'nuai.php\';\n\n// Fetch and decode parameters\n$paramsJson = nuGetProperty(\'nuaipromptgenerator_prompt_params\');\nif (empty($paramsJson)) {\n    return; // nothing to do\n}\n\n$params = nuDecode($paramsJson);\n$copy = $params[\'copy\'] ?? false;\n\n$outputString = nuAIPromptBuildPromptInformation($params);\n\n// Embed safely into JavaScript via JSON encoding\n$jsOutput = json_encode($outputString, JSON_UNESCAPED_SLASHES | JSON_UNESCAPED_UNICODE);\n\n$js = <<<JS\n(function() {\n     const text = $jsOutput;\n     nuGeneratorExecuted(text, $copy); \n})();\nJS;\n\nnuJavaScriptCallback($js);\n', NULL, NULL, 'hide', NULL, '1', '0', '1', '0', '', NULL),
('nuappcloner', 'nu_app_cloner', 'nuBuilder Application Cloner', 'nubuilder', 'Cloner', NULL, 'include_once \'nuappcloner.php\';\n\n// Get parameters from the form\n$params = nuGetProperty(\'nu_app_cloner_params\');\nif (!$params) {\n    nuAppClonerCallback(\'Error\', \'Failed to retrieve parameters\');\n    return;\n}\n\n$params = nuDecode($params);\n\n// Extract all parameters\n$targetHost = $params[\'targetHost\'] ?? \'\';\n$targetDB = $params[\'targetDB\'] ?? \'\';\n$targetUsername = $params[\'targetUsername\'] ?? \'\';\n$targetPassword = $params[\'targetPassword\'] ?? \'\';\n$targetCharset = $params[\'targetCharset\'] ?? \'utf8mb4\';\n$targetPort = intval($params[\'targetPort\'] ?? 3306);\n$sourcePath = realpath($params[\'sourcePath\'] ?? \'..\');\n$targetPath = $params[\'targetPath\'] ?? \'\';\n$insertType = $params[\'insertType\'] ?? \'INSERT\';\n$opts = $params[\'opts\'] ?? [];\n$config = $params[\'config\'] ?? [];\n\n// Convert string \"true\"/\"false\" to boolean if needed\nforeach ($config as $key => $value) {\n    if ($value === \'true\') $config[$key] = true;\n    if ($value === \'false\') $config[$key] = false;\n}\n\n\n// Create cloner instance\n$cloner = new nuBuilderCloner($config);\n\n// Run the clone operation\n$success = $cloner->cloneDatabase(\n    $targetDB,\n    $targetHost,\n    $targetUsername,\n    $targetPassword,\n    $targetCharset,\n    $targetPort,\n    $opts,\n    $insertType,\n    $sourcePath,\n    $targetPath\n);\n\nfunction nuAppClonerCallback(string $type, string $message): void {\n    nuJavaScriptCallback(\"nuMessage(\'$type\', \'\" . addslashes($message) . \"\');\");\n}', 'function nuOnProcedureRun() {\n    nuSetProperty(\'nu_app_cloner_params\',\'xx\');\n}', '1', 'hide', NULL, '1', '0', '1', '0', '', NULL),
('nuappcloner_BE', 'nuappcloner_BE', 'System PHP', 'nubuilder', NULL, NULL, 'if (nuDemo()) return;\n\nglobal $nuConfigDBUser;\nglobal $nuConfigDBPassword;\n\n$js = \"\n    	if (nuIsNewRecord()) { debugger;\n            nuSetValue(\'cla_target_username\', \'$nuConfigDBUser\'); \n            nuSetValue(\'cla_target_password\', \'$nuConfigDBPassword\'); \n        };\n\";\n\nnuAddJavaScript($js);', NULL, NULL, NULL, NULL, '1', '0', '1', '0', NULL, NULL),
('nuauthentication_BE', 'nuauthentication_BE', 'System PHP', 'nubuilder', NULL, '1', '$devMode = nuReplaceHashVariables(\"#DEV_MODE#\");\n\n$t = $devMode == \'1\' ? \'_template\' : \'\';\n\n$p  = nuProcedure(\'nu_authentication_2fa\'.$t);	\n\nif($p != \'\') { \n    eval($p); \n} else {\n    nuDisplayError(nuTranslate(\'The Procedure nu_authentication_2fa does not exist.\'));    \n}', NULL, NULL, NULL, NULL, '1', '0', '1', '0', NULL, NULL),
('nubuildtable_BB', 'nubuildtable_BB', 'System PHP', 'nubuilder', NULL, '1', '$select = \"\n    SELECT\n     CONCAT(\n     \'PROCEDURE:\',\n     `zzzzsys_php`.`zzzzsys_php_id`\n     ) AS `zzzzsys_php_id`,\n     `zzzzsys_php`.`sph_code` ,\n     `zzzzsys_php`.`sph_description`\n    FROM\n     `zzzzsys_php`\n    WHERE\n     (\n     (`zzzzsys_php`.`sph_system` <> \'1\') \n     AND (LOCATE(\'{TABLE_ID}\', `zzzzsys_php`.`sph_php`) > \'0\') AND (`zzzzsys_php`.`sph_template` <> 1)\n     )\n     \n    UNION\n    \n    SELECT\n     CONCAT(\n     \'SQL:\',\n     `zzzzsys_select`.`zzzzsys_select_id`\n     ) AS `id`,\n     \'nuSQL\',\n     `zzzzsys_select`.`sse_description`\n    FROM\n     `zzzzsys_select`\n    WHERE\n     (\n     (\n     `zzzzsys_select`.`sse_system` IS NULL\n     ) OR(`zzzzsys_select`.`sse_system` = \'\')\n     )\n     \n    UNION\n    \n    SELECT\n     CONCAT(\n     \'TABLE:\',\n     `TABLE_NAME`\n     ) AS `id`,\n     \'nuTABLE\',\n     `TABLE_NAME` \n    FROM \n     `information_schema`.`tables` \n    WHERE \n     `TABLE_SCHEMA` = database()\n     AND `TABLE_NAME` NOT LIKE \'\\\\\\\\_%\' ESCAPE \'\\\\\\\\\'\n\";\n\n\n$select = str_replace(\"{TABLE_ID}\", \'#\'.\'TABLE_ID\'.\'#\', $select);\n\n$insert = \"\nINSERT INTO zzzzsys_report_data ( \n `zzzzsys_report_data_id`,\n `srd_code`,\n `srd_description`)\n\".$select;\n\n\nnuRunQuery(\'DELETE FROM `zzzzsys_report_data`\');\nnuRunQuery($insert);\n', NULL, NULL, NULL, NULL, '1', '0', '1', '0', NULL, NULL),
('nucalcobjects_BB', 'nucalcobjects_BB', 'System PHP', 'nubuilder', NULL, '1', '$select = \"\n\n    SELECT \n       sob_all_zzzzsys_form_id AS theform,\n       \'\' AS theparent,\n       sob_all_id AS thechild,\n       CONCAT(sob_all_id) as thevalue\n    FROM zzzzsys_object \n    WHERE sob_input_type = \'number\'\n    OR sob_all_type = \'calc\'\n    \n    UNION \n    \n    SELECT \n       su.sob_all_zzzzsys_form_id AS theform,\n       su.sob_all_id AS theparent,\n       inp.sob_all_id AS thechild,\n       CONCAT(su.sob_all_id, \'.\', inp.sob_all_id) as thevalue\n    FROM zzzzsys_object AS su\n    JOIN zzzzsys_object AS inp ON su.sob_subform_zzzzsys_form_id = inp.sob_all_zzzzsys_form_id\n    WHERE su.sob_all_type = \'subform\'\n    AND (\n            inp.sob_input_type = \'nuNumber\' OR \n            inp.sob_input_type = \'number\' OR \n            inp.sob_all_type = \'calc\'\n        )\n\n\";\n    \nnuCreateTableFromSelect(\'#TABLE_ID#\', $select);', NULL, NULL, '', '', '1', '0', '1', '0', '', NULL),
('nuclonerphp', 'nu_cloner', 'Clone Forms, Objects, Events, PHP etc.', 'nubuilder', 'Cloner', '1', 'function hashCookieSet($h) {\n    return !(preg_match(\'/\\#(.*)\\#/\', $h) || trim($h) == \"\");\n}\n\nfunction pkWithoutEvent($pk) {\n    return substr($pk, 0, -3);\n}\n\nfunction eventFromPk($pk) {\n    return substr($pk, -3);\n}\n\nfunction lookupPk($arr, $key) {\n    \n    $a = array_column($arr, $key);\n    return isset($a[0]) ? $a [0] : \'\';\n\n}\n\nfunction addToArray(array &$arr, $key, $value) {\n    array_push($arr, [$key => $value]);\n}\n\nfunction getPk($pk) {\n    return \"#cloner_new_pks#\" != \'0\' ? nuID() : $pk;\n}\n\nfunction getTabList() {\n\n    $t = \"#cloner_tabs#\";\n    return !hashCookieSet($t) || strlen($t) < 3 ? \"\" : implode(\',\', json_decode($t));\n\n}\n\nfunction getSubformList() {\n\n    $t = \"#cloner_subforms#\";\n    return !hashCookieSet($t) || strlen($t) < 3 ? \"\" : \"\'\".implode(\"\',\'\", json_decode($t)).\"\'\";\n\n}\n\nfunction getIframeFormList() {\n\n    $t = \"#cloner_iframe_forms#\";\n    return !hashCookieSet($t) || strlen($t) < 3 ? \"\" : \"\'\".implode(\"\',\'\", json_decode($t)).\"\'\";\n\n}\n\nfunction getFormSource(&$f1) {\n\n    $f1 = \"#cloner_form_source#\";\n    if (!hashCookieSet($f1)) {\n        $f1 = \"#form_id#\";\n        return true;\n    }\n\n    return formExists($f1);\n\n}\n\nfunction getFormDestination(&$f2) {\n\n    $f2 = \"#cloner_form_dest#\";\n    if (!hashCookieSet($f2)) {\n        $f2 = \"\";\n        return true;\n    }\n\n    return formExists($f2);\n\n}\n\nfunction formSQL() {\n    return \"SELECT * FROM zzzzsys_form WHERE zzzzsys_form_id  = ? LIMIT 1\";\n}\n\nfunction formExists($f) {\n\n    $t = nuRunQuery(formSQL(), [$f]);\n    return db_num_rows($t) == 1;\n\n}\n\nfunction echoPlainText($val) {\n\n    echo \'<pre>\';\n    echo htmlspecialchars($val);\n    echo \'</pre>\';\n\n}\n\nfunction dumpFormInfo($f, $dump) {\n\n    if ($dump != \'1\') return;\n\n    $fi = getFormInfo($f);\n    echo \"<b>\";\n    echo \"-- nuBuilder cloner SQL Dump \" . \"<br>\";\n    echo \"-- Version 1.21 \" . \"<br>\";\n    echo \"-- Generation Time: \" . date(\"F d, Y h:i:s A\") . \"<br><br>\";\n    echo \"-- Form Description: \" . $fi[\"description\"] . \"<br>\";\n    echo \"-- Form Code: \" . $fi[\"code\"] . \"<br>\";\n    echo \"-- Form Table: \" . $fi[\"table\"] . \"<br>\";\n    echo \"-- Form Type: \" . $fi[\"type\"] . \"<br><br>\";\n\n    $notes = \"#cloner_notes#\";\n    echo hashCookieSet($notes) ? \"-- Notes: \" . $notes . \"<br>\" . \"<br>\" : \"\";\n    echo \"</b>\";\n\n}\n\nfunction createStatement($table, $columns, $row) {\n\n    $params = array_map(function ($val) {\n        return \"?\";\n    }\n    , $row);\n\n    return getStatement() . \"$table (\" . implode(\', \', $columns) . \") VALUES ( \" . implode(\" , \", $params) . \" ) \";\n\n}\n\nfunction echoHeader($header) {\n\n    echo \"<br>--<br>\";\n    echo \"-- <b>\" . $header . \"</b><br>\";\n    echo \"--<br><br>\";\n    \n}\n\nfunction getStatement() {\n    return \"#cloner_replace_into#\" == \'1\' ? \'REPLACE INTO \' : \'INSERT INTO \';\n}\n\nfunction dumpStatement($table, $row, &$first, $ident) {\n\n    $values = join(\', \', array_map(function ($value) {\n        return $value === null ? \'NULL\' : db_quote($value);\n    }\n    , $row));\n\n    if (!isset($first)) {\n        $ident = $ident == \'\' ? \'\' : \': \'. $ident;\n        echoHeader($table. $ident);\n        $first = false;\n    }\n\n    echoPlainText(getStatement() . \"$table (\" . implode(\', \', array_keys($row)) . \") \");\n    echoPlainText(\"VALUES ( \" . $values . \" ); \");\n\n}\n\n\nfunction writeRecord($table, $row, &$first, $ident) {\n\n    if (\"#cloner_dump#\" == \'1\') {\n         dumpStatement($table, $row, $first, $ident);\n    }\n    else {\n        $i = createStatement($table, array_keys($row) , $row);\n        nuRunQuery($i, array_values($row) , true);\n    }\n\n}\n\nfunction getFormType($f) {\n\n    $t = nuRunQuery(formSQL() , [$f]);\n    $row = db_fetch_array($t);\n\n    return $row[\'sfo_type\'];\n\n}\n\nfunction getFormInfo($f) {\n\n    $t = nuRunQuery(formSQL() , [$f]);\n    $row = db_fetch_object($t);\n\n    return [\n        \"code\" => $row->sfo_code,\n        \"description\" => $row->sfo_description,\n        \"type\" => $row->sfo_type,\n        \"table\" => $row->sfo_table\n    ];\n\n}\n\nfunction getNewFormCode($code) {\n\n    if (\"#cloner_new_pks#\" == \'0\') {\n        return $code;\n    } else {    \n        $s = \"SELECT COUNT(zzzzsys_form_id) + 1 FROM zzzzsys_form WHERE sfo_code LIKE ?\";\n        $t = nuRunQuery($s, [$code . \'_clone%\']);\n        $r = db_fetch_row($t);\n        return $code . \'_clone_\' . $r[0];\n    }\n\n}\n\nfunction cloneForm($f1) {\n\n    $t = nuRunQuery(formSQL(), [$f1]);\n    $row = db_fetch_array($t);\n\n    $newPk = getPk($row[\'zzzzsys_form_id\']);\n    $row[\'zzzzsys_form_id\'] = $newPk;\n    $row[\'sfo_code\'] = getNewFormCode($row[\'sfo_code\']);\n\n    writeRecord(\'zzzzsys_form\', $row, $first, $row[\'sfo_code\']);\n\n    return $newPk;\n\n}\n\nfunction cloneFormPHP($f1, $f2) {\n\n    $s = \"\n        SELECT\n            zzzzsys_php.*\n        FROM\n            zzzzsys_php\n        LEFT JOIN zzzzsys_form ON zzzzsys_form_id = LEFT(zzzzsys_php_id, LENGTH(zzzzsys_php_id) - 3)\n        WHERE\n            zzzzsys_form_id = ?\n	\";\n\n    $t = nuRunQuery($s, [$f1]);\n\n    while ($row = db_fetch_array($t)) {\n\n        $event = eventFromPk($row[\'zzzzsys_php_id\']);\n        $row[\'zzzzsys_php_id\'] = $f2 . $event;\n        $row[\'sph_code\'] = $f2 . $event;\n\n        writeRecord(\'zzzzsys_php\', $row, $first, \'\');\n\n    }\n\n}\n\nfunction cloneFormTabs($f1, $f2, $postifx = \'\') {\n\n    $tabPks = [];\n    \n    $s = \"SELECT * FROM zzzzsys_tab AS tab1 WHERE syt_zzzzsys_form_id  = ?\".whereTabs();\n    $t = nuRunQuery($s, [$f1]);\n\n    while ($row = db_fetch_array($t)) {\n\n        $newPk = getPk($row[\'zzzzsys_tab_id\']);\n        addToArray($tabPks, $row[\'zzzzsys_tab_id\'], $newPk);\n        $row[\'zzzzsys_tab_id\'] = $newPk;\n        $row[\'syt_title\'] = $row[\'syt_title\'].$postifx;\n        $row[\'syt_zzzzsys_form_id\'] = $f2;\n\n        writeRecord(\'zzzzsys_tab\', $row, $first, \'\');\n\n    }\n\n    return $tabPks;\n\n}\n\nfunction cloneFormBrowse($f1, $f2) {\n\n    $s = \"SELECT * FROM zzzzsys_browse WHERE sbr_zzzzsys_form_id  = ?\";\n    $t = nuRunQuery($s, [$f1]);\n\n    while ($row = db_fetch_array($t)) {\n\n        $newPk = getPk($row[\'zzzzsys_browse_id\']);\n        $row[\'zzzzsys_browse_id\'] = $newPk;\n        $row[\'sbr_zzzzsys_form_id\'] = $f2;\n\n        writeRecord(\'zzzzsys_browse\', $row, $first, \'\');\n\n    }\n\n}\n\nfunction whereTabs() {\n    \n    $tabs = getTabList();\n    \n    return $tabs != \'\' ? \" AND tab1.syt_order DIV 10 IN ($tabs) \" : \"\";\n    \n}\n\n\nfunction getTabIds($f1, $f2) {\n\n    $s = \"    \n        SELECT\n            tab1.zzzzsys_tab_id AS tab1,\n            tab2.zzzzsys_tab_id AS tab2\n        FROM\n            zzzzsys_tab AS tab1\n        LEFT JOIN zzzzsys_tab AS tab2\n        ON\n            tab1.syt_order = tab2.syt_order\n        WHERE\n            tab1.syt_zzzzsys_form_id = ? AND tab2.syt_zzzzsys_form_id = ? \n    \".whereTabs();\n\n    $t = nuRunQuery($s, [$f1, $f2]);\n\n    $tabPks = [];\n    while ($r = db_fetch_object($t)) {\n        addToArray($tabPks, $r->tab1, $r->tab2);\n    }\n\n    return $tabPks;\n\n}\n\nfunction cloneObjects($f1, $f2, array &$objectPks, $tabPks) {\n\n    $s = \"SELECT * FROM zzzzsys_object WHERE sob_all_zzzzsys_form_id = ?\";\n    $t = nuRunQuery($s, [$f1]);\n  \n    while ($row = db_fetch_array($t)) {\n\n        $row[\'sob_all_zzzzsys_form_id\'] = $f2;\n\n        $newPk = getPk($row[\'zzzzsys_object_id\']);\n        addToArray($objectPks, $row[\'zzzzsys_object_id\'], $newPk);\n\n        $row[\'zzzzsys_object_id\'] = $newPk;\n\n        $tabId = lookupPk($tabPks, $row[\'sob_all_zzzzsys_tab_id\']);\n\n        $row[\'sob_all_zzzzsys_tab_id\'] = $tabId;\n\n        if ($tabId != \"\") writeRecord(\'zzzzsys_object\', $row, $first,\'\');\n\n    }\n\n}\n\nfunction cloneObjectsPHP($f1, $objectPks) {\n\n    $s = \"\n        SELECT\n           zzzzsys_php.* \n        FROM\n           zzzzsys_php \n           LEFT JOIN\n              zzzzsys_object \n              ON zzzzsys_object_id = LEFT(zzzzsys_php_id, LENGTH(zzzzsys_php_id) - 3) \n        WHERE\n           sob_all_zzzzsys_form_id = ?\n	\";\n\n    $t = nuRunQuery($s, [$f1]);\n\n    while ($row = db_fetch_array($t)) {\n\n        $event = eventFromPk($row[\'zzzzsys_php_id\']);\n        $row[\'zzzzsys_php_id\'] = lookupPk($objectPks, pkWithoutEvent($row[\'zzzzsys_php_id\'])) . $event;\n        $code = lookupPk($objectPks, pkWithoutEvent($row[\'sph_code\']));\n        if ($code == \'\') { $row[\'sph_code\'] = $row[\'zzzzsys_php_id\']; }\n        $code .=  $event;\n\n        writeRecord(\'zzzzsys_php\', $row, $first, \'\');\n\n    }\n\n}\n\nfunction cloneFormSelect($f1, $f2, array &$formSelectPks) {\n\n    $s = \"\n        SELECT\n           zzzzsys_select.* \n        FROM\n           zzzzsys_select \n        WHERE LEFT(zzzzsys_select_id, LENGTH(zzzzsys_select_id) - 3)  = ?\n	\";\n\n    $t = nuRunQuery($s, [$f1]);\n\n    while ($row = db_fetch_array($t)) {\n\n        $event = eventFromPk($row[\'zzzzsys_select_id\']);\n        $newPk = $f2 . $event;\n        addToArray($formSelectPks, $row[\'zzzzsys_select_id\'], $newPk);\n        $row[\'zzzzsys_select_id\'] = $newPk;\n\n        writeRecord(\'zzzzsys_select\', $row, $first, \'\');\n\n    }\n\n}\n\nfunction cloneFormSelectClause($f1, $formSelectPks) {\n\n    $s = \"\n        SELECT\n           zzzzsys_select_clause.* \n        FROM\n           zzzzsys_select_clause \n           LEFT JOIN\n              zzzzsys_select \n              ON zzzzsys_select_id = ssc_zzzzsys_select_id \n           LEFT JOIN zzzzsys_form ON LEFT(zzzzsys_select_id, LENGTH(zzzzsys_select_id) - 3) = zzzzsys_form_id\n           WHERE zzzzsys_form_id  = ? \n	\";\n\n    $t = nuRunQuery($s, [$f1]);\n\n    while ($row = db_fetch_array($t)) {\n\n        $row[\'ssc_zzzzsys_select_id\'] = lookupPk($formSelectPks, $row[\'ssc_zzzzsys_select_id\']);\n        $row[\'zzzzsys_select_clause_id\'] = getPk($row[\'zzzzsys_select_clause_id\']);\n        if ($row[\'ssc_zzzzsys_select_id\'] != \"\") writeRecord(\'zzzzsys_select_clause\', $row, $first, \'\');\n\n    }\n\n}\n\nfunction cloneObjectsSelect($f1, $objectPks, array &$selectPks) {\n\n    $s = \"\n        SELECT\n           zzzzsys_select.* \n        FROM\n           zzzzsys_select \n           LEFT JOIN\n              zzzzsys_object \n              ON zzzzsys_object_id = LEFT(zzzzsys_select_id, LENGTH(zzzzsys_select_id) - 3) \n        WHERE\n           sob_all_zzzzsys_form_id = ?\n	\";\n\n    $t = nuRunQuery($s, [$f1]);\n\n    while ($row = db_fetch_array($t)) {\n\n        $event = eventFromPk($row[\'zzzzsys_select_id\']);\n        $newPk = lookupPk($objectPks, pkWithoutEvent($row[\'zzzzsys_select_id\'])) . $event;\n        addToArray($selectPks, $row[\'zzzzsys_select_id\'], $newPk);\n        $row[\'zzzzsys_select_id\'] = $newPk;\n\n        writeRecord(\'zzzzsys_select\', $row, $first, \'\');\n\n    }\n\n}\n\nfunction cloneObjectsSelectClause($f1, $selectPks) {\n\n    $s = \"\n        SELECT\n           zzzzsys_select_clause.* \n        FROM\n           zzzzsys_select_clause \n           LEFT JOIN\n              zzzzsys_select \n              ON zzzzsys_select_id = ssc_zzzzsys_select_id \n           LEFT JOIN\n              zzzzsys_object \n              ON zzzzsys_object_id = LEFT(zzzzsys_select_id, LENGTH(zzzzsys_select_id) - 3) \n        WHERE\n           sob_all_zzzzsys_form_id = ?\n	\";\n\n    $t = nuRunQuery($s, [$f1]);\n\n    while ($row = db_fetch_array($t)) {\n\n        $row[\'ssc_zzzzsys_select_id\'] = lookupPk($selectPks, $row[\'ssc_zzzzsys_select_id\']);\n        $row[\'zzzzsys_select_clause_id\'] = getPk($row[\'zzzzsys_select_clause_id\']);\n\n        if ($row[\'ssc_zzzzsys_select_id\'] != \"\") writeRecord(\'zzzzsys_select_clause\', $row, $first, \'\');\n\n    }\n\n}\n\nfunction cloneObjectsEvents($f1, $objectPks) {\n\n    $s = \"\n        SELECT\n            *\n        FROM\n            zzzzsys_event\n        WHERE\n            sev_zzzzsys_object_id IN (\n            SELECT\n                zzzzsys_object_id\n            FROM\n                zzzzsys_object\n            WHERE\n                sob_all_zzzzsys_form_id = ?\n        )\n    \";\n    $t = nuRunQuery($s, [$f1]);\n\n    while ($row = db_fetch_array($t)) {\n\n        $row[\'zzzzsys_event_id\'] = getPk($row[\'zzzzsys_event_id\']);\n        $row[\'sev_zzzzsys_object_id\'] = lookupPk($objectPks, $row[\'sev_zzzzsys_object_id\']);\n\n        writeRecord(\'zzzzsys_event\', $row, $first, \'\');\n\n    }\n\n}\n\nfunction getOpenForm($f2) {\n\n    $ft = getFormType($f2);\n    $r = $ft == \'browseedit\' ? \"\" : \"-1\";\n\n    $code = getFormInfo($f2) [\"code\"];\n\n    $msg = \"\n	   var buttons = \' <button onclick=\\\"$(\\\'#nuMessageDiv\\\').remove();nuForm(\\\'$f2\\\', \\\'$r\\\', \\\'\\\', \\\'\\\', \\\'2\\\');\\\" class=\\\"nuActionButton\\\">Open Form</button>\';\n	   nuMessage([\'<h2>Cloning complete.</h2>Code: $code\' + buttons]);\n	   console.log(\'Cloning complete. Form Code: $code\');\n   \";\n\n    return $msg;\n    \n}\n\nfunction clearHashCookies() {\n\n    return;\n    \"\n        function clearHashCookies() {\n            nuSetProperty(\'cloner_form_source\',\'\');\n            nuSetProperty(\'cloner_form_dest\',\'\');\n            nuSetProperty(\'cloner_tabs\',\'\');\n            nuSetProperty(\'cloner_objects\', \'1\');\n            nuSetProperty(\'cloner_subforms\', \'0\');\n            nuSetProperty(\'cloner_iframe_forms\', \'0\');\n            nuSetProperty(\'cloner_dump\',\'0\');\n            nuSetProperty(\'cloner_new_pks\',\'1\');\n            nuSetProperty(\'cloner_replace_into\',\'0\');\n        }\n        \n        clearHashCookies();\n    \";\n\n}\n\nfunction showError($msg) {\n    \n    nuJavaScriptCallback(\"nuMessage([\'<h2>Error</h2><br>\" . $msg . \"\']);\" . clearHashCookies());\n    \n}\n\nfunction showForm($f2, $dump) {\n\n    if ($dump == \'1\') return;\n    nuJavaScriptCallback(getOpenForm($f2) . clearHashCookies());\n\n}\n\nfunction whereSubforms() {\n    \n    $subforms = getSubformList();\n    return $subforms != \'\' ? \" AND sob_all_id IN ($subforms) \" : \"\";\n    \n}\n\nfunction whereRunIframeforms() {\n    \n    $forms = getIframeFormList();\n    return $forms != \'\' ? \" AND sob_all_id IN ($forms) \" : \"\";\n    \n}\n\nfunction updateObjectSubform($f1, $f2, $dump) {\n\n   $s = \"UPDATE zzzzsys_object SET sob_subform_zzzzsys_form_id = \'$f2\' WHERE sob_subform_zzzzsys_form_id = \'$f1\';\";\n   \n   if ($dump == \"1\") {\n       echoHeader(\'zzzzsys_object: UPDATE subform ID\');\n       echoPlainText($s);\n   } else {\n        $t = nuRunQuery($s);\n   }\n    \n}\n\nfunction updateIframeForm($f1, $f2, $dump) {\n\n   $s = \"UPDATE zzzzsys_object SET sob_run_zzzzsys_form_id = \'$f2\' WHERE sob_run_zzzzsys_form_id = \'$f1\';\";\n   \n   if ($dump == \"1\") {\n       echoHeader(\'zzzzsys_object: UPDATE Run iframe form\');\n       echoPlainText($s);\n   } else {\n        $t = nuRunQuery($s);\n   }\n    \n}\n\n\nfunction processIframeForms($f1, $tabPks, $dump) {\n\n    if (\"#cloner_iframe_forms#\" == \'0\') return;\n\n    $s = \"\n        SELECT\n            `sob_run_zzzzsys_form_id`\n        FROM\n            zzzzsys_object\n        WHERE\n            sob_all_zzzzsys_form_id = ? AND \n            sob_all_type = ? AND \n            sob_run_method = ? AND \n            IFNULL(sob_run_zzzzsys_form_id, \'\') <> \'\'\n        \";\n        \n    $s .= whereRunIframeforms();\n     \n    $t = nuRunQuery($s, [$f1,\'Run\',\'i\']);\n\n    while ($row = db_fetch_array($t)) {\n            \n           $f1 = $row[\'sob_run_zzzzsys_form_id\'];\n           \n           processForm($f1, $f2, $tabPks);\n           updateIframeForm($row[\'sob_run_zzzzsys_form_id\'], $f2, $dump);\n           processObjects($f1, $f2, $tabPks);\n           \n           $f2 = \"\";\n\n    }\n\n}\n\nfunction processSubforms($f1, $tabPks, $dump) {\n\n    if (\"#cloner_subforms#\" == \'0\') return;\n\n    $s = \"\n         SELECT \n            sob_subform_zzzzsys_form_id \n         FROM zzzzsys_object \n         WHERE sob_all_zzzzsys_form_id = ? AND sob_all_type = ?\n        \".whereSubforms();\n\n    $t = nuRunQuery($s, [$f1,\'subform\']);\n    while ($row = db_fetch_array($t)) {\n            \n           $f1 = $row[\'sob_subform_zzzzsys_form_id\'];\n\n           processForm($f1, $f2, $tabPks);\n           updateObjectSubform($row[\'sob_subform_zzzzsys_form_id\'], $f2, $dump);\n           processObjects($f1, $f2, $tabPks);\n           \n           $f2 = \"\";\n\n    }\n\n}\n\nfunction processForm($f1, &$f2, &$tabPks) {\n\n    if ($f2 != \"\") {\n        $tabPks = cloneFormTabs($f1, $f2, \'_clone\');\n        return;\n    }\n\n    $formSelectPks = [];\n    \n    $f2 = cloneForm($f1);\n    $tabPks = cloneFormTabs($f1, $f2);\n\n    cloneFormSelect($f1, $f2, $formSelectPks);\n    cloneFormSelectClause($f1, $formSelectPks);\n    cloneFormBrowse($f1, $f2);\n    cloneFormPHP($f1, $f2);\n\n}\n\nfunction processObjects($f1, $f2, &$tabPks) {\n\n    if (\"#cloner_objects#\" == \'0\') return;\n\n    $objectPks = [];\n    $selectPks = [];\n    \n    cloneObjects($f1, $f2, $objectPks, $tabPks);\n    cloneObjectsPHP($f1, $objectPks);\n    cloneObjectsSelect($f1, $objectPks, $selectPks);\n    cloneObjectsSelectClause($f1, $selectPks);\n    cloneObjectsEvents($f1, $objectPks);\n\n}\n\nfunction startCloner() {\n\n    $dump = \"#cloner_dump#\";\n\n	if(nuDemo(false) && $dump != \'1\'){\n\n		showError(\'Not available in the Demo...\');\n		return;\n\n	}\n	\n    $newPks = \"#cloner_new_pks#\";\n    if ($newPks == \'0\' && $dump != \'1\') {\n        showError(\'Primary keys can only be retained in dump mode.\');\n        return;\n    }\n\n    if (getFormSource($f1) == false) {\n        showError(\'The form $f1 (cloner_form_source) does not exist!\');\n        return;\n    }\n\n    if (getFormDestination($f2) == false) {\n        showError(\'The form $f2 (cloner_form_dest) does not exist!\');\n        return;\n    }\n\n\n\n    dumpFormInfo($f1, $dump);\n    processForm($f1, $f2, $tabPks);\n    processObjects($f1, $f2, $tabPks);\n    processSubforms($f1, $tabPks, $dump);\n    processIframeForms($f1, $tabPks, $dump);\n    \n    showForm($f2, $dump);\n\n}\n\nstartCloner();', NULL, NULL, 'hide', '', '1', '0', '0', '0', '', NULL),
('nucsvtransfer_BE', 'nucsvtransfer_BE', 'System PHP', 'nubuilder', NULL, '1', '\nfunction getCSVFiles() {\n\n    $f = [];\n    $dir = \'../temp/\';\n    $dh = opendir($dir);\n    while (false !== ($fileName = readdir($dh))) {\n        $ext = substr($fileName, strrpos($fileName, \'.\') + 1);\n        if (in_array($ext, [\n            \"txt\",\n            \"csv\",\n            \"tab\",\n            \"asc\"\n        ])) $f[] = $fileName;\n    }\n    closedir($dh);\n    return $f;\n}\n\n$f = getCSVFiles();\n$a = [];\n\n$countFiles = count($f);\nfor ($i = 0;$i < $countFiles;$i++) {\n\n    if ($f[$i][0] != \'.\') {\n        $a[] = \"\'\" . $f[$i] . \"\'\";\n    }\n}\n\nnuAddJavaScript(\"var nuCSVfiles = [\" . implode(\',\', $a) . \"];\");\n\n', NULL, NULL, NULL, NULL, '1', '0', '1', '0', '', NULL),
('nudebug_BB', 'nudebug_BB', 'System PHP', 'nubuilder', NULL, '1', '$getDistinctUserColumnQuery = function($column) {\n    return \"SELECT DISTINCT `$column` FROM `zzzzsys_debug` WHERE IFNULL(`$column`,\'\') <> \'\' ORDER BY `$column`\";\n};\n\n$sqlSFlag = function() use ($getDistinctUserColumnQuery) {\n    return $getDistinctUserColumnQuery(\'deb_flag\');\n};\n\n\n$flag = nuEncodeQueryRowResults($sqlSFlag(), [], [\'\']);\n\n$filterJS = \"\n    function getData(data) {\n        return JSON.parse(atob(data));\n    }\n\n    function getFlag() {\n        return getData(\'$flag\');\n    }\n\";\n\n\n\nnuAddJavaScript($filterJS);', NULL, NULL, NULL, NULL, '1', '0', '1', '0', NULL, NULL),
('nudebug_BD', 'nudebug_BD', 'System PHP', 'nubuilder', NULL, '1', '\n$i  = \'#instruction#\';\n\nif($i == \'all\'){\n    nuRunQuery(\"DELETE FROM zzzzsys_debug\");\n    \n}\n\n', NULL, NULL, '', '', '1', '0', '1', '0', '', NULL),
('nuemaillog_BB', 'nuemaillog_BB', 'System PHP', 'nubuilder', NULL, '1', '$getDistinctUserColumnQuery = function($column) {\n    return \"SELECT DISTINCT `$column` FROM `zzzzsys_email_log` WHERE IFNULL(`$column`,\'\') <> \'\' ORDER BY `$column`\";\n};\n\n$sqlState = function() use ($getDistinctUserColumnQuery) {\n    return $getDistinctUserColumnQuery(\'eml_state\');\n};\n\n\n$state = nuEncodeQueryRowResults($sqlState(), [], [\'\']);\n\n$filterJS = \"\n    function nuEmailLogFilterGetData(data) {\n        return JSON.parse(atob(data));\n    }\n\n    function nuEmailLogFilterGetGroup() {\n        return nuEmailLogFilterGetData(\'$state\');\n    }\n\";\n\n\n\nnuAddJavaScript($filterJS);', NULL, NULL, NULL, NULL, '1', '0', '1', '0', NULL, NULL),
('nuemailtemplate_BB', 'nuemailtemplate_BB', 'System PHP', 'nubuilder', NULL, NULL, '$getDistinctColumnQuery = function(string $column): string {\n    return \"\n        SELECT\n          DISTINCT TRIM({$column}) AS trimmed_col\n        FROM\n          zzzzsys_email_template\n          LEFT JOIN zzzzsys_form\n            ON zzzzsys_form_id = emt_form_id\n        WHERE\n          IFNULL({$column}, \'\') <> \'\'\n        ORDER BY\n          trimmed_col\n    \";\n};\n\n$sqlGroup = function() use ($getDistinctColumnQuery): string {\n    return $getDistinctColumnQuery(\'emt_group\');\n};\n$sqlCategory = function() use ($getDistinctColumnQuery): string {\n    return $getDistinctColumnQuery(\'emt_category\');\n};\n\n$group    = nuEncodeQueryRowResults($sqlGroup(),    []);\n$category = nuEncodeQueryRowResults($sqlCategory(), []);\n\n$filterJS = <<<JS\nfunction nuEmailTemplateFilterGetData(data) {\n    return JSON.parse(atob(data));\n}\nfunction nuEmailTemplateFilterGetGroup() {\n    return nuEmailTemplateFilterGetData(\'$group\');\n}\nfunction nuEmailTemplateFilterGetCategory() {\n    return nuEmailTemplateFilterGetData(\'$category\');\n}\nJS;\n\nnuAddJavaScript($filterJS);\n', NULL, NULL, NULL, NULL, '1', '0', '1', '0', NULL, NULL),
('nuemailtemplate_BS', 'nuemailtemplate_BS', 'System PHP', 'nubuilder', NULL, '1', 'if (\'#DEV_MODE#\' != 1 && \'#emt_template#\' == \'1\') {\n    nuDisplayError(nuTranslate(\"Templates cannot be saved. Clone it instead.\"));\n}', NULL, NULL, NULL, NULL, '1', '0', '1', '0', NULL, NULL),
('nufastform', 'nu_run_fast_form', 'Run Fast Form', 'nubuilder', 'Form', '1', 'nuBuildFastForm(\'#fastform_table#\', \'#fastform_type#\', \'#fastform_primary_key#\');', NULL, NULL, '', 'nufflaunch', '1', '0', '1', '0', '', NULL),
('nufastreport', 'nu_run_fast_report', 'Run Fast Report', 'nubuilder', 'Reporting', '1', 'nuBuildFastReport();\n\n', NULL, NULL, '', 'nufflaunch', '1', '0', '1', '0', '', NULL),
('nufile_BB', 'nufile_BB', 'System PHP', 'nubuilder', NULL, '1', '$select = \"\nSELECT \n    zf.*, \n    CASE \n        WHEN zf.sfi_group = \'nubuilder\' THEN 0\n        ELSE IFNULL(obj.counter, 0)\n    END AS counter\nFROM \n    zzzzsys_file zf\nLEFT JOIN (\n    SELECT \n        sob_image_zzzzsys_file_id AS zzzzsys_file_id,\n        COUNT(*) AS counter\n    FROM \n        zzzzsys_object\n    WHERE \n        sob_image_zzzzsys_file_id IS NOT NULL\n    GROUP BY \n        sob_image_zzzzsys_file_id\n) obj ON zf.zzzzsys_file_id = obj.zzzzsys_file_id\nORDER BY \n    sfi_code\n\n\";\n\n\nnuCreateTableFromSelect(\'#TABLE_ID#\', $select);', NULL, NULL, NULL, NULL, '1', '0', '1', '0', NULL, NULL),
('nuform_AD', 'nuform_AD', 'System PHP', 'nubuilder', NULL, '1', 'nuDeleteForm(\'#RECORD_ID#\');', NULL, NULL, '', '', '1', '0', '1', '0', '', NULL),
('nuform_AS', 'nuform_AS', 'System PHP', 'nubuilder', NULL, '1', '$recordId = \'#RECORD_ID#\';\n\nnuReorderBrowse($recordId);\nnuReorderTabs($recordId);', NULL, NULL, '', '', '1', '0', '1', '0', '', NULL),
('nuform_BB', 'nuform_BB', 'System PHP', 'nubuilder', NULL, '1', '// Temp table\n$denied = $GLOBALS[\'nuSetup\']->set_denied == 1;\n\n$condition = $denied\n? \"(zzzzsys_form_id NOT LIKE \'nu%\' OR zzzzsys_form_id = \'nuuserhome\')\"\n: \"1=1\";\n\n$sql = \"\n    SELECT *\n    FROM zzzzsys_form\n    WHERE $condition\n    ORDER BY sfo_code\n\";\n\nnuCreateTableFromSelect(\'#TABLE_ID#\', $sql);\n\n\n// Group Filter\n$getDistinctGroupColumnQuery = function($column, $condition) {\n    return \"\n        SELECT\n          DISTINCT TRIM(`$column`)  AS trimmed_group\n        FROM\n          zzzzsys_form\n        WHERE\n          $condition AND (\n            IFNULL(`$column`, \'\') <> \'\')\n        ORDER BY\n          trimmed_group\n    \";\n};\n\n$sqlGroup = function($condition) use ($getDistinctGroupColumnQuery) {\n    return $getDistinctGroupColumnQuery(\'sfo_group\', $condition);\n};\n\n$group = nuEncodeQueryRowResults($sqlGroup($condition), []);\n\n$filterJS = \"\n    function nuFormFilterGetData(data) {\n        return JSON.parse(atob(data));\n    }\n    function nuFormFilterGetGroup() {\n        return nuFormFilterGetData(\'$group\');\n    }\n\";\n\nnuAddJavaScript($filterJS);', NULL, NULL, '', '', '1', '0', '1', '0', '', NULL),
('nuform_BS', 'nuform_BS', 'System PHP', 'nubuilder', NULL, '1', '$o = \'#sfo_type#\';\n\nif (\'#sfo_type#\' == \'\') {\n    nuDisplayError(\'<b>Type</b> Cannot Be Blank..\', \'sfo_type\');\n}\nif (\'#sfo_description#\' == \'\') {\n    nuDisplayError(\'<b>Description</b> Cannot Be Blank..\', \'sfo_description\');\n}\n\n\nif ($o == \'browseedit\' || $o == \'subform\' || $o == \'browse\') {\n\n    if ($o != \'browse\') {\n        nuCheckTabs();\n    }\n\n    if ($o != \'subform\') {\n        nuCheckBrowse();\n    }\n\n    if (\'#sfo_browse_sql#\' == \'\') {\n        nuDisplayError(\'<b>Browse SQL</b> Cannot Be Blank..\', \'sfo_browse_sql\');\n    }\n}\n\nif ($o == \'edit\' or $o == \'launch\') {\n    nuCheckTabs();\n}\n\nif ($o != \'launch\') {\n    if (\'#sfo_table#\' == \'\') {\n        nuDisplayError(\'<b>Table Name</b> Cannot Be Blank..\', \'sfo_table\');\n    }\n    if (\'#sfo_primary_key#\' == \'\') {\n        nuDisplayError(\'<b>Primary Key</b> Cannot Be Blank..\', \'sfo_primary_key\');\n    }\n}\n\nfunction nuCheckBrowse() {\n\n    $r = 0;\n    $sf = nuSubformObject(\'zzzzsys_browse_sf\');\n\n    for ($i = 0; $i < count($sf->rows); $i++) {\n        if ($sf->deleted[$i] == 0) {\n            $r++;\n        }\n    }\n\n    if ($r == 0) {\n        nuDisplayError(\'<b>Must have at least 1</b> Browse Column Defined..\');\n    }\n\n}\n\nfunction nuCheckTabs() {\n\n    $r = 0;\n    $sf = nuSubformObject(\'zzzzsys_tab_sf\');\n\n    for ($i = 0; $i < count($sf->rows); $i++) {\n        if ($sf->deleted[$i] == 0) {\n            $r++;\n        }\n    }\n\n    if ($r == 0) {\n        nuDisplayError(\'<b>Must have at least 1</b> Tab Column Defined..\');\n    }\n\n}\n\n\nif (!empty($_POST[\'nuErrors\'])) {\n   nuSetValidationErrorTitle(\'Validation Error\');\n} ', NULL, NULL, '', '', '1', '0', '1', '0', '', NULL),
('nuformat_BS', 'nuFormat_BS', 'System PHP', 'nubuilder', NULL, '1', 'if (\'#srm_default#\' == 0) return;\n\n$update = \"\n\n    UPDATE `zzzzsys_format`\n	SET srm_default = 0\n    WHERE srm_type = \'#srm_type#\'\n    AND zzzzsys_format_id <> ?\n\n\";\n\nnuRunQuery($update, [\'#record_id#\']);', NULL, NULL, NULL, NULL, '1', '0', '1', '0', NULL, NULL),
('nuitem_AS', 'nuitem_AS', 'System PHP', 'nubuilder', NULL, '1', '// Don\'t store itm_created_on and itm_updated_on for nu-records:\n\n// Get the current record ID\n$recordID = \'#RECORD_ID#\';\n\n// Check if it starts with \'nu\'\nif (strpos($recordID, \'nu\') === 0) {\n    \n    // Prepare the SQL update\n    $sql = \"\n        UPDATE zzzzsys_item \n        SET itm_created_on = NULL, \n            itm_updated_on = NULL \n        WHERE zzzzsys_item_id = ?\n    \";\n\n    // Execute the query with parameter binding\n\n    nuRunQuery($sql, [$recordID]);\n}\n', NULL, NULL, NULL, NULL, '1', '0', '1', '0', NULL, NULL),
('nuitem_BB', 'nuitem_BB', 'System PHP', 'nubuilder', NULL, '1', '// Temp table\n\n$denied = $GLOBALS[\'nuSetup\']->set_denied == 1;\n\n$condition = $denied\n    ? \"(zzzzsys_item_id NOT LIKE \'nu%\')\"\n    : \"1=1\";\n\n$sql = \"\n    SELECT\n        zzzzsys_item_id,\n        itm_value,\n        itm_description,\n        itm_category,\n        itm_group,\n        itm_tag,\n        itm_language,\n        sob_all_id,\n        sfo_code,\n        itm_active,\n        itm_created_on,\n        itm_updated_on\n    FROM\n        zzzzsys_item\n    LEFT JOIN zzzzsys_object ON zzzzsys_object_id = itm_object_id\n    LEFT JOIN zzzzsys_form ON zzzzsys_form_id = zzzzsys_object.sob_all_zzzzsys_form_id\n    WHERE\n        $condition\n    ORDER BY\n        sfo_code ASC,\n        sob_all_id ASC\n\";\n\n\nnuCreateTableFromSelect(\'#TABLE_ID#\', $sql);\n\n\n// Filter\n$getDistinctGroupColumnQuery = function($column, $condition) {\n    return \"\n        SELECT DISTINCT TRIM(`$column`) AS `value`, TRIM(`$column`) AS `text`\n        FROM zzzzsys_item\n        WHERE \n            IFNULL(itm_group, \'\') <> \'\' \n            AND ($condition)\n        ORDER BY `value`\n    \";\n};\n\n$sqlGroup = function($condition) use ($getDistinctGroupColumnQuery) {\n    return $getDistinctGroupColumnQuery(\'itm_group\', $condition);\n};\n\n$group = nuEncodeQueryRowResults($sqlGroup($condition), [], [\'-1\',\'\']);\n\n$filterJS = \"\n    function nuItemsFilterGetData(data) {\n        return JSON.parse(atob(data));\n    }\n    function nuItemsFilterGetGroup() {\n        return nuItemsFilterGetData(\'$group\');\n    }\n\";\n\nnuAddJavaScript($filterJS);', NULL, NULL, NULL, NULL, '1', '0', '1', '0', NULL, NULL),
('nuobject_BB', 'nuobject_BB', 'System PHP', 'nubuilder', NULL, '1', '$select = \"SELECT zzzzsys_object_id AS theid FROM zzzzsys_object WHERE \";\n$where = \"1\";\nif ($GLOBALS[\'nuSetup\']->set_denied == 1) {\n    $where = \"sob_all_zzzzsys_form_id NOT LIKE \'nu%\' OR sob_all_zzzzsys_form_id = \'nuuserhome\'\";\n}\n\nnuCreateTableFromSelect(\'#TABLE_ID#\', $select.$where);', NULL, NULL, '', '', '1', '0', '1', '0', '', NULL),
('nuobject_BE', 'nuobject_BE', 'System PHP', 'nubuilder', NULL, '1', '$s = \"\n\nSELECT \n	sob_all_zzzzsys_form_id AS theform,\n	sob_all_id AS ids,\n	sob_all_type AS type\nFROM zzzzsys_object \nWHERE \nsob_all_zzzzsys_form_id = \'#sob_all_zzzzsys_form_id#\' AND \n	((sob_input_type = \'nuNumber\' AND sob_all_type = \'input\')\n	OR (sob_input_type = \'number\' AND sob_all_type = \'input\')\n	OR sob_all_type = \'calc\' OR sob_all_type = \'select\')\n\nUNION \n\nSELECT \n   su.sob_all_zzzzsys_form_id AS theform,\n   CONCAT(su.sob_all_id, \'.\', inp.sob_all_id) AS ids,\n   inp.sob_all_type AS type\nFROM zzzzsys_object AS su\nJOIN zzzzsys_object AS inp ON su.sob_subform_zzzzsys_form_id = inp.sob_all_zzzzsys_form_id\nWHERE \nsu.sob_all_type = \'subform\' AND \nsu.sob_all_zzzzsys_form_id = \'#sob_all_zzzzsys_form_id#\' AND \n	((inp.sob_input_type = \'nuNumber\' AND inp.sob_all_type = \'input\')\n	OR (inp.sob_input_type = \'number\' AND inp.sob_all_type = \'input\')\n	OR inp.sob_all_type = \'calc\' OR inp.sob_all_type = \'select\')\n\n\";\n\n$a  = [];\n$t  = nuRunQuery($s);\nwhile($r = db_fetch_object($t)){\n    $a[]  = $r;    \n}\n\n$j  = json_encode($a);\n\n$js = \"\n\nfunction nuCalcObjects(){\n    return $j;\n}\n\n\";\n\nnuAddJavaScript($js);\n\n', NULL, NULL, '', '', '1', '0', '1', '0', '', NULL);
INSERT INTO `zzzzsys_php` (`zzzzsys_php_id`, `sph_code`, `sph_description`, `sph_group`, `sph_category`, `sph_status`, `sph_php`, `sph_javascript`, `sph_javascript_active`, `sph_run`, `sph_zzzzsys_form_id`, `sph_system`, `sph_global`, `sph_demo`, `sph_template`, `sph_hide`, `sph_json`) VALUES
('nuobject_BS', 'nuobject_BS', 'System PHP', 'nubuilder', NULL, '1', '$r = \'#RECORD_ID#\';\n$f = \'#sob_all_zzzzsys_form_id#\';\n$o = \'#sob_all_id#\';\n\n$s = \"\n    \n        SELECT COUNT(*) \n        FROM zzzzsys_object\n        WHERE sob_all_zzzzsys_form_id = \'$f\'\n        AND sob_all_id = \'$o\'\n        AND zzzzsys_object_id != \'$r\'\n\n    \";\n\n$t = nuRunQuery($s);\n$r = db_fetch_row($t);\n\nif ($r[0] > 0) {\n    nuDisplayError(nuTranslate(\'This <b>ID</b> is already used on this Form..\'));\n}\n\nif (\'#sob_all_access#\' == 9 && \'#sob_all_access_condition#\' == \'\') {\n    nuDisplayErrorNotBlank(\'Access Condition\');\n}\n\n$o = \'#sob_all_type#\';\n\nif ($o == \'display\') {\n    if (\'#sob_display_sql#\' == \'\' && \'#sob_display_procedure#\' == \'\') {\n        nuDisplayErrorNotBlank(\'Display\');\n    }\n}\n\nif ($o == \'html\') {\n\n    if (\'#sob_html_code#\' == \'\' && \'#sob_html_chart_type#\' == \'\') {\n        nuDisplayError(nuTranslate(\'HTML Fields Cannot Both Be Blank..\'));\n    }\n    if (\'#sob_html_javascript#\' == \'\' && \'#sob_html_chart_type#\' != \'\') {\n        nuDisplayErrorNotBlank(\'HTML Javascript Array\');\n    }\n\n}\n\nif ($o == \'lookup\') {\n    if (\'#sob_lookup_zzzzsys_form_id#\' == \'\') {\n        nuDisplayErrorNotBlank(\'Form\');\n    }\n    if (\'#sob_lookup_code#\' == \'\') {\n        nuDisplayErrorNotBlank(\'Code\');\n    }\n    if (\'#sob_lookup_description#\' == \'\') {\n        nuDisplayErrorNotBlank(\'Descrition\');\n    }\n    if (\'#sob_lookup_description_width#\' == \'\') {\n        nuDisplayErrorNotBlank(\'Width\');\n    }\n}\n\nif ($o == \'run\') {\n    if (\'#sob_run_zzzzsys_form_id#\' == \'\') {\n        nuDisplayErrorNotBlank(\'Run\');\n    }\n    if (\'#sob_run_method#\' == \'\') {\n        nuDisplayErrorNotBlank(\'Method\');\n    }\n}\n\nif ($o == \'input\') {\n\n    if (\'#sob_input_type#\' == \'\') {\n        nuDisplayErrorNotBlank(\"Input\'s Input Type\");\n    }\n\n    if (\'#sob_input_type#\' == \'nuNumber\' || \'#sob_input_type#\' == \'nuDate\') {\n        if (\'#sob_input_format#\' == \'\') {\n            nuDisplayErrorNotBlank(\'Input Format\');\n        }\n    }\n\n    if (\'#sob_input_type#\' == \'nuAutoNumber\') {\n        if (\'#sob_input_count#\' == \'\') {\n            nuDisplayErrorNotBlank(\'Next Number\');\n        }\n    }\n\n}\n\nif ($o == \'select\') {\n    if (\'#sob_select_multiple#\' == \'\') {\n        nuDisplayErrorNotBlank(\'Multiple\');\n    }\n    if (\'#sob_select_sql#\' == \'\' && \'#sob_select_procedure#\' == \'\') {\n        nuDisplayErrorNotBlank(\'SQL/List or Procedure\');\n    }\n}\n\n\nif ($o == \'subform\') {\n    if (\'#sob_subform_zzzzsys_form_id#\' == \'\') {\n        nuDisplayErrorNotBlank(\'Form\');\n    }\n    if (\'#sob_subform_foreign_key#\' == \'\') {\n        nuDisplayErrorNotBlank(\'Foreign Key\');\n    }\n    if (\'#sob_subform_add#\' == \'\') {\n        nuDisplayErrorNotBlank(\'Addable\');\n    }\n    if (\'#sob_subform_delete#\' == \'\') {\n        nuDisplayErrorNotBlank(\'Deletable\');\n    }\n    if (\'#sob_subform_type#\' == \'\') {\n        nuDisplayErrorNotBlank(\'Type\');\n    }\n}\n\nif ($o == \'\') {\n    if (\'#sfo_browse_sql#\' == \'\') {\n        nuDisplayErrorNotBlank(\'Browse SQL\');\n    }\n}\n\nfunction nuDisplayErrorNotBlank($label) {\n\n    $label = \'<b>\' . $label . \'</b>\';\n    nuDisplayError($label . \' \' . nuTranslate(\'cannot be left blank\'));\n\n}\n\nif (!empty($_POST[\'nuErrors\'])) {\n   nuSetValidationErrorTitle(\'Validation Error\');\n} \n\n', NULL, NULL, '', '', '1', '0', '1', '0', '', NULL),
('nuobjectgrid_AD', 'nuobjectgrid_AD', 'System PHP', 'nubuilder', NULL, '1', 'nuDeleteForm(\'#RECORD_ID#\');', NULL, NULL, '', '', '1', '0', '1', '0', '', NULL),
('nuobjectgrid_AS', 'nuobjectgrid_AS', 'System PHP', 'nubuilder', NULL, '1', '$s  = \"\n    SELECT * \n    FROM zzzzsys_browse \n    WHERE sbr_zzzzsys_form_id = \'#RECORD_ID#\'\n    ORDER BY sbr_order;\n\";\n\n\n$t = nuRunQuery($s);\n$o = 10;\n\nwhile($r = db_fetch_object($t)){\n        \n    $s  = \"\n        UPDATE zzzzsys_browse \n        SET sbr_order = \'$o\'\n        WHERE zzzzsys_browse_id = \'$r->zzzzsys_browse_id\'\n        ORDER BY sbr_order;\n    \";\n    \n    nuRunQuery($s);\n    \n    $o = $o + 10;    \n    \n}\n\n$s  = \"\n    SELECT * \n    FROM zzzzsys_tab \n    WHERE syt_zzzzsys_form_id = \'#RECORD_ID#\'\n    ORDER BY syt_order;\n\";\n\n$t = nuRunQuery($s);\n$o = 10;\n\nwhile($r = db_fetch_object($t)){\n        \n    $s  = \"\n        UPDATE zzzzsys_tab \n        SET syt_order = \'$o\'\n        WHERE zzzzsys_tab_id = \'$r->zzzzsys_tab_id\'\n        ORDER BY syt_order;\n    \";\n    \n    nuRunQuery($s);\n    \n    $o = $o + 10;    \n    \n}\n', NULL, NULL, '', '', '1', '0', '1', '0', '', NULL),
('nuobjectgrid_BB', 'nuobjectgrid_BB', 'System PHP', 'nubuilder', NULL, '1', '$select = \"SELECT zzzzsys_form_id AS theid FROM zzzzsys_form WHERE \";\n$where = \"1\";\nif ($GLOBALS[\'nuSetup\']->set_denied == 1) {\n    $where = \"zzzzsys_form_id NOT LIKE \'nu%\' OR zzzzsys_form_id = \'nuuserhome\'\";\n}\n\nnuCreateTableFromSelect(\'#TABLE_ID#\', $select.$where);', NULL, NULL, '', '', '1', '0', '1', '0', '', NULL),
('nuobjectgrid_BD', 'nuobjectgrid_BD', 'System PHP', 'nubuilder', NULL, '1', 'nuDisplayError(nuTranslate(\'The Delete Operation is not available.\'));', NULL, NULL, NULL, NULL, '1', '0', '1', '0', NULL, NULL),
('nuobjectgrid_BS', 'nuobjectgrid_BS', 'System PHP', 'nubuilder', NULL, '1', '\n    $o = \'#sfo_type#\';\n\n    if(\'#sfo_type#\'             == \'\'){nuDisplayError(\'<b>Type</b> Cannot Be Blank..\', \'sfo_type\');}\n    if(\'#sfo_code#\'             == \'\'){nuDisplayError(\'<b>Code</b> Cannot Be Blank..\', \'sfo_code\');}\n    if(\'#sfo_description#\'      == \'\'){nuDisplayError(\'<b>Description</b> Cannot Be Blank..\', \'sfo_description\');}\n\n\n    \n    \n    if($o == \'browseedit\' || $o == \'subform\' || $o == \'browse\'){\n        \n        if($o != \'browse\'){\n            nuCheckTabs();\n        }\n        \n        if($o != \'subform\'){\n            nuCheckBrowse();\n        }\n        \n        if(\'#sfo_browse_sql#\'   == \'\'){nuDisplayError(\'<b>Browse SQL</b> Cannot Be Blank..\', \'sfo_browse_sql\');}\n    }\n\n    if($o == \'edit\' or $o == \'launch\'){\n        nuCheckTabs();\n    }\n\n    if($o != \'launch\'){\n        if(\'#sfo_table#\'            == \'\'){nuDisplayError(\'<b>Table Name</b> Cannot Be Blank..\', \'sfo_table\');}\n        if(\'#sfo_primary_key#\'      == \'\'){nuDisplayError(\'<b>Primary Key</b> Cannot Be Blank..\', \'sfo_primary_key\');}\n    }\n\nfunction nuCheckBrowse(){\n\n    $r  = 0;\n    $sf = nuSubformObject(\'zzzzsys_browse_sf\');\n    \n    for($i = 0 ; $i < count($sf->rows) ; $i++){\n       if($sf->deleted[$i] == 0){$r++;}\n    }\n    \n    if($r == 0){\n       nuDisplayError(\'<b>Must have at least 1</b> Browse Column Defined..\');\n    }\n    \n}\n\nfunction nuCheckTabs(){\n\n    $r  = 0;\n    $sf = nuSubformObject(\'zzzzsys_tab_sf\');\n    \n    for($i = 0 ; $i < count($sf->rows) ; $i++){\n       if($sf->deleted[$i] == 0){$r++;}\n    }\n    \n    if($r == 0){\n       nuDisplayError(\'<b>Must have at least 1</b> Tab Column Defined..\');\n    }\n    \n}\n\n\n\n\n', NULL, NULL, '', '', '1', '0', '1', '0', '', NULL),
('nupassword_BS', 'nupassword_BS', 'System PHP', 'nubuilder', NULL, '1', '$is		= \'#old_password#\';\n$was    = \'#new_password_check#\';\n$will   = \'#new_password#\';\n$ses    = \'#SESSION_ID#\';\n$userId = \"#USER_ID#\";\n\n//--\n\n$s      = \"\n    SELECT sss_access \n    FROM zzzzsys_session\n    WHERE zzzzsys_session_id = ?\n\";\n\n$t  = nuRunQuery($s, array($ses));\n$r  = db_fetch_object($t);\n$j  = json_decode($r->sss_access);\n\n//--\n\n$s      = \"\n    SELECT sus_login_password\n    FROM zzzzsys_user\n    WHERE zzzzsys_user_id = ?\n\";\n\n$t = nuRunQuery($s, array($userId));\n$r = db_fetch_object($t);\n$current = $r->sus_login_password;\n\n$useMd5 = $_SESSION[\'nubuilder_session_data\'][\'USE_MD5_PASSWORD_HASH\'] == true;\n\nif ($useMd5) {\n    $check =  md5($is) == $current;\n} else {\n    $check = password_verify($is, $current);\n}\n\nif ($check == false) {\n    nuDisplayError(nuTranslate(\'Incorrect Password\'));\n    return;\n}    \n\n//--\n\n$p    = nuProcedure(\'nu_check_password_policy\');\n\nif($p != \'\'){\n\n    eval($p);\n    \n    if($check == false){\n        return;\n    }\n\n}\n\n//--\n\nif($will == $was){\n\n    $s  = \"\n\n        UPDATE zzzzsys_user \n        SET sus_login_password = ?\n        WHERE zzzzsys_user_id = ?\n    \n    \";\n\n    $pwHash = $useMd5 == true ? md5($will) : nuPasswordHash($will);\n\n    nuRunQuery($s, array($pwHash, \"#RECORD_ID#\"));\n\n    nuSetUserJSONData(\'PASSWORD_CHANGED_TIME\', time() , $userId);\n    nuSetUserJSONData(\'PASSWORD_CHANGED_SOURCE\', \'user\', $userId);\n    \n}else {\n    nuDisplayError(nuTranslate(\'\"New Password\" must be the same as \"Confirm New Password\"\'));\n}\n', NULL, NULL, '', '', '1', '0', '1', '0', '', NULL),
('nuphp_AS', 'nuphp_AS', 'System PHP', 'nubuilder', NULL, '1', '$justphp = nuObjKey(nuHash(),\'filter\') == \'justphp\';\n\nif (\'#DEV_MODE#\' != 1 && substr(\'#RECORD_ID#\', 0, 2) === \'nu\' ) {\n   if ($justphp) {\n        nuDisplayError(nuTranslate(\'<h2>\'.nuTranslate(\'Information\').\'</h2><br>Changes in system forms are overwritten with an update\'));  \n   } \n}', NULL, NULL, NULL, NULL, '1', '0', '1', '0', NULL, NULL),
