('nuprocedure_BB', 'nuprocedure_BB', 'System PHP', 'nubuilder', NULL, '1', '$getDistinctColumnQuery = function($column) {\n    return \"\n        SELECT\n          DISTINCT TRIM($column) AS `value`, TRIM($column) as `text`\n        FROM\n          zzzzsys_php\n          LEFT JOIN zzzzsys_form ON zzzzsys_form_id = sph_zzzzsys_form_id\n        WHERE\n          IFNULL($column, \'\') <> \'\'\n          AND (\n            (\n              sph_system != \'1\' OR sph_system IS NULL\n            )\n            OR (\n              \'#DEV_MODE#\' = \'1\' AND LEFT(RIGHT(sph_code, 3), 1) <> \'_\'\n            )\n          )\n        ORDER BY\n          `value`\n    \";\n};\n\n$sqlGroup = function() use ($getDistinctColumnQuery) {\n    return $getDistinctColumnQuery(\'sph_group\');\n};\n\n$sqlCategory = function() use ($getDistinctColumnQuery) {\n    return $getDistinctColumnQuery(\'sph_category\');\n};\n\n$group = nuEncodeQueryRowResults($sqlGroup(), [], [\'-1\', \'\']);\n$category = nuEncodeQueryRowResults($sqlCategory(), [], [\'-1\', \'\']);\n\n$filterJS = \"\n    function nuProcedureFilterGetData(data) {\n        return JSON.parse(atob(data));\n    }\n    function nuProcedureFilterGetGroup() {\n        return nuProcedureFilterGetData(\'$group\');\n    }\n    function nuProcedureFilterGetCategory() {\n        return nuProcedureFilterGetData(\'$category\');\n    }\n\";\n\nnuAddJavaScript($filterJS);', NULL, NULL, '', '', '1', '0', '1', '0', '', NULL),
('nuprocedure_BE', 'nuprocedure_BE', 'System PHP', 'nubuilder', NULL, '1', '$rid = \'#RECORD_ID#\';\n\nif ($rid != \'-1\' and $rid != \'-2\') {\n\n    $s = \"SELECT * FROM zzzzsys_php WHERE zzzzsys_php_id = \'$rid\'\";\n    $t = nuRunQuery($s);\n    $r = db_fetch_object($t);\n\n    if (db_num_rows($t) == 0) {\n\n        $s = \"\n        INSERT INTO zzzzsys_php\n        (\n            zzzzsys_php_id,\n            sph_code,\n            sph_description,\n            sph_group,\n            sph_system\n        )\n        VALUES\n        (\n            \'$rid\',\n            \'$rid\',\n            \'System PHP\',\n            \'nubuilder\',\n            \'1\'\n        )\n        \";\n\n        nuRunQuery($s);\n\n    }\n\n}', NULL, NULL, '', '', '1', '0', '1', '0', '', NULL),
('nuprocedure_BS', 'nuprocedure_BS', 'System PHP', 'nubuilder', NULL, '1', '$justphp = nuObjKey(nuHash(),\'filter\') == \'justphp\';\n\nif (\'#DEV_MODE#\' != 1 && \'#sph_template#\' == \'1\' ) {\n   if (! $justphp) {\n        nuDisplayError(nuTranslate(\"Templates cannot be saved. Clone it instead.\"));\n        return;\n   } \n}\n\n\n$rid    = \'#RECORD_ID#\';\n\nif($rid != \'-1\' and $rid != \'-2\'){ \n    \n    $s      = \"SELECT * FROM zzzzsys_php WHERE zzzzsys_php_id = \'$rid\'\";\n    $t      = nuRunQuery($s);\n    $r      = db_fetch_object($t);\n    \n    if(db_num_rows($t) == 0){\n    \n        $s              = \"\n        INSERT INTO zzzzsys_php\n        (\n            zzzzsys_php_id,\n            sph_code,\n            sph_description,\n            sph_group,\n            sph_system\n        )\n        VALUES\n        (\n            \'$rid\', \n            \'$rid\', \n            \'System PHP\', \n            \'nubuilder\', \n            \'1\'\n        )\n        \";\n        \n        nuRunQuery($s);\n        \n    }\n    \n}\n', NULL, NULL, NULL, NULL, '1', '0', '1', '0', NULL, NULL),
('nurunlist_BB', 'nurunlist_BB', 'System PHP', 'nubuilder', NULL, '1', '$select =\n\n\"\n    SELECT * FROM (\n    	 	 SELECT\n    	 	 	 	 `zzzzsys_form`.`zzzzsys_form_id` AS `zzzzsys_debug_id`,\n    	 	 	 	 \'Form\' AS `run`,\n    	 	 	 	 `zzzzsys_form`.`sfo_code` AS `code`,\n    	 	 	 	 `zzzzsys_form`.`sfo_description` AS `description`\n    	 	 FROM\n    	 	 	 	 `zzzzsys_form`\n    	 	 UNION\n    	 	 SELECT\n    	 	 	 	 `zzzzsys_report`.`zzzzsys_report_id` AS `zzzzsys_debug_id`,\n    	 	 	 	 \'Report\' AS `run`,\n    	 	 	 	 `zzzzsys_report`.`sre_code` AS `code`,\n    	 	 	 	 `zzzzsys_report`.`sre_description` AS `description`\n    	 	 FROM\n    	 	 	 	 `zzzzsys_report`\n    	 	 UNION\n    	 	 SELECT\n    	 	 	 	 `zzzzsys_php`.`zzzzsys_php_id` AS `zzzzsys_debug_id`,\n    	 	 	 	 \'Procedure\' AS `run`,\n    	 	 	 	 `zzzzsys_php`.`sph_code` AS `code`,\n    	 	 	 	 `zzzzsys_php`.`sph_description` AS `description`\n    	 	 FROM\n    	 	 	 	 `zzzzsys_php`\n    	 	 WHERE\n    	 	 	 	 (`zzzzsys_php`.`sph_system` <> 1)\n    ) AS combined\n    ORDER BY\n	 	 `code`\n\";\n\nnuCreateTableFromSelect(\'#TABLE_ID#\', $select);', NULL, NULL, NULL, NULL, '1', '0', '1', '0', NULL, NULL),
('nuselect_BS', 'nuselect_BS', 'System PHP', 'nubuilder', NULL, '1', '$rid    = \'#RECORD_ID#\';\n\nif($rid != \'-1\' and $rid != \'-2\'){ \n    \n    $s      = \"SELECT * FROM zzzzsys_select WHERE zzzzsys_select_id = \'$rid\'\";\n    $t      = nuRunQuery($s);\n    $r      = db_fetch_object($t);\n    \n    if(db_num_rows($t) == 0){\n        \n        $s              = \"\n        INSERT INTO zzzzsys_select\n        (zzzzsys_select_id, sse_system)\n        VALUES\n        (\'$rid\', \'1\')\n        \";\n        \n        nuRunQuery($s);\n        \n    }\n    \n}\n\n', NULL, NULL, '', '', '1', '0', '1', '0', '', NULL),
('nusethashcookie', 'nu_set_hash_cookie', 'Sets session persistent hash cookies', 'nubuilder', 'Session', '1', '$name = \'#nu_set_hash_cookie_name#\';\n$value = \'#nu_set_hash_cookie_value#\';\n\nnuSetProperty($name, $value, true);\n\n\n$js = \"\n    if(window.nuOnPropertySet){\n        nuOnPropertySet(\'$name\', \'$value\');\n    }\n\";\n\nnuJavaScriptCallback($js);', NULL, NULL, 'hide', '', '1', '1', '1', '0', '', NULL),
('nusetup_AS', 'nusetup_AS', 'System PHP', 'nubuilder', NULL, '1', 'function nuSetupWriteVersionToFile($dbVersion, $filesVersion) {\n\n    $f = fopen(__DIR__ . \'/../version.txt\', \"w+\") or die(\"Unable to open file!\");\n    fwrite($f, \"nuBuilder Forte 4.5\\n\\n\");\n    fwrite($f, \"DB Version: \".\"$dbVersion\\n\");\n    fwrite($f, \"Files Version: \".\"$filesVersion\\n\\n\");\n    fwrite($f, \"(V.MajorVersion-CurrentDate.BuildNumber)\");\n    fclose($f);\n\n}\n\n\n$DEV_MODE = \'#DEV_MODE#\' == \'1\';\n\n// Write Version Info\n\nif ($DEV_MODE) {\n\n    nuSetupSetConfigOrder();\n\n    $nuDumpCodes = nuProcedure(\'nu_dump_form_codes\');\n    eval($nuDumpCodes);\n\n    $nuNewDBV = \'#set_db_version_inc#\';\n    if ($nuNewDBV != \'\') {\n        $qry = \"UPDATE zzzzsys_info SET inf_details = ? WHERE  inf_code = \'nuDBVersion\'\";\n        nuRunQuery($qry, [$nuNewDBV]);\n        $nuDBV = $nuNewDBV;\n    } else {\n        $nuDBV = \'#set_db_version#\';\n    }\n\n    $nuNewFilesV = \'#set_files_version_inc#\';\n    if ($nuNewFilesV != \'\') {\n        $qry = \"UPDATE zzzzsys_info SET inf_details = ? WHERE  inf_code = \'nuFilesVersion\'\";\n        nuRunQuery($qry, [$nuNewFilesV]);\n        $nuFilesV = $nuNewFilesV;\n    } else {\n        $nuFilesV = \'#set_files_version#\';\n    }\n\n    if ($nuNewFilesV != \'\' || $nuNewDBV != \'\') {\n        nuSetupWriteVersionToFile($nuDBV, $nuFilesV);\n    }\n\n    if (\'#set_dev_reset_tables#\' == true) {\n\n        $lang = [\n            \"Afrikaans\", \"Arabic\", \"Armenian\", \"Catalan\", \"Chinese\", \"Czech\", \"Danish\", \"Dutch\",\n            \"French\", \"German\", \"Greek\", \"Hindi\", \"Hungarian\", \"Italian\", \"Japanese\", \"Malay\",\n            \"Norwegian\", \"Polish\", \"Portuguese (Brazil)\", \"Portuguese\", \"Romanian\", \"Russian\",\n            \"Slovak\", \"Spanish\", \"Tamil\", \"Turkish\", \"Vietnamese\"\n        ];\n\n        nuRunQuery(\'UPDATE zzzzsys_setup SET set_languages_included = ?, set_language = NULL WHERE zzzzsys_setup_id = 1\', $lang);\n\n        nuResetEmailSettings();\n\n        $q = \"\n                DELETE FROM `zzzzsys_user`;\n                DELETE FROM `zzzzsys_access`;\n                DELETE FROM `zzzzsys_access_form`;\n                DELETE FROM `zzzzsys_access_php`;\n                DELETE FROM `zzzzsys_access_report`;\n                DELETE FROM `zzzzsys_cloner`;\n                DELETE FROM `zzzzsys_app_cloner`;\n                DELETE FROM `zzzzsys_file` WHERE `sfi_group` <> \'nubuilder\';\n                DELETE FROM `zzzzsys_format` WHERE `zzzzsys_format_id` NOT LIKE \'nu%\';\n                DELETE FROM `zzzzsys_note`;\n                DELETE FROM `zzzzsys_email_template` WHERE `zzzzsys_email_template_id` NOT LIKE \'nu%\';\n                DELETE FROM `zzzzsys_note_category`;\n                DELETE FROM `zzzzsys_select` WHERE `zzzzsys_select_id` NOT LIKE \'nu%\';\n                DELETE FROM `zzzzsys_select_clause` WHERE `zzzzsys_select_clause_id` NOT LIKE \'nu%\';\n                DELETE FROM `zzzzsys_php` WHERE IFNULL(`sph_php`, \'\') = \'\';\n                DELETE FROM `zzzzsys_translate`;\n                DELETE FROM `zzzzsys_permission_item`;\n                DELETE FROM `zzzzsys_user_permission`;\n                DELETE FROM `zzzzsys_email_log`;\n                DELETE FROM `zzzzsys_report_data`;\n                DELETE zzzzsys_event\n                FROM zzzzsys_event\n                LEFT JOIN zzzzsys_object ON zzzzsys_object.zzzzsys_object_id = zzzzsys_event.sev_zzzzsys_object_id\n                WHERE zzzzsys_object.zzzzsys_object_id IS NULL;\n                UPDATE `zzzzsys_object` SET `sob_input_attribute` = NULL WHERE `sob_input_attribute` = \'\';\n                UPDATE `zzzzsys_form` SET `sfo_browse_javascript` = NULL WHERE TRIM(`sfo_browse_javascript`) = \'\';\n                UPDATE `zzzzsys_form` SET `sfo_javascript` = NULL WHERE TRIM(`sfo_javascript`) = \'\';\n                UPDATE `zzzzsys_tab` SET `syt_access` = NULL WHERE TRIM(`syt_access`) = \'\';\n                UPDATE `zzzzsys_tab` SET `syt_order` = \'-1\' WHERE `zzzzsys_tab_id` = \'nufastforms\';\n                UPDATE `zzzzsys_item` SET `itm_created_on` = NULL, `itm_updated_on` = NULL WHERE `zzzzsys_item_id` LIKE \'nu%\';\n                DELETE FROM `zzzzsys_prompt_generator` WHERE zzzzsys_prompt_generator_id LIKE \'nu%\';\n                DELETE FROM `zzzzsys_debug`;\n                DELETE FROM `zzzzsys_session`;\n        \";\n\n        nuRunQuery($q);\n\n        nuSetupSetDefaultValues();\n\n\n    }\n\n}\n\nfunction nuResetEmailSettings() {\n\n    $update =\n\n    \"\n        UPDATE `zzzzsys_setup`\n        SET\n           `set_smtp_username` = \'1\',\n          `set_smtp_password` = \'1\',\n          `set_smtp_host` = \'1\',\n          `set_smtp_from_address` = \'1\',\n          `set_smtp_from_name` = \'1\',\n          `set_smtp_port` = \'1\',\n          `set_smtp_use_authentication` = \'1\',\n          `set_smtp_use_ssl` = \'1\'\n       \";\n\n    nuRunQuery($update);\n\n}\n\nfunction nuSetupSetDefaultValues() {\n\n    $columns = db_field_names(\'zzzzsys_object\');\n    foreach ($columns as $name) {\n\n        if ($name === \'sob_all_label\') {\n            $newValue = \'\';\n        } else {\n            $newValue = null;\n        }\n\n        nuRunQuery(\"UPDATE `zzzzsys_object` SET `$name` = ? WHERE TRIM(IFNULL($name,\'\')) = \'\' \", [$newValue]);\n\n    }\n    \n    \n    nuRunQuery(\"UPDATE `zzzzsys_object` SET sob_all_label = \' \' WHERE `sob_all_type` LIKE \'subform\' AND IFNULL(sob_all_label,\'\') = \'\' \");\n\n}\n\nfunction nuImportSelectedLanguageFiles($l) {\n    try {\n        for ($i = 0; $i < count($l); $i++) {\n            if (trim($l[$i]) == \'\') continue;\n            $file = dirname(__FILE__). \'/languages/\'. $l[$i].\'.sql\';\n            $sql = file_get_contents($file);\n            if ($sql) {\n                nuRunQuery($sql);\n            } else {\n                nuDisplayError(\"Error opening the file: $file\");\n            }\n        }\n    }catch (Exception $e) {\n        nuDisplayError(nuTranslate(\'<h2>\'.nuTranslate(\'Error\').\'</h2><br>Error while importing language files.\'));\n    }\n}\n\nfunction nuSetupSetConfigOrder() {\n\n    $select = \"SELECT zzzzsys_config_id FROM `zzzzsys_config` ORDER BY `zzzzsys_config`.`cfg_order` ASC\";\n    $stmt = nuRunQuery($select);\n\n    $i = 10;\n    while ($row = db_fetch_array($stmt)) {\n\n        $s = \"UPDATE `zzzzsys_config` SET cfg_order = ? WHERE `zzzzsys_config_id`  = ?\";\n        nuRunQuery($s, [$i, $row[\'zzzzsys_config_id\']]);\n        $i = $i + 10;\n\n    }\n\n}\n\n\nfunction nuSetupDeletePMASubfolders($path) {\n    // Allowed folder names\n    $allowedFolders = [\"zh_CN\", \"vi\", \"tr\", \"sk\", \"ru\", \"ro\", \"pt_BR\", \"pt\", \"pl\", \"nl\", \"ja\", \"it\", \"hy\", \"fr\", \"es\", \"el\", \"de\", \"da\", \"cs\", \"ca\", \"ar\"];\n    \n    // Ensure path is a directory\n    if (!is_dir($path)) {\n        return false;\n    }\n    \n    // Scan directory\n    $folders = scandir($path);\n    \n    foreach ($folders as $folder) {\n        if ($folder === \'.\' || $folder === \'..\') {\n            continue;\n        }\n        \n        $fullPath = $path . DIRECTORY_SEPARATOR . $folder;\n        \n        // Check if it\'s a directory and not in the allowed list\n        if (is_dir($fullPath) && !in_array($folder, $allowedFolders)) {\n            nuSetupDeleteSubfoldersRecursively($fullPath);\n        }\n    }\n}\n\nfunction nuSetupDeleteSubfoldersRecursively($folderPath) {\n    if (!is_dir($folderPath)) {\n        return;\n    }\n    \n    $files = array_diff(scandir($folderPath), [\'.\', \'..\']);\n    \n    foreach ($files as $file) {\n        $filePath = $folderPath . DIRECTORY_SEPARATOR . $file;\n        if (is_dir($filePath)) {\n            nuSetupDeleteSubfoldersRecursively($filePath);\n        } else {\n            unlink($filePath);\n        }\n    }\n    \n    rmdir($folderPath);\n}\n\nfunction removePMALanguages() {\n    nuSetupDeletePMASubfolders(\'../third_partynudb/locale\');\n}\n\nremovePMALanguages();\n\n// Include/Exclude languages\n$t = \"#set_languages_included_json#\";\n\nif ($t != \'-1\') {\n    // no language change\n\n    nuRunQuery(\"DELETE FROM zzzzsys_translate WHERE zzzzsys_translate_id LIKE \'nu%\'\");\n    if ($t != \'\') nuImportSelectedLanguageFiles(json_decode($t));\n\n}\n\nif (\'#set_language_current#\' != \'#set_language#\') {\n    $_SESSION[\'nubuilder_session_data\'][\'translation\'] = nuGetTranslation(\'#set_language#\');\n    $_SESSION[\'nubuilder_session_data\'][\'language\'] = \'#set_language#\';\n}\n\n// Check if header textarea changed\n\nif (\'#set_header_current#\' != \'#set_header#\' || \'#set_include_current#\' != \'#set_include#\' || \'#set_style_current#\' != \'#set_style#\') {\n    nuDisplayMessage(nuTranslate(\'<h2>\'.nuTranslate(\'Information\').\'</h2><br>You will need to log in again for the changes to take effect.\'));\n}', NULL, NULL, NULL, NULL, '1', '0', '1', '0', NULL, NULL),
('nusetup_BD', 'nusetup_BD', 'System PHP', 'nubuilder', NULL, '1', 'nuDisplayError(\'The Setup cannot be deleted!\');', NULL, NULL, NULL, NULL, '1', '0', '1', '0', NULL, NULL),
('nusetup_BE', 'nusetup_BE', 'System PHP', 'nubuilder', NULL, '1', '// Settings\n\nrequire_once(\'nusetuplibs.php\');\n\n$config = nuConfigScript();\n$configCode = $config[\'code\'];\n$configJS = $config[\'js\'];\n\n$configJS = $configJS == null ? \"\" : $configJS. \" \" . \"nuHide(\'nuconfigsettingsfromdb_hint\'); \";\n\n\nif ($configCode != null) {\n    eval($config[\'code\']);\n}\n\nnuAddJavaScript($configJS);\n\n\nif (isset($_SESSION[\'nubuilder_session_data\'][\'USER_ADDITIONAL1_LABEL\']) && isset($nuConfigUserAdditional1Label)) {\n    $_SESSION[\'nubuilder_session_data\'][\'USER_ADDITIONAL1_LABEL\'] = $nuConfigUserAdditional1Label;\n}    \n\nif (isset($_SESSION[\'nubuilder_session_data\'][\'USER_ADDITIONAL2_LABEL\']) && isset($nuConfigUserAdditional2Label)) {\n    $_SESSION[\'nubuilder_session_data\'][\'USER_ADDITIONAL2_LABEL\'] = $nuConfigUserAdditional2Label;\n}\n\nif (isset($_SESSION[\'nubuilder_session_data\'][\'USER_CODE_LABEL\']) && isset($nuConfigUserCodeLabel)) {\n    $_SESSION[\'nubuilder_session_data\'][\'USER_CODE_LABEL\'] = $nuConfigUserCodeLabel;\n}\n\nnuAddJavaScript (\" \n   nuSERVERRESPONSE.buttons.Clone = \'0\';\n   nuSERVERRESPONSE.buttons.Delete = \'0\';\n\", true);\n\n\n//File Version\n\nfunction getFileVersion() {\n    $f = __DIR__ . \'/../version.txt\';\n    if (is_readable($f)) {\n        $lines = file($f);\n        if (count($lines) >= 4) {\n            $v = $lines[3];\n            $v = preg_replace(\"/\\r|\\n/\", \"\", $v);\n            $v = substr($v, 15);\n            return $v;\n        } \n    }\n    return \"Unknown\";\n}\n\n\n\n$v = getFileVersion();\n\n$j = \"\n\n    function nuGetFilesVersion() {\n        return \'$v\';\n    }\n\n\";\n\nnuAddJavaScript($j);', NULL, NULL, NULL, NULL, '1', '0', '1', '0', NULL, NULL),
('nusetup_BS', 'nusetup_BS', 'System PHP', 'nubuilder', NULL, '1', '$DEV_MODE = \'#DEV_MODE#\' == \'1\';\nif ($DEV_MODE) {\n     if (nuSetupHasNonNuPrefixes()) {\n         return;\n     }\n}\n\nfunction nuSetupHasNonNuPrefixes() {\n\n    $select = \"\n        SELECT \'zzzzsys_browse\', `zzzzsys_browse_id` FROM `zzzzsys_browse` WHERE `zzzzsys_browse_id` NOT LIKE \'nu%\' UNION ALL\n        SELECT \'zzzzsys_cloner\', `zzzzsys_cloner_id` FROM `zzzzsys_cloner` WHERE `zzzzsys_cloner_id` NOT LIKE \'nu%\' UNION ALL\n        SELECT \'zzzzsys_code_snippet\', `zzzzsys_code_snippet_id` FROM `zzzzsys_code_snippet` WHERE `zzzzsys_code_snippet_id` NOT LIKE \'nu%\' UNION ALL\n        SELECT \'zzzzsys_config\', `zzzzsys_config_id` FROM `zzzzsys_config` WHERE `zzzzsys_config_id` NOT LIKE \'nu%\' UNION ALL\n        SELECT \'zzzzsys_debug\', `zzzzsys_debug_id` FROM `zzzzsys_debug` WHERE `zzzzsys_debug_id` NOT LIKE \'nu%\' UNION ALL\n        SELECT \'zzzzsys_email_log\', `zzzzsys_email_log_id` FROM `zzzzsys_email_log` WHERE `zzzzsys_email_log_id` NOT LIKE \'nu%\' UNION ALL\n        SELECT \'zzzzsys_email_template\', `zzzzsys_email_template_id` FROM `zzzzsys_email_template` WHERE `zzzzsys_email_template_id` NOT LIKE \'nu%\' UNION ALL\n        SELECT \'zzzzsys_event\', `zzzzsys_event_id` FROM `zzzzsys_event` WHERE `zzzzsys_event_id` NOT LIKE \'nu%\' UNION ALL\n        SELECT \'zzzzsys_file\', `zzzzsys_file_id` FROM `zzzzsys_file` WHERE `zzzzsys_file_id` NOT LIKE \'nu%\' UNION ALL\n        SELECT \'zzzzsys_form\', `zzzzsys_form_id` FROM `zzzzsys_form` WHERE `zzzzsys_form_id` NOT LIKE \'nu%\' UNION ALL\n        SELECT \'zzzzsys_format\', `zzzzsys_format_id` FROM `zzzzsys_format` WHERE `zzzzsys_format_id` NOT LIKE \'nu%\' UNION ALL\n        SELECT \'zzzzsys_info\', `zzzzsys_info_id` FROM `zzzzsys_info` WHERE `zzzzsys_info_id` NOT LIKE \'nu%\' UNION ALL\n        SELECT \'zzzzsys_note\', `zzzzsys_note_id` FROM `zzzzsys_note` WHERE `zzzzsys_note_id` NOT LIKE \'nu%\' UNION ALL\n        SELECT \'zzzzsys_note_category\', `zzzzsys_note_category_id` FROM `zzzzsys_note_category` WHERE `zzzzsys_note_category_id` NOT LIKE \'nu%\' UNION ALL\n        SELECT \'zzzzsys_object\', `zzzzsys_object_id` FROM `zzzzsys_object` WHERE `zzzzsys_object_id` NOT LIKE \'nu%\' UNION ALL\n        SELECT \'zzzzsys_permission_item\', `zzzzsys_permission_item_id` FROM `zzzzsys_permission_item` WHERE `zzzzsys_permission_item_id` NOT LIKE \'nu%\' UNION ALL\n        SELECT \'zzzzsys_php\', `zzzzsys_php_id` FROM `zzzzsys_php` WHERE `zzzzsys_php_id` NOT LIKE \'nu%\' UNION ALL\n        SELECT \'zzzzsys_report\', `zzzzsys_report_id` FROM `zzzzsys_report` WHERE `zzzzsys_report_id` NOT LIKE \'nu%\' UNION ALL\n        SELECT \'zzzzsys_select\', `zzzzsys_select_id` FROM `zzzzsys_select` WHERE `zzzzsys_select_id` NOT LIKE \'nu%\' UNION ALL\n        SELECT \'zzzzsys_select_clause\', `zzzzsys_select_clause_id` FROM `zzzzsys_select_clause` WHERE `zzzzsys_select_clause_id` NOT LIKE \'nu%\' UNION ALL\n        SELECT \'zzzzsys_tab\', `zzzzsys_tab_id` FROM `zzzzsys_tab` WHERE `zzzzsys_tab_id` NOT LIKE \'nu%\' UNION ALL\n        SELECT \'zzzzsys_translate\', `zzzzsys_translate_id` FROM `zzzzsys_translate` WHERE `zzzzsys_translate_id` NOT LIKE \'nu%\' UNION ALL\n        SELECT \'zzzzsys_user_permission\', `zzzzsys_user_permission_id` FROM `zzzzsys_user_permission` WHERE `zzzzsys_user_permission_id` NOT LIKE \'nu%\' UNION ALL\n        SELECT \'sob_all_zzzzsys_tab_id\', `sob_all_zzzzsys_tab_id` FROM `zzzzsys_object` WHERE `sob_all_zzzzsys_tab_id` NOT LIKE \'nu%\' UNION ALL\n        SELECT \'sob_all_zzzzsys_form_id\', `sob_all_zzzzsys_form_id` FROM `zzzzsys_object` WHERE `sob_all_zzzzsys_form_id` NOT LIKE \'nu%\' UNION ALL\n        SELECT \'sob_run_zzzzsys_form_id\', `sob_run_zzzzsys_form_id` FROM `zzzzsys_object` WHERE `sob_run_zzzzsys_form_id` NOT LIKE \'nu%\' AND IFNULL(sob_run_zzzzsys_form_id, \'\') != \'\' UNION ALL\n        SELECT \'sob_lookup_zzzzsys_form_id\', `sob_lookup_zzzzsys_form_id` FROM `zzzzsys_object` WHERE `sob_lookup_zzzzsys_form_id` NOT LIKE \'nu%\' AND IFNULL(sob_lookup_zzzzsys_form_id, \'\') != \'\'  UNION ALL\n        SELECT \'sob_subform_zzzzsys_form_id\', `sob_subform_zzzzsys_form_id` FROM `zzzzsys_object` WHERE `sob_subform_zzzzsys_form_id` NOT LIKE \'nu%\' AND IFNULL(sob_subform_zzzzsys_form_id, \'\') != \'\' ;\n    \";\n    \n    $stmt = nuRunQuery($select);\n\n    if (db_num_rows($stmt) > 0) {\n        $msg = \'Rows with no nu-prefixes found:<br>\';\n        while($row = db_fetch_row($stmt)){\n             $msg .= $row[0].\"->\".$row[1].\"<br>\";\n        }\n    \n        nuDisplayError($msg);\n        false;\n    }\n    \n    return true;\n\n}\n\nfunction nuConfigValueToTable($line, $setting, $oldValue) {\n\n    $parts = explode(\"=\", $line);\n\n    $newValue = $parts[1];\n    $newValue = str_replace(\'\"\', \"\", $newValue);\n    $newValue = str_replace(\"\'\", \"\", $newValue);\n\n    $partsValue = explode(\";\", $newValue);\n    $newValue = trim($partsValue[0]);\n\n    $update = $newValue != $oldValue;\n\n    if ($setting == \'nuCalendarStartOfWeek\' && strlen($newValue) > 1) {\n        $newValue = str_replace(\"Monday\", \"1\", $newValue);\n        $newValue = str_replace(\"Sunday\", \"0\", $newValue);\n    }\n\n    if ($update) nuRunQuery(\'UPDATE zzzzsys_config SET cfg_value = ? WHERE cfg_setting = ?\', [$newValue, $setting]);\n\n    return $update;\n\n}\n\nif (\"#configImport#\" == \'1\') {\n\n    // Import config settings form nuconfig.php\n    $s = \"SELECT cfg_setting, cfg_value AS old_value FROM zzzzsys_config \";\n    $t = nuRunQuery($s);\n    $config = file(__DIR__ .\"/../nuconfig.php\");\n\n    while ($r = db_fetch_object($t)) {\n\n        foreach ($config as $line) {\n            if (trim($line) !== \'\' && nuStringContains($r->cfg_setting, $line) == true) {\n                nuConfigValueToTable($line, $r->cfg_setting, $r->old_value);\n                break;\n            }\n\n        }\n\n    }\n\n}', NULL, NULL, NULL, NULL, '1', '0', '1', '0', NULL, NULL),
('nutablookup_BB', 'nutablookup_BB', 'System PHP', 'nubuilder', NULL, '1', '$s = \"SELECT zzzzsys_form_id AS theid FROM zzzzsys_form WHERE \";\n$w = \"1\";\nif ($GLOBALS[\'nuSetup\']->set_denied == 1) {\n    $w = \"zzzzsys_form_id NOT LIKE \'nu%\' OR zzzzsys_form_id = \'nuuserhome\'\";\n}\n\nnuCreateTableFromSelect(\'#TABLE_ID#\', $s.$w);', NULL, NULL, '', '', '1', '0', '1', '0', '', NULL),
('nutestemail', 'nu_test_email', 'Send a test email', 'nubuilder', 'Email', '1', '$to = \'#ema_to#\';\n$fromAddress = \'#set_smtp_from_address#\';\n$fromName = \'#set_smtp_from_name#\';\n$body = \'#ema_body#\';\n$subject = \'#ema_subject#\';\n$bcc = \'#ema_bcc#\';\n$cc = \'#ema_cc#\';\n$priority = \'#ema_priority#\';\n\n$recipient = ($to == \'\' && $bcc == \'\' && $cc == \'\') ? false : true;\n\nif (! $recipient || $fromAddress == \'\' || $fromName = \'\' || $body == \'\' || $subject == \'\') {\n    showMessage(nuTranslate(\'Error\'), nuTranslate(\'Required fields cannot be blank.\'));\n    return;\n}\n\n$result = nuSendEmail($to, $fromAddress, $fromName, $body, $subject, [], true, $cc, $bcc, [], $priority);\n\nif (count($result) == 2) {\n    showMessage(nuTranslate(\'Result\'), $result[1]);\n} else {\n    showMessage(nuTranslate(\'Result\'), $result[1].\'<br>\'.$result[2]);\n}\n\nfunction showMessage($title, $msg) {\n    nuJavaScriptCallback(\"nuMessage(\'$title\', \'$msg\');\");\n}', NULL, NULL, 'hide', '', '1', '0', '1', '0', '', NULL),
('nutranslate_AS', 'nutranslate_AS', 'System PHP', 'nubuilder', NULL, '1', '$i  = \'trl_english\';\r\n$t  = nuRunQuery(\'SELECT COUNT(*) FROM zzzzsys_debug\');\r\n$c  = db_fetch_row($t)[0];\r\n\r\n$j  = \";$(\'#$i\').val($c);\";\r\n\r\nnuJavaScriptCallback($j);\r\n', NULL, NULL, '', '', '1', '0', '1', '0', '', NULL),
('nutranslate_BB', 'nutranslate_BB', 'System PHP', 'nubuilder', NULL, '1', 'function sqlLanguage() {\n    $sql = \"SELECT DISTINCT trl_language FROM `zzzzsys_translate` ORDER BY trl_language \";\n    return $sql;\n}\n\nfunction getBase64JsonDTString($sql) {\n   $result = nuRunQuery($sql);\n   $a = [];\n   $a[] = \'\';\n   while ($row = db_fetch_row($result)) {\n     $a[] = $row;\n   }\n   return base64_encode(json_encode( $a ));\n}\n\n$language = getBase64JsonDTString(sqlLanguage(),[]);\n\n$js = \"\n\n   function nuTranslationFilterGetLanguage() {\n      return JSON.parse(atob(\'$language\'));\n   }\n \n\";\n\nnuAddJavaScript($js);\n', NULL, NULL, NULL, NULL, '1', '0', '1', '0', NULL, NULL),
('nutranslate_BD', 'nutranslate_BD', 'System PHP', 'nubuilder', NULL, '1', 'if (\'#DEV_MODE#\' != 1 && substr(\'#RECORD_ID#\', 0, 2) === \'nu\') {\n   nuDisplayError(\"nuBuilder\'s translation strings cannot be modified\");\n}', NULL, NULL, NULL, NULL, '1', '0', '1', '0', NULL, NULL),
('nutranslate_BE', 'nutranslate_BE', 'System PHP', 'nubuilder', NULL, '1', '$t = nuRunQuery(\"SELECT MAX(trl_language) FROM zzzzsys_translate GROUP BY trl_language\");\n\n$a = [];\nwhile ($r = db_fetch_row($t)) {\n    $a[] = $r[0];\n}\n\n$j = json_encode($a);\n$f = \"\n\nfunction nuLanguages(){\n    return $j;\n}\n\n\";\n\nnuAddJavaScript($f);', NULL, NULL, '', '', '1', '0', '1', '0', '', NULL),
('nutranslate_BS', 'nutranslate_BS', 'System PHP', 'nubuilder', NULL, '1', 'if (\'#DEV_MODE#\' != 1 && substr(\'#RECORD_ID#\', 0, 2) === \'nu\') {\n   nuDisplayError(\"nuBuilder\'s translation strings cannot be modified\");\n}', NULL, NULL, NULL, NULL, '1', '0', '1', '0', NULL, NULL),
('nuuser_AS', 'nuuser_AS', 'System PHP', 'nubuilder', NULL, '1', '$changePassword = \'#sus_change_password#\' == \'1\';\n\nif (\'#check_password#\' != \'\') {\n\n    $userId = \"#RECORD_ID#\";\n\n    if ($_SESSION[\'nubuilder_session_data\'][\'USE_MD5_PASSWORD_HASH\'] != true) {\n        $pw = nuPasswordHash(\'#check_password#\');\n    } else {\n        $pw = md5(\'#check_password#\');\n    }\n\n    nuRunQuery(\"UPDATE zzzzsys_user SET sus_login_password = \'$pw\' WHERE zzzzsys_user_id = ?\", [$userId]);\n\n    nuSetUserJSONData(\'PASSWORD_CHANGED_TIME\', time(), $userId);\n\n    if ($changePassword) {\n        $expirationTime = time() + 3600;\n        nuSetUserJSONData(\'OTP_EXPIRATION_TIME\', $expirationTime, $userId);\n    }\n    \n\n}\n\n\nfunction nuUserSavedInfo() {\n\n    return array(\n        \'change_password\' => $changePassword,\n        \'new_user\' => nuHasNewRecordID()\n    );\n\n}\n\nif (\'#user_send_welcome_email#\' == \'1\') {\n    $result = nuRunProcedure(\'nu_send_welcome_email\');\n    if ($result === false) {\n        nuRunProcedure(\'nu_send_welcome_email_template\');\n    }\n}', NULL, NULL, '', '', '1', '0', '1', '0', '', NULL),
('nuuser_BB', 'nuuser_BB', 'System PHP', 'nubuilder', NULL, '1', '$getDistinctUserColumnQuery = function($column) {\n\n    $sqlWhereExpired = \"(\n        ((\'#nu5fe0352637b2e4f_filter#\' LIKE \'#%\' OR \'#nu5fe0352637b2e4f_filter#\' = \'\') AND (sus_expires_on > NOW() OR sus_expires_on IS NULL)) OR\n        (\'#nu5fe0352637b2e4f_filter#\' = \'Expired\' AND sus_expires_on < NOW())\n    ) \";\n\n    return \"\n        SELECT DISTINCT IFNULL(`$column`, \'\') AS value, IFNULL(`$column`, \'\') AS `text`\n        FROM `zzzzsys_user`\n        WHERE IFNULL(`$column`, \'\') <> \'\'\n        AND $sqlWhereExpired\n        ORDER BY value\n    \";\n\n};\n\n$sqlPosition = function() use ($getDistinctUserColumnQuery) {\n    return $getDistinctUserColumnQuery(\'sus_position\');\n};\n\n$sqlTeam = function() use ($getDistinctUserColumnQuery) {\n    return $getDistinctUserColumnQuery(\'sus_team\');\n};\n\n$sqlDepartment = function() use ($getDistinctUserColumnQuery) {\n    $x = $getDistinctUserColumnQuery(\'sus_department\');\n    return $x;\n};\n\n$sqlLanguage = function() use ($getDistinctUserColumnQuery) {\n    return $getDistinctUserColumnQuery(\'sus_language\');\n};\n\n$sqlAccessLevel = function() {\n\n    $sqlWhereExpired = \"(\n        ((\'#nu5fe0352637b2e4f_filter#\' LIKE \'#%\' OR \'#nu5fe0352637b2e4f_filter#\' = \'\') AND (sus_expires_on > NOW() OR sus_expires_on IS NULL)) OR\n        (\'#nu5fe0352637b2e4f_filter#\' = \'Expired\' AND sus_expires_on < NOW()))\";\n\n    $sql = \"SELECT DISTINCT CONCAT(sal_code, \' : \', sal_description) AS display\n        FROM `zzzzsys_user`\n        INNER JOIN zzzzsys_access ON zzzzsys_access_id = sus_zzzzsys_access_id\n        WHERE $sqlWhereExpired\n        ORDER BY CONCAT(sal_code, \' : \', sal_description)\";\n\n    return $sql;\n\n};\n\n$position = nuEncodeQueryRowResults($sqlPosition(), [], [\'-1\',\'\']);\n$team = nuEncodeQueryRowResults($sqlTeam(), [], [\'-1\',\'\']);\n$department = nuEncodeQueryRowResults($sqlDepartment(), [], [\'-1\',\'\']);\n$language = nuEncodeQueryRowResults($sqlLanguage(), [], [\'-1\',\'\']);\n$accessLevel = nuEncodeQueryRowResults($sqlAccessLevel(), []);\n\n$filterJS = \"\n    function nuUserFilterGetData(data) {\n        return JSON.parse(atob(data));\n    }\n    function nuUserFilterGetPosition() {\n        return nuUserFilterGetData(\'$position\');\n    }\n    function nuUserFilterGetTeam() {\n        return nuUserFilterGetData(\'$team\');\n    }\n\n    function nuUserFilterGetDepartment() {\n        return nuUserFilterGetData(\'$department\');\n    }\n    function nuUserFilterGetLanguage() {\n        return nuUserFilterGetData(\'$language\');\n    }\n\n    function nuUserFilterGetAccessLevel() {\n        return nuUserFilterGetData(\'$accessLevel\');\n    }\n\";\n\n\n$addCode = $_SESSION[\'nubuilder_session_data\'][\'USER_CODE_LABEL\'] ?? \'\';\n\n$addCodeJS = \"\n\n    if (\'$addCode\' !== \'\') {\n        $(\'#nusort_5\').html(\'$addCode\')\n    };\n\n\";\n\nnuAddJavaScript($filterJS . $addCodeJS);', NULL, NULL, NULL, NULL, '1', '0', '1', '0', NULL, NULL),
('nuuser_BE', 'nuuser_BE', 'System PHP', 'nubuilder', NULL, '1', '$nubuilderSessionData = $_SESSION[\'nubuilder_session_data\'];\n\n$add1Label = $nubuilderSessionData[\'USER_ADDITIONAL1_LABEL\'] ?? \'\';\n$add2Label = $nubuilderSessionData[\'USER_ADDITIONAL2_LABEL\'] ?? \'\';\n$addCode = $nubuilderSessionData[\'USER_CODE_LABEL\'] ?? \'\';\n\n$js = \"\n\n    	if (\'$add1Label\') { nuSetLabelText(\'sus_additional1\', \'$add1Label\', true) };\n    	if (\'$add2Label\') { nuSetLabelText(\'sus_additional2\', \'$add2Label\', true) };\n    	if (\'$addCode\') { nuSetLabelText(\'sus_code\', \'$addCode\', true) };\n\";\n\nnuAddJavaScript($js);', NULL, NULL, NULL, NULL, '1', '0', '1', '0', NULL, NULL),
('nuuser_BS', 'nuuser_BS', 'System PHP', 'nubuilder', NULL, '1', '$newPassword = \'#new_password#\';\n$checkPassword = \'#check_password#\';\n$passwordsMatch = $newPassword === $checkPassword;\n$newRecord = nuHasNoRecordID();\n$email = \'#sus_email#\';\n$sendWelcomeEmail = \'#user_send_welcome_email#\' == \'1\';\n\n$err = \"\";\nif ($newRecord && (empty($newPassword) || empty($checkPassword))) {\n    $err = nuTranslate(\"Both password fields must be filled in.\");\n}\n\nif (!$passwordsMatch) {\n    $err = nuTranslate(\"The passwords do not match.\");\n}\n\nif ($sendWelcomeEmail) {\n\n    if (!nuIsValidEmail($email)) {\n        $err .= \'<br>\' . nuTranslate(\"Invalid email address.\");\n    }\n\n    if (!$newRecord && (empty($newPassword) || empty($checkPassword))) {\n        $err .= \'<br>\' . nuTranslate(\"Password required to send welcome email.\");\n    }\n\n}\n\nif (!empty($err)) {\n    nuDisplayError($err);\n}', NULL, NULL, '', '', '1', '0', '1', '0', '', NULL),
('nuuserhome_BE', 'nuuserhome_BE', 'System PHP', 'nubuilder', NULL, NULL, ' ', NULL, NULL, NULL, NULL, '1', '0', '1', '0', NULL, NULL);
