('68cd708a926449a_SE', 'investigators', NULL, '{\"tables\":[{\"id\":\"boxc17643629281531001\",\"position\":{\"top\":25,\"left\":21.988636016845703},\"tablename\":\"zzzzsys_user\",\"alias\":\"\",\"checkall\":false,\"checkboxes\":[true,true,false,true,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false,false]}],\"joins\":{}}', 'SELECT\n zzzzsys_user.zzzzsys_user_id,\n    zzzzsys_user.sus_zzzzsys_access_id,\n    zzzzsys_user.sus_name\n\nFROM\n    zzzzsys_user\n\nWHERE\n    ((sus_zzzzsys_access_id = 68e0e5333234b7b7))\n\n', NULL, '1');
