INSERT INTO `zzzzsys_setup` (`zzzzsys_setup_id`, `set_time_out_minutes`, `set_zzzzsys_timezone_id`, `set_language`, `set_languages_included`, `set_smtp_username`, `set_smtp_password`, `set_smtp_host`, `set_smtp_from_address`, `set_smtp_from_name`, `set_smtp_port`, `set_smtp_use_authentication`, `set_smtp_use_ssl`, `set_header`, `set_include`, `set_style`, `set_denied`, `set_json`) VALUES
('1', 480, '5281a1e1d267cf9', '', '[\"\",\"Afrikaans\",\"Arabic\",\"Armenian\",\"Catalan\",\"Chinese\",\"Czech\",\"Danish\",\"Dutch\",\"French\",\"German\",\"Greek\",\"Hindi\",\"Hungarian\",\"Italian\",\"Japanese\",\"Malay\",\"Norwegian\",\"Polish\",\"Portuguese (Brazil)\",\"Portuguese\",\"Romanian\",\"Russian\",\"Slovak\",\"Spanish\",\"Tamil\",\"Turkish\",\"Vietnamese\"]', 'noreply@example.com', '', 'smtp.example.com', 'noreply@example.com', 'SpiritForms', 465, '1', '1', '// Functions placed here are available anywhere in nuBuilder.\n\n\n// Runs after each Edit Form loads\nfunction nuLoadEditGlobal(formId, formCode) {\n\n}\n\n// Runs after each Browse Form loads\nfunction nuLoadBrowseGlobal(formId, formCode) {\n\n}\n\n\n//Add tooltip for Add button, etc.\nfunction nuOnLoad(formId, formCode) {\n    if (nuGlobalAccess()) {\n     ;\n    }\n\n    // Map of button IDs â†’ tooltips\n    const tooltips = {\n        \'#nuAddButton\': \'Add a new record\',\n        \'#nuPrintButton\': \'Copy to clipboard, save to .csv\'\n        // Add more if needed, e.g. \'#nuExportButton\': \'Export to CSV\'\n    };\n\n    // One delegated event handler for all buttons\n    $(document).on(\'mouseenter focus\', Object.keys(tooltips).join(\',\'), function() {\n        const $btn = $(this);\n        const id = \'#\' + $btn.attr(\'id\');\n        const tooltipText = tooltips[id];\n\n        if (tooltipText && !$btn.data(\'tooltip-set\')) {\n            $btn.attr(\'title\', tooltipText);\n            $btn.data(\'tooltip-set\', true);\n        }\n    });\n\n    // Optional: apply immediately if already present\n    for (const [selector, text] of Object.entries(tooltips)) {\n        const $el = $(selector);\n        if ($el.length && !$el.data(\'tooltip-set\')) {\n            $el.attr(\'title\', text).data(\'tooltip-set\', true);\n        }\n    }\n}\n\n\n\n', '// Add external CSS/JS file here\n\n<!--\n\n<link rel=\"stylesheet\" type=\"text/css\" href=\"path_to_css.css\"/>\n\n<script src=\"path_to_js.js\"></script>\n\n-->\n\n\n\n', '/* Define your own styles, override styles from nubuilder4.css */\n\n\n/* CSS overrides */\n\n\n\n/*Fix for datepicker/tooltip issue*/\n.datepicker-dropdown {\n  z-index: 9999; \n}\n\n/*Let tooltip stay visible when hovering over the tooltip*/\n.nu-tooltip-container:hover .nu-tooltip-popup,\n.nu-tooltip-popup:hover {\n  opacity: 1;\n  visibility: visible;\n  pointer-events: auto;\n}\n\n\n/* FINAL SELECT2 BOX ITEM DISPLAY SETTINGS*/\n.select2-container--default .select2-selection__choice {\n    /*Displayed item background color*/\n    background-color: #8c8682 !important;\n    /*Displayed item text color*/\n    color: black !important;\n}\n\n.select2-container--default .select2-selection--multiple {\n/* FINAL SELECT2 BOX BACKGROUND COLOR SETTING */\n  background-color: #8c8682 !important;\n}\n\n\n/* SELECT2 DROPDOWN SETTINGS */\n\n.select2-container--default .select2-results__option--selected {\n    background-color: #8c8682 !important;\n    color: #333 !important;\n}\n\n.select2-container--default .select2-results__option--highlighted.select2-results__option--selectable {\n    background-color: #2196F3 !important;\n    color: black !important;\n}\n\n\n\n\n/*\n .nuActionButton {\n background-color: #579cb7;\n}\n\n*/\n\n:root {\n	--nu-black: rgba(0, 0, 0, 0.8);\n	--nu-label: #21130d;\n	--nu-php: #f3f0f7;\n	--nu-js: #fffced;\n	--nu-html: #faf3ef;\n	--nu-sql: #eaf6ff;\n	--nu-css: #f4f7f4;\n	--nu-border: #e9ecef;\n	--nu-body: #fdfdfd;\n	--nu-edit-body: rgb(245 247 250 / 45%);\n	--nu-font-sans-serif: \"Noto Sans\", \"Helvetica Neue\", Arial, sans-serif;\n	--nu-font-code: \"Lucida Console\", sans-serif;\n}\n\n\n\n\n.nuEditBody {\n	background-color: rgb(12 45 95 / 45%);\n}\n\n.nuContentBoxContent {\n	height: inherit;\n	font-size: 15px;\n	border-bottom-left-radius: 7px;\n	border-bottom-right-radius: 7px;\n	border: 1px solid var(--nu-border);\n	background-color: #919497;\n}\n\n.nuActionHolder {\n	padding: 5px 0px 10px 0px;\n	background-color: #919497;\n	height: 35px;\n	text-align: left;\n	user-select: none;\n}\n\n.nuTabHolder {\nbackground-color: #919497;\n\n}\n\n\n.nuCellEven {\n	background-color: #919497;\n}\n\n.nuCellOdd {\n	background-color: #b5dadd;\n}\n\n.nuLogin {\n	background-color: black;\n	border-style: solid;\n	border-width: 1px 3px 3px 1px;\n	border-color: rgba(0, 0, 0, 0.08);\n	height: 300px;\n	width: 350px;\n	margin: 50px auto 0;\n	padding: 30px;\n	border-radius: 10px;\n}\n\n.nuBrowseSearch {\n	color: black;\n}\n\n\n// Pin Save, Delete, Clone bar to top (by Kevin)\n\n.nuBreadcrumbHolder {\n  position: sticky;\n  top: 0;\n  z-index: 1000;\n}\n\n.nuActionHolder {\n  position: sticky;\n  top: 33px;\n  z-index: 999;\n}\n\n.nuSubformTitleHolder {\n    background-color: #91a0b7;\n}\n\n.nuSubformScrollDiv {\n    background-color: #91a0b7;\n}', '0', NULL);
